window.QUIZ_DATA["prm"] = [{"id":1,"task":"re","taskLabel":"SP26-B5-FE","num":1,"question":"Which widget pattern protects authenticated routes?","options":{"A":"Navigator","B":"Guard","C":"Route protection","D":"Middleware"},"answer":"B","alternatives":[],"explanation":{"questionVi":"Mẫu widget nào bảo vệ các route cần xác thực?","optionsVi":{"A":"Navigator","B":"Guard","C":"Route protection","D":"Middleware"},"answerDisplay":"B. Guard","concept":"• Mẫu chặn/cho phép vào route đã xác thực (route guard / middleware).","whyCorrect":"• Mẫu Guard (route guard) chặn/cho phép vào route đã xác thực. Navigator chỉ điều hướng; Middleware là khái niệm web/server, không phải widget pattern Flutter chuẩn.\n• Mẫu chặn/cho phép vào route đã xác thực (route guard / middleware).\n• Bảo vệ màn cần login; khác Navigator chỉ push/pop.","intent":"• Mẫu chặn/cho phép vào route đã xác thực (route guard / middleware).\n• Chọn phương án khớp cơ chế Flutter, không chọn stack web/Android nhầm.","memoryTip":"• Auth: token/session tập trung; Guard chặn route; StreamBuilder hay dùng với auth stream.","whatIs":{"A":"Cơ chế xếp chồng màn hình (stack) và chuyển page.","B":"Mẫu chặn/cho phép vào route đã xác thực (route guard / middleware).","C":"Mẫu chặn/cho phép vào route đã xác thực (route guard / middleware).","D":"Mẫu chặn/cho phép vào route đã xác thực (route guard / middleware)."},"whyWrong":{"A":"• Là gì? Cơ chế xếp chồng màn hình (stack) và chuyển page.\n• Dùng để làm gì? push/pop route, điều hướng luồng màn hình.\n• Vì sao sai? Navigator chỉ điều hướng màn hình, không tự chặn route theo auth.","C":"• Là gì? Mẫu chặn/cho phép vào route đã xác thực (route guard / middleware).\n• Dùng để làm gì? Bảo vệ màn cần login; khác Navigator chỉ push/pop.\n• Vì sao sai? Đây là mô tả chung, không phải tên pattern/widget cụ thể như Guard.","D":"• Là gì? Mẫu chặn/cho phép vào route đã xác thực (route guard / middleware).\n• Dùng để làm gì? Bảo vệ màn cần login; khác Navigator chỉ push/pop.\n• Vì sao sai? Middleware là khái niệm server/web (Express…), không phải pattern widget Flutter chuẩn cho auth route."}},"source":"SP26-B5-FE"},{"id":2,"task":"re","taskLabel":"SP26-B5-FE","num":2,"question":"Why are tests important for refactoring?","options":{"A":"Reduce UI work","B":"Ensure changes don't break functionality","C":"Improve animations","D":"Change layout"},"answer":"B","alternatives":[],"explanation":{"questionVi":"Vì sao test quan trọng khi refactor?","optionsVi":{"A":"Giảm UI công việc","B":"Đảm bảo thay đổi không phá chức năng","C":"Cải thiện animations","D":"Thay đổi bố cục"},"answerDisplay":"B. Đảm bảo thay đổi không phá chức năng","concept":"• Đảm bảo thay đổi không phá chức năng. Bản dịch/diễn đạt phương án — đối chiếu với định nghĩa chuẩn của đề.","whyCorrect":"• Đảm bảo thay đổi không phá chức năng\n• Bản dịch/diễn đạt phương án — đối chiếu với định nghĩa chuẩn của đề.","intent":"• Đảm bảo thay đổi không phá chức năng\n• Bản dịch/diễn đạt phương án — đối chiếu với định nghĩa chuẩn của đề.","memoryTip":"• Unit = logic nhỏ · Widget = UI · Integration = nhiều phần/E2E · Test bảo vệ khi refactor.","whatIs":{"A":"Cụm «Giảm UI công việc» mang một nghĩa riêng cần đối chiếu với đề.","B":"Đảm bảo thay đổi không phá chức năng","C":"Cụm «Cải thiện animations» mang một nghĩa riêng cần đối chiếu với đề.","D":"Cụm «Thay đổi bố cục» mang một nghĩa riêng cần đối chiếu với đề."},"whyWrong":{"A":"• Là gì? Cụm «Giảm UI công việc» mang một nghĩa riêng cần đối chiếu với đề.\n• Dùng để làm gì? So bản chất với đáp án đúng; loại nếu sai đối tượng hoặc sai lớp khái niệm.\n• Vì sao sai? Không phải mục tiêu chính của test khi refactor; test bảo vệ hành vi khỏi bị hỏng.","C":"• Là gì? Cụm «Cải thiện animations» mang một nghĩa riêng cần đối chiếu với đề.\n• Dùng để làm gì? So bản chất với đáp án đúng; loại nếu sai đối tượng hoặc sai lớp khái niệm.\n• Vì sao sai? Không phải mục tiêu chính của test khi refactor; test bảo vệ hành vi khỏi bị hỏng.","D":"• Là gì? Cụm «Thay đổi bố cục» mang một nghĩa riêng cần đối chiếu với đề.\n• Dùng để làm gì? So bản chất với đáp án đúng; loại nếu sai đối tượng hoặc sai lớp khái niệm.\n• Vì sao sai? Không phải mục tiêu chính của test khi refactor; test bảo vệ hành vi khỏi bị hỏng."}},"source":"SP26-B5-FE","_pilotFixed":"2026-07-23-v1"},{"id":3,"task":"re","taskLabel":"SP26-B5-FE","num":3,"question":"What is the role of BuildContext in Flutter?","options":{"A":"Store application data","B":"Locate widgets in the widget tree","C":"Manage navigation history","D":"Render UI pixels"},"answer":"B","alternatives":[],"explanation":{"questionVi":"Vai trò của BuildContext là gì? in Flutter?","optionsVi":{"A":"Lưu application dữ liệu","B":"Định vị widget trên cây widget","C":"Quản lý lịch sử điều hướng","D":"Vẽ pixel giao diện"},"answerDisplay":"B. Định vị widget trên cây widget","concept":"• Handle trỏ tới vị trí Element của một widget trên widget tree.","whyCorrect":"• BuildContext dùng để định vị widget trong cây, tìm ancestor (Theme, Navigator, MediaQuery…). Không lưu data app hay vẽ pixel.\n• Handle trỏ tới vị trí Element của một widget trên widget tree.\n• Tìm ancestor/InheritedWidget (Theme, MediaQuery, Navigator.of…).","intent":"• BuildContext gắn với vị trí widget trên cây.\n• Dùng context để lấy InheritedWidget/Navigator — không phải kho data hay engine vẽ.","memoryTip":"• UI = cây widget; BuildContext định vị trên cây; build() chỉ mô tả UI.","whatIs":{"A":"Lưu dữ liệu ứng dụng (state/storage), không phải tọa độ widget.","B":"Handle trỏ tới vị trí Element của một widget trên widget tree.","C":"Quản lý lịch sử điều hướng","D":"Vẽ pixel/lớp đồ họa lên màn hình."},"whyWrong":{"A":"• Là gì? Lưu dữ liệu ứng dụng (state/storage), không phải tọa độ widget.\n• Dùng để làm gì? State management / local storage — khác vai trò BuildContext trên tree.\n• Vì sao sai? «Store application data» — Lưu dữ liệu ứng dụng (state/storage), không phải tọa độ widget. Đề cần: Handle trỏ tới vị trí Element của một widget trên widget tree.","C":"• Là gì? Quản lý lịch sử điều hướng\n• Dùng để làm gì? Bản dịch/diễn đạt phương án — đối chiếu với định nghĩa chuẩn của đề.\n• Vì sao sai? Lịch sử điều hướng do Navigator giữ; BuildContext chỉ giúp gọi Navigator.of(context).","D":"• Là gì? Vẽ pixel/lớp đồ họa lên màn hình.\n• Dùng để làm gì? Thuộc RenderObject/engine (Skia); không phải Handle BuildContext.\n• Vì sao sai? Vẽ pixel thuộc RenderObject/engine; BuildContext không tự paint."}},"source":"SP26-B5-FE"},{"id":4,"task":"re","taskLabel":"SP26-B5-FE","num":4,"question":"What role does the Flutter framework play in application development?","options":{"A":"It manages database servers","B":"It provides UI components and rendering logic","C":"It replaces the operating system","D":"It runs backend business logic"},"answer":"B","alternatives":[],"explanation":{"questionVi":"Vai trò củ Flutter framework trong phát triển ứng dụng?","optionsVi":{"A":"It manages cơ sở dữ liệu servers","B":"It provides UI thành phần và rendering logic","C":"It replaces the operating system","D":"Runs backend logic nghiệp vụ"},"answerDisplay":"B. It provides UI thành phần và rendering logic","concept":"• It provides UI thành phần và rendering logic. Bản dịch/diễn đạt phương án — đối chiếu với định nghĩa chuẩn của đề.","whyCorrect":"• Flutter cung cấp UI components + engine render. Không thay OS, không chạy backend/DB server.\n• It provides UI thành phần và rendering logic\n• Bản dịch/diễn đạt phương án — đối chiếu với định nghĩa chuẩn của đề.","intent":"• It provides UI thành phần và rendering logic\n• Chọn phương án khớp cơ chế Flutter, không chọn stack web/Android nhầm.","memoryTip":"• Flutter cung cấp UI components + engine render. Không thay OS, không chạy backend/DB server.","whatIs":{"A":"It manages cơ sở dữ liệu servers","B":"It provides UI thành phần và rendering logic","C":"Phần mềm quản lý phần cứng, tiến trình, bộ nhớ, I/O.","D":"It runs backend logic nghiệp vụ"},"whyWrong":{"A":"• Là gì? It manages cơ sở dữ liệu servers\n• Dùng để làm gì? Bản dịch/diễn đạt phương án — đối chiếu với định nghĩa chuẩn của đề.\n• Vì sao sai? Nằm ngoài vai trò framework UI Flutter.","C":"• Là gì? Phần mềm quản lý phần cứng, tiến trình, bộ nhớ, I/O.\n• Dùng để làm gì? Cấp tài nguyên và lập lịch cho chương trình.\n• Vì sao sai? Nằm ngoài vai trò framework UI Flutter.","D":"• Là gì? It runs backend logic nghiệp vụ\n• Dùng để làm gì? Bản dịch/diễn đạt phương án — đối chiếu với định nghĩa chuẩn của đề.\n• Vì sao sai? Nằm ngoài vai trò framework UI Flutter."}},"source":"SP26-B5-FE","_pilotFixed":"2026-07-23-v1"},{"id":5,"task":"re","taskLabel":"SP26-B5-FE","num":5,"question":"How is the Flutter UI constructed internally?","options":{"A":"Using XML layout files","B":"Using HTML and CSS","C":"Using a hierarchical widget tree","D":"Using native UI components only"},"answer":"C","alternatives":[],"explanation":{"questionVi":"Như thế nào Flutter UI constructed internally?","optionsVi":{"A":"Dùng XML bố cục files","B":"Dùng HTML và CSS","C":"Dùng một hierarchical cây widget","D":"Dùng native UI thành phần"},"answerDisplay":"C. Dùng một hierarchical cây widget","concept":"• Mô hình dữ liệu dạng cây cha–con, truy cập từ gốc xuống một nhánh.","whyCorrect":"• UI Flutter được mô tả bằng cây widget phân cấp (widget tree). Không dùng XML/HTML/CSS layout như Android/web cổ điển.\n• Mô hình dữ liệu dạng cây cha–con, truy cập từ gốc xuống một nhánh.\n• Tổ chức dữ liệu phân cấp (thư mục, BOM…).","intent":"• Phân biệt const, final, var và null safety.\n• Compile-time vs runtime assignment.","memoryTip":"• UI Flutter được mô tả bằng cây widget phân cấp (widget tree). Không dùng XML/HTML/CSS layout như Android/web cổ điển.","whatIs":{"A":"Cơ chế Flutter/Dart liên quan «Dùng XML bố cục files».","B":"Cơ chế Flutter/Dart liên quan «Dùng HTML và CSS».","C":"Mô hình dữ liệu dạng cây cha–con, truy cập từ gốc xuống một nhánh.","D":"Dùng native UI thành phần"},"whyWrong":{"A":"• Là gì? Cơ chế Flutter/Dart liên quan «Dùng XML bố cục files».\n• Dùng để làm gì? Đối chiếu đúng cơ chế/phạm trù với trọng tâm đề.\n• Vì sao sai? Flutter không dựng UI chính bằng XML/HTML/CSS như Android View/web cổ điển.","B":"• Là gì? Cơ chế Flutter/Dart liên quan «Dùng HTML và CSS».\n• Dùng để làm gì? Đối chiếu đúng cơ chế/phạm trù với trọng tâm đề.\n• Vì sao sai? Flutter không dựng UI chính bằng XML/HTML/CSS như Android View/web cổ điển.","D":"• Là gì? Dùng native UI thành phần\n• Dùng để làm gì? Bản dịch/diễn đạt phương án — đối chiếu với định nghĩa chuẩn của đề.\n• Vì sao sai? «Using native UI components only» — Dùng native UI thành phần. Đề cần: Mô hình dữ liệu dạng cây cha–con, truy cập từ gốc xuống một nhánh."}},"source":"SP26-B5-FE"},{"id":6,"task":"re","taskLabel":"SP26-B5-FE","num":6,"question":"Which widget enables custom scroll effects in Flutter?","options":{"A":"ListView","B":"SingleChildScrollView","C":"CustomScrollView","D":"Column"},"answer":"C","alternatives":[],"explanation":{"questionVi":"Cái nào widget enables custom scroll effects trong Flutter?","optionsVi":{"A":"ListView","B":"SingleChildScrollView","C":"CustomScrollView","D":"Column"},"answerDisplay":"C. CustomScrollView","concept":"• Cơ chế Flutter/Dart liên quan «CustomScrollView».","whyCorrect":"• CustomScrollView cho phép sliver + hiệu ứng scroll tùy biến. ListView/SingleChildScrollView đơn giản hơn; Column không scroll.\n• Cơ chế Flutter/Dart liên quan «CustomScrollView».","intent":"• Cơ chế Flutter/Dart liên quan «CustomScrollView».\n• Chọn phương án khớp cơ chế Flutter, không chọn stack web/Android nhầm.","memoryTip":"• Ghi nhớ cặp: câu hỏi ↔ C. CustomScrollView","whatIs":{"A":"Cơ chế Flutter/Dart liên quan «ListView».","B":"Cơ chế Flutter/Dart liên quan «SingleChildScrollView».","C":"Cơ chế Flutter/Dart liên quan «CustomScrollView».","D":"Xếp widget con theo cột dọc (main axis = vertical)."},"whyWrong":{"A":"• Là gì? Cơ chế Flutter/Dart liên quan «ListView».\n• Dùng để làm gì? Đối chiếu đúng cơ chế/phạm trù với trọng tâm đề.\n• Vì sao sai? «ListView» — Cơ chế Flutter/Dart liên quan «ListView». Đề cần: Cơ chế Flutter/Dart liên quan «CustomScrollView».","B":"• Là gì? Cơ chế Flutter/Dart liên quan «SingleChildScrollView».\n• Dùng để làm gì? Đối chiếu đúng cơ chế/phạm trù với trọng tâm đề.\n• Vì sao sai? «SingleChildScrollView» — Cơ chế Flutter/Dart liên quan «SingleChildScrollView». Đề cần: Cơ chế Flutter/Dart liên quan «CustomScrollView».","D":"• Là gì? Xếp widget con theo cột dọc (main axis = vertical).\n• Dùng để làm gì? Bố cục dọc; cross axis là ngang. Không scroll mặc định, không overlap.\n• Vì sao sai? «Column» — Xếp widget con theo cột dọc (main axis = vertical). Đề cần: Cơ chế Flutter/Dart liên quan «CustomScrollView»."}},"source":"SP26-B5-FE"},{"id":7,"task":"re","taskLabel":"SP26-B5-FE","num":7,"question":"Which practice improves rendering performance?","options":{"A":"Large widget trees","B":"Splitting widgets","C":"Global state","D":"Frequent rebuilds"},"answer":"B","alternatives":[],"explanation":{"questionVi":"Cái nào practice improves rendering performance?","optionsVi":{"A":"Large cây widgets","B":"Splitting widgets","C":"Global state","D":"Frequent rebuilds"},"answerDisplay":"B. Splitting widgets","concept":"• Mức mượt và tiết kiệm tài nguyên khi render/chạy app.","whyCorrect":"• Tách nhỏ widget giảm rebuild không cần thiết, cải thiện performance. Cây lớn, global state, rebuild liên tục làm chậm.\n• Mức mượt và tiết kiệm tài nguyên khi render/chạy app.\n• Skia/AOT/rebuild hẹp giúp UI mượt.","intent":"• Mức mượt và tiết kiệm tài nguyên khi render/chạy app.\n• Chọn phương án khớp cơ chế Flutter, không chọn stack web/Android nhầm.","memoryTip":"• Tách nhỏ widget giảm rebuild không cần thiết, cải thiện performance. Cây lớn, global state, rebuild liên tục làm chậm.","whatIs":{"A":"Cây cấu hình UI lồng nhau mô tả giao diện tại một thời điểm.","B":"Mức mượt và tiết kiệm tài nguyên khi render/chạy app.","C":"Cách chia sẻ và phản ứng với trạng thái dùng chung giữa nhiều widget/màn.","D":"Cụm «Frequent rebuilds» mang một nghĩa riêng cần đối chiếu với đề."},"whyWrong":{"A":"• Là gì? Cây cấu hình UI lồng nhau mô tả giao diện tại một thời điểm.\n• Dùng để làm gì? Đầu vào cho Element/Render pipeline của Flutter.\n• Vì sao sai? «Large widget trees» — Cây cấu hình UI lồng nhau mô tả giao diện tại một thời điểm. Đề cần: Mức mượt và tiết kiệm tài nguyên khi render/chạy app.","C":"• Là gì? Cách chia sẻ và phản ứng với trạng thái dùng chung giữa nhiều widget/màn.\n• Dùng để làm gì? Tránh truyền prop sâu; cập nhật UI khi state đổi.\n• Vì sao sai? Global khó kiểm soát, dễ rebuild/test kém — thường là đáp án nhiễu.","D":"• Là gì? Cụm «Frequent rebuilds» mang một nghĩa riêng cần đối chiếu với đề.\n• Dùng để làm gì? So bản chất với đáp án đúng; loại nếu sai đối tượng hoặc sai lớp khái niệm.\n• Vì sao sai? «Frequent rebuilds» — Cụm «Frequent rebuilds» mang một nghĩa riêng cần đối chiếu với đề. Đề cần: Mức mượt và tiết kiệm tài nguyên khi render/chạy app."}},"source":"SP26-B5-FE"},{"id":8,"task":"re","taskLabel":"SP26-B5-FE","num":8,"question":"What does an integration test verify?","options":{"A":"Single function","B":"Widget rendering","C":"End-to-end app behavior","D":"Theme consistency"},"answer":"C","alternatives":[],"explanation":{"questionVi":"Integration test xác minh gì?","optionsVi":{"A":"một hàm","B":"Widget rendering","C":"Kết thúc-để-kết thúc app behavior","D":"Theme consistency"},"answerDisplay":"C. Kết thúc-để-kết thúc app behavior","concept":"• Kết thúc-để-kết thúc app behavior. Bản dịch/diễn đạt phương án — đối chiếu với định nghĩa chuẩn của đề.","whyCorrect":"• Kết thúc-để-kết thúc app behavior\n• Bản dịch/diễn đạt phương án — đối chiếu với định nghĩa chuẩn của đề.","intent":"• Kết thúc-để-kết thúc app behavior\n• Bản dịch/diễn đạt phương án — đối chiếu với định nghĩa chuẩn của đề.","memoryTip":"• Unit = logic nhỏ · Widget = UI · Integration = nhiều phần/E2E · Test bảo vệ khi refactor.","whatIs":{"A":"Cụm «một hàm» mang một nghĩa riêng cần đối chiếu với đề.","B":"Cơ chế Flutter/Dart liên quan «Widget rendering».","C":"Kết thúc-để-kết thúc app behavior","D":"UI/hành vi thống nhất trên nhiều thiết bị nhờ một codebase Flutter."},"whyWrong":{"A":"• Là gì? Cụm «một hàm» mang một nghĩa riêng cần đối chiếu với đề.\n• Dùng để làm gì? So bản chất với đáp án đúng; loại nếu sai đối tượng hoặc sai lớp khái niệm.\n• Vì sao sai? «Single function» — Cụm «một hàm» mang một nghĩa riêng cần đối chiếu với đề. Đề cần: Kết thúc-để-kết thúc app behavior.","B":"• Là gì? Cơ chế Flutter/Dart liên quan «Widget rendering».\n• Dùng để làm gì? Đối chiếu đúng cơ chế/phạm trù với trọng tâm đề.\n• Vì sao sai? Integration: nhiều thành phần/E2E; không phải unit đơn lẻ.","D":"• Là gì? UI/hành vi thống nhất trên nhiều thiết bị nhờ một codebase Flutter.\n• Dùng để làm gì? Giảm lệch giao diện giữa iOS/Android.\n• Vì sao sai? Integration: nhiều thành phần/E2E; không phải unit đơn lẻ."}},"source":"SP26-B5-FE"},{"id":9,"task":"re","taskLabel":"SP26-B5-FE","num":9,"question":"Why is separating UI and state logic recommended?","options":{"A":"Reduce code size","B":"Improve maintainability","C":"Faster execution","D":"Better animations"},"answer":"B","alternatives":[],"explanation":{"questionVi":"Vì sao separating UI và state logic recommended?","optionsVi":{"A":"Giảm mã kích thước","B":"Cải thiện khả năng bảo trì","C":"Nhanh hơn execution","D":"Tốt hơn animations"},"answerDisplay":"B. Cải thiện khả năng bảo trì","concept":"• Cải thiện khả năng bảo trì. Bản dịch/diễn đạt phương án — đối chiếu với định nghĩa chuẩn của đề.","whyCorrect":"• Tách UI và state logic giúp bảo trì, test dễ, giảm coupling. Không chủ yếu vì animation hay tốc độ thuần.\n• Cải thiện khả năng bảo trì\n• Bản dịch/diễn đạt phương án — đối chiếu với định nghĩa chuẩn của đề.","intent":"• Cải thiện khả năng bảo trì\n• Bản dịch/diễn đạt phương án — đối chiếu với định nghĩa chuẩn của đề.","memoryTip":"• Tách UI và state logic giúp bảo trì, test dễ, giảm coupling. Không chủ yếu vì animation hay tốc độ thuần.","whatIs":{"A":"Cụm «Giảm mã kích thước» mang một nghĩa riêng cần đối chiếu với đề.","B":"Cải thiện khả năng bảo trì","C":"Cụm «Nhanh hơn execution» mang một nghĩa riêng cần đối chiếu với đề.","D":"Cụm «Tốt hơn animations» mang một nghĩa riêng cần đối chiếu với đề."},"whyWrong":{"A":"• Là gì? Cụm «Giảm mã kích thước» mang một nghĩa riêng cần đối chiếu với đề.\n• Dùng để làm gì? So bản chất với đáp án đúng; loại nếu sai đối tượng hoặc sai lớp khái niệm.\n• Vì sao sai? «Reduce code size» — Cụm «Giảm mã kích thước» mang một nghĩa riêng cần đối chiếu với đề. Đề cần: Cải thiện khả năng bảo trì.","C":"• Là gì? Cụm «Nhanh hơn execution» mang một nghĩa riêng cần đối chiếu với đề.\n• Dùng để làm gì? So bản chất với đáp án đúng; loại nếu sai đối tượng hoặc sai lớp khái niệm.\n• Vì sao sai? «Faster execution» — Cụm «Nhanh hơn execution» mang một nghĩa riêng cần đối chiếu với đề. Đề cần: Cải thiện khả năng bảo trì.","D":"• Là gì? Cụm «Tốt hơn animations» mang một nghĩa riêng cần đối chiếu với đề.\n• Dùng để làm gì? So bản chất với đáp án đúng; loại nếu sai đối tượng hoặc sai lớp khái niệm.\n• Vì sao sai? «Better animations» — Cụm «Tốt hơn animations» mang một nghĩa riêng cần đối chiếu với đề. Đề cần: Cải thiện khả năng bảo trì."}},"source":"SP26-B5-FE"},{"id":10,"task":"re","taskLabel":"SP26-B5-FE","num":10,"question":"When does Flutter rebuild the widget tree?","options":{"A":"On every frame","B":"When state changes","C":"Only when app restarts","D":"Only during hot restart"},"answer":"B","alternatives":[],"explanation":{"questionVi":"Câu hỏi: khi Flutter rebuild widget tree?","optionsVi":{"A":"Trên mọi frame","B":"Khi state thay đổi","C":"Chỉ Khi app restarts","D":"Chỉ Trong lúc hot restart"},"answerDisplay":"B. Khi state thay đổi","concept":"• Cây cấu hình UI lồng nhau mô tả giao diện tại một thời điểm.","whyCorrect":"• Flutter rebuild khi state thay đổi (setState, notifyListeners, emit state…). Không rebuild mỗi frame trừ khi animation/ticker yêu cầu.\n• Cây cấu hình UI lồng nhau mô tả giao diện tại một thời điểm.\n• Đầu vào cho Element/Render pipeline của Flutter.","intent":"• Cây cấu hình UI lồng nhau mô tả giao diện tại một thời điểm.\n• Chọn phương án khớp cơ chế Flutter, không chọn stack web/Android nhầm.","memoryTip":"• Đổi state → rebuild; BLoC/Cubit/Provider tách logic khỏi UI; state nên immutable.","whatIs":{"A":"Cơ chế Flutter/Dart liên quan «Trên mọi frame».","B":"Cây cấu hình UI lồng nhau mô tả giao diện tại một thời điểm.","C":"Cơ chế Flutter/Dart liên quan «Chỉ Khi app restarts».","D":"Chạy lại app từ đầu, reset state."},"whyWrong":{"A":"• Là gì? Cơ chế Flutter/Dart liên quan «Trên mọi frame».\n• Dùng để làm gì? Đối chiếu đúng cơ chế/phạm trù với trọng tâm đề.\n• Vì sao sai? Không rebuild mỗi frame (trừ animation/ticker). Chỉ khi state/config liên quan đổi.","C":"• Là gì? Cơ chế Flutter/Dart liên quan «Chỉ Khi app restarts».\n• Dùng để làm gì? Đối chiếu đúng cơ chế/phạm trù với trọng tâm đề.\n• Vì sao sai? App restart/hot restart nạp lại app; rebuild UI hàng ngày đến từ setState/state management.","D":"• Là gì? Chạy lại app từ đầu, reset state.\n• Dùng để làm gì? Khi cần khởi tạo lại toàn bộ sau đổi lớn.\n• Vì sao sai? App restart/hot restart nạp lại app; rebuild UI hàng ngày đến từ setState/state management."}},"source":"SP26-B5-FE"},{"id":11,"task":"re","taskLabel":"SP26-B5-FE","num":11,"question":"Which concept does BLoC heavily rely on?","options":{"A":"Future","B":"Stream","C":"Animation","D":"Theme"},"answer":"B","alternatives":[],"explanation":{"questionVi":"Cái nào concept BLoC heavily rely?","optionsVi":{"A":"Future","B":"Stream","C":"Animation","D":"Theme"},"answerDisplay":"B. Stream","concept":"• Cách chia sẻ và phản ứng với trạng thái dùng chung giữa nhiều widget/màn.","whyCorrect":"• BLoC dựa mạnh trên Stream (event in → state out). Future dùng một lần; không phải Theme/Animation.\n• Cách chia sẻ và phản ứng với trạng thái dùng chung giữa nhiều widget/màn.\n• Tránh truyền prop sâu; cập nhật UI khi state đổi.","intent":"• Cách chia sẻ và phản ứng với trạng thái dùng chung giữa nhiều widget/màn.\n• Tránh truyền prop sâu; cập nhật UI khi state đổi.","memoryTip":"• Đổi state → rebuild; BLoC/Cubit/Provider tách logic khỏi UI; state nên immutable.","whatIs":{"A":"Đối tượng đại diện một kết quả (hoặc lỗi) sẽ có sau thao tác bất đồng bộ.","B":"Cách chia sẻ và phản ứng với trạng thái dùng chung giữa nhiều widget/màn.","C":"Cơ chế Flutter/Dart liên quan «Animation».","D":"Cơ chế Flutter/Dart liên quan «Theme»."},"whyWrong":{"A":"• Là gì? Đối tượng đại diện một kết quả (hoặc lỗi) sẽ có sau thao tác bất đồng bộ.\n• Dùng để làm gì? async/await, gọi API, đọc file một lần.\n• Vì sao sai? «Future» — Đối tượng đại diện một kết quả (hoặc lỗi) sẽ có sau thao tác bất đồng bộ. Đề cần: Cách chia sẻ và phản ứng với trạng thái dùng chung giữa nhiều widget/màn.","C":"• Là gì? Cơ chế Flutter/Dart liên quan «Animation».\n• Dùng để làm gì? Đối chiếu đúng cơ chế/phạm trù với trọng tâm đề.\n• Vì sao sai? Liên quan chuyển động UI, không giải quyết khái niệm trong câu hỏi.","D":"• Là gì? Cơ chế Flutter/Dart liên quan «Theme».\n• Dùng để làm gì? Đối chiếu đúng cơ chế/phạm trù với trọng tâm đề.\n• Vì sao sai? Theme/ThemeData lo style giao diện, không phải state/auth/logic chính ở đây."}},"source":"SP26-B5-FE"},{"id":12,"task":"re","taskLabel":"SP26-B5-FE","num":12,"question":"Why is version control critical?","options":{"A":"UI changes","B":"Track and manage code changes","C":"Improve animations","D":"Store data"},"answer":"B","alternatives":[],"explanation":{"questionVi":"Vì sao quản lý phiên bản critical?","optionsVi":{"A":"UI thay đổi","B":"Track và Quản lý mã thay đổi","C":"Cải thiện animations","D":"Lưu dữ liệu"},"answerDisplay":"B. Track và Quản lý mã thay đổi","concept":"• Track và Quản lý mã thay đổi. Bản dịch/diễn đạt phương án — đối chiếu với định nghĩa chuẩn của đề.","whyCorrect":"• Version control theo dõi và quản lý thay đổi mã nguồn, cộng tác, rollback.\n• Track và Quản lý mã thay đổi\n• Bản dịch/diễn đạt phương án — đối chiếu với định nghĩa chuẩn của đề.","intent":"• Track và Quản lý mã thay đổi\n• Bản dịch/diễn đạt phương án — đối chiếu với định nghĩa chuẩn của đề.","memoryTip":"• Version control theo dõi và quản lý thay đổi mã nguồn, cộng tác, rollback.","whatIs":{"A":"Cụm «UI thay đổi» mang một nghĩa riêng cần đối chiếu với đề.","B":"Track và Quản lý mã thay đổi","C":"Cụm «Cải thiện animations» mang một nghĩa riêng cần đối chiếu với đề.","D":"Lưu dữ liệu ứng dụng (state/storage), không phải tọa độ widget."},"whyWrong":{"A":"• Là gì? Cụm «UI thay đổi» mang một nghĩa riêng cần đối chiếu với đề.\n• Dùng để làm gì? So bản chất với đáp án đúng; loại nếu sai đối tượng hoặc sai lớp khái niệm.\n• Vì sao sai? «UI changes» — Cụm «UI thay đổi» mang một nghĩa riêng cần đối chiếu với đề. Đề cần: Track và Quản lý mã thay đổi.","C":"• Là gì? Cụm «Cải thiện animations» mang một nghĩa riêng cần đối chiếu với đề.\n• Dùng để làm gì? So bản chất với đáp án đúng; loại nếu sai đối tượng hoặc sai lớp khái niệm.\n• Vì sao sai? Đây là lợi ích phụ hoặc không liên quan trực tiếp đến câu hỏi.","D":"• Là gì? Lưu dữ liệu ứng dụng (state/storage), không phải tọa độ widget.\n• Dùng để làm gì? State management / local storage — khác vai trò BuildContext trên tree.\n• Vì sao sai? «Store data» — Lưu dữ liệu ứng dụng (state/storage), không phải tọa độ widget. Đề cần: Track và Quản lý mã thay đổi."}},"source":"SP26-B5-FE"},{"id":13,"task":"re","taskLabel":"SP26-B5-FE","num":13,"question":"Why is immutability important in BLoC states?","options":{"A":"UI speed","B":"Predictable state changes","C":"Memory usage","D":"Theme control"},"answer":"B","alternatives":[],"explanation":{"questionVi":"Vì sao immutability important BLoC states?","optionsVi":{"A":"UI speed","B":"Predictable state thay đổi","C":"Memory usage","D":"Theme control"},"answerDisplay":"B. Predictable state thay đổi","concept":"• Cách chia sẻ và phản ứng với trạng thái dùng chung giữa nhiều widget/màn.","whyCorrect":"• State bất biến giúp thay đổi state có thể dự đoán, so sánh dễ, tránh side-effect khi mutate.\n• Cách chia sẻ và phản ứng với trạng thái dùng chung giữa nhiều widget/màn.\n• Tránh truyền prop sâu; cập nhật UI khi state đổi.","intent":"• Cách chia sẻ và phản ứng với trạng thái dùng chung giữa nhiều widget/màn.\n• Tránh truyền prop sâu; cập nhật UI khi state đổi.","memoryTip":"• Đổi state → rebuild; BLoC/Cubit/Provider tách logic khỏi UI; state nên immutable.","whatIs":{"A":"Cơ chế Flutter/Dart liên quan «UI speed».","B":"Cách chia sẻ và phản ứng với trạng thái dùng chung giữa nhiều widget/màn.","C":"Cơ chế Flutter/Dart liên quan «Memory usage».","D":"Cơ chế Flutter/Dart liên quan «Theme control»."},"whyWrong":{"A":"• Là gì? Cơ chế Flutter/Dart liên quan «UI speed».\n• Dùng để làm gì? Đối chiếu đúng cơ chế/phạm trù với trọng tâm đề.\n• Vì sao sai? «UI speed» — Cơ chế Flutter/Dart liên quan «UI speed». Đề cần: Cách chia sẻ và phản ứng với trạng thái dùng chung giữa nhiều widget/màn.","C":"• Là gì? Cơ chế Flutter/Dart liên quan «Memory usage».\n• Dùng để làm gì? Đối chiếu đúng cơ chế/phạm trù với trọng tâm đề.\n• Vì sao sai? «Memory usage» — Cơ chế Flutter/Dart liên quan «Memory usage». Đề cần: Cách chia sẻ và phản ứng với trạng thái dùng chung giữa nhiều widget/màn.","D":"• Là gì? Cơ chế Flutter/Dart liên quan «Theme control».\n• Dùng để làm gì? Đối chiếu đúng cơ chế/phạm trù với trọng tâm đề.\n• Vì sao sai? Theme/ThemeData lo style giao diện, không phải state/auth/logic chính ở đây."}},"source":"SP26-B5-FE"},{"id":14,"task":"re","taskLabel":"SP26-B5-FE","num":14,"question":"Which Flutter plugin provides SQLite support?","options":{"A":"hive","B":"moor","C":"sqflite","D":"shared_preferences"},"answer":"C","alternatives":[],"explanation":{"questionVi":"Cái nào Flutter plugin cung cấp SQLite support?","optionsVi":{"A":"hive","B":"moor","C":"sqflite","D":"shared_preferences"},"answerDisplay":"C. sqflite","concept":"• Cơ chế Flutter/Dart liên quan «sqflite».","whyCorrect":"• sqflite là plugin SQLite phổ biến trên Flutter. Hive = NoSQL local; shared_preferences = key-value đơn giản.\n• Cơ chế Flutter/Dart liên quan «sqflite».","intent":"• Cơ chế Flutter/Dart liên quan «sqflite».\n• Chọn phương án khớp cơ chế Flutter, không chọn stack web/Android nhầm.","memoryTip":"• sqflite là plugin SQLite phổ biến trên Flutter. Hive = NoSQL local; shared_preferences = key-value đơn giản.","whatIs":{"A":"Cơ chế Flutter/Dart liên quan «hive».","B":"Cơ chế Flutter/Dart liên quan «moor».","C":"Cơ chế Flutter/Dart liên quan «sqflite».","D":"Cơ chế Flutter/Dart liên quan «shared_preferences»."},"whyWrong":{"A":"• Là gì? Cơ chế Flutter/Dart liên quan «hive».\n• Dùng để làm gì? Đối chiếu đúng cơ chế/phạm trù với trọng tâm đề.\n• Vì sao sai? «hive» — Cơ chế Flutter/Dart liên quan «hive». Đề cần: Cơ chế Flutter/Dart liên quan «sqflite».","B":"• Là gì? Cơ chế Flutter/Dart liên quan «moor».\n• Dùng để làm gì? Đối chiếu đúng cơ chế/phạm trù với trọng tâm đề.\n• Vì sao sai? «moor» — Cơ chế Flutter/Dart liên quan «moor». Đề cần: Cơ chế Flutter/Dart liên quan «sqflite».","D":"• Là gì? Cơ chế Flutter/Dart liên quan «shared_preferences».\n• Dùng để làm gì? Đối chiếu đúng cơ chế/phạm trù với trọng tâm đề.\n• Vì sao sai? «shared_preferences» — Cơ chế Flutter/Dart liên quan «shared_preferences». Đề cần: Cơ chế Flutter/Dart liên quan «sqflite»."}},"source":"SP26-B5-FE"},{"id":15,"task":"re","taskLabel":"SP26-B5-FE","num":15,"question":"What is the main benefit of using Maps in Dart?","options":{"A":"Storing values without keys","B":"Storing key-value pairs","C":"Rendering UI components","D":"Managing asynchronous tasks"},"answer":"B","alternatives":[],"explanation":{"questionVi":"Cái gì là main benefit dùng Maps Dart?","optionsVi":{"A":"Storing values Không có keys","B":"Storing key–giá trị pairs","C":"Rendering UI thành phần","D":"Managing bất đồng bộ tasks"},"answerDisplay":"B. Storing key–giá trị pairs","concept":"• Ngôn ngữ lập trình chính của Flutter. Viết UI và logic app Flutter.","whyCorrect":"• Map trong Dart lưu cặp key-value.\n• Ngôn ngữ lập trình chính của Flutter.\n• Viết UI và logic app Flutter.","intent":"• Phân biệt List / Set / Map trong Dart.\n• Thứ tự, trùng lặp, hay key–value.","memoryTip":"• Map trong Dart lưu cặp key-value.","whatIs":{"A":"Storing values Không có keys","B":"Ngôn ngữ lập trình chính của Flutter.","C":"Cơ chế Flutter/Dart liên quan «Rendering UI thành phần».","D":"Managing bất đồng bộ tasks"},"whyWrong":{"A":"• Là gì? Storing values Không có keys\n• Dùng để làm gì? Bản dịch/diễn đạt phương án — đối chiếu với định nghĩa chuẩn của đề.\n• Vì sao sai? «Storing values without keys» — Storing values Không có keys. Đề cần: Ngôn ngữ lập trình chính của Flutter.","C":"• Là gì? Cơ chế Flutter/Dart liên quan «Rendering UI thành phần».\n• Dùng để làm gì? Đối chiếu đúng cơ chế/phạm trù với trọng tâm đề.\n• Vì sao sai? «Rendering UI components» — Cơ chế Flutter/Dart liên quan «Rendering UI thành phần». Đề cần: Ngôn ngữ lập trình chính của Flutter.","D":"• Là gì? Managing bất đồng bộ tasks\n• Dùng để làm gì? Bản dịch/diễn đạt phương án — đối chiếu với định nghĩa chuẩn của đề.\n• Vì sao sai? «Managing asynchronous tasks» — Managing bất đồng bộ tasks. Đề cần: Ngôn ngữ lập trình chính của Flutter."}},"source":"SP26-B5-FE"},{"id":16,"task":"re","taskLabel":"SP26-B5-FE","num":16,"question":"Which tool helps analyze UI performance in Flutter?","options":{"A":"Inspector","B":"DevTools","C":"Emulator","D":"Hot reload"},"answer":"B","alternatives":[],"explanation":{"questionVi":"Cái nào tool helps analyze UI performance trong Flutter?","optionsVi":{"A":"Inspector","B":"DevTools","C":"Emulator","D":"Hot reload"},"answerDisplay":"B. DevTools","concept":"• Mức mượt và tiết kiệm tài nguyên khi render/chạy app.","whyCorrect":"• Flutter DevTools phân tích performance UI, timeline, memory. Inspector chủ yếu cây widget.\n• Mức mượt và tiết kiệm tài nguyên khi render/chạy app.\n• Skia/AOT/rebuild hẹp giúp UI mượt.","intent":"• Mức mượt và tiết kiệm tài nguyên khi render/chạy app.\n• Chọn phương án khớp cơ chế Flutter, không chọn stack web/Android nhầm.","memoryTip":"• Flutter DevTools phân tích performance UI, timeline, memory. Inspector chủ yếu cây widget.","whatIs":{"A":"Cơ chế Flutter/Dart liên quan «Inspector».","B":"Mức mượt và tiết kiệm tài nguyên khi render/chạy app.","C":"Cơ chế Flutter/Dart liên quan «Emulator».","D":"Nạp lại code UI gần như giữ state đang chạy."},"whyWrong":{"A":"• Là gì? Cơ chế Flutter/Dart liên quan «Inspector».\n• Dùng để làm gì? Đối chiếu đúng cơ chế/phạm trù với trọng tâm đề.\n• Vì sao sai? Inspector chủ yếu xem widget tree, không đủ như DevTools đầy đủ.","C":"• Là gì? Cơ chế Flutter/Dart liên quan «Emulator».\n• Dùng để làm gì? Đối chiếu đúng cơ chế/phạm trù với trọng tâm đề.\n• Vì sao sai? Emulator chạy app giả lập; không phải công cụ phân tích performance.","D":"• Là gì? Nạp lại code UI gần như giữ state đang chạy.\n• Dùng để làm gì? Xem thay đổi nhanh khi dev.\n• Vì sao sai? Hot reload nạp code UI nhanh khi dev; không phải công cụ phân tích sâu."}},"source":"SP26-B5-FE"},{"id":17,"task":"re","taskLabel":"SP26-B5-FE","num":17,"question":"What does a Dart class primarily represent?","options":{"A":"A UI widget only","B":"A blueprint for creating objects","C":"A database table","D":"A network request"},"answer":"B","alternatives":[],"explanation":{"questionVi":"Cái gì Dart class primarily represent?","optionsVi":{"A":"Một UI widget","B":"Một blueprint cho creating object","C":"Một cơ sở dữ liệu table","D":"Một mạng request"},"answerDisplay":"B. Một blueprint cho creating object","concept":"• Ngôn ngữ lập trình chính của Flutter. Viết UI và logic app Flutter.","whyCorrect":"• Class là bản thiết kế (blueprint) để tạo object — OOP cơ bản.\n• Ngôn ngữ lập trình chính của Flutter.\n• Viết UI và logic app Flutter.","intent":"• Ngôn ngữ lập trình chính của Flutter.\n• Viết UI và logic app Flutter.","memoryTip":"• Class là bản thiết kế (blueprint) để tạo object — OOP cơ bản.","whatIs":{"A":"Cơ chế Flutter/Dart liên quan «Một UI widget».","B":"Ngôn ngữ lập trình chính của Flutter.","C":"Cơ chế Flutter/Dart liên quan «Một cơ sở dữ liệu table».","D":"Cơ chế Flutter/Dart liên quan «Một mạng request»."},"whyWrong":{"A":"• Là gì? Cơ chế Flutter/Dart liên quan «Một UI widget».\n• Dùng để làm gì? Đối chiếu đúng cơ chế/phạm trù với trọng tâm đề.\n• Vì sao sai? «A UI widget only» — Cơ chế Flutter/Dart liên quan «Một UI widget». Đề cần: Ngôn ngữ lập trình chính của Flutter.","C":"• Là gì? Cơ chế Flutter/Dart liên quan «Một cơ sở dữ liệu table».\n• Dùng để làm gì? Đối chiếu đúng cơ chế/phạm trù với trọng tâm đề.\n• Vì sao sai? «A database table» — Cơ chế Flutter/Dart liên quan «Một cơ sở dữ liệu table». Đề cần: Ngôn ngữ lập trình chính của Flutter.","D":"• Là gì? Cơ chế Flutter/Dart liên quan «Một mạng request».\n• Dùng để làm gì? Đối chiếu đúng cơ chế/phạm trù với trọng tâm đề.\n• Vì sao sai? «A network request» — Cơ chế Flutter/Dart liên quan «Một mạng request». Đề cần: Ngôn ngữ lập trình chính của Flutter."}},"source":"SP26-B5-FE"},{"id":18,"task":"re","taskLabel":"SP26-B5-FE","num":18,"question":"What is the purpose of SliverAppBar?","options":{"A":"Static app bar","B":"Scrollable flexible app bar","C":"Bottom navigation","D":"Drawer control"},"answer":"B","alternatives":[],"explanation":{"questionVi":"Cái gì là mục đích củ SliverAppBar?","optionsVi":{"A":"Static app bar","B":"Scrollable flexible app bar","C":"Bottom navigation","D":"Drawer control"},"answerDisplay":"B. Scrollable flexible app bar","concept":"• Phần mềm quản lý phần cứng, tiến trình, bộ nhớ, I/O.","whyCorrect":"• SliverAppBar: app bar co giãn theo scroll.\n• Phần mềm quản lý phần cứng, tiến trình, bộ nhớ, I/O.\n• Cấp tài nguyên và lập lịch cho chương trình.","intent":"• Phần mềm quản lý phần cứng, tiến trình, bộ nhớ, I/O.\n• Cấp tài nguyên và lập lịch cho chương trình.","memoryTip":"• SliverAppBar: app bar co giãn theo scroll.","whatIs":{"A":"Cụm «Static app bar» mang một nghĩa riêng cần đối chiếu với đề.","B":"Phần mềm quản lý phần cứng, tiến trình, bộ nhớ, I/O.","C":"Cụm «Bottom navigation» mang một nghĩa riêng cần đối chiếu với đề.","D":"Cụm «Drawer control» mang một nghĩa riêng cần đối chiếu với đề."},"whyWrong":{"A":"• Là gì? Cụm «Static app bar» mang một nghĩa riêng cần đối chiếu với đề.\n• Dùng để làm gì? So bản chất với đáp án đúng; loại nếu sai đối tượng hoặc sai lớp khái niệm.\n• Vì sao sai? AppBar co giãn trong scroll view; chỉ đúng khi hỏi đúng widget đó.","C":"• Là gì? Cụm «Bottom navigation» mang một nghĩa riêng cần đối chiếu với đề.\n• Dùng để làm gì? So bản chất với đáp án đúng; loại nếu sai đối tượng hoặc sai lớp khái niệm.\n• Vì sao sai? AppBar co giãn trong scroll view; chỉ đúng khi hỏi đúng widget đó.","D":"• Là gì? Cụm «Drawer control» mang một nghĩa riêng cần đối chiếu với đề.\n• Dùng để làm gì? So bản chất với đáp án đúng; loại nếu sai đối tượng hoặc sai lớp khái niệm.\n• Vì sao sai? AppBar co giãn trong scroll view; chỉ đúng khi hỏi đúng widget đó."}},"source":"SP26-B5-FE","_pilotFixed":"2026-07-23-v1"},{"id":19,"task":"re","taskLabel":"SP26-B5-FE","num":19,"question":"What is Hive mainly used for?","options":{"A":"Remote database","B":"Lightweight local NoSQL storage","C":"State management","D":"Routing"},"answer":"B","alternatives":[],"explanation":{"questionVi":"Hive chủ yếu dùng để làm gì?","optionsVi":{"A":"Remote cơ sở dữ liệu","B":"Lưu trữ NoSQL local nhẹ","C":"Quản lý state","D":"Routing"},"answerDisplay":"B. Lưu trữ NoSQL local nhẹ","concept":"• Phần mềm quản lý phần cứng, tiến trình, bộ nhớ, I/O.","whyCorrect":"• Phần mềm quản lý phần cứng, tiến trình, bộ nhớ, I/O.\n• Cấp tài nguyên và lập lịch cho chương trình.","intent":"• Phần mềm quản lý phần cứng, tiến trình, bộ nhớ, I/O.\n• Cấp tài nguyên và lập lịch cho chương trình.","memoryTip":"• KV nhỏ → shared_preferences · NoSQL local → Hive · SQL → sqflite.","whatIs":{"A":"Cụm «Remote cơ sở dữ liệu» mang một nghĩa riêng cần đối chiếu với đề.","B":"Phần mềm quản lý phần cứng, tiến trình, bộ nhớ, I/O.","C":"Cách chia sẻ và phản ứng với trạng thái dùng chung giữa nhiều widget/màn.","D":"Cơ chế xếp chồng màn hình (stack) và chuyển page."},"whyWrong":{"A":"• Là gì? Cụm «Remote cơ sở dữ liệu» mang một nghĩa riêng cần đối chiếu với đề.\n• Dùng để làm gì? So bản chất với đáp án đúng; loại nếu sai đối tượng hoặc sai lớp khái niệm.\n• Vì sao sai? Hive = NoSQL local; không thay cho SQLite quan hệ / HTTP / state management.","C":"• Là gì? Cách chia sẻ và phản ứng với trạng thái dùng chung giữa nhiều widget/màn.\n• Dùng để làm gì? Tránh truyền prop sâu; cập nhật UI khi state đổi.\n• Vì sao sai? Hive = NoSQL local; không thay cho SQLite quan hệ / HTTP / state management.","D":"• Là gì? Cơ chế xếp chồng màn hình (stack) và chuyển page.\n• Dùng để làm gì? push/pop route, điều hướng luồng màn hình.\n• Vì sao sai? Hive = NoSQL local; không thay cho SQLite quan hệ / HTTP / state management."}},"source":"SP26-B5-FE","_pilotFixed":"2026-07-23-v1"},{"id":20,"task":"re","taskLabel":"SP26-B5-FE","num":20,"question":"Which HTTP header is commonly used for authorization?","options":{"A":"Content-Type","B":"Accept","C":"Authorization","D":"Cache-Control"},"answer":"C","alternatives":[],"explanation":{"questionVi":"Cái nào HTTP header thường dùng cho authorization?","optionsVi":{"A":"Content-Type","B":"Accept","C":"Authorization (thường mang access token)","D":"Cache-Control"},"answerDisplay":"C. Authorization (thường mang access token)","concept":"• Authorization (thường mang access token). Bản dịch/diễn đạt phương án — đối chiếu với định nghĩa chuẩn của đề.","whyCorrect":"• Header Authorization mang token/credentials. Content-Type mô tả body; Accept chọn response type.\n• Authorization (thường mang access token)\n• Bản dịch/diễn đạt phương án — đối chiếu với định nghĩa chuẩn của đề.","intent":"• Authorization (thường mang access token)\n• Bản dịch/diễn đạt phương án — đối chiếu với định nghĩa chuẩn của đề.","memoryTip":"• GET lấy · POST tạo · Authorization mang token · parse JSON → object Dart.","whatIs":{"A":"Cơ chế/thuật ngữ CNTT «Content-Type».","B":"Cơ chế/thuật ngữ CNTT «Accept».","C":"Authorization (thường mang access token)","D":"Cơ chế/thuật ngữ CNTT «Cache-Control»."},"whyWrong":{"A":"• Là gì? Cơ chế/thuật ngữ CNTT «Content-Type».\n• Dùng để làm gì? Đối chiếu đúng định nghĩa/đặc trưng kỹ thuật mà đề hỏi.\n• Vì sao sai? Gói http gọi API; không quản lý state UI hay storage local.","B":"• Là gì? Cơ chế/thuật ngữ CNTT «Accept».\n• Dùng để làm gì? Đối chiếu đúng định nghĩa/đặc trưng kỹ thuật mà đề hỏi.\n• Vì sao sai? Gói http gọi API; không quản lý state UI hay storage local.","D":"• Là gì? Cơ chế/thuật ngữ CNTT «Cache-Control».\n• Dùng để làm gì? Đối chiếu đúng định nghĩa/đặc trưng kỹ thuật mà đề hỏi.\n• Vì sao sai? Gói http gọi API; không quản lý state UI hay storage local."}},"source":"SP26-B5-FE","_pilotFixed":"2026-07-23-v1"},{"id":21,"task":"re","taskLabel":"SP26-B5-FE","num":21,"question":"What does TextEditingController manage?","options":{"A":"Theme","B":"Text input value","C":"Validation rules","D":"Layout constraints"},"answer":"B","alternatives":[],"explanation":{"questionVi":"Cái gì TextEditingController quản lý?","optionsVi":{"A":"Theme","B":"Text input giá trị","C":"Validation rules","D":"Bố cục constraints"},"answerDisplay":"B. Text input giá trị","concept":"• Text input giá trị. Đối chiếu định nghĩa/lớp hỏi; tránh nhầm khái niệm gần (chủ thể ≠ biểu hiện, Nhà nước ≠ độc quyền…).","whyCorrect":"• TextEditingController quản lý giá trị và selection của ô text input.\n• Text input giá trị\n• Đối chiếu định nghĩa/lớp hỏi; tránh nhầm khái niệm gần (chủ thể ≠ biểu hiện, Nhà nước ≠ độc quyền…).","intent":"• Text input giá trị\n• Đối chiếu định nghĩa/lớp hỏi; tránh nhầm khái niệm gần (chủ thể ≠ biểu hiện, Nhà nước ≠ độc quyền…).","memoryTip":"• TextEditingController quản lý giá trị và selection của ô text input.","whatIs":{"A":"Cụm «Theme» mang một nghĩa riêng cần đối chiếu với đề.","B":"Text input giá trị","C":"Cụm «Validation rules» mang một nghĩa riêng cần đối chiếu với đề.","D":"Cụm «Bố cục constraints» mang một nghĩa riêng cần đối chiếu với đề."},"whyWrong":{"A":"• Là gì? Cụm «Theme» mang một nghĩa riêng cần đối chiếu với đề.\n• Dùng để làm gì? So bản chất với đáp án đúng; loại nếu sai đối tượng hoặc sai lớp khái niệm.\n• Vì sao sai? Theme/ThemeData lo style giao diện, không phải state/auth/logic chính ở đây.","C":"• Là gì? Cụm «Validation rules» mang một nghĩa riêng cần đối chiếu với đề.\n• Dùng để làm gì? So bản chất với đáp án đúng; loại nếu sai đối tượng hoặc sai lớp khái niệm.\n• Vì sao sai? «Validation rules» — Cụm «Validation rules» mang một nghĩa riêng cần đối chiếu với đề. Đề cần: Text input giá trị.","D":"• Là gì? Cụm «Bố cục constraints» mang một nghĩa riêng cần đối chiếu với đề.\n• Dùng để làm gì? So bản chất với đáp án đúng; loại nếu sai đối tượng hoặc sai lớp khái niệm.\n• Vì sao sai? «Layout constraints» — Cụm «Bố cục constraints» mang một nghĩa riêng cần đối chiếu với đề. Đề cần: Text input giá trị."}},"source":"SP26-B5-FE"},{"id":22,"task":"re","taskLabel":"SP26-B5-FE","num":22,"question":"Why is Dart considered suitable for Flutter development?","options":{"A":"It is only used for backend systems","B":"It supports both UI and application logic efficiently","C":"It replaces native languages","D":"It does not support asynchronous programming"},"answer":"B","alternatives":[],"explanation":{"questionVi":"Vì sao Dart considered suitable Flutter development?","optionsVi":{"A":"It là chỉ được dùng cho backend systems","B":"Supports both UI và application logic hiệu quả","C":"It replaces native languages","D":"It does không support bất đồng bộ programming"},"answerDisplay":"B. Supports both UI và application logic hiệu quả","concept":"• Ngôn ngữ lập trình chính của Flutter. Viết UI và logic app Flutter.","whyCorrect":"• Dart hỗ trợ cả logic app và UI (null-safety, async, hot reload) nên phù hợp Flutter.\n• Ngôn ngữ lập trình chính của Flutter.\n• Viết UI và logic app Flutter.","intent":"• Ngôn ngữ lập trình chính của Flutter.\n• Chọn phương án khớp cơ chế Flutter, không chọn stack web/Android nhầm.","memoryTip":"• Dart hỗ trợ cả logic app và UI (null-safety, async, hot reload) nên phù hợp Flutter.","whatIs":{"A":"It là chỉ được dùng cho backend systems","B":"Ngôn ngữ lập trình chính của Flutter.","C":"Cơ chế Flutter/Dart liên quan «It replaces native languages».","D":"It does không support bất đồng bộ programming"},"whyWrong":{"A":"• Là gì? It là chỉ được dùng cho backend systems\n• Dùng để làm gì? Bản dịch/diễn đạt phương án — đối chiếu với định nghĩa chuẩn của đề.\n• Vì sao sai? «It is only used for backend systems» — It là chỉ được dùng cho backend systems. Đề cần: Ngôn ngữ lập trình chính của Flutter.","C":"• Là gì? Cơ chế Flutter/Dart liên quan «It replaces native languages».\n• Dùng để làm gì? Đối chiếu đúng cơ chế/phạm trù với trọng tâm đề.\n• Vì sao sai? «It replaces native languages» — Cơ chế Flutter/Dart liên quan «It replaces native languages». Đề cần: Ngôn ngữ lập trình chính của Flutter.","D":"• Là gì? It does không support bất đồng bộ programming\n• Dùng để làm gì? Bản dịch/diễn đạt phương án — đối chiếu với định nghĩa chuẩn của đề.\n• Vì sao sai? «It does not support asynchronous programming» — It does không support bất đồng bộ programming. Đề cần: Ngôn ngữ lập trình chính của Flutter."}},"source":"SP26-B5-FE"},{"id":23,"task":"re","taskLabel":"SP26-B5-FE","num":23,"question":"What does the build() method return in a widget?","options":{"A":"A screen","B":"A widget tree describing the UI","C":"Application state","D":"Rendered pixels"},"answer":"B","alternatives":[],"explanation":{"questionVi":"Cái gì build() method trả về trong một widget?","optionsVi":{"A":"Một màn hình","B":"Cây widget mô tả UI","C":"Application state","D":"Rendered pixels"},"answerDisplay":"B. Cây widget mô tả UI","concept":"• Cây cấu hình UI lồng nhau mô tả giao diện tại một thời điểm.","whyCorrect":"• build() trả về widget tree mô tả UI cần render, không trả pixel hay state.\n• Cây cấu hình UI lồng nhau mô tả giao diện tại một thời điểm.\n• Đầu vào cho Element/Render pipeline của Flutter.","intent":"• Cây cấu hình UI lồng nhau mô tả giao diện tại một thời điểm.\n• Chọn phương án khớp cơ chế Flutter, không chọn stack web/Android nhầm.","memoryTip":"• UI = cây widget; BuildContext định vị trên cây; build() chỉ mô tả UI.","whatIs":{"A":"Cơ chế Flutter/Dart liên quan «Một màn hình».","B":"Cây cấu hình UI lồng nhau mô tả giao diện tại một thời điểm.","C":"Cơ chế Flutter/Dart liên quan «Application state».","D":"Vẽ pixel/lớp đồ họa lên màn hình."},"whyWrong":{"A":"• Là gì? Cơ chế Flutter/Dart liên quan «Một màn hình».\n• Dùng để làm gì? Đối chiếu đúng cơ chế/phạm trù với trọng tâm đề.\n• Vì sao sai? build() mô tả UI; không phải chỗ gọi để “cập nhật state”.","C":"• Là gì? Cơ chế Flutter/Dart liên quan «Application state».\n• Dùng để làm gì? Đối chiếu đúng cơ chế/phạm trù với trọng tâm đề.\n• Vì sao sai? build() mô tả UI; không phải chỗ gọi để “cập nhật state”.","D":"• Là gì? Vẽ pixel/lớp đồ họa lên màn hình.\n• Dùng để làm gì? Thuộc RenderObject/engine (Skia); không phải Handle BuildContext.\n• Vì sao sai? build() mô tả UI; không phải chỗ gọi để “cập nhật state”."}},"source":"SP26-B5-FE","_pilotFixed":"2026-07-23-v1"},{"id":24,"task":"re","taskLabel":"SP26-B5-FE","num":24,"question":"What represents the output of a BLoC?","options":{"A":"Events","B":"Widgets","C":"States","D":"Controllers"},"answer":"C","alternatives":[],"explanation":{"questionVi":"Gì represents output BLoC?","optionsVi":{"A":"Events","B":"Widgets","C":"States","D":"Controllers"},"answerDisplay":"C. States","concept":"• Cách chia sẻ và phản ứng với trạng thái dùng chung giữa nhiều widget/màn.","whyCorrect":"• BLoC nhận Events, phát States. Output chính là States.\n• Cách chia sẻ và phản ứng với trạng thái dùng chung giữa nhiều widget/màn.\n• Tránh truyền prop sâu; cập nhật UI khi state đổi.","intent":"• Cách chia sẻ và phản ứng với trạng thái dùng chung giữa nhiều widget/màn.\n• Tránh truyền prop sâu; cập nhật UI khi state đổi.","memoryTip":"• Đổi state → rebuild; BLoC/Cubit/Provider tách logic khỏi UI; state nên immutable.","whatIs":{"A":"Cơ chế Flutter/Dart liên quan «Events».","B":"Cơ chế Flutter/Dart liên quan «Widgets».","C":"Cách chia sẻ và phản ứng với trạng thái dùng chung giữa nhiều widget/màn.","D":"Cơ chế Flutter/Dart liên quan «Controllers»."},"whyWrong":{"A":"• Là gì? Cơ chế Flutter/Dart liên quan «Events».\n• Dùng để làm gì? Đối chiếu đúng cơ chế/phạm trù với trọng tâm đề.\n• Vì sao sai? «Events» — Cơ chế Flutter/Dart liên quan «Events». Đề cần: Cách chia sẻ và phản ứng với trạng thái dùng chung giữa nhiều widget/màn.","B":"• Là gì? Cơ chế Flutter/Dart liên quan «Widgets».\n• Dùng để làm gì? Đối chiếu đúng cơ chế/phạm trù với trọng tâm đề.\n• Vì sao sai? «Widgets» — Cơ chế Flutter/Dart liên quan «Widgets». Đề cần: Cách chia sẻ và phản ứng với trạng thái dùng chung giữa nhiều widget/màn.","D":"• Là gì? Cơ chế Flutter/Dart liên quan «Controllers».\n• Dùng để làm gì? Đối chiếu đúng cơ chế/phạm trù với trọng tâm đề.\n• Vì sao sai? «Controllers» — Cơ chế Flutter/Dart liên quan «Controllers». Đề cần: Cách chia sẻ và phản ứng với trạng thái dùng chung giữa nhiều widget/màn."}},"source":"SP26-B5-FE"},{"id":25,"task":"re","taskLabel":"SP26-B5-FE","num":25,"question":"What is Cubit in BLoC?","options":{"A":"UI widget","B":"Simplified BLoC without events","C":"Database layer","D":"Animation helper"},"answer":"B","alternatives":[],"explanation":{"questionVi":"Cái gì là Cubit BLoC?","optionsVi":{"A":"UI widget","B":"Simplified BLoC Không có sự kiện","C":"Cơ sở dữ liệu layer","D":"Animation helper"},"answerDisplay":"B. Simplified BLoC Không có sự kiện","concept":"• Cách chia sẻ và phản ứng với trạng thái dùng chung giữa nhiều widget/màn.","whyCorrect":"• Cubit là BLoC đơn giản hơn: emit state trực tiếp, không cần Event class.\n• Cách chia sẻ và phản ứng với trạng thái dùng chung giữa nhiều widget/màn.\n• Tránh truyền prop sâu; cập nhật UI khi state đổi.","intent":"• Cách chia sẻ và phản ứng với trạng thái dùng chung giữa nhiều widget/màn.\n• Tránh truyền prop sâu; cập nhật UI khi state đổi.","memoryTip":"• Đổi state → rebuild; BLoC/Cubit/Provider tách logic khỏi UI; state nên immutable.","whatIs":{"A":"Cơ chế Flutter/Dart liên quan «UI widget».","B":"Cách chia sẻ và phản ứng với trạng thái dùng chung giữa nhiều widget/màn.","C":"Cơ chế Flutter/Dart liên quan «Cơ sở dữ liệu layer».","D":"Cơ chế Flutter/Dart liên quan «Animation helper»."},"whyWrong":{"A":"• Là gì? Cơ chế Flutter/Dart liên quan «UI widget».\n• Dùng để làm gì? Đối chiếu đúng cơ chế/phạm trù với trọng tâm đề.\n• Vì sao sai? «UI widget» — Cơ chế Flutter/Dart liên quan «UI widget». Đề cần: Cách chia sẻ và phản ứng với trạng thái dùng chung giữa nhiều widget/màn.","C":"• Là gì? Cơ chế Flutter/Dart liên quan «Cơ sở dữ liệu layer».\n• Dùng để làm gì? Đối chiếu đúng cơ chế/phạm trù với trọng tâm đề.\n• Vì sao sai? «Database layer» — Cơ chế Flutter/Dart liên quan «Cơ sở dữ liệu layer». Đề cần: Cách chia sẻ và phản ứng với trạng thái dùng chung giữa nhiều widget/màn.","D":"• Là gì? Cơ chế Flutter/Dart liên quan «Animation helper».\n• Dùng để làm gì? Đối chiếu đúng cơ chế/phạm trù với trọng tâm đề.\n• Vì sao sai? Liên quan chuyển động UI, không giải quyết khái niệm trong câu hỏi."}},"source":"SP26-B5-FE"},{"id":26,"task":"re","taskLabel":"SP26-B5-FE","num":26,"question":"Which activity is typically performed after creating a new Flutter project?","options":{"A":"Deploying to app stores","B":"Running the default app on a device","C":"Configuring authentication","D":"Optimizing database queries"},"answer":"B","alternatives":[],"explanation":{"questionVi":"Cái nào activity typically performed sau khi creating new Flutter project?","optionsVi":{"A":"Deploying để app Stores","B":"Chạy default app trên một device","C":"Configuring xác thực","D":"Optimizing cơ sở dữ liệu truy vấn"},"answerDisplay":"B. Chạy default app trên một device","concept":"• Tiến trình đang chiếm CPU và thực thi lệnh.","whyCorrect":"• Sau khi tạo project, bước điển hình là chạy app mặc định trên device/emulator để kiểm tra môi trường.\n• Tiến trình đang chiếm CPU và thực thi lệnh.\n• Đang làm việc trên bộ xử lý.","intent":"• Tiến trình đang chiếm CPU và thực thi lệnh.\n• Chọn phương án khớp cơ chế Flutter, không chọn stack web/Android nhầm.","memoryTip":"• Sau khi tạo project, bước điển hình là chạy app mặc định trên device/emulator để kiểm tra môi trường.","whatIs":{"A":"Cơ chế Flutter/Dart liên quan «Deploying để app Stores».","B":"Tiến trình đang chiếm CPU và thực thi lệnh.","C":"Cơ chế Flutter/Dart liên quan «Configuring xác thực».","D":"Optimizing cơ sở dữ liệu truy vấn"},"whyWrong":{"A":"• Là gì? Cơ chế Flutter/Dart liên quan «Deploying để app Stores».\n• Dùng để làm gì? Đối chiếu đúng cơ chế/phạm trù với trọng tâm đề.\n• Vì sao sai? «Deploying to app stores» — Cơ chế Flutter/Dart liên quan «Deploying để app Stores». Đề cần: Tiến trình đang chiếm CPU và thực thi lệnh.","C":"• Là gì? Cơ chế Flutter/Dart liên quan «Configuring xác thực».\n• Dùng để làm gì? Đối chiếu đúng cơ chế/phạm trù với trọng tâm đề.\n• Vì sao sai? «Configuring authentication» — Cơ chế Flutter/Dart liên quan «Configuring xác thực». Đề cần: Tiến trình đang chiếm CPU và thực thi lệnh.","D":"• Là gì? Optimizing cơ sở dữ liệu truy vấn\n• Dùng để làm gì? Bản dịch/diễn đạt phương án — đối chiếu với định nghĩa chuẩn của đề.\n• Vì sao sai? «Optimizing database queries» — Optimizing cơ sở dữ liệu truy vấn. Đề cần: Tiến trình đang chiếm CPU và thực thi lệnh."}},"source":"SP26-B5-FE"},{"id":27,"task":"re","taskLabel":"SP26-B5-FE","num":27,"question":"Which practice improves deployment security?","options":{"A":"Debug builds","B":"Secure signing keys","C":"Hardcoding secrets","D":"Skipping validation"},"answer":"B","alternatives":[],"explanation":{"questionVi":"Thực hành nào cải thiện bảo mật triển khai?","optionsVi":{"A":"Debug builds","B":"Secure khóa ký","C":"Hardcoding secrets","D":"Skipping validation"},"answerDisplay":"B. Secure khóa ký","concept":"• Cụm «Secure khóa ký» mang một nghĩa riêng cần đối chiếu với đề.","whyCorrect":"• Cụm «Secure khóa ký» mang một nghĩa riêng cần đối chiếu với đề.\n• So bản chất với đáp án đúng; loại nếu sai đối tượng hoặc sai lớp khái niệm.","intent":"• Cụm «Secure khóa ký» mang một nghĩa riêng cần đối chiếu với đề.\n• So bản chất với đáp án đúng; loại nếu sai đối tượng hoặc sai lớp khái niệm.","whatIs":{"A":"Cụm «Debug builds» mang một nghĩa riêng cần đối chiếu với đề.","B":"Cụm «Secure khóa ký» mang một nghĩa riêng cần đối chiếu với đề.","C":"Cụm «Hardcoding secrets» mang một nghĩa riêng cần đối chiếu với đề.","D":"Cụm «Skipping validation» mang một nghĩa riêng cần đối chiếu với đề."},"whyWrong":{"A":"• Là gì? Cụm «Debug builds» mang một nghĩa riêng cần đối chiếu với đề.\n• Dùng để làm gì? So bản chất với đáp án đúng; loại nếu sai đối tượng hoặc sai lớp khái niệm.\n• Vì sao sai? Thực hành kém về bảo mật/chất lượng — không phải đáp án đúng.","C":"• Là gì? Cụm «Hardcoding secrets» mang một nghĩa riêng cần đối chiếu với đề.\n• Dùng để làm gì? So bản chất với đáp án đúng; loại nếu sai đối tượng hoặc sai lớp khái niệm.\n• Vì sao sai? «Hardcoding secrets» — Cụm «Hardcoding secrets» mang một nghĩa riêng cần đối chiếu với đề. Đề cần: Cụm «Secure khóa ký» mang một nghĩa riêng cần đối chiếu với đề.","D":"• Là gì? Cụm «Skipping validation» mang một nghĩa riêng cần đối chiếu với đề.\n• Dùng để làm gì? So bản chất với đáp án đúng; loại nếu sai đối tượng hoặc sai lớp khái niệm.\n• Vì sao sai? Thực hành kém về bảo mật/chất lượng — không phải đáp án đúng."}},"source":"SP26-B5-FE"},{"id":28,"task":"re","taskLabel":"SP26-B5-FE","num":28,"question":"Why is Chapter 14 considered optional (Plus)?","options":{"A":"Deployment is UI logic","B":"Apps can be tested without publishing","C":"It replaces authentication","D":"It handles APIs"},"answer":"B","alternatives":[],"explanation":{"questionVi":"Vì sao Chapter 14 considered optional (Plus)?","optionsVi":{"A":"Triển khai là UI logic","B":"App có thể be tested Không có publishing","C":"It replaces xác thực","D":"It handles APIs"},"answerDisplay":"B. App có thể be tested Không có publishing","concept":"• App có thể be tested Không có publishing. Bản dịch/diễn đạt phương án — đối chiếu với định nghĩa chuẩn của đề.","whyCorrect":"• Chương deploy thường optional vì có thể test app đầy đủ mà chưa publish store.\n• App có thể be tested Không có publishing\n• Bản dịch/diễn đạt phương án — đối chiếu với định nghĩa chuẩn của đề.","intent":"• App có thể be tested Không có publishing\n• Bản dịch/diễn đạt phương án — đối chiếu với định nghĩa chuẩn của đề.","memoryTip":"• Chương deploy thường optional vì có thể test app đầy đủ mà chưa publish store.","whatIs":{"A":"Cụm «Triển khai là UI logic» mang một nghĩa riêng cần đối chiếu với đề.","B":"App có thể be tested Không có publishing","C":"Cụm «It replaces xác thực» mang một nghĩa riêng cần đối chiếu với đề.","D":"Cụm «It handles APIs» mang một nghĩa riêng cần đối chiếu với đề."},"whyWrong":{"A":"• Là gì? Cụm «Triển khai là UI logic» mang một nghĩa riêng cần đối chiếu với đề.\n• Dùng để làm gì? So bản chất với đáp án đúng; loại nếu sai đối tượng hoặc sai lớp khái niệm.\n• Vì sao sai? «Deployment is UI logic» — Cụm «Triển khai là UI logic» mang một nghĩa riêng cần đối chiếu với đề. Đề cần: App có thể be tested Không có publishing.","C":"• Là gì? Cụm «It replaces xác thực» mang một nghĩa riêng cần đối chiếu với đề.\n• Dùng để làm gì? So bản chất với đáp án đúng; loại nếu sai đối tượng hoặc sai lớp khái niệm.\n• Vì sao sai? «It replaces authentication» — Cụm «It replaces xác thực» mang một nghĩa riêng cần đối chiếu với đề. Đề cần: App có thể be tested Không có publishing.","D":"• Là gì? Cụm «It handles APIs» mang một nghĩa riêng cần đối chiếu với đề.\n• Dùng để làm gì? So bản chất với đáp án đúng; loại nếu sai đối tượng hoặc sai lớp khái niệm.\n• Vì sao sai? «It handles APIs» — Cụm «It handles APIs» mang một nghĩa riêng cần đối chiếu với đề. Đề cần: App có thể be tested Không có publishing."}},"source":"SP26-B5-FE"},{"id":29,"task":"re","taskLabel":"SP26-B5-FE","num":29,"question":"What is the primary purpose of ThemeData in Flutter?","options":{"A":"Manage navigation","B":"Define application-wide visual styles","C":"Handle state changes","D":"Control animations"},"answer":"B","alternatives":[],"explanation":{"questionVi":"Cái gì là primary purpose ThemeData trong Flutter?","optionsVi":{"A":"Quản lý navigation","B":"Định nghĩ style giao diện àn app","C":"Xử lý state thay đổi","D":"Control animations"},"answerDisplay":"B. Định nghĩ style giao diện àn app","concept":"• Phần mềm quản lý phần cứng, tiến trình, bộ nhớ, I/O.","whyCorrect":"• ThemeData định nghĩa style toàn app (màu, font, component theme).\n• Phần mềm quản lý phần cứng, tiến trình, bộ nhớ, I/O.\n• Cấp tài nguyên và lập lịch cho chương trình.","intent":"• Phần mềm quản lý phần cứng, tiến trình, bộ nhớ, I/O.\n• Chọn phương án khớp cơ chế Flutter, không chọn stack web/Android nhầm.","memoryTip":"• ThemeData định nghĩa style toàn app (màu, font, component theme).","whatIs":{"A":"Cơ chế Flutter/Dart liên quan «Quản lý navigation».","B":"Phần mềm quản lý phần cứng, tiến trình, bộ nhớ, I/O.","C":"Cơ chế Flutter/Dart liên quan «Xử lý state thay đổi».","D":"Cơ chế Flutter/Dart liên quan «Control animations»."},"whyWrong":{"A":"• Là gì? Cơ chế Flutter/Dart liên quan «Quản lý navigation».\n• Dùng để làm gì? Đối chiếu đúng cơ chế/phạm trù với trọng tâm đề.\n• Vì sao sai? Theme/ThemeData lo style giao diện, không phải state/auth/logic chính ở đây.","C":"• Là gì? Cơ chế Flutter/Dart liên quan «Xử lý state thay đổi».\n• Dùng để làm gì? Đối chiếu đúng cơ chế/phạm trù với trọng tâm đề.\n• Vì sao sai? Theme/ThemeData lo style giao diện, không phải state/auth/logic chính ở đây.","D":"• Là gì? Cơ chế Flutter/Dart liên quan «Control animations».\n• Dùng để làm gì? Đối chiếu đúng cơ chế/phạm trù với trọng tâm đề.\n• Vì sao sai? Theme/ThemeData lo style giao diện, không phải state/auth/logic chính ở đây."}},"source":"SP26-B5-FE","_pilotFixed":"2026-07-23-v1"},{"id":30,"task":"re","taskLabel":"SP26-B5-FE","num":30,"question":"Which method is used to update the UI when state changes?","options":{"A":"build()","B":"setState()","C":"initState()","D":"dispose()"},"answer":"B","alternatives":[],"explanation":{"questionVi":"Cái nào method dùng để update UI khi state changes?","optionsVi":{"A":"build()","B":"SetState()","C":"InitState()","D":"Dispose()"},"answerDisplay":"B. SetState()","concept":"• API đánh dấu State đã đổi và xếp lịch rebuild nhánh widget liên quan.","whyCorrect":"• setState() đánh dấu StatefulWidget cần rebuild UI khi state đổi. build() được gọi lại; initState/dispose là lifecycle.\n• API đánh dấu State đã đổi và xếp lịch rebuild nhánh widget liên quan.\n• Cập nhật UI sau khi dữ liệu nội bộ thay đổi.","intent":"• API đánh dấu State đã đổi và xếp lịch rebuild nhánh widget liên quan.\n• Cập nhật UI sau khi dữ liệu nội bộ thay đổi.","memoryTip":"• setState() đánh dấu StatefulWidget cần rebuild UI khi state đổi. build() được gọi lại; initState/dispose là lifecycle.","whatIs":{"A":"Cụm «build()» mang một nghĩa riêng cần đối chiếu với đề.","B":"API đánh dấu State đã đổi và xếp lịch rebuild nhánh widget liên quan.","C":"Cụm «InitState()» mang một nghĩa riêng cần đối chiếu với đề.","D":"Phần mềm quản lý phần cứng, tiến trình, bộ nhớ, I/O."},"whyWrong":{"A":"• Là gì? Cụm «build()» mang một nghĩa riêng cần đối chiếu với đề.\n• Dùng để làm gì? So bản chất với đáp án đúng; loại nếu sai đối tượng hoặc sai lớp khái niệm.\n• Vì sao sai? build() mô tả UI; không phải chỗ gọi để “cập nhật state”.","C":"• Là gì? Cụm «InitState()» mang một nghĩa riêng cần đối chiếu với đề.\n• Dùng để làm gì? So bản chất với đáp án đúng; loại nếu sai đối tượng hoặc sai lớp khái niệm.\n• Vì sao sai? initState chạy 1 lần khi tạo State; không dùng để rebuild sau thay đổi.","D":"• Là gì? Phần mềm quản lý phần cứng, tiến trình, bộ nhớ, I/O.\n• Dùng để làm gì? Cấp tài nguyên và lập lịch cho chương trình.\n• Vì sao sai? dispose giải phóng resource; không cập nhật UI."}},"source":"SP26-B5-FE"},{"id":31,"task":"re","taskLabel":"SP26-B5-FE","num":31,"question":"Which Flutter package is commonly used for simple key-value storage?","options":{"A":"sqflite","B":"shared_preferences","C":"provider","D":"http"},"answer":"B","alternatives":[],"explanation":{"questionVi":"Cái nào Flutter package thường dùng cho simple key-giá trị storage?","optionsVi":{"A":"sqflite","B":"shared_preferences","C":"provider","D":"http"},"answerDisplay":"B. shared_preferences","concept":"• Cấu trúc ánh xạ khóa → giá trị. Tra cứu nhanh theo key.","whyCorrect":"• shared_preferences lưu key-value đơn giản (bool/int/string). sqflite cho quan hệ; provider là state management.\n• Cấu trúc ánh xạ khóa → giá trị.\n• Tra cứu nhanh theo key.","intent":"• Cấu trúc ánh xạ khóa → giá trị.\n• Chọn phương án khớp cơ chế Flutter, không chọn stack web/Android nhầm.","memoryTip":"• shared_preferences lưu key-value đơn giản (bool/int/string). sqflite cho quan hệ; provider là state management.","whatIs":{"A":"Cơ chế Flutter/Dart liên quan «sqflite».","B":"Cấu trúc ánh xạ khóa → giá trị.","C":"Cách chia sẻ và phản ứng với trạng thái dùng chung giữa nhiều widget/màn.","D":"Cơ chế/thuật ngữ CNTT «http»."},"whyWrong":{"A":"• Là gì? Cơ chế Flutter/Dart liên quan «sqflite».\n• Dùng để làm gì? Đối chiếu đúng cơ chế/phạm trù với trọng tâm đề.\n• Vì sao sai? sqflite = SQLite; không phải key-value đơn giản hay remote API.","C":"• Là gì? Cách chia sẻ và phản ứng với trạng thái dùng chung giữa nhiều widget/màn.\n• Dùng để làm gì? Tránh truyền prop sâu; cập nhật UI khi state đổi.\n• Vì sao sai? Provider là DI/state; không phải thư viện lưu trữ hay HTTP.","D":"• Là gì? Cơ chế/thuật ngữ CNTT «http».\n• Dùng để làm gì? Đối chiếu đúng định nghĩa/đặc trưng kỹ thuật mà đề hỏi.\n• Vì sao sai? Gói http gọi API; không quản lý state UI hay storage local."}},"source":"SP26-B5-FE"},{"id":32,"task":"re","taskLabel":"SP26-B5-FE","num":32,"question":"Why should architecture be decided early?","options":{"A":"Avoid UI work","B":"Reduce refactoring cost","C":"Improve animations","D":"Change theme"},"answer":"B","alternatives":[],"explanation":{"questionVi":"Vì sao architecture decided early?","optionsVi":{"A":"Tránh UI công việc","B":"Giảm refactor chi phí","C":"Cải thiện animations","D":"Thay đổi theme"},"answerDisplay":"B. Giảm refactor chi phí","concept":"• Phần mềm quản lý phần cứng, tiến trình, bộ nhớ, I/O.","whyCorrect":"• Chọn architecture sớm giảm chi phí refactor sau này khi app lớn.\n• Phần mềm quản lý phần cứng, tiến trình, bộ nhớ, I/O.\n• Cấp tài nguyên và lập lịch cho chương trình.","intent":"• Phần mềm quản lý phần cứng, tiến trình, bộ nhớ, I/O.\n• Cấp tài nguyên và lập lịch cho chương trình.","memoryTip":"• Chọn architecture sớm giảm chi phí refactor sau này khi app lớn.","whatIs":{"A":"Cụm «Tránh UI công việc» mang một nghĩa riêng cần đối chiếu với đề.","B":"Phần mềm quản lý phần cứng, tiến trình, bộ nhớ, I/O.","C":"Cụm «Cải thiện animations» mang một nghĩa riêng cần đối chiếu với đề.","D":"Cụm «Thay đổi theme» mang một nghĩa riêng cần đối chiếu với đề."},"whyWrong":{"A":"• Là gì? Cụm «Tránh UI công việc» mang một nghĩa riêng cần đối chiếu với đề.\n• Dùng để làm gì? So bản chất với đáp án đúng; loại nếu sai đối tượng hoặc sai lớp khái niệm.\n• Vì sao sai? «Avoid UI work» — Cụm «Tránh UI công việc» mang một nghĩa riêng cần đối chiếu với đề. Đề cần: Phần mềm quản lý phần cứng, tiến trình, bộ nhớ, I/O.","C":"• Là gì? Cụm «Cải thiện animations» mang một nghĩa riêng cần đối chiếu với đề.\n• Dùng để làm gì? So bản chất với đáp án đúng; loại nếu sai đối tượng hoặc sai lớp khái niệm.\n• Vì sao sai? Đây là lợi ích phụ hoặc không liên quan trực tiếp đến câu hỏi.","D":"• Là gì? Cụm «Thay đổi theme» mang một nghĩa riêng cần đối chiếu với đề.\n• Dùng để làm gì? So bản chất với đáp án đúng; loại nếu sai đối tượng hoặc sai lớp khái niệm.\n• Vì sao sai? Theme/ThemeData lo style giao diện, không phải state/auth/logic chính ở đây."}},"source":"SP26-B5-FE"},{"id":33,"task":"re","taskLabel":"SP26-B5-FE","num":33,"question":"What is pagination used for?","options":{"A":"UI animation","B":"Handling large datasets efficiently","C":"Theme management","D":"Authentication"},"answer":"B","alternatives":[],"explanation":{"questionVi":"Pagination dùng để làm gì?","optionsVi":{"A":"UI animation","B":"Handling large datasets hiệu quả","C":"Theme management","D":"Authentication"},"answerDisplay":"B. Handling large datasets hiệu quả","concept":"• Handling large datasets hiệu quả. Bản dịch/diễn đạt phương án — đối chiếu với định nghĩa chuẩn của đề.","whyCorrect":"• Handling large datasets hiệu quả\n• Bản dịch/diễn đạt phương án — đối chiếu với định nghĩa chuẩn của đề.","intent":"• Handling large datasets hiệu quả\n• Bản dịch/diễn đạt phương án — đối chiếu với định nghĩa chuẩn của đề.","whatIs":{"A":"Cụm «UI animation» mang một nghĩa riêng cần đối chiếu với đề.","B":"Handling large datasets hiệu quả","C":"Cụm «Theme management» mang một nghĩa riêng cần đối chiếu với đề.","D":"Cụm «Authentication» mang một nghĩa riêng cần đối chiếu với đề."},"whyWrong":{"A":"• Là gì? Cụm «UI animation» mang một nghĩa riêng cần đối chiếu với đề.\n• Dùng để làm gì? So bản chất với đáp án đúng; loại nếu sai đối tượng hoặc sai lớp khái niệm.\n• Vì sao sai? «UI animation» — Cụm «UI animation» mang một nghĩa riêng cần đối chiếu với đề. Đề cần: Handling large datasets hiệu quả.","C":"• Là gì? Cụm «Theme management» mang một nghĩa riêng cần đối chiếu với đề.\n• Dùng để làm gì? So bản chất với đáp án đúng; loại nếu sai đối tượng hoặc sai lớp khái niệm.\n• Vì sao sai? «Theme management» — Cụm «Theme management» mang một nghĩa riêng cần đối chiếu với đề. Đề cần: Handling large datasets hiệu quả.","D":"• Là gì? Cụm «Authentication» mang một nghĩa riêng cần đối chiếu với đề.\n• Dùng để làm gì? So bản chất với đáp án đúng; loại nếu sai đối tượng hoặc sai lớp khái niệm.\n• Vì sao sai? «Authentication» — Cụm «Authentication» mang một nghĩa riêng cần đối chiếu với đề. Đề cần: Handling large datasets hiệu quả."}},"source":"SP26-B5-FE"},{"id":34,"task":"re","taskLabel":"SP26-B5-FE","num":34,"question":"Which widget helps avoid rebuilding unchanged UI parts?","options":{"A":"Container","B":"RepaintBoundary","C":"Column","D":"FutureBuilder"},"answer":"B","alternatives":[],"explanation":{"questionVi":"Widget nào helps Tránh rebuilding unchanged UI parts?","optionsVi":{"A":"Container","B":"RepaintBoundary","C":"Column","D":"FutureBuilder"},"answerDisplay":"B. RepaintBoundary","concept":"• Vẽ pixel/lớp đồ họa lên màn hình. Thuộc RenderObject/engine (Skia); không phải Handle BuildContext.","whyCorrect":"• RepaintBoundary cô lập vùng repaint, tránh vẽ lại phần UI không đổi.\n• Vẽ pixel/lớp đồ họa lên màn hình.\n• Thuộc RenderObject/engine (Skia); không phải Handle BuildContext.","intent":"• Vẽ pixel/lớp đồ họa lên màn hình.\n• Chọn phương án khớp cơ chế Flutter, không chọn stack web/Android nhầm.","memoryTip":"• Đổi state → rebuild; BLoC/Cubit/Provider tách logic khỏi UI; state nên immutable.","whatIs":{"A":"Widget trang trí/layout tổng quát (màu, margin, padding, constraints…).","B":"Vẽ pixel/lớp đồ họa lên màn hình.","C":"Xếp widget con theo cột dọc (main axis = vertical).","D":"Cơ chế Flutter/Dart liên quan «FutureBuilder»."},"whyWrong":{"A":"• Là gì? Widget trang trí/layout tổng quát (màu, margin, padding, constraints…).\n• Dùng để làm gì? Tiện ích đa năng; không chuyên biệt cho khoảng trống cố định hay flex fill.\n• Vì sao sai? Container trang trí/layout tổng quát, không chuyên biệt cho khái niệm câu hỏi.","C":"• Là gì? Xếp widget con theo cột dọc (main axis = vertical).\n• Dùng để làm gì? Bố cục dọc; cross axis là ngang. Không scroll mặc định, không overlap.\n• Vì sao sai? Column xếp dọc, không scroll mặc định, không overlap.","D":"• Là gì? Cơ chế Flutter/Dart liên quan «FutureBuilder».\n• Dùng để làm gì? Đối chiếu đúng cơ chế/phạm trù với trọng tâm đề.\n• Vì sao sai? FutureBuilder cho Future one-shot; không phải Stream liên tục."}},"source":"SP26-B5-FE"},{"id":35,"task":"re","taskLabel":"SP26-B5-FE","num":35,"question":"Which widget is used to handle asynchronous API responses in UI?","options":{"A":"FutureBuilder","B":"ListView","C":"Provider","D":"Form"},"answer":"A","alternatives":[],"explanation":{"questionVi":"Widget nào dùng để Xử lý bất đồng bộ API responses UI?","optionsVi":{"A":"FutureBuilder","B":"ListView","C":"Provider","D":"Form"},"answerDisplay":"A. FutureBuilder","concept":"• Cơ chế Flutter/Dart liên quan «FutureBuilder».","whyCorrect":"• FutureBuilder lắng nghe Future (API) và rebuild UI theo ConnectionState/data/error.\n• Cơ chế Flutter/Dart liên quan «FutureBuilder».","intent":"• Cơ chế Flutter/Dart liên quan «FutureBuilder».\n• Chọn phương án khớp cơ chế Flutter, không chọn stack web/Android nhầm.","memoryTip":"• GET lấy · POST tạo · Authorization mang token · parse JSON → object Dart.","whatIs":{"A":"Cơ chế Flutter/Dart liên quan «FutureBuilder».","B":"Cơ chế Flutter/Dart liên quan «ListView».","C":"Cách chia sẻ và phản ứng với trạng thái dùng chung giữa nhiều widget/màn.","D":"Cơ chế Flutter/Dart liên quan «Form»."},"whyWrong":{"B":"• Là gì? Cơ chế Flutter/Dart liên quan «ListView».\n• Dùng để làm gì? Đối chiếu đúng cơ chế/phạm trù với trọng tâm đề.\n• Vì sao sai? «ListView» — Cơ chế Flutter/Dart liên quan «ListView». Đề cần: Cơ chế Flutter/Dart liên quan «FutureBuilder».","C":"• Là gì? Cách chia sẻ và phản ứng với trạng thái dùng chung giữa nhiều widget/màn.\n• Dùng để làm gì? Tránh truyền prop sâu; cập nhật UI khi state đổi.\n• Vì sao sai? «Provider» — Cách chia sẻ và phản ứng với trạng thái dùng chung giữa nhiều widget/màn. Đề cần: Cơ chế Flutter/Dart liên quan «FutureBuilder».","D":"• Là gì? Cơ chế Flutter/Dart liên quan «Form».\n• Dùng để làm gì? Đối chiếu đúng cơ chế/phạm trù với trọng tâm đề.\n• Vì sao sai? «Form» — Cơ chế Flutter/Dart liên quan «Form». Đề cần: Cơ chế Flutter/Dart liên quan «FutureBuilder»."}},"source":"SP26-B5-FE"},{"id":36,"task":"re","taskLabel":"SP26-B5-FE","num":36,"question":"Which Dart feature helps organize code into reusable libraries?","options":{"A":"Widgets","B":"Packages and imports","C":"Hot reload","D":"Layout constraints"},"answer":"B","alternatives":[],"explanation":{"questionVi":"Cái nào Dart feature helps Tổ chức code vào tái sử dụng thư viện?","optionsVi":{"A":"Widgets","B":"Packages và imports","C":"Hot reload","D":"Bố cục constraints"},"answerDisplay":"B. Packages và imports","concept":"• Ngôn ngữ lập trình chính của Flutter. Viết UI và logic app Flutter.","whyCorrect":"• package + import tổ chức code thành thư viện tái sử dụng.\n• Ngôn ngữ lập trình chính của Flutter.\n• Viết UI và logic app Flutter.","intent":"• Ngôn ngữ lập trình chính của Flutter.\n• Viết UI và logic app Flutter.","memoryTip":"• package + import tổ chức code thành thư viện tái sử dụng.","whatIs":{"A":"Cơ chế Flutter/Dart liên quan «Widgets».","B":"Ngôn ngữ lập trình chính của Flutter.","C":"Nạp lại code UI gần như giữ state đang chạy.","D":"Cơ chế Flutter/Dart liên quan «Bố cục constraints»."},"whyWrong":{"A":"• Là gì? Cơ chế Flutter/Dart liên quan «Widgets».\n• Dùng để làm gì? Đối chiếu đúng cơ chế/phạm trù với trọng tâm đề.\n• Vì sao sai? «Widgets» — Cơ chế Flutter/Dart liên quan «Widgets». Đề cần: Ngôn ngữ lập trình chính của Flutter.","C":"• Là gì? Nạp lại code UI gần như giữ state đang chạy.\n• Dùng để làm gì? Xem thay đổi nhanh khi dev.\n• Vì sao sai? Hot reload nạp code UI nhanh khi dev; không phải công cụ phân tích sâu.","D":"• Là gì? Cơ chế Flutter/Dart liên quan «Bố cục constraints».\n• Dùng để làm gì? Đối chiếu đúng cơ chế/phạm trù với trọng tâm đề.\n• Vì sao sai? «Layout constraints» — Cơ chế Flutter/Dart liên quan «Bố cục constraints». Đề cần: Ngôn ngữ lập trình chính của Flutter."}},"source":"SP26-B5-FE"},{"id":37,"task":"re","taskLabel":"SP26-B5-FE","num":37,"question":"What is refresh token used for?","options":{"A":"UI refresh","B":"Extend session without re-login","C":"Theme update","D":"Navigation reset"},"answer":"B","alternatives":[],"explanation":{"questionVi":"Cái gì là refresh token used?","optionsVi":{"A":"UI refresh","B":"Extend phiên Không có re-login","C":"Theme update","D":"Navigation reset"},"answerDisplay":"B. Extend phiên Không có re-login","concept":"• Extend phiên Không có re-login. Bản dịch/diễn đạt phương án — đối chiếu với định nghĩa chuẩn của đề.","whyCorrect":"• Refresh token dùng để lấy access token mới, kéo dài phiên mà không login lại.\n• Extend phiên Không có re-login\n• Bản dịch/diễn đạt phương án — đối chiếu với định nghĩa chuẩn của đề.","intent":"• Extend phiên Không có re-login\n• Bản dịch/diễn đạt phương án — đối chiếu với định nghĩa chuẩn của đề.","memoryTip":"• GET lấy · POST tạo · Authorization mang token · parse JSON → object Dart.","whatIs":{"A":"Cụm «UI refresh» mang một nghĩa riêng cần đối chiếu với đề.","B":"Extend phiên Không có re-login","C":"Cụm «Theme update» mang một nghĩa riêng cần đối chiếu với đề.","D":"Cụm «Navigation reset» mang một nghĩa riêng cần đối chiếu với đề."},"whyWrong":{"A":"• Là gì? Cụm «UI refresh» mang một nghĩa riêng cần đối chiếu với đề.\n• Dùng để làm gì? So bản chất với đáp án đúng; loại nếu sai đối tượng hoặc sai lớp khái niệm.\n• Vì sao sai? Auth/session không giải quyết bằng chỉnh UI/theme/animation.","C":"• Là gì? Cụm «Theme update» mang một nghĩa riêng cần đối chiếu với đề.\n• Dùng để làm gì? So bản chất với đáp án đúng; loại nếu sai đối tượng hoặc sai lớp khái niệm.\n• Vì sao sai? Theme/ThemeData lo style giao diện, không phải state/auth/logic chính ở đây.","D":"• Là gì? Cụm «Navigation reset» mang một nghĩa riêng cần đối chiếu với đề.\n• Dùng để làm gì? So bản chất với đáp án đúng; loại nếu sai đối tượng hoặc sai lớp khái niệm.\n• Vì sao sai? «Navigation reset» — Cụm «Navigation reset» mang một nghĩa riêng cần đối chiếu với đề. Đề cần: Extend phiên Không có re-login."}},"source":"SP26-B5-FE"},{"id":38,"task":"re","taskLabel":"SP26-B5-FE","num":38,"question":"What is rebuild scope optimization in Flutter?","options":{"A":"Reducing widget tree depth","B":"Limiting rebuild to affected widgets","C":"Caching API responses","D":"Using global state"},"answer":"B","alternatives":[],"explanation":{"questionVi":"Cái gì là rebuild scope tối ưu trong Flutter?","optionsVi":{"A":"Reducing cây widget depth","B":"Limiting rebuild để affected widgets","C":"Caching API responses","D":"Dùng global state"},"answerDisplay":"B. Limiting rebuild để affected widgets","concept":"• Limiting rebuild để affected widgets. Bản dịch/diễn đạt phương án — đối chiếu với định nghĩa chuẩn của đề.","whyCorrect":"• Rebuild scope optimization: chỉ rebuild widget bị ảnh hưởng, không rebuild cả cây.\n• Limiting rebuild để affected widgets\n• Bản dịch/diễn đạt phương án — đối chiếu với định nghĩa chuẩn của đề.","intent":"• Limiting rebuild để affected widgets\n• Chọn phương án khớp cơ chế Flutter, không chọn stack web/Android nhầm.","memoryTip":"• Đổi state → rebuild; BLoC/Cubit/Provider tách logic khỏi UI; state nên immutable.","whatIs":{"A":"Cây cấu hình UI lồng nhau mô tả giao diện tại một thời điểm.","B":"Limiting rebuild để affected widgets","C":"Cơ chế Flutter/Dart liên quan «Caching API responses».","D":"Cách chia sẻ và phản ứng với trạng thái dùng chung giữa nhiều widget/màn."},"whyWrong":{"A":"• Là gì? Cây cấu hình UI lồng nhau mô tả giao diện tại một thời điểm.\n• Dùng để làm gì? Đầu vào cho Element/Render pipeline của Flutter.\n• Vì sao sai? «Reducing widget tree depth» — Cây cấu hình UI lồng nhau mô tả giao diện tại một thời điểm. Đề cần: Limiting rebuild để affected widgets.","C":"• Là gì? Cơ chế Flutter/Dart liên quan «Caching API responses».\n• Dùng để làm gì? Đối chiếu đúng cơ chế/phạm trù với trọng tâm đề.\n• Vì sao sai? «Caching API responses» — Cơ chế Flutter/Dart liên quan «Caching API responses». Đề cần: Limiting rebuild để affected widgets.","D":"• Là gì? Cách chia sẻ và phản ứng với trạng thái dùng chung giữa nhiều widget/màn.\n• Dùng để làm gì? Tránh truyền prop sâu; cập nhật UI khi state đổi.\n• Vì sao sai? Global khó kiểm soát, dễ rebuild/test kém — thường là đáp án nhiễu."}},"source":"SP26-B5-FE"},{"id":39,"task":"re","taskLabel":"SP26-B5-FE","num":39,"question":"Why is BLoC suitable for large teams?","options":{"A":"Less code","B":"Standardized architecture","C":"Faster builds","D":"UI reuse"},"answer":"B","alternatives":[],"explanation":{"questionVi":"Vì sao BLoC suitable large teams?","optionsVi":{"A":"Less mã","B":"Standardized kiến trúc","C":"Nhanh hơn builds","D":"UI tái sử dụng"},"answerDisplay":"B. Standardized kiến trúc","concept":"• Cách chia sẻ và phản ứng với trạng thái dùng chung giữa nhiều widget/màn.","whyCorrect":"• BLoC chuẩn hóa luồng event/state, dễ phân chia việc trong team lớn.\n• Cách chia sẻ và phản ứng với trạng thái dùng chung giữa nhiều widget/màn.\n• Tránh truyền prop sâu; cập nhật UI khi state đổi.","intent":"• Cách chia sẻ và phản ứng với trạng thái dùng chung giữa nhiều widget/màn.\n• Tránh truyền prop sâu; cập nhật UI khi state đổi.","memoryTip":"• Đổi state → rebuild; BLoC/Cubit/Provider tách logic khỏi UI; state nên immutable.","whatIs":{"A":"Cơ chế Flutter/Dart liên quan «Less mã».","B":"Cách chia sẻ và phản ứng với trạng thái dùng chung giữa nhiều widget/màn.","C":"Cơ chế Flutter/Dart liên quan «Nhanh hơn builds».","D":"Cơ chế Flutter/Dart liên quan «UI tái sử dụng»."},"whyWrong":{"A":"• Là gì? Cơ chế Flutter/Dart liên quan «Less mã».\n• Dùng để làm gì? Đối chiếu đúng cơ chế/phạm trù với trọng tâm đề.\n• Vì sao sai? «Less code» — Cơ chế Flutter/Dart liên quan «Less mã». Đề cần: Cách chia sẻ và phản ứng với trạng thái dùng chung giữa nhiều widget/màn.","C":"• Là gì? Cơ chế Flutter/Dart liên quan «Nhanh hơn builds».\n• Dùng để làm gì? Đối chiếu đúng cơ chế/phạm trù với trọng tâm đề.\n• Vì sao sai? Đây là lợi ích phụ hoặc không liên quan trực tiếp đến câu hỏi.","D":"• Là gì? Cơ chế Flutter/Dart liên quan «UI tái sử dụng».\n• Dùng để làm gì? Đối chiếu đúng cơ chế/phạm trù với trọng tâm đề.\n• Vì sao sai? «UI reuse» — Cơ chế Flutter/Dart liên quan «UI tái sử dụng». Đề cần: Cách chia sẻ và phản ứng với trạng thái dùng chung giữa nhiều widget/màn."}},"source":"SP26-B5-FE"},{"id":40,"task":"re","taskLabel":"SP26-B5-FE","num":40,"question":"Which widget reacts to async data from local storage?","options":{"A":"FutureBuilder","B":"StreamBuilder","C":"ListView","D":"Provider"},"answer":"A","alternatives":[],"explanation":{"questionVi":"Widget nào reacts async dữ liệu từ local storage?","optionsVi":{"A":"FutureBuilder","B":"StreamBuilder","C":"ListView","D":"Provider"},"answerDisplay":"A. FutureBuilder","concept":"• Cơ chế Flutter/Dart liên quan «FutureBuilder».","whyCorrect":"• Local storage thường trả Future → FutureBuilder.\n• Cơ chế Flutter/Dart liên quan «FutureBuilder».","intent":"• Cơ chế Flutter/Dart liên quan «FutureBuilder».\n• Chọn phương án khớp cơ chế Flutter, không chọn stack web/Android nhầm.","memoryTip":"• KV nhỏ → shared_preferences · NoSQL local → Hive · SQL → sqflite.","whatIs":{"A":"Cơ chế Flutter/Dart liên quan «FutureBuilder».","B":"Cơ chế Flutter/Dart liên quan «StreamBuilder».","C":"Cơ chế Flutter/Dart liên quan «ListView».","D":"Cách chia sẻ và phản ứng với trạng thái dùng chung giữa nhiều widget/màn."},"whyWrong":{"B":"• Là gì? Cơ chế Flutter/Dart liên quan «StreamBuilder».\n• Dùng để làm gì? Đối chiếu đúng cơ chế/phạm trù với trọng tâm đề.\n• Vì sao sai? «StreamBuilder» — Cơ chế Flutter/Dart liên quan «StreamBuilder». Đề cần: Cơ chế Flutter/Dart liên quan «FutureBuilder».","C":"• Là gì? Cơ chế Flutter/Dart liên quan «ListView».\n• Dùng để làm gì? Đối chiếu đúng cơ chế/phạm trù với trọng tâm đề.\n• Vì sao sai? «ListView» — Cơ chế Flutter/Dart liên quan «ListView». Đề cần: Cơ chế Flutter/Dart liên quan «FutureBuilder».","D":"• Là gì? Cách chia sẻ và phản ứng với trạng thái dùng chung giữa nhiều widget/màn.\n• Dùng để làm gì? Tránh truyền prop sâu; cập nhật UI khi state đổi.\n• Vì sao sai? «Provider» — Cách chia sẻ và phản ứng với trạng thái dùng chung giữa nhiều widget/màn. Đề cần: Cơ chế Flutter/Dart liên quan «FutureBuilder»."}},"source":"SP26-B5-FE"},{"id":41,"task":"re","taskLabel":"SP26-B5-FE","num":41,"question":"What is a token in authentication systems?","options":{"A":"UI key","B":"Temporary access credential","C":"Database ID","D":"Theme value"},"answer":"B","alternatives":[],"explanation":{"questionVi":"Token trong hệ xác thực là gì?","optionsVi":{"A":"UI key","B":"Temporary truy cập credential","C":"Cơ sở dữ liệu ID","D":"Theme giá trị"},"answerDisplay":"B. Temporary truy cập credential","concept":"• Temporary truy cập credential. Bản dịch/diễn đạt phương án — đối chiếu với định nghĩa chuẩn của đề.","whyCorrect":"• Temporary truy cập credential\n• Bản dịch/diễn đạt phương án — đối chiếu với định nghĩa chuẩn của đề.","intent":"• Temporary truy cập credential\n• Bản dịch/diễn đạt phương án — đối chiếu với định nghĩa chuẩn của đề.","memoryTip":"• Auth: token/session tập trung; Guard chặn route; StreamBuilder hay dùng với auth stream.","whatIs":{"A":"Cụm «UI key» mang một nghĩa riêng cần đối chiếu với đề.","B":"Temporary truy cập credential","C":"Cụm «Cơ sở dữ liệu ID» mang một nghĩa riêng cần đối chiếu với đề.","D":"Theme giá trị"},"whyWrong":{"A":"• Là gì? Cụm «UI key» mang một nghĩa riêng cần đối chiếu với đề.\n• Dùng để làm gì? So bản chất với đáp án đúng; loại nếu sai đối tượng hoặc sai lớp khái niệm.\n• Vì sao sai? Auth/session không giải quyết bằng chỉnh UI/theme/animation.","C":"• Là gì? Cụm «Cơ sở dữ liệu ID» mang một nghĩa riêng cần đối chiếu với đề.\n• Dùng để làm gì? So bản chất với đáp án đúng; loại nếu sai đối tượng hoặc sai lớp khái niệm.\n• Vì sao sai? «Database ID» — Cụm «Cơ sở dữ liệu ID» mang một nghĩa riêng cần đối chiếu với đề. Đề cần: Temporary truy cập credential.","D":"• Là gì? Theme giá trị\n• Dùng để làm gì? Đối chiếu định nghĩa/lớp hỏi; tránh nhầm khái niệm gần (chủ thể ≠ biểu hiện, Nhà nước ≠ độc quyền…).\n• Vì sao sai? Git quản lý phiên bản code — chỉ đúng khi hỏi version control."}},"source":"SP26-B5-FE"},{"id":42,"task":"re","taskLabel":"SP26-B5-FE","num":42,"question":"What does a Tween define?","options":{"A":"Animation speed","B":"Value range for animation","C":"UI layout","D":"State logic"},"answer":"B","alternatives":[],"explanation":{"questionVi":"Cái gì Tween định nghĩ?","optionsVi":{"A":"Animation speed","B":"Giá trị range cho animation","C":"UI bố cục","D":"State logic"},"answerDisplay":"B. Giá trị range cho animation","concept":"• Đường cong/thời gian điều khiển nhịp chuyển động UI (ease-in/out…).","whyCorrect":"• Tween định nghĩa khoảng giá trị bắt đầu–kết thúc cho animation.\n• Đường cong/thời gian điều khiển nhịp chuyển động UI (ease-in/out…).\n• Làm animation mượt, không tuyến tính cứng.","intent":"• Đường cong/thời gian điều khiển nhịp chuyển động UI (ease-in/out…).\n• Làm animation mượt, không tuyến tính cứng.","memoryTip":"• Animation/Tween định nghĩa chuyển động; luôn dispose controller để tránh rò memory.","whatIs":{"A":"Cụm «Animation speed» mang một nghĩa riêng cần đối chiếu với đề.","B":"Đường cong/thời gian điều khiển nhịp chuyển động UI (ease-in/out…).","C":"Cụm «UI bố cục» mang một nghĩa riêng cần đối chiếu với đề.","D":"Cụm «State logic» mang một nghĩa riêng cần đối chiếu với đề."},"whyWrong":{"A":"• Là gì? Cụm «Animation speed» mang một nghĩa riêng cần đối chiếu với đề.\n• Dùng để làm gì? So bản chất với đáp án đúng; loại nếu sai đối tượng hoặc sai lớp khái niệm.\n• Vì sao sai? Liên quan chuyển động UI, không giải quyết khái niệm trong câu hỏi.","C":"• Là gì? Cụm «UI bố cục» mang một nghĩa riêng cần đối chiếu với đề.\n• Dùng để làm gì? So bản chất với đáp án đúng; loại nếu sai đối tượng hoặc sai lớp khái niệm.\n• Vì sao sai? Liên quan chuyển động UI, không giải quyết khái niệm trong câu hỏi.","D":"• Là gì? Cụm «State logic» mang một nghĩa riêng cần đối chiếu với đề.\n• Dùng để làm gì? So bản chất với đáp án đúng; loại nếu sai đối tượng hoặc sai lớp khái niệm.\n• Vì sao sai? Liên quan chuyển động UI, không giải quyết khái niệm trong câu hỏi."}},"source":"SP26-B5-FE","_pilotFixed":"2026-07-23-v1"},{"id":43,"task":"re","taskLabel":"SP26-B5-FE","num":43,"question":"Which Dart feature allows defining reusable, type-safe components?","options":{"A":"Mixins","B":"Generics","C":"Futures","D":"Streams"},"answer":"B","alternatives":[],"explanation":{"questionVi":"Cái nào Dart feature allows defining tái sử dụng, type-safe components?","optionsVi":{"A":"Mixins","B":"Generics","C":"Futures","D":"Streams"},"answerDisplay":"B. Generics","concept":"• Ngôn ngữ lập trình chính của Flutter. Viết UI và logic app Flutter.","whyCorrect":"• Generics cho component/type-safe tái sử dụng (List<T>, class Box<T>).\n• Ngôn ngữ lập trình chính của Flutter.\n• Viết UI và logic app Flutter.","intent":"• Ngôn ngữ lập trình chính của Flutter.\n• Viết UI và logic app Flutter.","memoryTip":"• Generics cho component/type-safe tái sử dụng (List<T>, class Box<T>).","whatIs":{"A":"Cơ chế Flutter/Dart liên quan «Mixins».","B":"Ngôn ngữ lập trình chính của Flutter.","C":"Cơ chế Flutter/Dart liên quan «Futures».","D":"Cơ chế Flutter/Dart liên quan «Streams»."},"whyWrong":{"A":"• Là gì? Cơ chế Flutter/Dart liên quan «Mixins».\n• Dùng để làm gì? Đối chiếu đúng cơ chế/phạm trù với trọng tâm đề.\n• Vì sao sai? «Mixins» — Cơ chế Flutter/Dart liên quan «Mixins». Đề cần: Ngôn ngữ lập trình chính của Flutter.","C":"• Là gì? Cơ chế Flutter/Dart liên quan «Futures».\n• Dùng để làm gì? Đối chiếu đúng cơ chế/phạm trù với trọng tâm đề.\n• Vì sao sai? «Futures» — Cơ chế Flutter/Dart liên quan «Futures». Đề cần: Ngôn ngữ lập trình chính của Flutter.","D":"• Là gì? Cơ chế Flutter/Dart liên quan «Streams».\n• Dùng để làm gì? Đối chiếu đúng cơ chế/phạm trù với trọng tâm đề.\n• Vì sao sai? «Streams» — Cơ chế Flutter/Dart liên quan «Streams». Đề cần: Ngôn ngữ lập trình chính của Flutter."}},"source":"SP26-B5-FE"},{"id":44,"task":"re","taskLabel":"SP26-B5-FE","num":44,"question":"Which widget animates between two widgets?","options":{"A":"AnimatedSwitcher","B":"AnimatedOpacity","C":"AnimatedAlign","D":"AnimatedSize"},"answer":"A","alternatives":[],"explanation":{"questionVi":"Widget nào animates giữ two widgets?","optionsVi":{"A":"AnimatedSwitcher","B":"AnimatedOpacity","C":"AnimatedAlign","D":"AnimatedSize"},"answerDisplay":"A. AnimatedSwitcher","concept":"• Thiết bị/khái niệm mạng «AnimatedSwitcher».","whyCorrect":"• AnimatedSwitcher chuyển động giữa hai child widget khác nhau. Các Animated* khác animate một property.\n• Thiết bị/khái niệm mạng «AnimatedSwitcher».\n• Đối chiếu đúng tầng OSI và chức năng (routing / switching / physical).","intent":"• Thiết bị/khái niệm mạng «AnimatedSwitcher».\n• Chọn phương án khớp cơ chế Flutter, không chọn stack web/Android nhầm.","memoryTip":"• Animation/Tween định nghĩa chuyển động; luôn dispose controller để tránh rò memory.","whatIs":{"A":"Thiết bị/khái niệm mạng «AnimatedSwitcher».","B":"Cơ chế Flutter/Dart liên quan «AnimatedOpacity».","C":"Cơ chế Flutter/Dart liên quan «AnimatedAlign».","D":"Cơ chế Flutter/Dart liên quan «AnimatedSize»."},"whyWrong":{"B":"• Là gì? Cơ chế Flutter/Dart liên quan «AnimatedOpacity».\n• Dùng để làm gì? Đối chiếu đúng cơ chế/phạm trù với trọng tâm đề.\n• Vì sao sai? «AnimatedOpacity» — Cơ chế Flutter/Dart liên quan «AnimatedOpacity». Đề cần: Thiết bị/khái niệm mạng «AnimatedSwitcher».","C":"• Là gì? Cơ chế Flutter/Dart liên quan «AnimatedAlign».\n• Dùng để làm gì? Đối chiếu đúng cơ chế/phạm trù với trọng tâm đề.\n• Vì sao sai? «AnimatedAlign» — Cơ chế Flutter/Dart liên quan «AnimatedAlign». Đề cần: Thiết bị/khái niệm mạng «AnimatedSwitcher».","D":"• Là gì? Cơ chế Flutter/Dart liên quan «AnimatedSize».\n• Dùng để làm gì? Đối chiếu đúng cơ chế/phạm trù với trọng tâm đề.\n• Vì sao sai? «AnimatedSize» — Cơ chế Flutter/Dart liên quan «AnimatedSize». Đề cần: Thiết bị/khái niệm mạng «AnimatedSwitcher»."}},"source":"SP26-B5-FE"},{"id":45,"task":"re","taskLabel":"SP26-B5-FE","num":45,"question":"Why should setState() be called sparingly?","options":{"A":"It increases app size","B":"It may trigger unnecessary rebuilds","C":"It blocks UI thread","D":"It causes memory leaks"},"answer":"B","alternatives":[],"explanation":{"questionVi":"Vì sao setState() called sparingly?","optionsVi":{"A":"It increases app kích thước","B":"It may trigger unnecessary rebuilds","C":"It blocks luồng UI","D":"It causes memory leaks"},"answerDisplay":"B. It may trigger unnecessary rebuilds","concept":"• API đánh dấu State đã đổi và xếp lịch rebuild nhánh widget liên quan.","whyCorrect":"• setState() gọi nhiều/không cần thiết gây rebuild thừa → giảm performance.\n• API đánh dấu State đã đổi và xếp lịch rebuild nhánh widget liên quan.\n• Cập nhật UI sau khi dữ liệu nội bộ thay đổi.","intent":"• Phân biệt List / Set / Map trong Dart.\n• Thứ tự, trùng lặp, hay key–value.","memoryTip":"• Đổi state → rebuild; BLoC/Cubit/Provider tách logic khỏi UI; state nên immutable.","whatIs":{"A":"It increases app kích thước","B":"API đánh dấu State đã đổi và xếp lịch rebuild nhánh widget liên quan.","C":"Cách chia sẻ và phản ứng với trạng thái dùng chung giữa nhiều widget/màn.","D":"Cụm «It causes memory leaks» mang một nghĩa riêng cần đối chiếu với đề."},"whyWrong":{"A":"• Là gì? It increases app kích thước\n• Dùng để làm gì? Bản dịch/diễn đạt phương án — đối chiếu với định nghĩa chuẩn của đề.\n• Vì sao sai? «It increases app size» — It increases app kích thước. Đề cần: API đánh dấu State đã đổi và xếp lịch rebuild nhánh widget liên quan.","C":"• Là gì? Cách chia sẻ và phản ứng với trạng thái dùng chung giữa nhiều widget/màn.\n• Dùng để làm gì? Tránh truyền prop sâu; cập nhật UI khi state đổi.\n• Vì sao sai? setState rebuild StatefulWidget; không phải mọi cơ chế state (BLoC/Cubit…).","D":"• Là gì? Cụm «It causes memory leaks» mang một nghĩa riêng cần đối chiếu với đề.\n• Dùng để làm gì? So bản chất với đáp án đúng; loại nếu sai đối tượng hoặc sai lớp khái niệm.\n• Vì sao sai? «It causes memory leaks» — Cụm «It causes memory leaks» mang một nghĩa riêng cần đối chiếu với đề. Đề cần: API đánh dấu State đã đổi và xếp lịch rebuild nhánh widget liên quan."}},"source":"SP26-B5-FE"},{"id":46,"task":"re","taskLabel":"SP26-B5-FE","num":46,"question":"What is test isolation?","options":{"A":"Running all tests together","B":"Independence of test cases","C":"UI separation","D":"Mocking only"},"answer":"B","alternatives":[],"explanation":{"questionVi":"Test isolation là gì?","optionsVi":{"A":"Chạy tất cả tests together","B":"Tính độc lập giữa các test case","C":"UI separation","D":"Mocking"},"answerDisplay":"B. Tính độc lập giữa các test case","concept":"• Tính độc lập giữa các test case. Bản dịch/diễn đạt phương án — đối chiếu với định nghĩa chuẩn của đề.","whyCorrect":"• Tính độc lập giữa các test case\n• Bản dịch/diễn đạt phương án — đối chiếu với định nghĩa chuẩn của đề.","intent":"• Tính độc lập giữa các test case\n• Bản dịch/diễn đạt phương án — đối chiếu với định nghĩa chuẩn của đề.","whatIs":{"A":"Tiến trình đang chiếm CPU và thực thi lệnh.","B":"Tính độc lập giữa các test case","C":"Cụm «UI separation» mang một nghĩa riêng cần đối chiếu với đề.","D":"Cụm «Mocking» mang một nghĩa riêng cần đối chiếu với đề."},"whyWrong":{"A":"• Là gì? Tiến trình đang chiếm CPU và thực thi lệnh.\n• Dùng để làm gì? Đang làm việc trên bộ xử lý.\n• Vì sao sai? «Running all tests together» — Tiến trình đang chiếm CPU và thực thi lệnh. Đề cần: Tính độc lập giữa các test case.","C":"• Là gì? Cụm «UI separation» mang một nghĩa riêng cần đối chiếu với đề.\n• Dùng để làm gì? So bản chất với đáp án đúng; loại nếu sai đối tượng hoặc sai lớp khái niệm.\n• Vì sao sai? «UI separation» — Cụm «UI separation» mang một nghĩa riêng cần đối chiếu với đề. Đề cần: Tính độc lập giữa các test case.","D":"• Là gì? Cụm «Mocking» mang một nghĩa riêng cần đối chiếu với đề.\n• Dùng để làm gì? So bản chất với đáp án đúng; loại nếu sai đối tượng hoặc sai lớp khái niệm.\n• Vì sao sai? «Mocking only» — Cụm «Mocking» mang một nghĩa riêng cần đối chiếu với đề. Đề cần: Tính độc lập giữa các test case."}},"source":"SP26-B5-FE"},{"id":47,"task":"re","taskLabel":"SP26-B5-FE","num":47,"question":"What does crossAxisAlignment control?","options":{"A":"Vertical alignment in Column","B":"Horizontal alignment in Column","C":"Child order","D":"Widget size"},"answer":"B","alternatives":[],"explanation":{"questionVi":"Cái gì crossAxisAlignment control?","optionsVi":{"A":"Vertical alignment in Column","B":"Horizontal alignment in Column","C":"Child order","D":"Widget kích thước"},"answerDisplay":"B. Horizontal alignment in Column","concept":"• Phần mềm quản lý phần cứng, tiến trình, bộ nhớ, I/O.","whyCorrect":"• Trong Column (trục chính dọc), crossAxisAlignment điều khiển căn ngang. (Trong Row thì ngược lại.)\n• Phần mềm quản lý phần cứng, tiến trình, bộ nhớ, I/O.\n• Cấp tài nguyên và lập lịch cho chương trình.","intent":"• Phần mềm quản lý phần cứng, tiến trình, bộ nhớ, I/O.\n• Cấp tài nguyên và lập lịch cho chương trình.","memoryTip":"• Trong Column (trục chính dọc), crossAxisAlignment điều khiển căn ngang. (Trong Row thì ngược lại.)","whatIs":{"A":"Xếp widget con theo cột dọc (main axis = vertical).","B":"Phần mềm quản lý phần cứng, tiến trình, bộ nhớ, I/O.","C":"Cụm «Child order» mang một nghĩa riêng cần đối chiếu với đề.","D":"Cơ chế Flutter/Dart liên quan «Widget kích thước»."},"whyWrong":{"A":"• Là gì? Xếp widget con theo cột dọc (main axis = vertical).\n• Dùng để làm gì? Bố cục dọc; cross axis là ngang. Không scroll mặc định, không overlap.\n• Vì sao sai? Column xếp dọc, không scroll mặc định, không overlap.","C":"• Là gì? Cụm «Child order» mang một nghĩa riêng cần đối chiếu với đề.\n• Dùng để làm gì? So bản chất với đáp án đúng; loại nếu sai đối tượng hoặc sai lớp khái niệm.\n• Vì sao sai? Cụm «Child order» mang một nghĩa riêng cần đối chiếu với đề. crossAxisAlignment chỉ căn theo trục vuông góc main axis.","D":"• Là gì? Cơ chế Flutter/Dart liên quan «Widget kích thước».\n• Dùng để làm gì? Đối chiếu đúng cơ chế/phạm trù với trọng tâm đề.\n• Vì sao sai? Cơ chế Flutter/Dart liên quan «Widget kích thước». crossAxisAlignment chỉ căn theo trục vuông góc main axis."}},"source":"SP26-B5-FE"},{"id":48,"task":"re","taskLabel":"SP26-B5-FE","num":48,"question":"Which tool is commonly used for version control?","options":{"A":"SVN","B":"Git","C":"FTP","D":"ZIP"},"answer":"B","alternatives":[],"explanation":{"questionVi":"Cái nào tool thường dùng cho quản lý phiên bản?","optionsVi":{"A":"SVN","B":"Git","C":"FTP","D":"ZIP"},"answerDisplay":"B. Git","concept":"• Cụm «Git» mang một nghĩa riêng cần đối chiếu với đề.","whyCorrect":"• Git là công cụ version control phổ biến nhất hiện nay.\n• Cụm «Git» mang một nghĩa riêng cần đối chiếu với đề.\n• So bản chất với đáp án đúng; loại nếu sai đối tượng hoặc sai lớp khái niệm.","intent":"• Cụm «Git» mang một nghĩa riêng cần đối chiếu với đề.\n• So bản chất với đáp án đúng; loại nếu sai đối tượng hoặc sai lớp khái niệm.","memoryTip":"• Git là công cụ version control phổ biến nhất hiện nay.","whatIs":{"A":"Cụm «SVN» mang một nghĩa riêng cần đối chiếu với đề.","B":"Cụm «Git» mang một nghĩa riêng cần đối chiếu với đề.","C":"Cụm «FTP» mang một nghĩa riêng cần đối chiếu với đề.","D":"Cụm «ZIP» mang một nghĩa riêng cần đối chiếu với đề."},"whyWrong":{"A":"• Là gì? Cụm «SVN» mang một nghĩa riêng cần đối chiếu với đề.\n• Dùng để làm gì? So bản chất với đáp án đúng; loại nếu sai đối tượng hoặc sai lớp khái niệm.\n• Vì sao sai? Không phải công cụ VCS phổ biến nhất hiện nay (Git).","C":"• Là gì? Cụm «FTP» mang một nghĩa riêng cần đối chiếu với đề.\n• Dùng để làm gì? So bản chất với đáp án đúng; loại nếu sai đối tượng hoặc sai lớp khái niệm.\n• Vì sao sai? Không phải công cụ VCS phổ biến nhất hiện nay (Git).","D":"• Là gì? Cụm «ZIP» mang một nghĩa riêng cần đối chiếu với đề.\n• Dùng để làm gì? So bản chất với đáp án đúng; loại nếu sai đối tượng hoặc sai lớp khái niệm.\n• Vì sao sai? Không phải công cụ VCS phổ biến nhất hiện nay (Git)."}},"source":"SP26-B5-FE","_pilotFixed":"2026-07-23-v1"},{"id":49,"task":"fe","taskLabel":"SP26-FE","num":1,"question":"Why is clean architecture beneficial?","options":{"A":"Fewer files","B":"Easier maintenance and testing","C":"Better UI","D":"Faster builds"},"answer":"B","alternatives":[],"explanation":{"questionVi":"Vì sao clean architecture có lợi?","optionsVi":{"A":"Fewer files","B":"Dễ hơn maintenance và testing","C":"Tốt hơn UI","D":"Nhanh hơn builds"},"answerDisplay":"B. Dễ hơn maintenance và testing","concept":"• Dễ hơn maintenance và testing. Bản dịch/diễn đạt phương án — đối chiếu với định nghĩa chuẩn của đề.","whyCorrect":"• Dễ hơn maintenance và testing\n• Bản dịch/diễn đạt phương án — đối chiếu với định nghĩa chuẩn của đề.","intent":"• Dễ hơn maintenance và testing\n• Bản dịch/diễn đạt phương án — đối chiếu với định nghĩa chuẩn của đề.","whatIs":{"A":"Cụm «Fewer files» mang một nghĩa riêng cần đối chiếu với đề.","B":"Dễ hơn maintenance và testing","C":"Cụm «Tốt hơn UI» mang một nghĩa riêng cần đối chiếu với đề.","D":"Cụm «Nhanh hơn builds» mang một nghĩa riêng cần đối chiếu với đề."},"whyWrong":{"A":"• Là gì? Cụm «Fewer files» mang một nghĩa riêng cần đối chiếu với đề.\n• Dùng để làm gì? So bản chất với đáp án đúng; loại nếu sai đối tượng hoặc sai lớp khái niệm.\n• Vì sao sai? «Fewer files» — Cụm «Fewer files» mang một nghĩa riêng cần đối chiếu với đề. Đề cần: Dễ hơn maintenance và testing.","C":"• Là gì? Cụm «Tốt hơn UI» mang một nghĩa riêng cần đối chiếu với đề.\n• Dùng để làm gì? So bản chất với đáp án đúng; loại nếu sai đối tượng hoặc sai lớp khái niệm.\n• Vì sao sai? Tách lớp giúp bảo trì/test — đúng khi hỏi lợi ích architecture.","D":"• Là gì? Cụm «Nhanh hơn builds» mang một nghĩa riêng cần đối chiếu với đề.\n• Dùng để làm gì? So bản chất với đáp án đúng; loại nếu sai đối tượng hoặc sai lớp khái niệm.\n• Vì sao sai? Tách lớp giúp bảo trì/test — đúng khi hỏi lợi ích architecture."}},"source":"SP26-FE"},{"id":50,"task":"fe","taskLabel":"SP26-FE","num":2,"question":"What is Dart primarily designed for in the Flutter ecosystem?","options":{"A":"Database management","B":"User interface development","C":"General-purpose programming with UI focus","D":"Network security"},"answer":"C","alternatives":[],"explanation":{"questionVi":"Cái gì là Dart primarily designed Flutter ecosystem?","optionsVi":{"A":"Cơ sở dữ liệu management","B":"Người dùng interface phát triển","C":"General-purpose programming với UI focus","D":"Mạng bảo mật"},"answerDisplay":"C. General-purpose programming với UI focus","concept":"• Phần mềm quản lý phần cứng, tiến trình, bộ nhớ, I/O.","whyCorrect":"• Phần mềm quản lý phần cứng, tiến trình, bộ nhớ, I/O.\n• Cấp tài nguyên và lập lịch cho chương trình.","intent":"• Phần mềm quản lý phần cứng, tiến trình, bộ nhớ, I/O.\n• Chọn phương án khớp cơ chế Flutter, không chọn stack web/Android nhầm.","whatIs":{"A":"Cơ sở dữ liệu management","B":"Người dùng interface phát triển","C":"Phần mềm quản lý phần cứng, tiến trình, bộ nhớ, I/O.","D":"Cơ chế Flutter/Dart liên quan «Mạng bảo mật»."},"whyWrong":{"A":"• Là gì? Cơ sở dữ liệu management\n• Dùng để làm gì? Bản dịch/diễn đạt phương án — đối chiếu với định nghĩa chuẩn của đề.\n• Vì sao sai? «Database management» — Cơ sở dữ liệu management. Đề cần: Phần mềm quản lý phần cứng, tiến trình, bộ nhớ, I/O.","B":"• Là gì? Người dùng interface phát triển\n• Dùng để làm gì? Bản dịch/diễn đạt phương án — đối chiếu với định nghĩa chuẩn của đề.\n• Vì sao sai? «User interface development» — Người dùng interface phát triển. Đề cần: Phần mềm quản lý phần cứng, tiến trình, bộ nhớ, I/O.","D":"• Là gì? Cơ chế Flutter/Dart liên quan «Mạng bảo mật».\n• Dùng để làm gì? Đối chiếu đúng cơ chế/phạm trù với trọng tâm đề.\n• Vì sao sai? «Network security» — Cơ chế Flutter/Dart liên quan «Mạng bảo mật». Đề cần: Phần mềm quản lý phần cứng, tiến trình, bộ nhớ, I/O."}},"source":"SP26-FE"},{"id":51,"task":"fe","taskLabel":"SP26-FE","num":3,"question":"Why is secure authentication critical in mobile apps?","options":{"A":"UI quality","B":"Protect user data","C":"Reduce code","D":"Improve speed"},"answer":"B","alternatives":[],"explanation":{"questionVi":"Vì sao xác thực an toàn quan trọng trên mobile?","optionsVi":{"A":"UI quality","B":"Bảo vệ người dùng dữ liệu","C":"Giảm mã","D":"Cải thiện speed"},"answerDisplay":"B. Bảo vệ người dùng dữ liệu","concept":"• Bảo vệ người dùng dữ liệu. Bản dịch/diễn đạt phương án — đối chiếu với định nghĩa chuẩn của đề.","whyCorrect":"• Bảo vệ người dùng dữ liệu\n• Bản dịch/diễn đạt phương án — đối chiếu với định nghĩa chuẩn của đề.","intent":"• Bảo vệ người dùng dữ liệu\n• Bản dịch/diễn đạt phương án — đối chiếu với định nghĩa chuẩn của đề.","memoryTip":"• Auth: token/session tập trung; Guard chặn route; StreamBuilder hay dùng với auth stream.","whatIs":{"A":"Cụm «UI quality» mang một nghĩa riêng cần đối chiếu với đề.","B":"Bảo vệ người dùng dữ liệu","C":"Cụm «Giảm mã» mang một nghĩa riêng cần đối chiếu với đề.","D":"Cụm «Cải thiện speed» mang một nghĩa riêng cần đối chiếu với đề."},"whyWrong":{"A":"• Là gì? Cụm «UI quality» mang một nghĩa riêng cần đối chiếu với đề.\n• Dùng để làm gì? So bản chất với đáp án đúng; loại nếu sai đối tượng hoặc sai lớp khái niệm.\n• Vì sao sai? «UI quality» — Cụm «UI quality» mang một nghĩa riêng cần đối chiếu với đề. Đề cần: Bảo vệ người dùng dữ liệu.","C":"• Là gì? Cụm «Giảm mã» mang một nghĩa riêng cần đối chiếu với đề.\n• Dùng để làm gì? So bản chất với đáp án đúng; loại nếu sai đối tượng hoặc sai lớp khái niệm.\n• Vì sao sai? «Reduce code» — Cụm «Giảm mã» mang một nghĩa riêng cần đối chiếu với đề. Đề cần: Bảo vệ người dùng dữ liệu.","D":"• Là gì? Cụm «Cải thiện speed» mang một nghĩa riêng cần đối chiếu với đề.\n• Dùng để làm gì? So bản chất với đáp án đúng; loại nếu sai đối tượng hoặc sai lớp khái niệm.\n• Vì sao sai? «Improve speed» — Cụm «Cải thiện speed» mang một nghĩa riêng cần đối chiếu với đề. Đề cần: Bảo vệ người dùng dữ liệu."}},"source":"SP26-FE"},{"id":52,"task":"fe","taskLabel":"SP26-FE","num":4,"question":"Which HTTP method is typically used to retrieve data?","options":{"A":"POST","B":"PUT","C":"GET","D":"DELETE"},"answer":"C","alternatives":[],"explanation":{"questionVi":"HTTP method nào thường dùng để lấy dữ liệu?","optionsVi":{"A":"POST","B":"PUT","C":"GET","D":"DELETE"},"answerDisplay":"C. GET","concept":"• Cơ chế/thuật ngữ CNTT «GET». Đối chiếu đúng định nghĩa/đặc trưng kỹ thuật mà đề hỏi.","whyCorrect":"• Cơ chế/thuật ngữ CNTT «GET».\n• Đối chiếu đúng định nghĩa/đặc trưng kỹ thuật mà đề hỏi.","intent":"• Cơ chế/thuật ngữ CNTT «GET».\n• Đối chiếu đúng định nghĩa/đặc trưng kỹ thuật mà đề hỏi.","memoryTip":"• GET lấy · POST tạo · Authorization mang token · parse JSON → object Dart.","whatIs":{"A":"Phần mềm quản lý phần cứng, tiến trình, bộ nhớ, I/O.","B":"Cơ chế/thuật ngữ CNTT «PUT».","C":"Cơ chế/thuật ngữ CNTT «GET».","D":"Cơ chế/thuật ngữ CNTT «DELETE»."},"whyWrong":{"A":"• Là gì? Phần mềm quản lý phần cứng, tiến trình, bộ nhớ, I/O.\n• Dùng để làm gì? Cấp tài nguyên và lập lịch cho chương trình.\n• Vì sao sai? PUT/DELETE cập nhật/xóa; không phải thao tác retrieve mặc định.","B":"• Là gì? Cơ chế/thuật ngữ CNTT «PUT».\n• Dùng để làm gì? Đối chiếu đúng định nghĩa/đặc trưng kỹ thuật mà đề hỏi.\n• Vì sao sai? PUT/DELETE cập nhật/xóa; không phải thao tác retrieve mặc định.","D":"• Là gì? Cơ chế/thuật ngữ CNTT «DELETE».\n• Dùng để làm gì? Đối chiếu đúng định nghĩa/đặc trưng kỹ thuật mà đề hỏi.\n• Vì sao sai? Gói http gọi API; không quản lý state UI hay storage local."}},"source":"SP26-FE"},{"id":53,"task":"fe","taskLabel":"SP26-FE","num":5,"question":"What happens if a non-nullable variable is not initialized in Dart?","options":{"A":"The app runs normally","B":"A runtime exception occurs","C":"A compile-time error occurs","D":"The value becomes null automatically"},"answer":"C","alternatives":[],"explanation":{"questionVi":"Gì happens if non-nullable variable not initialized Dart?","optionsVi":{"A":"The app runs normally","B":"Một runtime exception occurs","C":"Xảy ra lỗi compile-time","D":"Giá trị becomes null tự động"},"answerDisplay":"C. Xảy ra lỗi compile-time","concept":"• Hệ thống kiểu Dart phân biệt null/non-null để giảm crash.","whyCorrect":"• Biến non-nullable không khởi tạo → lỗi compile-time (null safety).\n• Hệ thống kiểu Dart phân biệt null/non-null để giảm crash.\n• Bắt buộc khởi tạo non-nullable trước khi dùng.","intent":"• Phân biệt const, final, var và null safety.\n• Compile-time vs runtime assignment.","memoryTip":"• Biến non-nullable không khởi tạo → lỗi compile-time (null safety).","whatIs":{"A":"Cơ chế Flutter/Dart liên quan «The app runs normally».","B":"Một runtime exception occurs","C":"Hệ thống kiểu Dart phân biệt null/non-null để giảm crash.","D":"Giá trị becomes null tự động"},"whyWrong":{"A":"• Là gì? Cơ chế Flutter/Dart liên quan «The app runs normally».\n• Dùng để làm gì? Đối chiếu đúng cơ chế/phạm trù với trọng tâm đề.\n• Vì sao sai? «The app runs normally» — Cơ chế Flutter/Dart liên quan «The app runs normally». Đề cần: Hệ thống kiểu Dart phân biệt null/non-null để giảm crash.","B":"• Là gì? Một runtime exception occurs\n• Dùng để làm gì? Bản dịch/diễn đạt phương án — đối chiếu với định nghĩa chuẩn của đề.\n• Vì sao sai? «A runtime exception occurs» — Một runtime exception occurs. Đề cần: Hệ thống kiểu Dart phân biệt null/non-null để giảm crash.","D":"• Là gì? Giá trị becomes null tự động\n• Dùng để làm gì? Bản dịch/diễn đạt phương án — đối chiếu với định nghĩa chuẩn của đề.\n• Vì sao sai? «The value becomes null automatically» — Giá trị becomes null tự động. Đề cần: Hệ thống kiểu Dart phân biệt null/non-null để giảm crash."}},"source":"SP26-FE"},{"id":54,"task":"fe","taskLabel":"SP26-FE","num":6,"question":"Which command builds a release APK?","options":{"A":"flutter run","B":"flutter build apk","C":"flutter doctor","D":"flutter clean"},"answer":"B","alternatives":[],"explanation":{"questionVi":"Lệnh nào build APK release?","optionsVi":{"A":"flutter run","B":"flutter build apk","C":"flutter doctor","D":"flutter clean"},"answerDisplay":"B. flutter build apk","concept":"• Gói cài đặt Android chứa mã và tài nguyên đã build.","whyCorrect":"• Gói cài đặt Android chứa mã và tài nguyên đã build.\n• Phát hành/cài app lên thiết bị.","intent":"• Gói cài đặt Android chứa mã và tài nguyên đã build.\n• Phát hành/cài app lên thiết bị.","whatIs":{"A":"Cơ chế Flutter/Dart liên quan «flutter run».","B":"Gói cài đặt Android chứa mã và tài nguyên đã build.","C":"Lệnh kiểm tra môi trường SDK, toolchain, thiết bị Flutter.","D":"Cơ chế Flutter/Dart liên quan «flutter clean»."},"whyWrong":{"A":"• Là gì? Cơ chế Flutter/Dart liên quan «flutter run».\n• Dùng để làm gì? Đối chiếu đúng cơ chế/phạm trù với trọng tâm đề.\n• Vì sao sai? «flutter run» — Cơ chế Flutter/Dart liên quan «flutter run». Đề cần: Gói cài đặt Android chứa mã và tài nguyên đã build.","C":"• Là gì? Lệnh kiểm tra môi trường SDK, toolchain, thiết bị Flutter.\n• Dùng để làm gì? Xác nhận cài đặt/PATH sau setup.\n• Vì sao sai? «flutter doctor» — Lệnh kiểm tra môi trường SDK, toolchain, thiết bị Flutter. Đề cần: Gói cài đặt Android chứa mã và tài nguyên đã build.","D":"• Là gì? Cơ chế Flutter/Dart liên quan «flutter clean».\n• Dùng để làm gì? Đối chiếu đúng cơ chế/phạm trù với trọng tâm đề.\n• Vì sao sai? «flutter clean» — Cơ chế Flutter/Dart liên quan «flutter clean». Đề cần: Gói cài đặt Android chứa mã và tài nguyên đã build."}},"source":"SP26-FE"},{"id":55,"task":"fe","taskLabel":"SP26-FE","num":7,"question":"Which widget allows overlapping of its child widgets?","options":{"A":"Column","B":"Row","C":"Stack","D":"Expanded"},"answer":"C","alternatives":[],"explanation":{"questionVi":"Widget nào cho phép các widget con chồng lên nhau?","optionsVi":{"A":"Column","B":"Row","C":"Stack","D":"Expanded"},"answerDisplay":"C. Stack","concept":"• Xếp chồng widget con theo trục Z, cho phép overlap.","whyCorrect":"• Stack xếp chồng / cho phép overlap child.\n• Xếp chồng widget con theo trục Z, cho phép overlap.\n• Badge, overlay, layer UI chồng lên nhau.","intent":"• Stack cho overlap theo trục Z.\n• Row/Column/Expanded là layout flex, không chồng lớp.","memoryTip":"• Stack xếp chồng / cho phép overlap child.","whatIs":{"A":"Xếp widget con theo cột dọc (main axis = vertical).","B":"Xếp widget con theo hàng ngang (main axis = horizontal).","C":"Xếp chồng widget con theo trục Z, cho phép overlap.","D":"Buộc widget con chiếm toàn bộ không gian còn lại theo main axis của Flex (Row/Column/Flex)."},"whyWrong":{"A":"• Là gì? Xếp widget con theo cột dọc (main axis = vertical).\n• Dùng để làm gì? Bố cục dọc; cross axis là ngang. Không scroll mặc định, không overlap.\n• Vì sao sai? Column xếp dọc, không scroll mặc định, không overlap.","B":"• Là gì? Xếp widget con theo hàng ngang (main axis = horizontal).\n• Dùng để làm gì? Bố cục ngang; cross axis là dọc.\n• Vì sao sai? Row xếp ngang.","D":"• Là gì? Buộc widget con chiếm toàn bộ không gian còn lại theo main axis của Flex (Row/Column/Flex).\n• Dùng để làm gì? Trong Row giãn ngang, trong Column giãn dọc; nhiều Expanded chia phần trống theo flex. Tương đương Flexible(fit: FlexFit.tight).\n• Vì sao sai? Expanded chiếm phần còn lại trên trục chính Flex; không tạo khoảng trống cố định."}},"source":"SP26-FE"},{"id":56,"task":"fe","taskLabel":"SP26-FE","num":8,"question":"Which platforms can Flutter applications target using a single codebase?","options":{"A":"Android only","B":"iOS only","C":"Android, iOS, web, and desktop","D":"Web servers only"},"answer":"C","alternatives":[],"explanation":{"questionVi":"Cái nào nền tảng Flutter applications nhắm tới dùng một codebase?","optionsVi":{"A":"Android","B":"iOS","C":"Android, iOS, web, và desktop","D":"Web servers"},"answerDisplay":"C. Android, iOS, web, và desktop","concept":"• Phần mềm quản lý phần cứng, tiến trình, bộ nhớ, I/O.","whyCorrect":"• Flutter multi-platform: mobile + web + desktop từ một codebase.\n• Phần mềm quản lý phần cứng, tiến trình, bộ nhớ, I/O.\n• Cấp tài nguyên và lập lịch cho chương trình.","intent":"• Phần mềm quản lý phần cứng, tiến trình, bộ nhớ, I/O.\n• Chọn phương án khớp cơ chế Flutter, không chọn stack web/Android nhầm.","memoryTip":"• Flutter multi-platform: mobile + web + desktop từ một codebase.","whatIs":{"A":"Cơ chế Flutter/Dart liên quan «Android».","B":"Phần mềm quản lý phần cứng, tiến trình, bộ nhớ, I/O.","C":"Phần mềm quản lý phần cứng, tiến trình, bộ nhớ, I/O.","D":"Cơ chế Flutter/Dart liên quan «Web servers»."},"whyWrong":{"A":"• Là gì? Cơ chế Flutter/Dart liên quan «Android».\n• Dùng để làm gì? Đối chiếu đúng cơ chế/phạm trù với trọng tâm đề.\n• Vì sao sai? Flutter multi-platform, không giới hạn một nền tảng như option này.","B":"• Là gì? Phần mềm quản lý phần cứng, tiến trình, bộ nhớ, I/O.\n• Dùng để làm gì? Cấp tài nguyên và lập lịch cho chương trình.\n• Vì sao sai? Flutter multi-platform, không giới hạn một nền tảng như option này.","D":"• Là gì? Cơ chế Flutter/Dart liên quan «Web servers».\n• Dùng để làm gì? Đối chiếu đúng cơ chế/phạm trù với trọng tâm đề.\n• Vì sao sai? Flutter multi-platform, không giới hạn một nền tảng như option này."}},"source":"SP26-FE","_pilotFixed":"2026-07-23-v1"},{"id":57,"task":"fe","taskLabel":"SP26-FE","num":9,"question":"What is the main risk of improper state management?","options":{"A":"UI inconsistency","B":"Longer compile time","C":"Package conflicts","D":"Build errors"},"answer":"A","alternatives":[],"explanation":{"questionVi":"Cái gì là main risk improper state management?","optionsVi":{"A":"UI inconsistency","B":"Longer Biên dịch time","C":"Gói conflicts","D":"Build lỗi"},"answerDisplay":"A. UI inconsistency","concept":"• Cách chia sẻ và phản ứng với trạng thái dùng chung giữa nhiều widget/màn.","whyCorrect":"• State sai → UI không nhất quán / bug hiển thị.\n• Cách chia sẻ và phản ứng với trạng thái dùng chung giữa nhiều widget/màn.\n• Tránh truyền prop sâu; cập nhật UI khi state đổi.","intent":"• Cách chia sẻ và phản ứng với trạng thái dùng chung giữa nhiều widget/màn.\n• Tránh truyền prop sâu; cập nhật UI khi state đổi.","memoryTip":"• Đổi state → rebuild; BLoC/Cubit/Provider tách logic khỏi UI; state nên immutable.","whatIs":{"A":"Cách chia sẻ và phản ứng với trạng thái dùng chung giữa nhiều widget/màn.","B":"Cụm «Longer Biên dịch time» mang một nghĩa riêng cần đối chiếu với đề.","C":"Cụm «Gói conflicts» mang một nghĩa riêng cần đối chiếu với đề.","D":"Cụm «Build lỗi» mang một nghĩa riêng cần đối chiếu với đề."},"whyWrong":{"B":"• Là gì? Cụm «Longer Biên dịch time» mang một nghĩa riêng cần đối chiếu với đề.\n• Dùng để làm gì? So bản chất với đáp án đúng; loại nếu sai đối tượng hoặc sai lớp khái niệm.\n• Vì sao sai? «Longer compile time» — Cụm «Longer Biên dịch time» mang một nghĩa riêng cần đối chiếu với đề. Đề cần: Cách chia sẻ và phản ứng với trạng thái dùng chung giữa nhiều widget/màn.","C":"• Là gì? Cụm «Gói conflicts» mang một nghĩa riêng cần đối chiếu với đề.\n• Dùng để làm gì? So bản chất với đáp án đúng; loại nếu sai đối tượng hoặc sai lớp khái niệm.\n• Vì sao sai? «Package conflicts» — Cụm «Gói conflicts» mang một nghĩa riêng cần đối chiếu với đề. Đề cần: Cách chia sẻ và phản ứng với trạng thái dùng chung giữa nhiều widget/màn.","D":"• Là gì? Cụm «Build lỗi» mang một nghĩa riêng cần đối chiếu với đề.\n• Dùng để làm gì? So bản chất với đáp án đúng; loại nếu sai đối tượng hoặc sai lớp khái niệm.\n• Vì sao sai? «Build errors» — Cụm «Build lỗi» mang một nghĩa riêng cần đối chiếu với đề. Đề cần: Cách chia sẻ và phản ứng với trạng thái dùng chung giữa nhiều widget/màn."}},"source":"SP26-FE"},{"id":58,"task":"fe","taskLabel":"SP26-FE","num":10,"question":"What does CurvedAnimation provide?","options":{"A":"Layout control","B":"Animation curve behavior","C":"State updates","D":"Navigation"},"answer":"B","alternatives":[],"explanation":{"questionVi":"Cái gì CurvedAnimation cung cấp?","optionsVi":{"A":"Điều khiển bố cục (layout)","B":"Hành vi đường cong animation","C":"Cập nhật state","D":"Điều hướng màn hình"},"answerDisplay":"B. Hành vi đường cong animation","concept":"• Đường cong/thời gian điều khiển nhịp chuyển động UI (ease-in/out…).","whyCorrect":"• Đường cong/thời gian điều khiển nhịp chuyển động UI (ease-in/out…).\n• Làm animation mượt, không tuyến tính cứng.","intent":"• Đường cong/thời gian điều khiển nhịp chuyển động UI (ease-in/out…).\n• Làm animation mượt, không tuyến tính cứng.","whatIs":{"A":"Điều khiển cách xếp vị trí/kích thước widget con trên màn hình.","B":"Đường cong/thời gian điều khiển nhịp chuyển động UI (ease-in/out…).","C":"Cụm «Cập nhật state» mang một nghĩa riêng cần đối chiếu với đề.","D":"Cụm «Điều hướng màn hình» mang một nghĩa riêng cần đối chiếu với đề."},"whyWrong":{"A":"• Là gì? Điều khiển cách xếp vị trí/kích thước widget con trên màn hình.\n• Dùng để làm gì? Bố cục UI (Row/Column/Stack…); khác nhịp animation.\n• Vì sao sai? «Layout control» — Điều khiển cách xếp vị trí/kích thước widget con trên màn hình. Đề cần: Đường cong/thời gian điều khiển nhịp chuyển động UI (ease-in/out…).","C":"• Là gì? Cụm «Cập nhật state» mang một nghĩa riêng cần đối chiếu với đề.\n• Dùng để làm gì? So bản chất với đáp án đúng; loại nếu sai đối tượng hoặc sai lớp khái niệm.\n• Vì sao sai? «State updates» — Cụm «Cập nhật state» mang một nghĩa riêng cần đối chiếu với đề. Đề cần: Đường cong/thời gian điều khiển nhịp chuyển động UI (ease-in/out…).","D":"• Là gì? Cụm «Điều hướng màn hình» mang một nghĩa riêng cần đối chiếu với đề.\n• Dùng để làm gì? So bản chất với đáp án đúng; loại nếu sai đối tượng hoặc sai lớp khái niệm.\n• Vì sao sai? «Navigation» — Cụm «Điều hướng màn hình» mang một nghĩa riêng cần đối chiếu với đề. Đề cần: Đường cong/thời gian điều khiển nhịp chuyển động UI (ease-in/out…)."}},"source":"SP26-FE"},{"id":59,"task":"fe","taskLabel":"SP26-FE","num":11,"question":"How can data be passed to a new screen?","options":{"A":"Using global variables","B":"Via constructor arguments","C":"Using ThemeData","D":"Using Scaffold"},"answer":"B","alternatives":[],"explanation":{"questionVi":"Làm sao có thể dữ liệu passed new screen?","optionsVi":{"A":"Dùng global biến","B":"Via constructor arguments","C":"Dùng ThemeData","D":"Dùng Scaffold"},"answerDisplay":"B. Via constructor arguments","concept":"• Cụm «Via constructor arguments» mang một nghĩa riêng cần đối chiếu với đề.","whyCorrect":"• Cách chuẩn: truyền qua constructor của màn hình mới (hoặc route arguments).\n• Cụm «Via constructor arguments» mang một nghĩa riêng cần đối chiếu với đề.\n• So bản chất với đáp án đúng; loại nếu sai đối tượng hoặc sai lớp khái niệm.","intent":"• Cụm «Via constructor arguments» mang một nghĩa riêng cần đối chiếu với đề.\n• So bản chất với đáp án đúng; loại nếu sai đối tượng hoặc sai lớp khái niệm.","memoryTip":"• Cách chuẩn: truyền qua constructor của màn hình mới (hoặc route arguments).","whatIs":{"A":"Cụm «Dùng global biến» mang một nghĩa riêng cần đối chiếu với đề.","B":"Cụm «Via constructor arguments» mang một nghĩa riêng cần đối chiếu với đề.","C":"Cụm «Dùng ThemeData» mang một nghĩa riêng cần đối chiếu với đề.","D":"Cụm «Dùng Scaffold» mang một nghĩa riêng cần đối chiếu với đề."},"whyWrong":{"A":"• Là gì? Cụm «Dùng global biến» mang một nghĩa riêng cần đối chiếu với đề.\n• Dùng để làm gì? So bản chất với đáp án đúng; loại nếu sai đối tượng hoặc sai lớp khái niệm.\n• Vì sao sai? Global khó kiểm soát, dễ rebuild/test kém — thường là đáp án nhiễu.","C":"• Là gì? Cụm «Dùng ThemeData» mang một nghĩa riêng cần đối chiếu với đề.\n• Dùng để làm gì? So bản chất với đáp án đúng; loại nếu sai đối tượng hoặc sai lớp khái niệm.\n• Vì sao sai? Theme/ThemeData lo style giao diện, không phải state/auth/logic chính ở đây.","D":"• Là gì? Cụm «Dùng Scaffold» mang một nghĩa riêng cần đối chiếu với đề.\n• Dùng để làm gì? So bản chất với đáp án đúng; loại nếu sai đối tượng hoặc sai lớp khái niệm.\n• Vì sao sai? Scaffold khung màn (AppBar/body); không apply theme toàn app."}},"source":"SP26-FE"},{"id":60,"task":"fe","taskLabel":"SP26-FE","num":12,"question":"What is the purpose of parsing JSON?","options":{"A":"Encrypt data","B":"Convert JSON into Dart objects","C":"Send requests","D":"Cache responses"},"answer":"B","alternatives":[],"explanation":{"questionVi":"Mục đích parse JSON là gì?","optionsVi":{"A":"Encrypt dữ liệu","B":"Chuyển JSON thành Dart object","C":"Send requests","D":"Cache responses"},"answerDisplay":"B. Chuyển JSON thành Dart object","concept":"• Phần mềm quản lý phần cứng, tiến trình, bộ nhớ, I/O.","whyCorrect":"• Phần mềm quản lý phần cứng, tiến trình, bộ nhớ, I/O.\n• Cấp tài nguyên và lập lịch cho chương trình.","intent":"• Phần mềm quản lý phần cứng, tiến trình, bộ nhớ, I/O.\n• Cấp tài nguyên và lập lịch cho chương trình.","memoryTip":"• GET lấy · POST tạo · Authorization mang token · parse JSON → object Dart.","whatIs":{"A":"Cụm «Encrypt dữ liệu» mang một nghĩa riêng cần đối chiếu với đề.","B":"Phần mềm quản lý phần cứng, tiến trình, bộ nhớ, I/O.","C":"Cụm «Send requests» mang một nghĩa riêng cần đối chiếu với đề.","D":"Cụm «Cache responses» mang một nghĩa riêng cần đối chiếu với đề."},"whyWrong":{"A":"• Là gì? Cụm «Encrypt dữ liệu» mang một nghĩa riêng cần đối chiếu với đề.\n• Dùng để làm gì? So bản chất với đáp án đúng; loại nếu sai đối tượng hoặc sai lớp khái niệm.\n• Vì sao sai? «Encrypt data» — Cụm «Encrypt dữ liệu» mang một nghĩa riêng cần đối chiếu với đề. Đề cần: Phần mềm quản lý phần cứng, tiến trình, bộ nhớ, I/O.","C":"• Là gì? Cụm «Send requests» mang một nghĩa riêng cần đối chiếu với đề.\n• Dùng để làm gì? So bản chất với đáp án đúng; loại nếu sai đối tượng hoặc sai lớp khái niệm.\n• Vì sao sai? «Send requests» — Cụm «Send requests» mang một nghĩa riêng cần đối chiếu với đề. Đề cần: Phần mềm quản lý phần cứng, tiến trình, bộ nhớ, I/O.","D":"• Là gì? Cụm «Cache responses» mang một nghĩa riêng cần đối chiếu với đề.\n• Dùng để làm gì? So bản chất với đáp án đúng; loại nếu sai đối tượng hoặc sai lớp khái niệm.\n• Vì sao sai? «Cache responses» — Cụm «Cache responses» mang một nghĩa riêng cần đối chiếu với đề. Đề cần: Phần mềm quản lý phần cứng, tiến trình, bộ nhớ, I/O."}},"source":"SP26-FE"},{"id":61,"task":"fe","taskLabel":"SP26-FE","num":13,"question":"Which phase involves gathering requirements?","options":{"A":"Implementation","B":"Design","C":"Analysis","D":"Testing"},"answer":"C","alternatives":[],"explanation":{"questionVi":"Cái nào phase involves gathering requirements?","optionsVi":{"A":"Implementation","B":"Design","C":"Analysis","D":"Testing"},"answerDisplay":"C. Analysis","concept":"• Cụm «Analysis» mang một nghĩa riêng cần đối chiếu với đề.","whyCorrect":"• Thu thập yêu cầu thuộc giai đoạn Analysis.\n• Cụm «Analysis» mang một nghĩa riêng cần đối chiếu với đề.\n• So bản chất với đáp án đúng; loại nếu sai đối tượng hoặc sai lớp khái niệm.","intent":"• Cụm «Analysis» mang một nghĩa riêng cần đối chiếu với đề.\n• So bản chất với đáp án đúng; loại nếu sai đối tượng hoặc sai lớp khái niệm.","memoryTip":"• Thu thập yêu cầu thuộc giai đoạn Analysis.","whatIs":{"A":"Cụm «Implementation» mang một nghĩa riêng cần đối chiếu với đề.","B":"Cụm «Design» mang một nghĩa riêng cần đối chiếu với đề.","C":"Cụm «Analysis» mang một nghĩa riêng cần đối chiếu với đề.","D":"Cụm «Testing» mang một nghĩa riêng cần đối chiếu với đề."},"whyWrong":{"A":"• Là gì? Cụm «Implementation» mang một nghĩa riêng cần đối chiếu với đề.\n• Dùng để làm gì? So bản chất với đáp án đúng; loại nếu sai đối tượng hoặc sai lớp khái niệm.\n• Vì sao sai? «Implementation» — Cụm «Implementation» mang một nghĩa riêng cần đối chiếu với đề. Đề cần: Cụm «Analysis» mang một nghĩa riêng cần đối chiếu với đề.","B":"• Là gì? Cụm «Design» mang một nghĩa riêng cần đối chiếu với đề.\n• Dùng để làm gì? So bản chất với đáp án đúng; loại nếu sai đối tượng hoặc sai lớp khái niệm.\n• Vì sao sai? «Design» — Cụm «Design» mang một nghĩa riêng cần đối chiếu với đề. Đề cần: Cụm «Analysis» mang một nghĩa riêng cần đối chiếu với đề.","D":"• Là gì? Cụm «Testing» mang một nghĩa riêng cần đối chiếu với đề.\n• Dùng để làm gì? So bản chất với đáp án đúng; loại nếu sai đối tượng hoặc sai lớp khái niệm.\n• Vì sao sai? «Testing» — Cụm «Testing» mang một nghĩa riêng cần đối chiếu với đề. Đề cần: Cụm «Analysis» mang một nghĩa riêng cần đối chiếu với đề."}},"source":"SP26-FE"},{"id":62,"task":"fe","taskLabel":"SP26-FE","num":14,"question":"Which Flutter tool helps debug network requests?","options":{"A":"DevTools","B":"Inspector","C":"Emulator","D":"Hot reload"},"answer":"A","alternatives":[],"explanation":{"questionVi":"Cái nào Flutter tool helps debug mạng requests?","optionsVi":{"A":"DevTools","B":"Inspector","C":"Emulator","D":"Hot reload"},"answerDisplay":"A. DevTools","concept":"• Cơ chế Flutter/Dart liên quan «DevTools».","whyCorrect":"• Flutter DevTools hỗ trợ debug network, performance, v.v.\n• Cơ chế Flutter/Dart liên quan «DevTools».","intent":"• Cơ chế Flutter/Dart liên quan «DevTools».\n• Chọn phương án khớp cơ chế Flutter, không chọn stack web/Android nhầm.","memoryTip":"• Flutter DevTools hỗ trợ debug network, performance, v.v.","whatIs":{"A":"Cơ chế Flutter/Dart liên quan «DevTools».","B":"Cơ chế Flutter/Dart liên quan «Inspector».","C":"Cơ chế Flutter/Dart liên quan «Emulator».","D":"Nạp lại code UI gần như giữ state đang chạy."},"whyWrong":{"B":"• Là gì? Cơ chế Flutter/Dart liên quan «Inspector».\n• Dùng để làm gì? Đối chiếu đúng cơ chế/phạm trù với trọng tâm đề.\n• Vì sao sai? «Inspector» — Cơ chế Flutter/Dart liên quan «Inspector». Đề cần: Cơ chế Flutter/Dart liên quan «DevTools».","C":"• Là gì? Cơ chế Flutter/Dart liên quan «Emulator».\n• Dùng để làm gì? Đối chiếu đúng cơ chế/phạm trù với trọng tâm đề.\n• Vì sao sai? «Emulator» — Cơ chế Flutter/Dart liên quan «Emulator». Đề cần: Cơ chế Flutter/Dart liên quan «DevTools».","D":"• Là gì? Nạp lại code UI gần như giữ state đang chạy.\n• Dùng để làm gì? Xem thay đổi nhanh khi dev.\n• Vì sao sai? «Hot reload» — Nạp lại code UI gần như giữ state đang chạy. Đề cần: Cơ chế Flutter/Dart liên quan «DevTools»."}},"source":"SP26-FE"},{"id":63,"task":"fe","taskLabel":"SP26-FE","num":15,"question":"Which Dart feature supports object-oriented programming?","options":{"A":"Widgets","B":"Classes and objects","C":"Hot reload","D":"Layout builders"},"answer":"B","alternatives":[],"explanation":{"questionVi":"Cái nào Dart feature supports object-oriented programming?","optionsVi":{"A":"Widgets","B":"Class và object","C":"Hot reload","D":"Bố cục builders"},"answerDisplay":"B. Class và object","concept":"• Ngôn ngữ lập trình chính của Flutter. Viết UI và logic app Flutter.","whyCorrect":"• OOP trong Dart dựa trên class và object.\n• Ngôn ngữ lập trình chính của Flutter.\n• Viết UI và logic app Flutter.","intent":"• Ngôn ngữ lập trình chính của Flutter.\n• Viết UI và logic app Flutter.","memoryTip":"• OOP trong Dart dựa trên class và object.","whatIs":{"A":"Cơ chế Flutter/Dart liên quan «Widgets».","B":"Ngôn ngữ lập trình chính của Flutter.","C":"Nạp lại code UI gần như giữ state đang chạy.","D":"Cơ chế Flutter/Dart liên quan «Bố cục builders»."},"whyWrong":{"A":"• Là gì? Cơ chế Flutter/Dart liên quan «Widgets».\n• Dùng để làm gì? Đối chiếu đúng cơ chế/phạm trù với trọng tâm đề.\n• Vì sao sai? «Widgets» — Cơ chế Flutter/Dart liên quan «Widgets». Đề cần: Ngôn ngữ lập trình chính của Flutter.","C":"• Là gì? Nạp lại code UI gần như giữ state đang chạy.\n• Dùng để làm gì? Xem thay đổi nhanh khi dev.\n• Vì sao sai? Hot reload nạp code UI nhanh khi dev; không phải công cụ phân tích sâu.","D":"• Là gì? Cơ chế Flutter/Dart liên quan «Bố cục builders».\n• Dùng để làm gì? Đối chiếu đúng cơ chế/phạm trù với trọng tâm đề.\n• Vì sao sai? «Layout builders» — Cơ chế Flutter/Dart liên quan «Bố cục builders». Đề cần: Ngôn ngữ lập trình chính của Flutter."}},"source":"SP26-FE"},{"id":64,"task":"fe","taskLabel":"SP26-FE","num":16,"question":"Which approach helps reduce unnecessary widget rebuilds?","options":{"A":"Using global variables","B":"Fine-grained state updates","C":"Hot restart","D":"Large widgets"},"answer":"B","alternatives":[],"explanation":{"questionVi":"Cái nào approach helps Giảm unnecessary widget rebuilds?","optionsVi":{"A":"Dùng global biến","B":"Fine-grained state updates","C":"Hot restart","D":"Large widgets"},"answerDisplay":"B. Fine-grained state updates","concept":"• Cơ chế Flutter/Dart liên quan «Fine-grained state updates».","whyCorrect":"• Cập nhật state hẹp (fine-grained) giảm rebuild thừa.\n• Cơ chế Flutter/Dart liên quan «Fine-grained state updates».","intent":"• Cơ chế Flutter/Dart liên quan «Fine-grained state updates».\n• Chọn phương án khớp cơ chế Flutter, không chọn stack web/Android nhầm.","memoryTip":"• Đổi state → rebuild; BLoC/Cubit/Provider tách logic khỏi UI; state nên immutable.","whatIs":{"A":"Cơ chế Flutter/Dart liên quan «Dùng global biến».","B":"Cơ chế Flutter/Dart liên quan «Fine-grained state updates».","C":"Chạy lại app từ đầu, reset state.","D":"Cơ chế Flutter/Dart liên quan «Large widgets»."},"whyWrong":{"A":"• Là gì? Cơ chế Flutter/Dart liên quan «Dùng global biến».\n• Dùng để làm gì? Đối chiếu đúng cơ chế/phạm trù với trọng tâm đề.\n• Vì sao sai? «Using global variables» — Cơ chế Flutter/Dart liên quan «Dùng global biến». Đề cần: Cơ chế Flutter/Dart liên quan «Fine-grained state updates».","C":"• Là gì? Chạy lại app từ đầu, reset state.\n• Dùng để làm gì? Khi cần khởi tạo lại toàn bộ sau đổi lớn.\n• Vì sao sai? «Hot restart» — Chạy lại app từ đầu, reset state. Đề cần: Cơ chế Flutter/Dart liên quan «Fine-grained state updates».","D":"• Là gì? Cơ chế Flutter/Dart liên quan «Large widgets».\n• Dùng để làm gì? Đối chiếu đúng cơ chế/phạm trù với trọng tâm đề.\n• Vì sao sai? «Large widgets» — Cơ chế Flutter/Dart liên quan «Large widgets». Đề cần: Cơ chế Flutter/Dart liên quan «Fine-grained state updates»."}},"source":"SP26-FE"},{"id":65,"task":"fe","taskLabel":"SP26-FE","num":17,"question":"Which action best demonstrates Flutter's reactive UI model?","options":{"A":"Manually updating UI elements","B":"Rebuilding UI in response to state changes","C":"Editing layout XML","D":"Calling native APIs"},"answer":"B","alternatives":[],"explanation":{"questionVi":"Cái nào action best demonstrates Flutter's reactive UI model?","optionsVi":{"A":"Manually updating UI elements","B":"Rebuilding UI trong response để state thay đổi","C":"Editing bố cục XML","D":"Calling native APIs"},"answerDisplay":"B. Rebuilding UI trong response để state thay đổi","concept":"• Rebuilding UI trong response để state thay đổi. Bản dịch/diễn đạt phương án — đối chiếu với định nghĩa chuẩn của đề.","whyCorrect":"• UI reactive: state đổi → rebuild UI.\n• Rebuilding UI trong response để state thay đổi\n• Bản dịch/diễn đạt phương án — đối chiếu với định nghĩa chuẩn của đề.","intent":"• Rebuilding UI trong response để state thay đổi\n• Chọn phương án khớp cơ chế Flutter, không chọn stack web/Android nhầm.","memoryTip":"• UI reactive: state đổi → rebuild UI.","whatIs":{"A":"Cơ chế Flutter/Dart liên quan «Manually updating UI elements».","B":"Rebuilding UI trong response để state thay đổi","C":"Cơ chế Flutter/Dart liên quan «Editing bố cục XML».","D":"Cơ chế Flutter/Dart liên quan «Calling native APIs»."},"whyWrong":{"A":"• Là gì? Cơ chế Flutter/Dart liên quan «Manually updating UI elements».\n• Dùng để làm gì? Đối chiếu đúng cơ chế/phạm trù với trọng tâm đề.\n• Vì sao sai? «Manually updating UI elements» — Cơ chế Flutter/Dart liên quan «Manually updating UI elements». Đề cần: Rebuilding UI trong response để state thay đổi.","C":"• Là gì? Cơ chế Flutter/Dart liên quan «Editing bố cục XML».\n• Dùng để làm gì? Đối chiếu đúng cơ chế/phạm trù với trọng tâm đề.\n• Vì sao sai? Flutter không dựng UI chính bằng XML/HTML/CSS như Android View/web cổ điển.","D":"• Là gì? Cơ chế Flutter/Dart liên quan «Calling native APIs».\n• Dùng để làm gì? Đối chiếu đúng cơ chế/phạm trù với trọng tâm đề.\n• Vì sao sai? «Calling native APIs» — Cơ chế Flutter/Dart liên quan «Calling native APIs». Đề cần: Rebuilding UI trong response để state thay đổi."}},"source":"SP26-FE"},{"id":66,"task":"fe","taskLabel":"SP26-FE","num":18,"question":"Why are const widgets recommended?","options":{"A":"They improve readability","B":"They reduce rebuild cost","C":"They add state","D":"They handle navigation"},"answer":"B","alternatives":[],"explanation":{"questionVi":"Vì sao const widgets recommended?","optionsVi":{"A":"They Cải thiện readability","B":"They Giảm rebuild chi phí","C":"They add state","D":"They Xử lý navigation"},"answerDisplay":"B. They Giảm rebuild chi phí","concept":"• Hằng được xác định từ lúc biên dịch (compile-time).","whyCorrect":"• const widget tái sử dụng instance, giảm chi phí rebuild.\n• Hằng được xác định từ lúc biên dịch (compile-time).\n• Giá trị bất biến, tối ưu và an toàn.","intent":"• Phân biệt const, final, var và null safety.\n• Compile-time vs runtime assignment.","memoryTip":"• UI = cây widget; BuildContext định vị trên cây; build() chỉ mô tả UI.","whatIs":{"A":"They Cải thiện readability","B":"Hằng được xác định từ lúc biên dịch (compile-time).","C":"Cơ chế Flutter/Dart liên quan «They add state».","D":"Cơ chế Flutter/Dart liên quan «They Xử lý navigation»."},"whyWrong":{"A":"• Là gì? They Cải thiện readability\n• Dùng để làm gì? Bản dịch/diễn đạt phương án — đối chiếu với định nghĩa chuẩn của đề.\n• Vì sao sai? const giúp tái sử dụng widget, giảm rebuild — đúng khi hỏi tối ưu const.","C":"• Là gì? Cơ chế Flutter/Dart liên quan «They add state».\n• Dùng để làm gì? Đối chiếu đúng cơ chế/phạm trù với trọng tâm đề.\n• Vì sao sai? const giúp tái sử dụng widget, giảm rebuild — đúng khi hỏi tối ưu const.","D":"• Là gì? Cơ chế Flutter/Dart liên quan «They Xử lý navigation».\n• Dùng để làm gì? Đối chiếu đúng cơ chế/phạm trù với trọng tâm đề.\n• Vì sao sai? const giúp tái sử dụng widget, giảm rebuild — đúng khi hỏi tối ưu const."}},"source":"SP26-FE"},{"id":67,"task":"fe","taskLabel":"SP26-FE","num":19,"question":"Why should animations be disposed properly?","options":{"A":"Improve UI","B":"Prevent memory leaks","C":"Speed up builds","D":"Fix layout"},"answer":"B","alternatives":[],"explanation":{"questionVi":"Vì sao animations disposed properly?","optionsVi":{"A":"Cải thiện UI","B":"Ngăn memory leaks","C":"Speed up builds","D":"Fix bố cục"},"answerDisplay":"B. Ngăn memory leaks","concept":"• Phần mềm quản lý phần cứng, tiến trình, bộ nhớ, I/O.","whyCorrect":"• AnimationController/ticker cần dispose để tránh rò memory.\n• Phần mềm quản lý phần cứng, tiến trình, bộ nhớ, I/O.\n• Cấp tài nguyên và lập lịch cho chương trình.","intent":"• Phần mềm quản lý phần cứng, tiến trình, bộ nhớ, I/O.\n• Cấp tài nguyên và lập lịch cho chương trình.","memoryTip":"• Animation/Tween định nghĩa chuyển động; luôn dispose controller để tránh rò memory.","whatIs":{"A":"Cụm «Cải thiện UI» mang một nghĩa riêng cần đối chiếu với đề.","B":"Phần mềm quản lý phần cứng, tiến trình, bộ nhớ, I/O.","C":"Cụm «Speed up builds» mang một nghĩa riêng cần đối chiếu với đề.","D":"Cụm «Fix bố cục» mang một nghĩa riêng cần đối chiếu với đề."},"whyWrong":{"A":"• Là gì? Cụm «Cải thiện UI» mang một nghĩa riêng cần đối chiếu với đề.\n• Dùng để làm gì? So bản chất với đáp án đúng; loại nếu sai đối tượng hoặc sai lớp khái niệm.\n• Vì sao sai? «Improve UI» — Cụm «Cải thiện UI» mang một nghĩa riêng cần đối chiếu với đề. Đề cần: Phần mềm quản lý phần cứng, tiến trình, bộ nhớ, I/O.","C":"• Là gì? Cụm «Speed up builds» mang một nghĩa riêng cần đối chiếu với đề.\n• Dùng để làm gì? So bản chất với đáp án đúng; loại nếu sai đối tượng hoặc sai lớp khái niệm.\n• Vì sao sai? «Speed up builds» — Cụm «Speed up builds» mang một nghĩa riêng cần đối chiếu với đề. Đề cần: Phần mềm quản lý phần cứng, tiến trình, bộ nhớ, I/O.","D":"• Là gì? Cụm «Fix bố cục» mang một nghĩa riêng cần đối chiếu với đề.\n• Dùng để làm gì? So bản chất với đáp án đúng; loại nếu sai đối tượng hoặc sai lớp khái niệm.\n• Vì sao sai? «Fix layout» — Cụm «Fix bố cục» mang một nghĩa riêng cần đối chiếu với đề. Đề cần: Phần mềm quản lý phần cứng, tiến trình, bộ nhớ, I/O."}},"source":"SP26-FE"},{"id":68,"task":"fe","taskLabel":"SP26-FE","num":20,"question":"Which Flutter test focuses on UI components?","options":{"A":"Unit test","B":"Widget test","C":"Integration test","D":"Load test"},"answer":"B","alternatives":[],"explanation":{"questionVi":"Cái nào Flutter test focuses UI components?","optionsVi":{"A":"Unit test","B":"Widget test","C":"Integration test","D":"Load test"},"answerDisplay":"B. Widget test","concept":"• Cơ chế Flutter/Dart liên quan «Widget test».","whyCorrect":"• Widget test kiểm tra UI components Flutter.\n• Cơ chế Flutter/Dart liên quan «Widget test».","intent":"• Cơ chế Flutter/Dart liên quan «Widget test».\n• Chọn phương án khớp cơ chế Flutter, không chọn stack web/Android nhầm.","memoryTip":"• Widget test kiểm tra UI components Flutter.","whatIs":{"A":"Cơ chế Flutter/Dart liên quan «Unit test».","B":"Cơ chế Flutter/Dart liên quan «Widget test».","C":"Cơ chế Flutter/Dart liên quan «Integration test».","D":"Cơ chế Flutter/Dart liên quan «Load test»."},"whyWrong":{"A":"• Là gì? Cơ chế Flutter/Dart liên quan «Unit test».\n• Dùng để làm gì? Đối chiếu đúng cơ chế/phạm trù với trọng tâm đề.\n• Vì sao sai? «Unit test» — Cơ chế Flutter/Dart liên quan «Unit test». Đề cần: Cơ chế Flutter/Dart liên quan «Widget test».","C":"• Là gì? Cơ chế Flutter/Dart liên quan «Integration test».\n• Dùng để làm gì? Đối chiếu đúng cơ chế/phạm trù với trọng tâm đề.\n• Vì sao sai? «Integration test» — Cơ chế Flutter/Dart liên quan «Integration test». Đề cần: Cơ chế Flutter/Dart liên quan «Widget test».","D":"• Là gì? Cơ chế Flutter/Dart liên quan «Load test».\n• Dùng để làm gì? Đối chiếu đúng cơ chế/phạm trù với trọng tâm đề.\n• Vì sao sai? «Load test» — Cơ chế Flutter/Dart liên quan «Load test». Đề cần: Cơ chế Flutter/Dart liên quan «Widget test»."}},"source":"SP26-FE"},{"id":69,"task":"fe","taskLabel":"SP26-FE","num":21,"question":"Why should database operations be asynchronous?","options":{"A":"Simplify syntax","B":"Avoid blocking UI thread","C":"Reduce code","D":"Improve theme"},"answer":"B","alternatives":[],"explanation":{"questionVi":"Vì sao thao tác DB nên bất đồng bộ?","optionsVi":{"A":"Simplify syntax","B":"Tránh chặn luồng UI","C":"Giảm mã","D":"Cải thiện theme"},"answerDisplay":"B. Tránh chặn luồng UI","concept":"• Cách chia sẻ và phản ứng với trạng thái dùng chung giữa nhiều widget/màn.","whyCorrect":"• Cách chia sẻ và phản ứng với trạng thái dùng chung giữa nhiều widget/màn.\n• Tránh truyền prop sâu; cập nhật UI khi state đổi.","intent":"• Cách chia sẻ và phản ứng với trạng thái dùng chung giữa nhiều widget/màn.\n• Tránh truyền prop sâu; cập nhật UI khi state đổi.","whatIs":{"A":"Cơ chế Flutter/Dart liên quan «Simplify syntax».","B":"Cách chia sẻ và phản ứng với trạng thái dùng chung giữa nhiều widget/màn.","C":"Cơ chế Flutter/Dart liên quan «Giảm mã».","D":"Cơ chế Flutter/Dart liên quan «Cải thiện theme»."},"whyWrong":{"A":"• Là gì? Cơ chế Flutter/Dart liên quan «Simplify syntax».\n• Dùng để làm gì? Đối chiếu đúng cơ chế/phạm trù với trọng tâm đề.\n• Vì sao sai? «Simplify syntax» — Cơ chế Flutter/Dart liên quan «Simplify syntax». Đề cần: Cách chia sẻ và phản ứng với trạng thái dùng chung giữa nhiều widget/màn.","C":"• Là gì? Cơ chế Flutter/Dart liên quan «Giảm mã».\n• Dùng để làm gì? Đối chiếu đúng cơ chế/phạm trù với trọng tâm đề.\n• Vì sao sai? «Reduce code» — Cơ chế Flutter/Dart liên quan «Giảm mã». Đề cần: Cách chia sẻ và phản ứng với trạng thái dùng chung giữa nhiều widget/màn.","D":"• Là gì? Cơ chế Flutter/Dart liên quan «Cải thiện theme».\n• Dùng để làm gì? Đối chiếu đúng cơ chế/phạm trù với trọng tâm đề.\n• Vì sao sai? «Improve theme» — Cơ chế Flutter/Dart liên quan «Cải thiện theme». Đề cần: Cách chia sẻ và phản ứng với trạng thái dùng chung giữa nhiều widget/màn."}},"source":"SP26-FE"},{"id":70,"task":"fe","taskLabel":"SP26-FE","num":22,"question":"Why is Chapter 13 considered optional (Plus)?","options":{"A":"It replaces core concepts","B":"Apps can work without deep optimization","C":"It manages navigation","D":"It handles authentication"},"answer":"B","alternatives":[],"explanation":{"questionVi":"Vì sao Chapter 13 considered optional (Plus)?","optionsVi":{"A":"It replaces core concepts","B":"App có thể công việc Không có deep optimization","C":"It manages navigation","D":"It handles xác thực"},"answerDisplay":"B. App có thể công việc Không có deep optimization","concept":"• App có thể công việc Không có deep optimization. Bản dịch/diễn đạt phương án — đối chiếu với định nghĩa chuẩn của đề.","whyCorrect":"• Tối ưu sâu (plus) không bắt buộc để app chạy được.\n• App có thể công việc Không có deep optimization\n• Bản dịch/diễn đạt phương án — đối chiếu với định nghĩa chuẩn của đề.","intent":"• App có thể công việc Không có deep optimization\n• Bản dịch/diễn đạt phương án — đối chiếu với định nghĩa chuẩn của đề.","memoryTip":"• Tối ưu sâu (plus) không bắt buộc để app chạy được.","whatIs":{"A":"Cụm «It replaces core concepts» mang một nghĩa riêng cần đối chiếu với đề.","B":"App có thể công việc Không có deep optimization","C":"Cụm «It manages navigation» mang một nghĩa riêng cần đối chiếu với đề.","D":"Cụm «It handles xác thực» mang một nghĩa riêng cần đối chiếu với đề."},"whyWrong":{"A":"• Là gì? Cụm «It replaces core concepts» mang một nghĩa riêng cần đối chiếu với đề.\n• Dùng để làm gì? So bản chất với đáp án đúng; loại nếu sai đối tượng hoặc sai lớp khái niệm.\n• Vì sao sai? «It replaces core concepts» — Cụm «It replaces core concepts» mang một nghĩa riêng cần đối chiếu với đề. Đề cần: App có thể công việc Không có deep optimization.","C":"• Là gì? Cụm «It manages navigation» mang một nghĩa riêng cần đối chiếu với đề.\n• Dùng để làm gì? So bản chất với đáp án đúng; loại nếu sai đối tượng hoặc sai lớp khái niệm.\n• Vì sao sai? «It manages navigation» — Cụm «It manages navigation» mang một nghĩa riêng cần đối chiếu với đề. Đề cần: App có thể công việc Không có deep optimization.","D":"• Là gì? Cụm «It handles xác thực» mang một nghĩa riêng cần đối chiếu với đề.\n• Dùng để làm gì? So bản chất với đáp án đúng; loại nếu sai đối tượng hoặc sai lớp khái niệm.\n• Vì sao sai? «It handles authentication» — Cụm «It handles xác thực» mang một nghĩa riêng cần đối chiếu với đề. Đề cần: App có thể công việc Không có deep optimization."}},"source":"SP26-FE"},{"id":71,"task":"fe","taskLabel":"SP26-FE","num":23,"question":"Which widget applies a theme to an entire Flutter application?","options":{"A":"Scaffold","B":"Theme","C":"MaterialApp","D":"Container"},"answer":"C","alternatives":[],"explanation":{"questionVi":"Cái nào widget applies theme entire Flutter application?","optionsVi":{"A":"Scaffold","B":"Theme","C":"MaterialApp","D":"Container"},"answerDisplay":"C. MaterialApp","concept":"• Cơ chế Flutter/Dart liên quan «MaterialApp».","whyCorrect":"• MaterialApp (theme:) áp theme toàn app.\n• Cơ chế Flutter/Dart liên quan «MaterialApp».","intent":"• Cơ chế Flutter/Dart liên quan «MaterialApp».\n• Chọn phương án khớp cơ chế Flutter, không chọn stack web/Android nhầm.","memoryTip":"• MaterialApp (theme:) áp theme toàn app.","whatIs":{"A":"Cơ chế Flutter/Dart liên quan «Scaffold».","B":"Cơ chế Flutter/Dart liên quan «Theme».","C":"Cơ chế Flutter/Dart liên quan «MaterialApp».","D":"Widget trang trí/layout tổng quát (màu, margin, padding, constraints…)."},"whyWrong":{"A":"• Là gì? Cơ chế Flutter/Dart liên quan «Scaffold».\n• Dùng để làm gì? Đối chiếu đúng cơ chế/phạm trù với trọng tâm đề.\n• Vì sao sai? «Scaffold» — Cơ chế Flutter/Dart liên quan «Scaffold». Đề cần: Cơ chế Flutter/Dart liên quan «MaterialApp».","B":"• Là gì? Cơ chế Flutter/Dart liên quan «Theme».\n• Dùng để làm gì? Đối chiếu đúng cơ chế/phạm trù với trọng tâm đề.\n• Vì sao sai? «Theme» — Cơ chế Flutter/Dart liên quan «Theme». Đề cần: Cơ chế Flutter/Dart liên quan «MaterialApp».","D":"• Là gì? Widget trang trí/layout tổng quát (màu, margin, padding, constraints…).\n• Dùng để làm gì? Tiện ích đa năng; không chuyên biệt cho khoảng trống cố định hay flex fill.\n• Vì sao sai? «Container» — Widget trang trí/layout tổng quát (màu, margin, padding, constraints…). Đề cần: Cơ chế Flutter/Dart liên quan «MaterialApp»."}},"source":"SP26-FE"},{"id":72,"task":"fe","taskLabel":"SP26-FE","num":24,"question":"What is the purpose of SliverAppBar?","options":{"A":"Static app bar","B":"Scrollable flexible app bar","C":"Bottom navigation","D":"Drawer control"},"answer":"B","alternatives":[],"explanation":{"questionVi":"Cái gì là mục đích củ SliverAppBar?","optionsVi":{"A":"Static app bar","B":"Scrollable flexible app bar","C":"Bottom navigation","D":"Drawer control"},"answerDisplay":"B. Scrollable flexible app bar","concept":"• Phần mềm quản lý phần cứng, tiến trình, bộ nhớ, I/O.","whyCorrect":"• SliverAppBar: app bar co giãn theo scroll.\n• Phần mềm quản lý phần cứng, tiến trình, bộ nhớ, I/O.\n• Cấp tài nguyên và lập lịch cho chương trình.","intent":"• Phần mềm quản lý phần cứng, tiến trình, bộ nhớ, I/O.\n• Cấp tài nguyên và lập lịch cho chương trình.","memoryTip":"• SliverAppBar: app bar co giãn theo scroll.","whatIs":{"A":"Cụm «Static app bar» mang một nghĩa riêng cần đối chiếu với đề.","B":"Phần mềm quản lý phần cứng, tiến trình, bộ nhớ, I/O.","C":"Cụm «Bottom navigation» mang một nghĩa riêng cần đối chiếu với đề.","D":"Cụm «Drawer control» mang một nghĩa riêng cần đối chiếu với đề."},"whyWrong":{"A":"• Là gì? Cụm «Static app bar» mang một nghĩa riêng cần đối chiếu với đề.\n• Dùng để làm gì? So bản chất với đáp án đúng; loại nếu sai đối tượng hoặc sai lớp khái niệm.\n• Vì sao sai? AppBar co giãn trong scroll view; chỉ đúng khi hỏi đúng widget đó.","C":"• Là gì? Cụm «Bottom navigation» mang một nghĩa riêng cần đối chiếu với đề.\n• Dùng để làm gì? So bản chất với đáp án đúng; loại nếu sai đối tượng hoặc sai lớp khái niệm.\n• Vì sao sai? AppBar co giãn trong scroll view; chỉ đúng khi hỏi đúng widget đó.","D":"• Là gì? Cụm «Drawer control» mang một nghĩa riêng cần đối chiếu với đề.\n• Dùng để làm gì? So bản chất với đáp án đúng; loại nếu sai đối tượng hoặc sai lớp khái niệm.\n• Vì sao sai? AppBar co giãn trong scroll view; chỉ đúng khi hỏi đúng widget đó."}},"source":"SP26-FE"},{"id":73,"task":"fe","taskLabel":"SP26-FE","num":25,"question":"Which widget is best used to add fixed empty space?","options":{"A":"Padding","B":"Expanded","C":"SizedBox","D":"Container"},"answer":"C","alternatives":[],"explanation":{"questionVi":"Widget nào tốt nhất để thêm khoảng trống cố định?","optionsVi":{"A":"Padding","B":"Expanded","C":"SizedBox","D":"Container"},"answerDisplay":"C. SizedBox","concept":"• Tạo hộp kích thước cố định hoặc khoảng trống size cho trước.","whyCorrect":"• SizedBox tạo khoảng trống kích thước cố định.\n• Tạo hộp kích thước cố định hoặc khoảng trống size cho trước.\n• Spacer cố định (width/height); khác Expanded (chiếm phần còn lại).","intent":"• Phân biệt khoảng trống cố định (SizedBox) và flex fill (Expanded).\n• Padding/Container không thay thế SizedBox cho spacer size rõ ràng.","memoryTip":"• SizedBox tạo khoảng trống kích thước cố định.","whatIs":{"A":"Thêm khoảng lề bên trong quanh child (inset).","B":"Buộc widget con chiếm toàn bộ không gian còn lại theo main axis của Flex (Row/Column/Flex).","C":"Tạo hộp kích thước cố định hoặc khoảng trống size cho trước.","D":"Widget trang trí/layout tổng quát (màu, margin, padding, constraints…)."},"whyWrong":{"A":"• Là gì? Thêm khoảng lề bên trong quanh child (inset).\n• Dùng để làm gì? Đẩy nội dung cách mép; không tự tạo «ô trống» kích thước độc lập như SizedBox.\n• Vì sao sai? Padding thêm lề quanh child; không chuyên tạo «ô trống» width/height cố định như SizedBox.","B":"• Là gì? Buộc widget con chiếm toàn bộ không gian còn lại theo main axis của Flex (Row/Column/Flex).\n• Dùng để làm gì? Trong Row giãn ngang, trong Column giãn dọc; nhiều Expanded chia phần trống theo flex. Tương đương Flexible(fit: FlexFit.tight).\n• Vì sao sai? Expanded chiếm phần còn lại trên trục chính Flex; không tạo khoảng trống cố định.","D":"• Là gì? Widget trang trí/layout tổng quát (màu, margin, padding, constraints…).\n• Dùng để làm gì? Tiện ích đa năng; không chuyên biệt cho khoảng trống cố định hay flex fill.\n• Vì sao sai? Container trang trí/layout tổng quát, không chuyên biệt cho khái niệm câu hỏi."}},"source":"SP26-FE"},{"id":74,"task":"fe","taskLabel":"SP26-FE","num":26,"question":"Which package supports BLoC architecture?","options":{"A":"provider","B":"flutter_bloc","C":"sqflite","D":"http"},"answer":"B","alternatives":[],"explanation":{"questionVi":"Cái nào package supports BLoC architecture?","optionsVi":{"A":"provider","B":"flutter_bloc","C":"sqflite","D":"http"},"answerDisplay":"B. flutter_bloc","concept":"• Cách chia sẻ và phản ứng với trạng thái dùng chung giữa nhiều widget/màn.","whyCorrect":"• Package flutter_bloc hỗ trợ BLoC/Cubit.\n• Cách chia sẻ và phản ứng với trạng thái dùng chung giữa nhiều widget/màn.\n• Tránh truyền prop sâu; cập nhật UI khi state đổi.","intent":"• Cách chia sẻ và phản ứng với trạng thái dùng chung giữa nhiều widget/màn.\n• Tránh truyền prop sâu; cập nhật UI khi state đổi.","memoryTip":"• Đổi state → rebuild; BLoC/Cubit/Provider tách logic khỏi UI; state nên immutable.","whatIs":{"A":"Cách chia sẻ và phản ứng với trạng thái dùng chung giữa nhiều widget/màn.","B":"Cách chia sẻ và phản ứng với trạng thái dùng chung giữa nhiều widget/màn.","C":"Cơ chế Flutter/Dart liên quan «sqflite».","D":"Cơ chế/thuật ngữ CNTT «http»."},"whyWrong":{"A":"• Là gì? Cách chia sẻ và phản ứng với trạng thái dùng chung giữa nhiều widget/màn.\n• Dùng để làm gì? Tránh truyền prop sâu; cập nhật UI khi state đổi.\n• Vì sao sai? Provider là DI/state; không phải thư viện lưu trữ hay HTTP.","C":"• Là gì? Cơ chế Flutter/Dart liên quan «sqflite».\n• Dùng để làm gì? Đối chiếu đúng cơ chế/phạm trù với trọng tâm đề.\n• Vì sao sai? sqflite = SQLite; không phải key-value đơn giản hay remote API.","D":"• Là gì? Cơ chế/thuật ngữ CNTT «http».\n• Dùng để làm gì? Đối chiếu đúng định nghĩa/đặc trưng kỹ thuật mà đề hỏi.\n• Vì sao sai? Gói http gọi API; không quản lý state UI hay storage local."}},"source":"SP26-FE"},{"id":75,"task":"fe","taskLabel":"SP26-FE","num":27,"question":"Which Flutter widget reacts to authentication state changes?","options":{"A":"FutureBuilder","B":"StreamBuilder","C":"ListView","D":"Form"},"answer":"B","alternatives":[],"explanation":{"questionVi":"Cái nào Flutter widget reacts authentication state changes?","optionsVi":{"A":"FutureBuilder","B":"StreamBuilder","C":"ListView","D":"Form"},"answerDisplay":"B. StreamBuilder","concept":"• Cơ chế Flutter/Dart liên quan «StreamBuilder».","whyCorrect":"• Auth state dạng stream → StreamBuilder (FutureBuilder cho one-shot).\n• Cơ chế Flutter/Dart liên quan «StreamBuilder».","intent":"• Cơ chế Flutter/Dart liên quan «StreamBuilder».\n• Chọn phương án khớp cơ chế Flutter, không chọn stack web/Android nhầm.","memoryTip":"• Auth: token/session tập trung; Guard chặn route; StreamBuilder hay dùng với auth stream.","whatIs":{"A":"Cơ chế Flutter/Dart liên quan «FutureBuilder».","B":"Cơ chế Flutter/Dart liên quan «StreamBuilder».","C":"Cơ chế Flutter/Dart liên quan «ListView».","D":"Cơ chế Flutter/Dart liên quan «Form»."},"whyWrong":{"A":"• Là gì? Cơ chế Flutter/Dart liên quan «FutureBuilder».\n• Dùng để làm gì? Đối chiếu đúng cơ chế/phạm trù với trọng tâm đề.\n• Vì sao sai? «FutureBuilder» — Cơ chế Flutter/Dart liên quan «FutureBuilder». Đề cần: Cơ chế Flutter/Dart liên quan «StreamBuilder».","C":"• Là gì? Cơ chế Flutter/Dart liên quan «ListView».\n• Dùng để làm gì? Đối chiếu đúng cơ chế/phạm trù với trọng tâm đề.\n• Vì sao sai? «ListView» — Cơ chế Flutter/Dart liên quan «ListView». Đề cần: Cơ chế Flutter/Dart liên quan «StreamBuilder».","D":"• Là gì? Cơ chế Flutter/Dart liên quan «Form».\n• Dùng để làm gì? Đối chiếu đúng cơ chế/phạm trù với trọng tâm đề.\n• Vì sao sai? «Form» — Cơ chế Flutter/Dart liên quan «Form». Đề cần: Cơ chế Flutter/Dart liên quan «StreamBuilder»."}},"source":"SP26-FE"},{"id":76,"task":"fe","taskLabel":"SP26-FE","num":28,"question":"What is technical debt?","options":{"A":"UI lag","B":"Future cost of poor design decisions","C":"Memory usage","D":"API limit"},"answer":"B","alternatives":[],"explanation":{"questionVi":"Nợ kỹ thuật (technical debt) là gì?","optionsVi":{"A":"UI lag","B":"Chi phí tương lai do quyết định thiết kế kém","C":"Memory usage","D":"API limit"},"answerDisplay":"B. Chi phí tương lai do quyết định thiết kế kém","concept":"• Đối tượng đại diện một kết quả (hoặc lỗi) sẽ có sau thao tác bất đồng bộ.","whyCorrect":"• Đối tượng đại diện một kết quả (hoặc lỗi) sẽ có sau thao tác bất đồng bộ.\n• async/await, gọi API, đọc file một lần.","intent":"• Đối tượng đại diện một kết quả (hoặc lỗi) sẽ có sau thao tác bất đồng bộ.\n• async/await, gọi API, đọc file một lần.","whatIs":{"A":"Cụm «UI lag» mang một nghĩa riêng cần đối chiếu với đề.","B":"Đối tượng đại diện một kết quả (hoặc lỗi) sẽ có sau thao tác bất đồng bộ.","C":"Cụm «Memory usage» mang một nghĩa riêng cần đối chiếu với đề.","D":"Cụm «API limit» mang một nghĩa riêng cần đối chiếu với đề."},"whyWrong":{"A":"• Là gì? Cụm «UI lag» mang một nghĩa riêng cần đối chiếu với đề.\n• Dùng để làm gì? So bản chất với đáp án đúng; loại nếu sai đối tượng hoặc sai lớp khái niệm.\n• Vì sao sai? Nợ kỹ thuật = chi phí tương lai do thiết kế kém.","C":"• Là gì? Cụm «Memory usage» mang một nghĩa riêng cần đối chiếu với đề.\n• Dùng để làm gì? So bản chất với đáp án đúng; loại nếu sai đối tượng hoặc sai lớp khái niệm.\n• Vì sao sai? Nợ kỹ thuật = chi phí tương lai do thiết kế kém.","D":"• Là gì? Cụm «API limit» mang một nghĩa riêng cần đối chiếu với đề.\n• Dùng để làm gì? So bản chất với đáp án đúng; loại nếu sai đối tượng hoặc sai lớp khái niệm.\n• Vì sao sai? «API limit» — Cụm «API limit» mang một nghĩa riêng cần đối chiếu với đề. Đề cần: Đối tượng đại diện một kết quả (hoặc lỗi) sẽ có sau thao tác bất đồng bộ."}},"source":"SP26-FE"},{"id":77,"task":"fe","taskLabel":"SP26-FE","num":29,"question":"What is implicit animation?","options":{"A":"Manual animation control","B":"Animation without controller","C":"API animation","D":"Navigation animation"},"answer":"B","alternatives":[],"explanation":{"questionVi":"Cái gì là implicit animation?","optionsVi":{"A":"Manual animation control","B":"Animation Không có controller","C":"API animation","D":"Navigation animation"},"answerDisplay":"B. Animation Không có controller","concept":"• Animation Không có controller. Bản dịch/diễn đạt phương án — đối chiếu với định nghĩa chuẩn của đề.","whyCorrect":"• Implicit animation (AnimatedOpacity…) không cần AnimationController.\n• Animation Không có controller\n• Bản dịch/diễn đạt phương án — đối chiếu với định nghĩa chuẩn của đề.","intent":"• Animation Không có controller\n• Bản dịch/diễn đạt phương án — đối chiếu với định nghĩa chuẩn của đề.","memoryTip":"• Animation/Tween định nghĩa chuyển động; luôn dispose controller để tránh rò memory.","whatIs":{"A":"Cụm «Manual animation control» mang một nghĩa riêng cần đối chiếu với đề.","B":"Animation Không có controller","C":"Cụm «API animation» mang một nghĩa riêng cần đối chiếu với đề.","D":"Cụm «Navigation animation» mang một nghĩa riêng cần đối chiếu với đề."},"whyWrong":{"A":"• Là gì? Cụm «Manual animation control» mang một nghĩa riêng cần đối chiếu với đề.\n• Dùng để làm gì? So bản chất với đáp án đúng; loại nếu sai đối tượng hoặc sai lớp khái niệm.\n• Vì sao sai? Liên quan chuyển động UI, không giải quyết khái niệm trong câu hỏi.","C":"• Là gì? Cụm «API animation» mang một nghĩa riêng cần đối chiếu với đề.\n• Dùng để làm gì? So bản chất với đáp án đúng; loại nếu sai đối tượng hoặc sai lớp khái niệm.\n• Vì sao sai? Liên quan chuyển động UI, không giải quyết khái niệm trong câu hỏi.","D":"• Là gì? Cụm «Navigation animation» mang một nghĩa riêng cần đối chiếu với đề.\n• Dùng để làm gì? So bản chất với đáp án đúng; loại nếu sai đối tượng hoặc sai lớp khái niệm.\n• Vì sao sai? Liên quan chuyển động UI, không giải quyết khái niệm trong câu hỏi."}},"source":"SP26-FE"},{"id":78,"task":"fe","taskLabel":"SP26-FE","num":30,"question":"Which Dart data structure is best suited for storing an ordered collection of items?","options":{"A":"Set","B":"Map","C":"List","D":"Queue"},"answer":"C","alternatives":[],"explanation":{"questionVi":"Cái nào Dart dữ liệu structure best suited storing ordered collection items?","optionsVi":{"A":"Set","B":"Map","C":"List","D":"Queue"},"answerDisplay":"C. List","concept":"• Ngôn ngữ lập trình chính của Flutter. Viết UI và logic app Flutter.","whyCorrect":"• List: tập hợp có thứ tự.\n• Ngôn ngữ lập trình chính của Flutter.\n• Viết UI và logic app Flutter.","intent":"• Phân biệt List / Set / Map trong Dart.\n• Thứ tự, trùng lặp, hay key–value.","memoryTip":"• List: tập hợp có thứ tự.","whatIs":{"A":"Tập hợp giá trị không trùng.","B":"Cấu trúc ánh xạ khóa → giá trị.","C":"Ngôn ngữ lập trình chính của Flutter.","D":"Cơ chế Flutter/Dart liên quan «Queue»."},"whyWrong":{"A":"• Là gì? Tập hợp giá trị không trùng.\n• Dùng để làm gì? Loại trùng, kiểm tra membership.\n• Vì sao sai? Set không cho trùng và không dùng index như List.","B":"• Là gì? Cấu trúc ánh xạ khóa → giá trị.\n• Dùng để làm gì? Tra cứu nhanh theo key.\n• Vì sao sai? «Map» — Cấu trúc ánh xạ khóa → giá trị. Đề cần: Ngôn ngữ lập trình chính của Flutter.","D":"• Là gì? Cơ chế Flutter/Dart liên quan «Queue».\n• Dùng để làm gì? Đối chiếu đúng cơ chế/phạm trù với trọng tâm đề.\n• Vì sao sai? «Queue» — Cơ chế Flutter/Dart liên quan «Queue». Đề cần: Ngôn ngữ lập trình chính của Flutter."}},"source":"SP26-FE"},{"id":79,"task":"fe","taskLabel":"SP26-FE","num":31,"question":"Which Flutter concept supports reactive UI updates?","options":{"A":"Manual refresh","B":"Widget rebuilding","C":"Hot restart","D":"Native callbacks"},"answer":"B","alternatives":[],"explanation":{"questionVi":"Cái nào Flutter concept supports reactive UI updates?","optionsVi":{"A":"Manual refresh","B":"Widget rebuilding","C":"Hot restart","D":"Native callbacks"},"answerDisplay":"B. Widget rebuilding","concept":"• Cơ chế Flutter/Dart liên quan «Widget rebuilding».","whyCorrect":"• Reactive UI dựa trên rebuild widget khi state đổi.\n• Cơ chế Flutter/Dart liên quan «Widget rebuilding».","intent":"• Cơ chế Flutter/Dart liên quan «Widget rebuilding».\n• Chọn phương án khớp cơ chế Flutter, không chọn stack web/Android nhầm.","memoryTip":"• Reactive UI dựa trên rebuild widget khi state đổi.","whatIs":{"A":"Cơ chế Flutter/Dart liên quan «Manual refresh».","B":"Cơ chế Flutter/Dart liên quan «Widget rebuilding».","C":"Chạy lại app từ đầu, reset state.","D":"Cơ chế Flutter/Dart liên quan «Native callbacks»."},"whyWrong":{"A":"• Là gì? Cơ chế Flutter/Dart liên quan «Manual refresh».\n• Dùng để làm gì? Đối chiếu đúng cơ chế/phạm trù với trọng tâm đề.\n• Vì sao sai? «Manual refresh» — Cơ chế Flutter/Dart liên quan «Manual refresh». Đề cần: Cơ chế Flutter/Dart liên quan «Widget rebuilding».","C":"• Là gì? Chạy lại app từ đầu, reset state.\n• Dùng để làm gì? Khi cần khởi tạo lại toàn bộ sau đổi lớn.\n• Vì sao sai? «Hot restart» — Chạy lại app từ đầu, reset state. Đề cần: Cơ chế Flutter/Dart liên quan «Widget rebuilding».","D":"• Là gì? Cơ chế Flutter/Dart liên quan «Native callbacks».\n• Dùng để làm gì? Đối chiếu đúng cơ chế/phạm trù với trọng tâm đề.\n• Vì sao sai? «Native callbacks» — Cơ chế Flutter/Dart liên quan «Native callbacks». Đề cần: Cơ chế Flutter/Dart liên quan «Widget rebuilding»."}},"source":"SP26-FE"},{"id":80,"task":"fe","taskLabel":"SP26-FE","num":32,"question":"Which type of test checks individual functions or classes?","options":{"A":"Widget test","B":"Integration test","C":"Unit test","D":"System test"},"answer":"C","alternatives":[],"explanation":{"questionVi":"Loại nào củ test checks individual functions hoặc classes?","optionsVi":{"A":"Widget test","B":"Integration test","C":"Unit test","D":"System test"},"answerDisplay":"C. Unit test","concept":"• Cụm «Unit test» mang một nghĩa riêng cần đối chiếu với đề.","whyCorrect":"• Unit test kiểm tra hàm/class đơn lẻ.\n• Cụm «Unit test» mang một nghĩa riêng cần đối chiếu với đề.\n• So bản chất với đáp án đúng; loại nếu sai đối tượng hoặc sai lớp khái niệm.","intent":"• Cụm «Unit test» mang một nghĩa riêng cần đối chiếu với đề.\n• So bản chất với đáp án đúng; loại nếu sai đối tượng hoặc sai lớp khái niệm.","memoryTip":"• Unit test kiểm tra hàm/class đơn lẻ.","whatIs":{"A":"Cơ chế Flutter/Dart liên quan «Widget test».","B":"Cụm «Integration test» mang một nghĩa riêng cần đối chiếu với đề.","C":"Cụm «Unit test» mang một nghĩa riêng cần đối chiếu với đề.","D":"Cụm «System test» mang một nghĩa riêng cần đối chiếu với đề."},"whyWrong":{"A":"• Là gì? Cơ chế Flutter/Dart liên quan «Widget test».\n• Dùng để làm gì? Đối chiếu đúng cơ chế/phạm trù với trọng tâm đề.\n• Vì sao sai? Widget test: UI component; không phải pure logic hay full app E2E.","B":"• Là gì? Cụm «Integration test» mang một nghĩa riêng cần đối chiếu với đề.\n• Dùng để làm gì? So bản chất với đáp án đúng; loại nếu sai đối tượng hoặc sai lớp khái niệm.\n• Vì sao sai? Integration: nhiều thành phần/E2E; không phải unit đơn lẻ.","D":"• Là gì? Cụm «System test» mang một nghĩa riêng cần đối chiếu với đề.\n• Dùng để làm gì? So bản chất với đáp án đúng; loại nếu sai đối tượng hoặc sai lớp khái niệm.\n• Vì sao sai? «System test» — Cụm «System test» mang một nghĩa riêng cần đối chiếu với đề. Đề cần: Cụm «Unit test» mang một nghĩa riêng cần đối chiếu với đề."}},"source":"SP26-FE"},{"id":81,"task":"fe","taskLabel":"SP26-FE","num":33,"question":"What is the role of events in BLoC?","options":{"A":"Store UI","B":"Trigger state changes","C":"Render widgets","D":"Handle layout"},"answer":"B","alternatives":[],"explanation":{"questionVi":"Vai trò của events in BLoC là gì?","optionsVi":{"A":"Lưu UI","B":"Trigger state thay đổi","C":"Render widgets","D":"Xử lý bố cục"},"answerDisplay":"B. Trigger state thay đổi","concept":"• Cách chia sẻ và phản ứng với trạng thái dùng chung giữa nhiều widget/màn.","whyCorrect":"• Events kích hoạt xử lý → emit state mới.\n• Cách chia sẻ và phản ứng với trạng thái dùng chung giữa nhiều widget/màn.\n• Tránh truyền prop sâu; cập nhật UI khi state đổi.","intent":"• Cách chia sẻ và phản ứng với trạng thái dùng chung giữa nhiều widget/màn.\n• Tránh truyền prop sâu; cập nhật UI khi state đổi.","memoryTip":"• Đổi state → rebuild; BLoC/Cubit/Provider tách logic khỏi UI; state nên immutable.","whatIs":{"A":"Cơ chế Flutter/Dart liên quan «Lưu UI».","B":"Cách chia sẻ và phản ứng với trạng thái dùng chung giữa nhiều widget/màn.","C":"Cơ chế Flutter/Dart liên quan «Render widgets».","D":"Cơ chế Flutter/Dart liên quan «Xử lý bố cục»."},"whyWrong":{"A":"• Là gì? Cơ chế Flutter/Dart liên quan «Lưu UI».\n• Dùng để làm gì? Đối chiếu đúng cơ chế/phạm trù với trọng tâm đề.\n• Vì sao sai? «Store UI» — Cơ chế Flutter/Dart liên quan «Lưu UI». Đề cần: Cách chia sẻ và phản ứng với trạng thái dùng chung giữa nhiều widget/màn.","C":"• Là gì? Cơ chế Flutter/Dart liên quan «Render widgets».\n• Dùng để làm gì? Đối chiếu đúng cơ chế/phạm trù với trọng tâm đề.\n• Vì sao sai? «Render widgets» — Cơ chế Flutter/Dart liên quan «Render widgets». Đề cần: Cách chia sẻ và phản ứng với trạng thái dùng chung giữa nhiều widget/màn.","D":"• Là gì? Cơ chế Flutter/Dart liên quan «Xử lý bố cục».\n• Dùng để làm gì? Đối chiếu đúng cơ chế/phạm trù với trọng tâm đề.\n• Vì sao sai? «Handle layout» — Cơ chế Flutter/Dart liên quan «Xử lý bố cục». Đề cần: Cách chia sẻ và phản ứng với trạng thái dùng chung giữa nhiều widget/màn."}},"source":"SP26-FE"},{"id":82,"task":"fe","taskLabel":"SP26-FE","num":34,"question":"What is the main purpose of hot reload in Flutter?","options":{"A":"Improve runtime performance","B":"Instantly reflect code changes in UI","C":"Publish apps faster","D":"Reduce memory usage"},"answer":"B","alternatives":[],"explanation":{"questionVi":"Cái gì là main purpose hot reload trong Flutter?","optionsVi":{"A":"Cải thiện runtime hiệu năng","B":"Instantly reflect mã thay đổi trong UI","C":"Publish app nhanh hơn","D":"Giảm memory usage"},"answerDisplay":"B. Instantly reflect mã thay đổi trong UI","concept":"• Nạp lại code UI gần như giữ state đang chạy.","whyCorrect":"• Hot reload áp code change lên UI gần như ngay, giữ state.\n• Nạp lại code UI gần như giữ state đang chạy.\n• Xem thay đổi nhanh khi dev.","intent":"• Nạp lại code UI gần như giữ state đang chạy.\n• Chọn phương án khớp cơ chế Flutter, không chọn stack web/Android nhầm.","memoryTip":"• Hot reload áp code change lên UI gần như ngay, giữ state.","whatIs":{"A":"Mức mượt và tiết kiệm tài nguyên khi render/chạy app.","B":"Nạp lại code UI gần như giữ state đang chạy.","C":"Cơ chế Flutter/Dart liên quan «Publish app nhanh hơn».","D":"Cơ chế Flutter/Dart liên quan «Giảm memory usage»."},"whyWrong":{"A":"• Là gì? Mức mượt và tiết kiệm tài nguyên khi render/chạy app.\n• Dùng để làm gì? Skia/AOT/rebuild hẹp giúp UI mượt.\n• Vì sao sai? Hot reload nạp code UI nhanh khi dev; không phải công cụ phân tích sâu.","C":"• Là gì? Cơ chế Flutter/Dart liên quan «Publish app nhanh hơn».\n• Dùng để làm gì? Đối chiếu đúng cơ chế/phạm trù với trọng tâm đề.\n• Vì sao sai? Hot reload nạp code UI nhanh khi dev; không phải công cụ phân tích sâu.","D":"• Là gì? Cơ chế Flutter/Dart liên quan «Giảm memory usage».\n• Dùng để làm gì? Đối chiếu đúng cơ chế/phạm trù với trọng tâm đề.\n• Vì sao sai? Hot reload nạp code UI nhanh khi dev; không phải công cụ phân tích sâu."}},"source":"SP26-FE"},{"id":83,"task":"fe","taskLabel":"SP26-FE","num":35,"question":"Why are forms important in mobile applications?","options":{"A":"UI decoration","B":"User data collection","C":"State management","D":"Navigation"},"answer":"B","alternatives":[],"explanation":{"questionVi":"Vì sao forms important mobile applications?","optionsVi":{"A":"UI decoration","B":"Người dùng dữ liệu collection","C":"Quản lý state","D":"Điều hướng màn hình"},"answerDisplay":"B. Người dùng dữ liệu collection","concept":"• Người dùng dữ liệu collection. Bản dịch/diễn đạt phương án — đối chiếu với định nghĩa chuẩn của đề.","whyCorrect":"• Form dùng thu thập dữ liệu người dùng.\n• Người dùng dữ liệu collection\n• Bản dịch/diễn đạt phương án — đối chiếu với định nghĩa chuẩn của đề.","intent":"• Người dùng dữ liệu collection\n• Bản dịch/diễn đạt phương án — đối chiếu với định nghĩa chuẩn của đề.","memoryTip":"• Form dùng thu thập dữ liệu người dùng.","whatIs":{"A":"Cụm «UI decoration» mang một nghĩa riêng cần đối chiếu với đề.","B":"Người dùng dữ liệu collection","C":"Cách chia sẻ và phản ứng với trạng thái dùng chung giữa nhiều widget/màn.","D":"Cụm «Điều hướng màn hình» mang một nghĩa riêng cần đối chiếu với đề."},"whyWrong":{"A":"• Là gì? Cụm «UI decoration» mang một nghĩa riêng cần đối chiếu với đề.\n• Dùng để làm gì? So bản chất với đáp án đúng; loại nếu sai đối tượng hoặc sai lớp khái niệm.\n• Vì sao sai? «UI decoration» — Cụm «UI decoration» mang một nghĩa riêng cần đối chiếu với đề. Đề cần: Người dùng dữ liệu collection.","C":"• Là gì? Cách chia sẻ và phản ứng với trạng thái dùng chung giữa nhiều widget/màn.\n• Dùng để làm gì? Tránh truyền prop sâu; cập nhật UI khi state đổi.\n• Vì sao sai? «State management» — Cách chia sẻ và phản ứng với trạng thái dùng chung giữa nhiều widget/màn. Đề cần: Người dùng dữ liệu collection.","D":"• Là gì? Cụm «Điều hướng màn hình» mang một nghĩa riêng cần đối chiếu với đề.\n• Dùng để làm gì? So bản chất với đáp án đúng; loại nếu sai đối tượng hoặc sai lớp khái niệm.\n• Vì sao sai? «Navigation» — Cụm «Điều hướng màn hình» mang một nghĩa riêng cần đối chiếu với đề. Đề cần: Người dùng dữ liệu collection."}},"source":"SP26-FE"},{"id":84,"task":"fe","taskLabel":"SP26-FE","num":36,"question":"Which method retrieves data from SharedPreferences?","options":{"A":"get()","B":"read()","C":"fetch()","D":"load()"},"answer":"A","alternatives":[],"explanation":{"questionVi":"Cái nào method retrieves dữ liệu từ SharedPreferences?","optionsVi":{"A":"get()","B":"read()","C":"fetch()","D":"load()"},"answerDisplay":"A. get()","concept":"• Cụm «get()» mang một nghĩa riêng cần đối chiếu với đề.","whyCorrect":"• SharedPreferences dùng getString/getInt… (get).\n• Cụm «get()» mang một nghĩa riêng cần đối chiếu với đề.\n• So bản chất với đáp án đúng; loại nếu sai đối tượng hoặc sai lớp khái niệm.","intent":"• Cụm «get()» mang một nghĩa riêng cần đối chiếu với đề.\n• So bản chất với đáp án đúng; loại nếu sai đối tượng hoặc sai lớp khái niệm.","memoryTip":"• KV nhỏ → shared_preferences · NoSQL local → Hive · SQL → sqflite.","whatIs":{"A":"Cụm «get()» mang một nghĩa riêng cần đối chiếu với đề.","B":"Cụm «read()» mang một nghĩa riêng cần đối chiếu với đề.","C":"Cụm «fetch()» mang một nghĩa riêng cần đối chiếu với đề.","D":"Cụm «load()» mang một nghĩa riêng cần đối chiếu với đề."},"whyWrong":{"B":"• Là gì? Cụm «read()» mang một nghĩa riêng cần đối chiếu với đề.\n• Dùng để làm gì? So bản chất với đáp án đúng; loại nếu sai đối tượng hoặc sai lớp khái niệm.\n• Vì sao sai? shared_preferences chỉ key-value đơn giản (bool/int/string), không phù hợp mọi nhu cầu.","C":"• Là gì? Cụm «fetch()» mang một nghĩa riêng cần đối chiếu với đề.\n• Dùng để làm gì? So bản chất với đáp án đúng; loại nếu sai đối tượng hoặc sai lớp khái niệm.\n• Vì sao sai? shared_preferences chỉ key-value đơn giản (bool/int/string), không phù hợp mọi nhu cầu.","D":"• Là gì? Cụm «load()» mang một nghĩa riêng cần đối chiếu với đề.\n• Dùng để làm gì? So bản chất với đáp án đúng; loại nếu sai đối tượng hoặc sai lớp khái niệm.\n• Vì sao sai? shared_preferences chỉ key-value đơn giản (bool/int/string), không phù hợp mọi nhu cầu."}},"source":"SP26-FE"},{"id":85,"task":"fe","taskLabel":"SP26-FE","num":37,"question":"What is the main benefit of Flutter's widget-based architecture?","options":{"A":"Widgets are only used for layout design","B":"Widgets allow code reuse across platforms","C":"Widgets automatically manage databases","D":"Widgets replace backend services"},"answer":"B","alternatives":[],"explanation":{"questionVi":"Câu hỏi: main benefit Flutter's widget-based architecture?","optionsVi":{"A":"Widgets là chỉ được dùng cho bố cục thiết kế","B":"Widgets Cho phép mã tái sử dụng qua platforms","C":"Widgets tự động Quản lý databases","D":"Widgets Thay thế backend services"},"answerDisplay":"B. Widgets Cho phép mã tái sử dụng qua platforms","concept":"• Phần mềm quản lý phần cứng, tiến trình, bộ nhớ, I/O.","whyCorrect":"• Widget tree + một codebase tái sử dụng qua nền tảng.\n• Phần mềm quản lý phần cứng, tiến trình, bộ nhớ, I/O.\n• Cấp tài nguyên và lập lịch cho chương trình.","intent":"• Phần mềm quản lý phần cứng, tiến trình, bộ nhớ, I/O.\n• Chọn phương án khớp cơ chế Flutter, không chọn stack web/Android nhầm.","memoryTip":"• Widget tree + một codebase tái sử dụng qua nền tảng.","whatIs":{"A":"Widgets là chỉ được dùng cho bố cục thiết kế","B":"Phần mềm quản lý phần cứng, tiến trình, bộ nhớ, I/O.","C":"Widgets tự động Quản lý databases","D":"Widgets Thay thế backend services"},"whyWrong":{"A":"• Là gì? Widgets là chỉ được dùng cho bố cục thiết kế\n• Dùng để làm gì? Bản dịch/diễn đạt phương án — đối chiếu với định nghĩa chuẩn của đề.\n• Vì sao sai? «Widgets are only used for layout design» — Widgets là chỉ được dùng cho bố cục thiết kế. Đề cần: Phần mềm quản lý phần cứng, tiến trình, bộ nhớ, I/O.","C":"• Là gì? Widgets tự động Quản lý databases\n• Dùng để làm gì? Bản dịch/diễn đạt phương án — đối chiếu với định nghĩa chuẩn của đề.\n• Vì sao sai? «Widgets automatically manage databases» — Widgets tự động Quản lý databases. Đề cần: Phần mềm quản lý phần cứng, tiến trình, bộ nhớ, I/O.","D":"• Là gì? Widgets Thay thế backend services\n• Dùng để làm gì? Bản dịch/diễn đạt phương án — đối chiếu với định nghĩa chuẩn của đề.\n• Vì sao sai? «Widgets replace backend services» — Widgets Thay thế backend services. Đề cần: Phần mềm quản lý phần cứng, tiến trình, bộ nhớ, I/O."}},"source":"SP26-FE"},{"id":86,"task":"fe","taskLabel":"SP26-FE","num":38,"question":"Why are widgets lightweight in Flutter?","options":{"A":"They manage system resources","B":"They are immutable descriptions","C":"They store UI state","D":"They handle rendering directly"},"answer":"B","alternatives":[],"explanation":{"questionVi":"Vì sao widgets lightweight trong Flutter?","optionsVi":{"A":"They Quản lý system resources","B":"They là immutable descriptions","C":"They Lưu UI state","D":"They Xử lý rendering trực tiếp"},"answerDisplay":"B. They là immutable descriptions","concept":"• They là immutable descriptions. Bản dịch/diễn đạt phương án — đối chiếu với định nghĩa chuẩn của đề.","whyCorrect":"• Widget là mô tả bất biến, nhẹ; Element/RenderObject làm việc nặng.\n• They là immutable descriptions\n• Bản dịch/diễn đạt phương án — đối chiếu với định nghĩa chuẩn của đề.","intent":"• They là immutable descriptions\n• Chọn phương án khớp cơ chế Flutter, không chọn stack web/Android nhầm.","memoryTip":"• Widget là mô tả bất biến, nhẹ; Element/RenderObject làm việc nặng.","whatIs":{"A":"They Quản lý system resources","B":"They là immutable descriptions","C":"Cơ chế Flutter/Dart liên quan «They Lưu UI state».","D":"They Xử lý rendering trực tiếp"},"whyWrong":{"A":"• Là gì? They Quản lý system resources\n• Dùng để làm gì? Bản dịch/diễn đạt phương án — đối chiếu với định nghĩa chuẩn của đề.\n• Vì sao sai? «They manage system resources» — They Quản lý system resources. Đề cần: They là immutable descriptions.","C":"• Là gì? Cơ chế Flutter/Dart liên quan «They Lưu UI state».\n• Dùng để làm gì? Đối chiếu đúng cơ chế/phạm trù với trọng tâm đề.\n• Vì sao sai? «They store UI state» — Cơ chế Flutter/Dart liên quan «They Lưu UI state». Đề cần: They là immutable descriptions.","D":"• Là gì? They Xử lý rendering trực tiếp\n• Dùng để làm gì? Bản dịch/diễn đạt phương án — đối chiếu với định nghĩa chuẩn của đề.\n• Vì sao sai? «They handle rendering directly» — They Xử lý rendering trực tiếp. Đề cần: They là immutable descriptions."}},"source":"SP26-FE"},{"id":87,"task":"fe","taskLabel":"SP26-FE","num":39,"question":"Why should authentication state be centralized?","options":{"A":"Reduce UI code","B":"Ensure consistent access control","C":"Improve animations","D":"Simplify layout"},"answer":"B","alternatives":[],"explanation":{"questionVi":"Vì sao authentication state centralized?","optionsVi":{"A":"Giảm UI mã","B":"Đảm bảo consistent truy cập control","C":"Cải thiện animations","D":"Simplify bố cục"},"answerDisplay":"B. Đảm bảo consistent truy cập control","concept":"• Đảm bảo consistent truy cập control. Bản dịch/diễn đạt phương án — đối chiếu với định nghĩa chuẩn của đề.","whyCorrect":"• Auth tập trung → kiểm soát truy cập nhất quán toàn app.\n• Đảm bảo consistent truy cập control\n• Bản dịch/diễn đạt phương án — đối chiếu với định nghĩa chuẩn của đề.","intent":"• Đảm bảo consistent truy cập control\n• Bản dịch/diễn đạt phương án — đối chiếu với định nghĩa chuẩn của đề.","memoryTip":"• Auth: token/session tập trung; Guard chặn route; StreamBuilder hay dùng với auth stream.","whatIs":{"A":"Cụm «Giảm UI mã» mang một nghĩa riêng cần đối chiếu với đề.","B":"Đảm bảo consistent truy cập control","C":"Cụm «Cải thiện animations» mang một nghĩa riêng cần đối chiếu với đề.","D":"Cụm «Simplify bố cục» mang một nghĩa riêng cần đối chiếu với đề."},"whyWrong":{"A":"• Là gì? Cụm «Giảm UI mã» mang một nghĩa riêng cần đối chiếu với đề.\n• Dùng để làm gì? So bản chất với đáp án đúng; loại nếu sai đối tượng hoặc sai lớp khái niệm.\n• Vì sao sai? Đây là lợi ích phụ hoặc không liên quan trực tiếp đến câu hỏi.","C":"• Là gì? Cụm «Cải thiện animations» mang một nghĩa riêng cần đối chiếu với đề.\n• Dùng để làm gì? So bản chất với đáp án đúng; loại nếu sai đối tượng hoặc sai lớp khái niệm.\n• Vì sao sai? Đây là lợi ích phụ hoặc không liên quan trực tiếp đến câu hỏi.","D":"• Là gì? Cụm «Simplify bố cục» mang một nghĩa riêng cần đối chiếu với đề.\n• Dùng để làm gì? So bản chất với đáp án đúng; loại nếu sai đối tượng hoặc sai lớp khái niệm.\n• Vì sao sai? Auth/session không giải quyết bằng chỉnh UI/theme/animation."}},"source":"SP26-FE"},{"id":88,"task":"fe","taskLabel":"SP26-FE","num":40,"question":"Which widget can hide user input text when configured for password entry?","options":{"A":"TextField","B":"ObscureText","C":"SecureInput","D":"PasswordField"},"answer":"A","alternatives":[],"explanation":{"questionVi":"Cái nào widget hide user input text khi configured password entry?","optionsVi":{"A":"TextField","B":"ObscureText","C":"SecureInput","D":"PasswordField"},"answerDisplay":"A. TextField","concept":"• Cơ chế Flutter/Dart liên quan «TextField».","whyCorrect":"• TextField với obscureText: true ẩn mật khẩu (ObscureText không phải widget).\n• Cơ chế Flutter/Dart liên quan «TextField».","intent":"• Cơ chế Flutter/Dart liên quan «TextField».\n• Chọn phương án khớp cơ chế Flutter, không chọn stack web/Android nhầm.","memoryTip":"• TextField với obscureText: true ẩn mật khẩu (ObscureText không phải widget).","whatIs":{"A":"Cơ chế Flutter/Dart liên quan «TextField».","B":"Cơ chế Flutter/Dart liên quan «ObscureText».","C":"Cơ chế Flutter/Dart liên quan «SecureInput».","D":"Cơ chế Flutter/Dart liên quan «PasswordField»."},"whyWrong":{"B":"• Là gì? Cơ chế Flutter/Dart liên quan «ObscureText».\n• Dùng để làm gì? Đối chiếu đúng cơ chế/phạm trù với trọng tâm đề.\n• Vì sao sai? «ObscureText» — Cơ chế Flutter/Dart liên quan «ObscureText». Đề cần: Cơ chế Flutter/Dart liên quan «TextField».","C":"• Là gì? Cơ chế Flutter/Dart liên quan «SecureInput».\n• Dùng để làm gì? Đối chiếu đúng cơ chế/phạm trù với trọng tâm đề.\n• Vì sao sai? «SecureInput» — Cơ chế Flutter/Dart liên quan «SecureInput». Đề cần: Cơ chế Flutter/Dart liên quan «TextField».","D":"• Là gì? Cơ chế Flutter/Dart liên quan «PasswordField».\n• Dùng để làm gì? Đối chiếu đúng cơ chế/phạm trù với trọng tâm đề.\n• Vì sao sai? «PasswordField» — Cơ chế Flutter/Dart liên quan «PasswordField». Đề cần: Cơ chế Flutter/Dart liên quan «TextField»."}},"source":"SP26-FE"},{"id":89,"task":"fe","taskLabel":"SP26-FE","num":41,"question":"What is Flutter primarily used for?","options":{"A":"Designing databases for mobile apps","B":"Creating native applications from a single codebase","C":"Developing server-side applications only","D":"Building operating systems for mobile devices"},"answer":"B","alternatives":[],"explanation":{"questionVi":"Cái gì là Flutter primarily used?","optionsVi":{"A":"Designing databases cho mobile app","B":"Creating native applications từ một một codebase","C":"đang dev server-side applications","D":"Building operating systems for mobile devices"},"answerDisplay":"B. Creating native applications từ một một codebase","concept":"• Creating native applications từ một một codebase. Bản dịch/diễn đạt phương án — đối chiếu với định nghĩa chuẩn của đề.","whyCorrect":"• Flutter: app native-like đa nền tảng từ một codebase.\n• Creating native applications từ một một codebase\n• Bản dịch/diễn đạt phương án — đối chiếu với định nghĩa chuẩn của đề.","intent":"• Creating native applications từ một một codebase\n• Chọn phương án khớp cơ chế Flutter, không chọn stack web/Android nhầm.","memoryTip":"• Flutter: app native-like đa nền tảng từ một codebase.","whatIs":{"A":"Cơ chế Flutter/Dart liên quan «Designing databases cho mobile app».","B":"Creating native applications từ một một codebase","C":"đang dev server-side applications","D":"Phần mềm quản lý phần cứng, tiến trình, bộ nhớ, I/O."},"whyWrong":{"A":"• Là gì? Cơ chế Flutter/Dart liên quan «Designing databases cho mobile app».\n• Dùng để làm gì? Đối chiếu đúng cơ chế/phạm trù với trọng tâm đề.\n• Vì sao sai? «Designing databases for mobile apps» — Cơ chế Flutter/Dart liên quan «Designing databases cho mobile app». Đề cần: Creating native applications từ một một codebase.","C":"• Là gì? đang dev server-side applications\n• Dùng để làm gì? Bản dịch/diễn đạt phương án — đối chiếu với định nghĩa chuẩn của đề.\n• Vì sao sai? «Developing server-side applications only» — đang dev server-side applications. Đề cần: Creating native applications từ một một codebase.","D":"• Là gì? Phần mềm quản lý phần cứng, tiến trình, bộ nhớ, I/O.\n• Dùng để làm gì? Cấp tài nguyên và lập lịch cho chương trình.\n• Vì sao sai? Nằm ngoài vai trò framework UI Flutter."}},"source":"SP26-FE"},{"id":90,"task":"fe","taskLabel":"SP26-FE","num":42,"question":"Which method resets all form fields?","options":{"A":"clear()","B":"reset()","C":"dispose()","D":"remove()"},"answer":"B","alternatives":[],"explanation":{"questionVi":"Cái nào method resets all form fields?","optionsVi":{"A":"Xómột()","B":"reset()","C":"Dispose()","D":"Gỡ bỏ()"},"answerDisplay":"B. reset()","concept":"• Cụm «reset()» mang một nghĩa riêng cần đối chiếu với đề.","whyCorrect":"• FormState.reset() xóa/reset các field.\n• Cụm «reset()» mang một nghĩa riêng cần đối chiếu với đề.\n• So bản chất với đáp án đúng; loại nếu sai đối tượng hoặc sai lớp khái niệm.","intent":"• Phân biệt List / Set / Map trong Dart.\n• Thứ tự, trùng lặp, hay key–value.","memoryTip":"• FormState.reset() xóa/reset các field.","whatIs":{"A":"Cụm «Xómột()» mang một nghĩa riêng cần đối chiếu với đề.","B":"Cụm «reset()» mang một nghĩa riêng cần đối chiếu với đề.","C":"Phần mềm quản lý phần cứng, tiến trình, bộ nhớ, I/O.","D":"Cụm «Gỡ bỏ()» mang một nghĩa riêng cần đối chiếu với đề."},"whyWrong":{"A":"• Là gì? Cụm «Xómột()» mang một nghĩa riêng cần đối chiếu với đề.\n• Dùng để làm gì? So bản chất với đáp án đúng; loại nếu sai đối tượng hoặc sai lớp khái niệm.\n• Vì sao sai? «clear()» — Cụm «Xómột()» mang một nghĩa riêng cần đối chiếu với đề. Đề cần: Cụm «reset()» mang một nghĩa riêng cần đối chiếu với đề.","C":"• Là gì? Phần mềm quản lý phần cứng, tiến trình, bộ nhớ, I/O.\n• Dùng để làm gì? Cấp tài nguyên và lập lịch cho chương trình.\n• Vì sao sai? dispose giải phóng resource; không cập nhật UI.","D":"• Là gì? Cụm «Gỡ bỏ()» mang một nghĩa riêng cần đối chiếu với đề.\n• Dùng để làm gì? So bản chất với đáp án đúng; loại nếu sai đối tượng hoặc sai lớp khái niệm.\n• Vì sao sai? «remove()» — Cụm «Gỡ bỏ()» mang một nghĩa riêng cần đối chiếu với đề. Đề cần: Cụm «reset()» mang một nghĩa riêng cần đối chiếu với đề."}},"source":"SP26-FE"},{"id":91,"task":"fe","taskLabel":"SP26-FE","num":43,"question":"Which Dart keyword is used to define a constant value at compile time?","options":{"A":"final","B":"static","C":"const","D":"var"},"answer":"C","alternatives":[],"explanation":{"questionVi":"Cái nào Dart keyword dùng để định nghĩ hằng số giá trị Biên dịch time?","optionsVi":{"A":"final","B":"static","C":"const","D":"var"},"answerDisplay":"C. const","concept":"• Ngôn ngữ lập trình chính của Flutter. Viết UI và logic app Flutter.","whyCorrect":"• const = hằng compile-time; final = gán 1 lần runtime.\n• Ngôn ngữ lập trình chính của Flutter.\n• Viết UI và logic app Flutter.","intent":"• Phân biệt const, final, var và null safety.\n• Compile-time vs runtime assignment.","memoryTip":"• const = hằng compile-time; final = gán 1 lần runtime.","whatIs":{"A":"Biến chỉ gán một lần (thường lúc runtime).","B":"Cơ chế Flutter/Dart liên quan «static».","C":"Ngôn ngữ lập trình chính của Flutter.","D":"Khai báo biến với kiểu suy luận; có thể gán lại (trừ khi final)."},"whyWrong":{"A":"• Là gì? Biến chỉ gán một lần (thường lúc runtime).\n• Dùng để làm gì? Không gán lại sau init; khác const compile-time.\n• Vì sao sai? final gán một lần lúc runtime; const là hằng compile-time.","B":"• Là gì? Cơ chế Flutter/Dart liên quan «static».\n• Dùng để làm gì? Đối chiếu đúng cơ chế/phạm trù với trọng tâm đề.\n• Vì sao sai? «static» — Cơ chế Flutter/Dart liên quan «static». Đề cần: Ngôn ngữ lập trình chính của Flutter.","D":"• Là gì? Khai báo biến với kiểu suy luận; có thể gán lại (trừ khi final).\n• Dùng để làm gì? Viết gọn khi kiểu rõ từ vế phải.\n• Vì sao sai? var chỉ suy luận kiểu, không tạo hằng compile-time."}},"source":"SP26-FE"},{"id":92,"task":"fe","taskLabel":"SP26-FE","num":44,"question":"What happens after successful login?","options":{"A":"App closes","B":"User session starts","C":"Theme changes","D":"Navigation resets"},"answer":"B","alternatives":[],"explanation":{"questionVi":"Gì happens sau khi successful login?","optionsVi":{"A":"App closes","B":"Người dùng phiên starts","C":"Theme thay đổi","D":"Navigation resets"},"answerDisplay":"B. Người dùng phiên starts","concept":"• Cụm «Người dùng phiên starts» mang một nghĩa riêng cần đối chiếu với đề.","whyCorrect":"• Login thành công → bắt đầu phiên người dùng (session/token).\n• Cụm «Người dùng phiên starts» mang một nghĩa riêng cần đối chiếu với đề.\n• So bản chất với đáp án đúng; loại nếu sai đối tượng hoặc sai lớp khái niệm.","intent":"• Cụm «Người dùng phiên starts» mang một nghĩa riêng cần đối chiếu với đề.\n• So bản chất với đáp án đúng; loại nếu sai đối tượng hoặc sai lớp khái niệm.","memoryTip":"• Auth: token/session tập trung; Guard chặn route; StreamBuilder hay dùng với auth stream.","whatIs":{"A":"Phần mềm quản lý phần cứng, tiến trình, bộ nhớ, I/O.","B":"Cụm «Người dùng phiên starts» mang một nghĩa riêng cần đối chiếu với đề.","C":"Cụm «Theme thay đổi» mang một nghĩa riêng cần đối chiếu với đề.","D":"Cụm «Navigation resets» mang một nghĩa riêng cần đối chiếu với đề."},"whyWrong":{"A":"• Là gì? Phần mềm quản lý phần cứng, tiến trình, bộ nhớ, I/O.\n• Dùng để làm gì? Cấp tài nguyên và lập lịch cho chương trình.\n• Vì sao sai? «App closes» — Phần mềm quản lý phần cứng, tiến trình, bộ nhớ, I/O. Đề cần: Cụm «Người dùng phiên starts» mang một nghĩa riêng cần đối chiếu với đề.","C":"• Là gì? Cụm «Theme thay đổi» mang một nghĩa riêng cần đối chiếu với đề.\n• Dùng để làm gì? So bản chất với đáp án đúng; loại nếu sai đối tượng hoặc sai lớp khái niệm.\n• Vì sao sai? Theme/ThemeData lo style giao diện, không phải state/auth/logic chính ở đây.","D":"• Là gì? Cụm «Navigation resets» mang một nghĩa riêng cần đối chiếu với đề.\n• Dùng để làm gì? So bản chất với đáp án đúng; loại nếu sai đối tượng hoặc sai lớp khái niệm.\n• Vì sao sai? «Navigation resets» — Cụm «Navigation resets» mang một nghĩa riêng cần đối chiếu với đề. Đề cần: Cụm «Người dùng phiên starts» mang một nghĩa riêng cần đối chiếu với đề."}},"source":"SP26-FE"},{"id":93,"task":"fe","taskLabel":"SP26-FE","num":45,"question":"Which step is required before running a Flutter app for the first time?","options":{"A":"Publishing the app","B":"Setting up the Flutter SDK","C":"Configuring a database","D":"Writing backend APIs"},"answer":"B","alternatives":[],"explanation":{"questionVi":"Cái nào step required trước khi Chạy Flutter app first time?","optionsVi":{"A":"Publishing the app","B":"Setting up the Flutter SDK","C":"Configuring một cơ sở dữ liệu","D":"Writing backend APIs"},"answerDisplay":"B. Setting up the Flutter SDK","concept":"• Tiến trình đang chiếm CPU và thực thi lệnh.","whyCorrect":"• Cần cài/setup Flutter SDK trước khi run app.\n• Tiến trình đang chiếm CPU và thực thi lệnh.\n• Đang làm việc trên bộ xử lý.","intent":"• OS quản lý tiến trình qua các trạng thái.\n• Chờ I/O (Waiting) khác chờ CPU (Ready) và khác Suspended.","memoryTip":"• Cần cài/setup Flutter SDK trước khi run app.","whatIs":{"A":"Cơ chế Flutter/Dart liên quan «Publishing the app».","B":"Tiến trình đang chiếm CPU và thực thi lệnh.","C":"Configuring một cơ sở dữ liệu","D":"Cơ chế Flutter/Dart liên quan «Writing backend APIs»."},"whyWrong":{"A":"• Là gì? Cơ chế Flutter/Dart liên quan «Publishing the app».\n• Dùng để làm gì? Đối chiếu đúng cơ chế/phạm trù với trọng tâm đề.\n• Vì sao sai? «Publishing the app» — Cơ chế Flutter/Dart liên quan «Publishing the app». Đề cần: Tiến trình đang chiếm CPU và thực thi lệnh.","C":"• Là gì? Configuring một cơ sở dữ liệu\n• Dùng để làm gì? Bản dịch/diễn đạt phương án — đối chiếu với định nghĩa chuẩn của đề.\n• Vì sao sai? «Configuring a database» — Configuring một cơ sở dữ liệu. Đề cần: Tiến trình đang chiếm CPU và thực thi lệnh.","D":"• Là gì? Cơ chế Flutter/Dart liên quan «Writing backend APIs».\n• Dùng để làm gì? Đối chiếu đúng cơ chế/phạm trù với trọng tâm đề.\n• Vì sao sai? «Writing backend APIs» — Cơ chế Flutter/Dart liên quan «Writing backend APIs». Đề cần: Tiến trình đang chiếm CPU và thực thi lệnh."}},"source":"SP26-FE"},{"id":94,"task":"fe","taskLabel":"SP26-FE","num":46,"question":"Which widget reacts to async data from local storage?","options":{"A":"FutureBuilder","B":"StreamBuilder","C":"ListView","D":"Provider"},"answer":"A","alternatives":[],"explanation":{"questionVi":"Widget nào reacts async dữ liệu từ local storage?","optionsVi":{"A":"FutureBuilder","B":"StreamBuilder","C":"ListView","D":"Provider"},"answerDisplay":"A. FutureBuilder","concept":"• Cơ chế Flutter/Dart liên quan «FutureBuilder».","whyCorrect":"• Local storage thường trả Future → FutureBuilder.\n• Cơ chế Flutter/Dart liên quan «FutureBuilder».","intent":"• Cơ chế Flutter/Dart liên quan «FutureBuilder».\n• Chọn phương án khớp cơ chế Flutter, không chọn stack web/Android nhầm.","memoryTip":"• KV nhỏ → shared_preferences · NoSQL local → Hive · SQL → sqflite.","whatIs":{"A":"Cơ chế Flutter/Dart liên quan «FutureBuilder».","B":"Cơ chế Flutter/Dart liên quan «StreamBuilder».","C":"Cơ chế Flutter/Dart liên quan «ListView».","D":"Cách chia sẻ và phản ứng với trạng thái dùng chung giữa nhiều widget/màn."},"whyWrong":{"B":"• Là gì? Cơ chế Flutter/Dart liên quan «StreamBuilder».\n• Dùng để làm gì? Đối chiếu đúng cơ chế/phạm trù với trọng tâm đề.\n• Vì sao sai? «StreamBuilder» — Cơ chế Flutter/Dart liên quan «StreamBuilder». Đề cần: Cơ chế Flutter/Dart liên quan «FutureBuilder».","C":"• Là gì? Cơ chế Flutter/Dart liên quan «ListView».\n• Dùng để làm gì? Đối chiếu đúng cơ chế/phạm trù với trọng tâm đề.\n• Vì sao sai? «ListView» — Cơ chế Flutter/Dart liên quan «ListView». Đề cần: Cơ chế Flutter/Dart liên quan «FutureBuilder».","D":"• Là gì? Cách chia sẻ và phản ứng với trạng thái dùng chung giữa nhiều widget/màn.\n• Dùng để làm gì? Tránh truyền prop sâu; cập nhật UI khi state đổi.\n• Vì sao sai? «Provider» — Cách chia sẻ và phản ứng với trạng thái dùng chung giữa nhiều widget/màn. Đề cần: Cơ chế Flutter/Dart liên quan «FutureBuilder»."}},"source":"SP26-FE"},{"id":95,"task":"fe","taskLabel":"SP26-FE","num":47,"question":"What does golden testing verify?","options":{"A":"API responses","B":"UI appearance consistency","C":"Database state","D":"Authentication"},"answer":"B","alternatives":[],"explanation":{"questionVi":"Cái gì golden testing verify?","optionsVi":{"A":"API responses","B":"UI appearance consistency","C":"Cơ sở dữ liệu state","D":"Authentication"},"answerDisplay":"B. UI appearance consistency","concept":"• UI/hành vi thống nhất trên nhiều thiết bị nhờ một codebase Flutter.","whyCorrect":"• Golden test so sánh snapshot giao diện.\n• UI/hành vi thống nhất trên nhiều thiết bị nhờ một codebase Flutter.\n• Giảm lệch giao diện giữa iOS/Android.","intent":"• UI/hành vi thống nhất trên nhiều thiết bị nhờ một codebase Flutter.\n• Giảm lệch giao diện giữa iOS/Android.","memoryTip":"• Unit = logic nhỏ · Widget = UI · Integration = nhiều phần/E2E · Test bảo vệ khi refactor.","whatIs":{"A":"Cụm «API responses» mang một nghĩa riêng cần đối chiếu với đề.","B":"UI/hành vi thống nhất trên nhiều thiết bị nhờ một codebase Flutter.","C":"Cụm «Cơ sở dữ liệu state» mang một nghĩa riêng cần đối chiếu với đề.","D":"Cụm «Authentication» mang một nghĩa riêng cần đối chiếu với đề."},"whyWrong":{"A":"• Là gì? Cụm «API responses» mang một nghĩa riêng cần đối chiếu với đề.\n• Dùng để làm gì? So bản chất với đáp án đúng; loại nếu sai đối tượng hoặc sai lớp khái niệm.\n• Vì sao sai? Golden test so sánh ảnh UI; khác integration/unit thuần.","C":"• Là gì? Cụm «Cơ sở dữ liệu state» mang một nghĩa riêng cần đối chiếu với đề.\n• Dùng để làm gì? So bản chất với đáp án đúng; loại nếu sai đối tượng hoặc sai lớp khái niệm.\n• Vì sao sai? Golden test so sánh ảnh UI; khác integration/unit thuần.","D":"• Là gì? Cụm «Authentication» mang một nghĩa riêng cần đối chiếu với đề.\n• Dùng để làm gì? So bản chất với đáp án đúng; loại nếu sai đối tượng hoặc sai lớp khái niệm.\n• Vì sao sai? Golden test so sánh ảnh UI; khác integration/unit thuần."}},"source":"SP26-FE"},{"id":96,"task":"fe","taskLabel":"SP26-FE","num":48,"question":"Why should state be kept as local as possible?","options":{"A":"Better animations","B":"Reduce unnecessary rebuilds","C":"Simplify UI","D":"Improve navigation"},"answer":"B","alternatives":[],"explanation":{"questionVi":"Vì sao state kept local possible?","optionsVi":{"A":"Tốt hơn animations","B":"Giảm unnecessary rebuild","C":"Simplify UI","D":"Cải thiện navigation"},"answerDisplay":"B. Giảm unnecessary rebuild","concept":"• Phần mềm quản lý phần cứng, tiến trình, bộ nhớ, I/O.","whyCorrect":"• State càng local càng ít widget bị rebuild oan.\n• Phần mềm quản lý phần cứng, tiến trình, bộ nhớ, I/O.\n• Cấp tài nguyên và lập lịch cho chương trình.","intent":"• Phần mềm quản lý phần cứng, tiến trình, bộ nhớ, I/O.\n• Cấp tài nguyên và lập lịch cho chương trình.","memoryTip":"• State càng local càng ít widget bị rebuild oan.","whatIs":{"A":"Cụm «Tốt hơn animations» mang một nghĩa riêng cần đối chiếu với đề.","B":"Phần mềm quản lý phần cứng, tiến trình, bộ nhớ, I/O.","C":"Cụm «Simplify UI» mang một nghĩa riêng cần đối chiếu với đề.","D":"Cụm «Cải thiện navigation» mang một nghĩa riêng cần đối chiếu với đề."},"whyWrong":{"A":"• Là gì? Cụm «Tốt hơn animations» mang một nghĩa riêng cần đối chiếu với đề.\n• Dùng để làm gì? So bản chất với đáp án đúng; loại nếu sai đối tượng hoặc sai lớp khái niệm.\n• Vì sao sai? «Better animations» — Cụm «Tốt hơn animations» mang một nghĩa riêng cần đối chiếu với đề. Đề cần: Phần mềm quản lý phần cứng, tiến trình, bộ nhớ, I/O.","C":"• Là gì? Cụm «Simplify UI» mang một nghĩa riêng cần đối chiếu với đề.\n• Dùng để làm gì? So bản chất với đáp án đúng; loại nếu sai đối tượng hoặc sai lớp khái niệm.\n• Vì sao sai? «Simplify UI» — Cụm «Simplify UI» mang một nghĩa riêng cần đối chiếu với đề. Đề cần: Phần mềm quản lý phần cứng, tiến trình, bộ nhớ, I/O.","D":"• Là gì? Cụm «Cải thiện navigation» mang một nghĩa riêng cần đối chiếu với đề.\n• Dùng để làm gì? So bản chất với đáp án đúng; loại nếu sai đối tượng hoặc sai lớp khái niệm.\n• Vì sao sai? «Improve navigation» — Cụm «Cải thiện navigation» mang một nghĩa riêng cần đối chiếu với đề. Đề cần: Phần mềm quản lý phần cứng, tiến trình, bộ nhớ, I/O."}},"source":"SP26-FE"},{"id":97,"task":"fe","taskLabel":"SP26-FE","num":49,"question":"What is the benefit of composing widgets in Flutter?","options":{"A":"Faster compilation","B":"Better code reuse and UI consistency","C":"Reduced memory usage","D":"Automatic navigation"},"answer":"B","alternatives":[],"explanation":{"questionVi":"Cái gì là benefit composing widgets trong Flutter?","optionsVi":{"A":"Nhanh hơn compilation","B":"Tốt hơn mã tái sử dụng và UI consistency","C":"Reduced memory usage","D":"Automatic navigation"},"answerDisplay":"B. Tốt hơn mã tái sử dụng và UI consistency","concept":"• Phần mềm quản lý phần cứng, tiến trình, bộ nhớ, I/O.","whyCorrect":"• Ghép widget nhỏ → tái sử dụng và UI đồng nhất.\n• Phần mềm quản lý phần cứng, tiến trình, bộ nhớ, I/O.\n• Cấp tài nguyên và lập lịch cho chương trình.","intent":"• Phần mềm quản lý phần cứng, tiến trình, bộ nhớ, I/O.\n• Chọn phương án khớp cơ chế Flutter, không chọn stack web/Android nhầm.","memoryTip":"• Ghép widget nhỏ → tái sử dụng và UI đồng nhất.","whatIs":{"A":"Thiết bị/khái niệm mạng «Nhanh hơn compilation».","B":"Phần mềm quản lý phần cứng, tiến trình, bộ nhớ, I/O.","C":"Thiết bị/khái niệm mạng «Reduced memory usage».","D":"Thiết bị/khái niệm mạng «Automatic navigation»."},"whyWrong":{"A":"• Là gì? Thiết bị/khái niệm mạng «Nhanh hơn compilation».\n• Dùng để làm gì? Đối chiếu đúng tầng OSI và chức năng (routing / switching / physical).\n• Vì sao sai? «Faster compilation» — Thiết bị/khái niệm mạng «Nhanh hơn compilation». Đề cần: Phần mềm quản lý phần cứng, tiến trình, bộ nhớ, I/O.","C":"• Là gì? Thiết bị/khái niệm mạng «Reduced memory usage».\n• Dùng để làm gì? Đối chiếu đúng tầng OSI và chức năng (routing / switching / physical).\n• Vì sao sai? «Reduced memory usage» — Thiết bị/khái niệm mạng «Reduced memory usage». Đề cần: Phần mềm quản lý phần cứng, tiến trình, bộ nhớ, I/O.","D":"• Là gì? Thiết bị/khái niệm mạng «Automatic navigation».\n• Dùng để làm gì? Đối chiếu đúng tầng OSI và chức năng (routing / switching / physical).\n• Vì sao sai? «Automatic navigation» — Thiết bị/khái niệm mạng «Automatic navigation». Đề cần: Phần mềm quản lý phần cứng, tiến trình, bộ nhớ, I/O."}},"source":"SP26-FE"},{"id":98,"task":"fe","taskLabel":"SP26-FE","num":50,"question":"Which status code indicates server error?","options":{"A":"200","B":"301","C":"404","D":"500"},"answer":"D","alternatives":[],"explanation":{"questionVi":"Cái nào status code indicates server lỗi?","optionsVi":{"A":"200","B":"301","C":"404","D":"500"},"answerDisplay":"D. 500","concept":"• Một giá trị số cụ thể (500) cần kiểm tra trong điều kiện/công thức đề.","whyCorrect":"• 5xx = lỗi server; 500 Internal Server Error.\n• Một giá trị số cụ thể (500) cần kiểm tra trong điều kiện/công thức đề.\n• Thay vào phép tính hoặc tiêu chí để xem có thỏa không.","intent":"• Một giá trị số cụ thể (500) cần kiểm tra trong điều kiện/công thức đề.\n• Thay vào phép tính hoặc tiêu chí để xem có thỏa không.","memoryTip":"• GET lấy · POST tạo · Authorization mang token · parse JSON → object Dart.","whatIs":{"A":"Một giá trị số cụ thể (200) cần kiểm tra trong điều kiện/công thức đề.","B":"Một giá trị số cụ thể (301) cần kiểm tra trong điều kiện/công thức đề.","C":"Một giá trị số cụ thể (404) cần kiểm tra trong điều kiện/công thức đề.","D":"Một giá trị số cụ thể (500) cần kiểm tra trong điều kiện/công thức đề."},"whyWrong":{"A":"• Là gì? Một giá trị số cụ thể (200) cần kiểm tra trong điều kiện/công thức đề.\n• Dùng để làm gì? Thay vào phép tính hoặc tiêu chí để xem có thỏa không.\n• Vì sao sai? 200 = OK, không phải lỗi server.","B":"• Là gì? Một giá trị số cụ thể (301) cần kiểm tra trong điều kiện/công thức đề.\n• Dùng để làm gì? Thay vào phép tính hoặc tiêu chí để xem có thỏa không.\n• Vì sao sai? 301 = redirect, không phải server error.","C":"• Là gì? Một giá trị số cụ thể (404) cần kiểm tra trong điều kiện/công thức đề.\n• Dùng để làm gì? Thay vào phép tính hoặc tiêu chí để xem có thỏa không.\n• Vì sao sai? 404 = không tìm thấy, không phải 5xx server error."}},"source":"SP26-FE"},{"id":99,"task":"fe","taskLabel":"SP26 FE","num":58,"question":"What does Curves/Animation provide?","options":{"A":"Layout control","B":"Animation curve behavior","C":"State updates","D":"Navigation"},"answer":"B","alternatives":[],"source":"fe","exam":"PRM393_SP26_FE","explanation":{"questionVi":"Curves/Animation cung cấp gì?","optionsVi":{"A":"Điều khiển bố cục (layout)","B":"Hành vi đường cong animation","C":"Cập nhật state","D":"Điều hướng màn hình"},"answerDisplay":"B. Hành vi đường cong animation","concept":"• Đường cong/thời gian điều khiển nhịp chuyển động UI (ease-in/out…).","whyCorrect":"• Curves định nghĩa đường cong/hành vi animation (easing).\n• Đường cong/thời gian điều khiển nhịp chuyển động UI (ease-in/out…).\n• Làm animation mượt, không tuyến tính cứng.","intent":"• Đường cong/thời gian điều khiển nhịp chuyển động UI (ease-in/out…).\n• Làm animation mượt, không tuyến tính cứng.","memoryTip":"• Animation/Tween định nghĩa chuyển động; luôn dispose controller để tránh rò memory.","whatIs":{"A":"Điều khiển cách xếp vị trí/kích thước widget con trên màn hình.","B":"Đường cong/thời gian điều khiển nhịp chuyển động UI (ease-in/out…).","C":"Cụm «Cập nhật state» mang một nghĩa riêng cần đối chiếu với đề.","D":"Cụm «Điều hướng màn hình» mang một nghĩa riêng cần đối chiếu với đề."},"whyWrong":{"A":"• Là gì? Điều khiển cách xếp vị trí/kích thước widget con trên màn hình.\n• Dùng để làm gì? Bố cục UI (Row/Column/Stack…); khác nhịp animation.\n• Vì sao sai? Liên quan chuyển động UI, không giải quyết khái niệm trong câu hỏi.","C":"• Là gì? Cụm «Cập nhật state» mang một nghĩa riêng cần đối chiếu với đề.\n• Dùng để làm gì? So bản chất với đáp án đúng; loại nếu sai đối tượng hoặc sai lớp khái niệm.\n• Vì sao sai? Liên quan chuyển động UI, không giải quyết khái niệm trong câu hỏi.","D":"• Là gì? Cụm «Điều hướng màn hình» mang một nghĩa riêng cần đối chiếu với đề.\n• Dùng để làm gì? So bản chất với đáp án đúng; loại nếu sai đối tượng hoặc sai lớp khái niệm.\n• Vì sao sai? Liên quan chuyển động UI, không giải quyết khái niệm trong câu hỏi."}}},{"id":100,"task":"slides","taskLabel":"Slides","num":99,"question":"According to Flutter architecture overview, which three layers are described?","options":{"A":"Framework (Dart), Engine (C++), Embedder","B":"HTML, CSS, JavaScript only","C":"JVM, ART, Dalvik only","D":"Kernel, Shell, Desktop only"},"answer":"A","alternatives":[],"source":"slides","exam":"PRM393_SLIDES_M1","explanation":{"questionVi":"Theo tổng quan kiến trúc Flutter, ba tầng nào được mô tả?","optionsVi":{"A":"Framework (Dart), Engine (C++), Embedder","B":"Chỉ HTML, CSS, JavaScript","C":"Chỉ JVM, ART, Dalvik","D":"Chỉ Kernel, Shell, Desktop"},"answerDisplay":"A. Framework (Dart), Engine (C++), Embedder","concept":"• Ba tầng kiến trúc Flutter: Framework (Dart UI), Engine (C++/Skia), Embedder (OS).","whyCorrect":"• Slide M1: ba tầng Framework (Dart) – Engine (C++) – Embedder.\n• Ba tầng kiến trúc Flutter: Framework (Dart UI), Engine (C++/Skia), Embedder (OS).\n• Tách UI, render và tích hợp nền tảng.","intent":"• Ba tầng kiến trúc Flutter: Framework (Dart UI), Engine (C++/Skia), Embedder (OS).\n• Chọn phương án khớp cơ chế Flutter, không chọn stack web/Android nhầm.","memoryTip":"• Slide M1: ba tầng Framework (Dart) – Engine (C++) – Embedder.","whatIs":{"A":"Ba tầng kiến trúc Flutter: Framework (Dart UI), Engine (C++/Skia), Embedder (OS).","B":"Stack dựng giao diện web trên trình duyệt.","C":"Runtime chạy bytecode Java/Kotlin trên Android.","D":"Các lớp hệ điều hành/môi trường desktop (kernel, shell…)."},"whyWrong":{"B":"• Là gì? Stack dựng giao diện web trên trình duyệt.\n• Dùng để làm gì? Trang web; khác pipeline widget/engine Flutter.\n• Vì sao sai? Flutter không dựng UI chính bằng XML/HTML/CSS như Android View/web cổ điển.","C":"• Là gì? Runtime chạy bytecode Java/Kotlin trên Android.\n• Dùng để làm gì? Thực thi app Android native, không phải 3 tầng Flutter.\n• Vì sao sai? JVM/ART/Dalvik là runtime Android Java/Kotlin, không phải 3 tầng Flutter.","D":"• Là gì? Các lớp hệ điều hành/môi trường desktop (kernel, shell…).\n• Dùng để làm gì? Quản lý máy/OS; không phải 3 tầng Framework–Engine–Embedder của Flutter.\n• Vì sao sai? Kernel/Shell là khái niệm hệ điều hành, không phải kiến trúc Flutter."}}},{"id":101,"task":"slides","taskLabel":"Slides","num":100,"question":"What is the correct high-level rendering workflow in Flutter?","options":{"A":"GPU → Widget Tree → SQL → Disk","B":"Widget Tree → Render Tree → Composited Scene → GPU Rendering","C":"XML Layout → Bridge → Native View only","D":"CSS DOM → Browser → Print only"},"answer":"B","alternatives":[],"source":"slides","exam":"PRM393_SLIDES_M1","explanation":{"questionVi":"Quy trình render cấp cao đúng trong Flutter là gì?","optionsVi":{"A":"GPU → Cây Widget → SQL → Đĩa","B":"Cây Widget → Cây Render → Cảnh ghép → GPU render","C":"Chỉ XML Layout → Bridge → Native View","D":"Chỉ CSS DOM → Trình duyệt → In"},"answerDisplay":"B. Cây Widget → Cây Render → Cảnh ghép → GPU render","concept":"• Cây đối tượng layout/paint sau khi widget được inflate.","whyCorrect":"• Cây đối tượng layout/paint sau khi widget được inflate.\n• Tính kích thước, vị trí và vẽ lên layer.","intent":"• Cây đối tượng layout/paint sau khi widget được inflate.\n• Chọn phương án khớp cơ chế Flutter, không chọn stack web/Android nhầm.","whatIs":{"A":"Cây cấu hình UI lồng nhau mô tả giao diện tại một thời điểm.","B":"Cây đối tượng layout/paint sau khi widget được inflate.","C":"Thiết bị tầng 2 (Data Link): nối segment LAN, lọc/chuyển frame theo MAC.","D":"Chỉ CSS DOM → Trình duyệt → In"},"whyWrong":{"A":"• Là gì? Cây cấu hình UI lồng nhau mô tả giao diện tại một thời điểm.\n• Dùng để làm gì? Đầu vào cho Element/Render pipeline của Flutter.\n• Vì sao sai? «GPU → Widget Tree → SQL → Disk» — Cây cấu hình UI lồng nhau mô tả giao diện tại một thời điểm. Đề cần: Cây đối tượng layout/paint sau khi widget được inflate.","C":"• Là gì? Thiết bị tầng 2 (Data Link): nối segment LAN, lọc/chuyển frame theo MAC.\n• Dùng để làm gì? Không định tuyến theo IP giữa các mạng logic khác nhau.\n• Vì sao sai? Flutter không dựng UI chính bằng XML/HTML/CSS như Android View/web cổ điển.","D":"• Là gì? Chỉ CSS DOM → Trình duyệt → In\n• Dùng để làm gì? Bản dịch/diễn đạt phương án — đối chiếu với định nghĩa chuẩn của đề.\n• Vì sao sai? Flutter không dựng UI chính bằng XML/HTML/CSS như Android View/web cổ điển."}}},{"id":102,"task":"slides","taskLabel":"Slides","num":101,"question":"Which statement matches a key concept of Flutter UI?","options":{"A":"Everything must be written in Kotlin","B":"UI is defined only with HTML files","C":"Everything in Flutter is a Widget","D":"Flutter cannot draw custom UI"},"answer":"C","alternatives":[],"source":"slides","exam":"PRM393_SLIDES_M1","explanation":{"questionVi":"Phát biểu nào khớp khái niệm cốt lõi về UI Flutter?","optionsVi":{"A":"Mọi thứ phải viết bằng Kotlin","B":"UI chỉ định nghĩa bằng file HTML","C":"Mọi thứ trong Flutter đều là Widget","D":"Flutter không thể vẽ UI tùy chỉnh"},"answerDisplay":"C. Mọi thứ trong Flutter đều là Widget","concept":"• Mọi thứ trong Flutter đều là Widget. Bản dịch/diễn đạt phương án — đối chiếu với định nghĩa chuẩn của đề.","whyCorrect":"• Mọi thứ trong Flutter đều là Widget\n• Bản dịch/diễn đạt phương án — đối chiếu với định nghĩa chuẩn của đề.","intent":"• Mọi thứ trong Flutter đều là Widget\n• Chọn phương án khớp cơ chế Flutter, không chọn stack web/Android nhầm.","whatIs":{"A":"Ngôn ngữ chính cho Android native hiện đại.","B":"UI chỉ định nghĩa bằng file HTML","C":"Mọi thứ trong Flutter đều là Widget","D":"Flutter không thể vẽ UI tùy chỉnh"},"whyWrong":{"A":"• Là gì? Ngôn ngữ chính cho Android native hiện đại.\n• Dùng để làm gì? App Android/JVM; Flutter UI dùng Dart.\n• Vì sao sai? Flutter UI viết bằng Dart + widget, không bắt buộc Kotlin.","B":"• Là gì? UI chỉ định nghĩa bằng file HTML\n• Dùng để làm gì? Bản dịch/diễn đạt phương án — đối chiếu với định nghĩa chuẩn của đề.\n• Vì sao sai? Flutter không dựng UI chính bằng XML/HTML/CSS như Android View/web cổ điển.","D":"• Là gì? Flutter không thể vẽ UI tùy chỉnh\n• Dùng để làm gì? Bản dịch/diễn đạt phương án — đối chiếu với định nghĩa chuẩn của đề.\n• Vì sao sai? Flutter vẽ UI tùy biến qua widget/custom paint; phát biểu phủ định là sai."}}},{"id":103,"task":"slides","taskLabel":"Slides","num":102,"question":"Which engine technology does Flutter use for rendering (as mentioned in slides)?","options":{"A":"WebKit only","B":"Skia (C++ engine, GPU acceleration)","C":"OpenGL ES exclusive without Skia","D":"Swing toolkit"},"answer":"B","alternatives":[],"source":"slides","exam":"PRM393_SLIDES_M1","explanation":{"questionVi":"Flutter dùng công nghệ engine nào để render?","optionsVi":{"A":"Chỉ WebKit","B":"Skia (engine C++, tăng tốc GPU)","C":"Chỉ OpenGL ES, không dùng Skia","D":"Bộ toolkit Swing (Java)"},"answerDisplay":"B. Skia (engine C++, tăng tốc GPU)","concept":"• Thư viện đồ họa 2D (C++) mà Flutter Engine dùng để vẽ.","whyCorrect":"• Thư viện đồ họa 2D (C++) mà Flutter Engine dùng để vẽ.\n• Render UI nhất quán, tận dụng GPU.","intent":"• Thư viện đồ họa 2D (C++) mà Flutter Engine dùng để vẽ.\n• Chọn phương án khớp cơ chế Flutter, không chọn stack web/Android nhầm.","whatIs":{"A":"Engine trình duyệt để render HTML/CSS.","B":"Thư viện đồ họa 2D (C++) mà Flutter Engine dùng để vẽ.","C":"Thư viện đồ họa 2D (C++) mà Flutter Engine dùng để vẽ.","D":"Cơ chế Flutter/Dart liên quan «Bộ toolkit Swing (Java)»."},"whyWrong":{"A":"• Là gì? Engine trình duyệt để render HTML/CSS.\n• Dùng để làm gì? Hiển thị web; không phải engine vẽ chính của Flutter.\n• Vì sao sai? «WebKit only» — Engine trình duyệt để render HTML/CSS. Đề cần: Thư viện đồ họa 2D (C++) mà Flutter Engine dùng để vẽ.","C":"• Là gì? Thư viện đồ họa 2D (C++) mà Flutter Engine dùng để vẽ.\n• Dùng để làm gì? Render UI nhất quán, tận dụng GPU.\n• Vì sao sai? «OpenGL ES exclusive without Skia» lệch đối tượng/cơ chế so với đáp án đúng của đề.","D":"• Là gì? Cơ chế Flutter/Dart liên quan «Bộ toolkit Swing (Java)».\n• Dùng để làm gì? Đối chiếu đúng cơ chế/phạm trù với trọng tâm đề.\n• Vì sao sai? «Swing toolkit» — Cơ chế Flutter/Dart liên quan «Bộ toolkit Swing (Java)». Đề cần: Thư viện đồ họa 2D (C++) mà Flutter Engine dùng để vẽ."}}},{"id":104,"task":"slides","taskLabel":"Slides","num":103,"question":"Compared with React Native in the comparison table, Flutter uses which language?","options":{"A":"Dart","B":"JavaScript only","C":"Ruby","D":"PHP"},"answer":"A","alternatives":[],"source":"slides","exam":"PRM393_SLIDES_M1","explanation":{"questionVi":"So với React Native, Flutter dùng ngôn ngữ nào?","optionsVi":{"A":"Dart","B":"Chỉ JavaScript","C":"Ruby","D":"PHP"},"answerDisplay":"A. Dart","concept":"• Ngôn ngữ lập trình chính của Flutter. Viết UI và logic app Flutter.","whyCorrect":"• Ngôn ngữ lập trình chính của Flutter.\n• Viết UI và logic app Flutter.","intent":"• Ngôn ngữ lập trình chính của Flutter.\n• Chọn phương án khớp cơ chế Flutter, không chọn stack web/Android nhầm.","whatIs":{"A":"Ngôn ngữ lập trình chính của Flutter.","B":"Stack dựng giao diện web trên trình duyệt.","C":"Cơ chế Flutter/Dart liên quan «Ruby».","D":"Cơ chế Flutter/Dart liên quan «PHP»."},"whyWrong":{"B":"• Là gì? Stack dựng giao diện web trên trình duyệt.\n• Dùng để làm gì? Trang web; khác pipeline widget/engine Flutter.\n• Vì sao sai? JavaScript là ngôn ngữ React Native; Flutter dùng Dart.","C":"• Là gì? Cơ chế Flutter/Dart liên quan «Ruby».\n• Dùng để làm gì? Đối chiếu đúng cơ chế/phạm trù với trọng tâm đề.\n• Vì sao sai? Ruby không phải ngôn ngữ UI chính của Flutter (Dart).","D":"• Là gì? Cơ chế Flutter/Dart liên quan «PHP».\n• Dùng để làm gì? Đối chiếu đúng cơ chế/phạm trù với trọng tâm đề.\n• Vì sao sai? PHP không phải ngôn ngữ UI chính của Flutter (Dart)."}}},{"id":105,"task":"slides","taskLabel":"Slides","num":104,"question":"What is a main benefit of Flutter listed in the introduction slides?","options":{"A":"Must rewrite UI for every OS with different languages only","B":"Consistency: same UI across devices (plus performance/flexibility)","C":"Cannot compile to ARM","D":"No widget set available"},"answer":"B","alternatives":[],"source":"slides","exam":"PRM393_SLIDES_M1","explanation":{"questionVi":"Lợi ích chính nào của Flutter được nêu trong slide giới thiệu?","optionsVi":{"A":"Phải viết lại UI cho từng OS bằng ngôn ngữ khác nhau","B":"Nhất quán: cùng UI trên nhiều thiết bị (kèm hiệu năng/linh hoạt)","C":"Không biên dịch được sang ARM","D":"Không có bộ widget sẵn"},"answerDisplay":"B. Nhất quán: cùng UI trên nhiều thiết bị (kèm hiệu năng/linh hoạt)","concept":"• UI/hành vi thống nhất trên nhiều thiết bị nhờ một codebase Flutter.","whyCorrect":"• UI/hành vi thống nhất trên nhiều thiết bị nhờ một codebase Flutter.\n• Giảm lệch giao diện giữa iOS/Android.","intent":"• Phân biệt List / Set / Map trong Dart.\n• Thứ tự, trùng lặp, hay key–value.","whatIs":{"A":"Phần mềm quản lý phần cứng, tiến trình, bộ nhớ, I/O.","B":"UI/hành vi thống nhất trên nhiều thiết bị nhờ một codebase Flutter.","C":"Phát biểu phủ định khả năng biên dịch ra kiến trúc ARM.","D":"Tập hợp giá trị không trùng."},"whyWrong":{"A":"• Là gì? Phần mềm quản lý phần cứng, tiến trình, bộ nhớ, I/O.\n• Dùng để làm gì? Cấp tài nguyên và lập lịch cho chương trình.\n• Vì sao sai? «Must rewrite UI for every OS with different languages only» — Phần mềm quản lý phần cứng, tiến trình, bộ nhớ, I/O. Đề cần: UI/hành vi thống nhất trên nhiều thiết bị nhờ một codebase Flutter.","C":"• Là gì? Phát biểu phủ định khả năng biên dịch ra kiến trúc ARM.\n• Dùng để làm gì? Trái thực tế Flutter/AOT hỗ trợ ARM trên mobile.\n• Vì sao sai? «Cannot compile to ARM» — Phát biểu phủ định khả năng biên dịch ra kiến trúc ARM. Đề cần: UI/hành vi thống nhất trên nhiều thiết bị nhờ một codebase Flutter.","D":"• Là gì? Tập hợp giá trị không trùng.\n• Dùng để làm gì? Loại trùng, kiểm tra membership.\n• Vì sao sai? Set không cho trùng và không dùng index như List."}}},{"id":106,"task":"slides","taskLabel":"Slides","num":105,"question":"Which command verifies Flutter SDK installation after adding PATH?","options":{"A":"npm doctor","B":"pip check","C":"flutter doctor","D":"adb uninstall"},"answer":"C","alternatives":[],"source":"slides","exam":"PRM393_SLIDES_M1","explanation":{"questionVi":"Lệnh nào kiểm tra cài đặt Flutter SDK sau khi thêm PATH?","optionsVi":{"A":"npm doctor","B":"pip check","C":"flutter doctor","D":"adb uninstall"},"answerDisplay":"C. flutter doctor","concept":"• Lệnh kiểm tra môi trường SDK, toolchain, thiết bị Flutter.","whyCorrect":"• Lệnh kiểm tra môi trường SDK, toolchain, thiết bị Flutter.\n• Xác nhận cài đặt/PATH sau setup.","intent":"• Lệnh kiểm tra môi trường SDK, toolchain, thiết bị Flutter.\n• Chọn phương án khớp cơ chế Flutter, không chọn stack web/Android nhầm.","whatIs":{"A":"Cơ chế Flutter/Dart liên quan «npm doctor».","B":"Cơ chế Flutter/Dart liên quan «pip check».","C":"Lệnh kiểm tra môi trường SDK, toolchain, thiết bị Flutter.","D":"Cơ chế Flutter/Dart liên quan «adb uninstall»."},"whyWrong":{"A":"• Là gì? Cơ chế Flutter/Dart liên quan «npm doctor».\n• Dùng để làm gì? Đối chiếu đúng cơ chế/phạm trù với trọng tâm đề.\n• Vì sao sai? «npm doctor» — Cơ chế Flutter/Dart liên quan «npm doctor». Đề cần: Lệnh kiểm tra môi trường SDK, toolchain, thiết bị Flutter.","B":"• Là gì? Cơ chế Flutter/Dart liên quan «pip check».\n• Dùng để làm gì? Đối chiếu đúng cơ chế/phạm trù với trọng tâm đề.\n• Vì sao sai? «pip check» — Cơ chế Flutter/Dart liên quan «pip check». Đề cần: Lệnh kiểm tra môi trường SDK, toolchain, thiết bị Flutter.","D":"• Là gì? Cơ chế Flutter/Dart liên quan «adb uninstall».\n• Dùng để làm gì? Đối chiếu đúng cơ chế/phạm trù với trọng tâm đề.\n• Vì sao sai? «adb uninstall» — Cơ chế Flutter/Dart liên quan «adb uninstall». Đề cần: Lệnh kiểm tra môi trường SDK, toolchain, thiết bị Flutter."}}},{"id":107,"task":"slides","taskLabel":"Slides","num":106,"question":"What is DartPad mainly useful for according to the slides?","options":{"A":"Run Flutter/Dart code in browser without local install","B":"Deploy apps to App Store automatically","C":"Compile C++ engine source","D":"Manage Android signing keys only"},"answer":"A","alternatives":[],"source":"slides","exam":"PRM393_SLIDES_M1","explanation":{"questionVi":"Theo slide, DartPad chủ yếu hữu ích để làm gì?","optionsVi":{"A":"Chạy code Flutter/Dart trên trình duyệt, không cần cài local","B":"Tự động deploy app lên App Store","C":"Biên dịch mã nguồn engine C++","D":"Chỉ quản lý khóa ký Android"},"answerDisplay":"A. Chạy code Flutter/Dart trên trình duyệt, không cần cài local","concept":"• Chạy thử Flutter/Dart trên trình duyệt (DartPad) không cài SDK local.","whyCorrect":"• Chạy thử Flutter/Dart trên trình duyệt (DartPad) không cài SDK local.\n• Demo/học nhanh; không thay cho build/deploy production.","intent":"• Chạy thử Flutter/Dart trên trình duyệt (DartPad) không cài SDK local.\n• Demo/học nhanh; không thay cho build/deploy production.","whatIs":{"A":"Chạy thử Flutter/Dart trên trình duyệt (DartPad) không cài SDK local.","B":"Tự động đẩy app lên App Store.","C":"Biên dịch mã nguồn engine C++ của Flutter.","D":"Chỉ quản lý khóa ký Android"},"whyWrong":{"B":"• Là gì? Tự động đẩy app lên App Store.\n• Dùng để làm gì? Thuộc CI/CD/release — không phải công dụng chính của DartPad.\n• Vì sao sai? DartPad chạy code trên browser để học/demo; không deploy App Store.","C":"• Là gì? Biên dịch mã nguồn engine C++ của Flutter.\n• Dùng để làm gì? Việc nâng cao cho contributor engine; không phải dùng DartPad học cơ bản.\n• Vì sao sai? Biên dịch engine C++ không phải công dụng DartPad.","D":"• Là gì? Chỉ quản lý khóa ký Android\n• Dùng để làm gì? Thuộc quy trình ký release APK; khác mục đích DartPad.\n• Vì sao sai? Signing keys thuộc release Android; DartPad không quản lý khóa ký."}}},{"id":108,"task":"slides","taskLabel":"Slides","num":107,"question":"When installing Android Studio for Flutter, which plugin is required?","options":{"A":"Only Python plugin","B":"Flutter plugin (Dart plugin installs with it)","C":"Only COBOL plugin","D":"Only Photoshop plugin"},"answer":"B","alternatives":[],"source":"slides","exam":"PRM393_SLIDES_M1","explanation":{"questionVi":"Khi cài Android Studio cho Flutter, plugin nào là bắt buộc?","optionsVi":{"A":"Chỉ plugin Python","B":"Plugin Flutter (kèm plugin Dart)","C":"Chỉ plugin COBOL","D":"Chỉ plugin Photoshop"},"answerDisplay":"B. Plugin Flutter (kèm plugin Dart)","concept":"• Ngôn ngữ lập trình chính của Flutter. Viết UI và logic app Flutter.","whyCorrect":"• Ngôn ngữ lập trình chính của Flutter.\n• Viết UI và logic app Flutter.","intent":"• Ngôn ngữ lập trình chính của Flutter.\n• Chọn phương án khớp cơ chế Flutter, không chọn stack web/Android nhầm.","whatIs":{"A":"Cơ chế Flutter/Dart liên quan «Chỉ plugin Python».","B":"Ngôn ngữ lập trình chính của Flutter.","C":"Cơ chế Flutter/Dart liên quan «Chỉ plugin COBOL».","D":"Phần mềm quản lý phần cứng, tiến trình, bộ nhớ, I/O."},"whyWrong":{"A":"• Là gì? Cơ chế Flutter/Dart liên quan «Chỉ plugin Python».\n• Dùng để làm gì? Đối chiếu đúng cơ chế/phạm trù với trọng tâm đề.\n• Vì sao sai? «Only Python plugin» — Cơ chế Flutter/Dart liên quan «Chỉ plugin Python». Đề cần: Ngôn ngữ lập trình chính của Flutter.","C":"• Là gì? Cơ chế Flutter/Dart liên quan «Chỉ plugin COBOL».\n• Dùng để làm gì? Đối chiếu đúng cơ chế/phạm trù với trọng tâm đề.\n• Vì sao sai? «Only COBOL plugin» — Cơ chế Flutter/Dart liên quan «Chỉ plugin COBOL». Đề cần: Ngôn ngữ lập trình chính của Flutter.","D":"• Là gì? Phần mềm quản lý phần cứng, tiến trình, bộ nhớ, I/O.\n• Dùng để làm gì? Cấp tài nguyên và lập lịch cho chương trình.\n• Vì sao sai? «Only Photoshop plugin» — Phần mềm quản lý phần cứng, tiến trình, bộ nhớ, I/O. Đề cần: Ngôn ngữ lập trình chính của Flutter."}}},{"id":109,"task":"slides","taskLabel":"Slides","num":108,"question":"Dart in Flutter is described as supporting which compilation modes?","options":{"A":"Only interpreted BASIC","B":"Only COBOL batch","C":"AOT and JIT compilation","D":"Only assembly hand-writing"},"answer":"C","alternatives":[],"source":"slides","exam":"PRM393_SLIDES_M1","explanation":{"questionVi":"Dart trong Flutter hỗ trợ những chế độ biên dịch nào?","optionsVi":{"A":"Chỉ BASIC thông dịch","B":"Chỉ COBOL batch","C":"Biên dịch AOT và JIT","D":"Chỉ viết assembly tay"},"answerDisplay":"C. Biên dịch AOT và JIT","concept":"• Hai chế độ biên dịch Dart: JIT (dev) và AOT (release).","whyCorrect":"• Hai chế độ biên dịch Dart: JIT (dev) và AOT (release).\n• JIT hỗ trợ hot reload; AOT tối ưu bản ship.","intent":"• Hai chế độ biên dịch Dart: JIT (dev) và AOT (release).\n• Chọn phương án khớp cơ chế Flutter, không chọn stack web/Android nhầm.","whatIs":{"A":"Cơ chế Flutter/Dart liên quan «Chỉ BASIC thông dịch».","B":"Cơ chế Flutter/Dart liên quan «Chỉ COBOL batch».","C":"Hai chế độ biên dịch Dart: JIT (dev) và AOT (release).","D":"Cơ chế Flutter/Dart liên quan «Chỉ viết assembly tay»."},"whyWrong":{"A":"• Là gì? Cơ chế Flutter/Dart liên quan «Chỉ BASIC thông dịch».\n• Dùng để làm gì? Đối chiếu đúng cơ chế/phạm trù với trọng tâm đề.\n• Vì sao sai? «Only interpreted BASIC» — Cơ chế Flutter/Dart liên quan «Chỉ BASIC thông dịch». Đề cần: Hai chế độ biên dịch Dart: JIT (dev) và AOT (release).","B":"• Là gì? Cơ chế Flutter/Dart liên quan «Chỉ COBOL batch».\n• Dùng để làm gì? Đối chiếu đúng cơ chế/phạm trù với trọng tâm đề.\n• Vì sao sai? «Only COBOL batch» — Cơ chế Flutter/Dart liên quan «Chỉ COBOL batch». Đề cần: Hai chế độ biên dịch Dart: JIT (dev) và AOT (release).","D":"• Là gì? Cơ chế Flutter/Dart liên quan «Chỉ viết assembly tay».\n• Dùng để làm gì? Đối chiếu đúng cơ chế/phạm trù với trọng tâm đề.\n• Vì sao sai? «Only assembly hand-writing» — Cơ chế Flutter/Dart liên quan «Chỉ viết assembly tay». Đề cần: Hai chế độ biên dịch Dart: JIT (dev) và AOT (release)."}}},{"id":110,"task":"slides","taskLabel":"Slides","num":109,"question":"Which collection type stores ordered elements that may contain duplicates?","options":{"A":"Set","B":"List","C":"Map only without order","D":"Hash without values"},"answer":"B","alternatives":[],"source":"slides","exam":"PRM393_SLIDES_M2","explanation":{"questionVi":"Collection nào lưu phần tử có thứ tự và cho phép trùng?","optionsVi":{"A":"Set","B":"List","C":"Chỉ Map không thứ tự","D":"Hash không có value"},"answerDisplay":"B. List","concept":"• Collection có thứ tự, phần tử truy cập bằng chỉ số, cho phép trùng.","whyCorrect":"• Collection có thứ tự, phần tử truy cập bằng chỉ số, cho phép trùng.\n• Lưu dãy phần tử 0..n-1.","intent":"• Phân biệt List / Set / Map trong Dart.\n• Thứ tự, trùng lặp, hay key–value.","whatIs":{"A":"Tập hợp giá trị không trùng.","B":"Collection có thứ tự, phần tử truy cập bằng chỉ số, cho phép trùng.","C":"Cấu trúc ánh xạ khóa → giá trị.","D":"Cụm «Hash không có value» mang một nghĩa riêng cần đối chiếu với đề."},"whyWrong":{"A":"• Là gì? Tập hợp giá trị không trùng.\n• Dùng để làm gì? Loại trùng, kiểm tra membership.\n• Vì sao sai? Set không cho trùng và không dùng index như List.","C":"• Là gì? Cấu trúc ánh xạ khóa → giá trị.\n• Dùng để làm gì? Tra cứu nhanh theo key.\n• Vì sao sai? «Map only without order» — Cấu trúc ánh xạ khóa → giá trị. Đề cần: Collection có thứ tự, phần tử truy cập bằng chỉ số, cho phép trùng.","D":"• Là gì? Cụm «Hash không có value» mang một nghĩa riêng cần đối chiếu với đề.\n• Dùng để làm gì? So bản chất với đáp án đúng; loại nếu sai đối tượng hoặc sai lớp khái niệm.\n• Vì sao sai? «Hash without values» — Cụm «Hash không có value» mang một nghĩa riêng cần đối chiếu với đề. Đề cần: Collection có thứ tự, phần tử truy cập bằng chỉ số, cho phép trùng."}}},{"id":111,"task":"slides","taskLabel":"Slides","num":110,"question":"Which collection stores unique values only?","options":{"A":"Set","B":"List always allowing duplicates only","C":"String buffer only","D":"StreamController only"},"answer":"A","alternatives":[],"source":"slides","exam":"PRM393_SLIDES_M2","explanation":{"questionVi":"Collection nào chỉ lưu các giá trị không trùng?","optionsVi":{"A":"Set","B":"Chỉ List luôn cho phép trùng","C":"Chỉ string buffer","D":"Chỉ StreamController"},"answerDisplay":"A. Set","concept":"• Tập hợp giá trị không trùng. Loại trùng, kiểm tra membership.","whyCorrect":"• Tập hợp giá trị không trùng.\n• Loại trùng, kiểm tra membership.","intent":"• Phân biệt List / Set / Map trong Dart.\n• Thứ tự, trùng lặp, hay key–value.","whatIs":{"A":"Tập hợp giá trị không trùng.","B":"Collection có thứ tự, phần tử truy cập bằng chỉ số, cho phép trùng.","C":"Cụm «Chỉ string buffer» mang một nghĩa riêng cần đối chiếu với đề.","D":"Cơ chế Flutter/Dart liên quan «Chỉ StreamController»."},"whyWrong":{"B":"• Là gì? Collection có thứ tự, phần tử truy cập bằng chỉ số, cho phép trùng.\n• Dùng để làm gì? Lưu dãy phần tử 0..n-1.\n• Vì sao sai? List cho phép phần tử trùng; Set mới unique.","C":"• Là gì? Cụm «Chỉ string buffer» mang một nghĩa riêng cần đối chiếu với đề.\n• Dùng để làm gì? So bản chất với đáp án đúng; loại nếu sai đối tượng hoặc sai lớp khái niệm.\n• Vì sao sai? «String buffer only» — Cụm «Chỉ string buffer» mang một nghĩa riêng cần đối chiếu với đề. Đề cần: Tập hợp giá trị không trùng.","D":"• Là gì? Cơ chế Flutter/Dart liên quan «Chỉ StreamController».\n• Dùng để làm gì? Đối chiếu đúng cơ chế/phạm trù với trọng tâm đề.\n• Vì sao sai? «StreamController only» — Cơ chế Flutter/Dart liên quan «Chỉ StreamController». Đề cần: Tập hợp giá trị không trùng."}}},{"id":112,"task":"slides","taskLabel":"Slides","num":111,"question":"What does a Map primarily store in Dart?","options":{"A":"Only one integer","B":"Only UI widgets","C":"Key–value pairs","D":"Only file handles"},"answer":"C","alternatives":[],"source":"slides","exam":"PRM393_SLIDES_M2","explanation":{"questionVi":"Map trong Dart chủ yếu lưu gì?","optionsVi":{"A":"Chỉ một số nguyên","B":"Chỉ widget UI","C":"Các cặp key–value","D":"Chỉ file handle"},"answerDisplay":"C. Các cặp key–value","concept":"• Cấu trúc ánh xạ khóa → giá trị. Tra cứu nhanh theo key.","whyCorrect":"• Cấu trúc ánh xạ khóa → giá trị.\n• Tra cứu nhanh theo key.","intent":"• Phân biệt List / Set / Map trong Dart.\n• Thứ tự, trùng lặp, hay key–value.","whatIs":{"A":"Cơ chế Flutter/Dart liên quan «Chỉ một số nguyên».","B":"Cơ chế Flutter/Dart liên quan «Chỉ widget UI».","C":"Cấu trúc ánh xạ khóa → giá trị.","D":"Cơ chế Flutter/Dart liên quan «Chỉ file handle»."},"whyWrong":{"A":"• Là gì? Cơ chế Flutter/Dart liên quan «Chỉ một số nguyên».\n• Dùng để làm gì? Đối chiếu đúng cơ chế/phạm trù với trọng tâm đề.\n• Vì sao sai? «Only one integer» — Cơ chế Flutter/Dart liên quan «Chỉ một số nguyên». Đề cần: Cấu trúc ánh xạ khóa → giá trị.","B":"• Là gì? Cơ chế Flutter/Dart liên quan «Chỉ widget UI».\n• Dùng để làm gì? Đối chiếu đúng cơ chế/phạm trù với trọng tâm đề.\n• Vì sao sai? «Only UI widgets» — Cơ chế Flutter/Dart liên quan «Chỉ widget UI». Đề cần: Cấu trúc ánh xạ khóa → giá trị.","D":"• Là gì? Cơ chế Flutter/Dart liên quan «Chỉ file handle».\n• Dùng để làm gì? Đối chiếu đúng cơ chế/phạm trù với trọng tâm đề.\n• Vì sao sai? «Only file handles» — Cơ chế Flutter/Dart liên quan «Chỉ file handle». Đề cần: Cấu trúc ánh xạ khóa → giá trị."}}},{"id":113,"task":"slides","taskLabel":"Slides","num":112,"question":"Which keyword creates a compile-time constant in Dart?","options":{"A":"var","B":"const","C":"dynamic always","D":"late without value forever"},"answer":"B","alternatives":[],"source":"slides","exam":"PRM393_SLIDES_M2","explanation":{"questionVi":"Từ khóa nào tạo hằng compile-time trong Dart?","optionsVi":{"A":"var","B":"const","C":"Luôn dynamic","D":"late mà không gán giá trị mãi"},"answerDisplay":"B. const","concept":"• Ngôn ngữ lập trình chính của Flutter. Viết UI và logic app Flutter.","whyCorrect":"• Ngôn ngữ lập trình chính của Flutter.\n• Viết UI và logic app Flutter.","intent":"• Phân biệt const, final, var và null safety.\n• Compile-time vs runtime assignment.","memoryTip":"• const = compile-time; final = gán 1 lần runtime.","whatIs":{"A":"Khai báo biến với kiểu suy luận; có thể gán lại (trừ khi final).","B":"Ngôn ngữ lập trình chính của Flutter.","C":"Tắt kiểm tra kiểu tĩnh; kiểm tra chủ yếu lúc chạy.","D":"late mà không gán giá trị mãi"},"whyWrong":{"A":"• Là gì? Khai báo biến với kiểu suy luận; có thể gán lại (trừ khi final).\n• Dùng để làm gì? Viết gọn khi kiểu rõ từ vế phải.\n• Vì sao sai? var chỉ suy luận kiểu, không tạo hằng compile-time.","C":"• Là gì? Tắt kiểm tra kiểu tĩnh; kiểm tra chủ yếu lúc chạy.\n• Dùng để làm gì? Linh hoạt nhưng dễ lỗi runtime.\n• Vì sao sai? dynamic nới lỏng kiểu, không phải const.","D":"• Là gì? late mà không gán giá trị mãi\n• Dùng để làm gì? Bản dịch/diễn đạt phương án — đối chiếu với định nghĩa chuẩn của đề.\n• Vì sao sai? «late without value forever» — late mà không gán giá trị mãi. Đề cần: Ngôn ngữ lập trình chính của Flutter."}}},{"id":114,"task":"slides","taskLabel":"Slides","num":113,"question":"What is null safety designed to help with?","options":{"A":"Prevent unexpected null errors by making types non-nullable by default","B":"Force every variable to be null always","C":"Disable type checking completely","D":"Replace HTTP with FTP"},"answer":"A","alternatives":[],"source":"slides","exam":"PRM393_SLIDES_M2","explanation":{"questionVi":"Null safety được thiết kế để giúp điều gì?","optionsVi":{"A":"Giảm lỗi null bất ngờ bằng kiểu non-nullable mặc định","B":"Ép mọi biến luôn null","C":"Tắt hoàn toàn kiểm tra kiểu","D":"Thay HTTP bằng FTP"},"answerDisplay":"A. Giảm lỗi null bất ngờ bằng kiểu non-nullable mặc định","concept":"• Hệ thống kiểu Dart phân biệt null/non-null để giảm crash.","whyCorrect":"• Hệ thống kiểu Dart phân biệt null/non-null để giảm crash.\n• Bắt buộc khởi tạo non-nullable trước khi dùng.","intent":"• Phân biệt const, final, var và null safety.\n• Compile-time vs runtime assignment.","whatIs":{"A":"Hệ thống kiểu Dart phân biệt null/non-null để giảm crash.","B":"Cụm «Ép mọi biến luôn null» mang một nghĩa riêng cần đối chiếu với đề.","C":"Tắt hoàn toàn kiểm tra kiểu","D":"Cơ chế/thuật ngữ CNTT «Thay HTTP bằng FTP»."},"whyWrong":{"B":"• Là gì? Cụm «Ép mọi biến luôn null» mang một nghĩa riêng cần đối chiếu với đề.\n• Dùng để làm gì? So bản chất với đáp án đúng; loại nếu sai đối tượng hoặc sai lớp khái niệm.\n• Vì sao sai? «Force every variable to be null always» — Cụm «Ép mọi biến luôn null» mang một nghĩa riêng cần đối chiếu với đề. Đề cần: Hệ thống kiểu Dart phân biệt null/non-null để giảm crash.","C":"• Là gì? Tắt hoàn toàn kiểm tra kiểu\n• Dùng để làm gì? Bản dịch/diễn đạt phương án — đối chiếu với định nghĩa chuẩn của đề.\n• Vì sao sai? «Disable type checking completely» — Tắt hoàn toàn kiểm tra kiểu. Đề cần: Hệ thống kiểu Dart phân biệt null/non-null để giảm crash.","D":"• Là gì? Cơ chế/thuật ngữ CNTT «Thay HTTP bằng FTP».\n• Dùng để làm gì? Đối chiếu đúng định nghĩa/đặc trưng kỹ thuật mà đề hỏi.\n• Vì sao sai? Gói http gọi API; không quản lý state UI hay storage local."}}},{"id":115,"task":"slides","taskLabel":"Slides","num":114,"question":"If a non-nullable variable is not initialized before use, what typically happens?","options":{"A":"It silently becomes null","B":"The OS reboots","C":"A compile-time error occurs","D":"Git commits fail"},"answer":"C","alternatives":[],"source":"slides","exam":"PRM393_SLIDES_M2","explanation":{"questionVi":"Nếu biến non-nullable chưa khởi tạo mà đã dùng thì thường xảy ra gì?","optionsVi":{"A":"Im lặng thành null","B":"Hệ điều hành khởi động lại","C":"Xảy ra lỗi compile-time","D":"Git commit thất bại"},"answerDisplay":"C. Xảy ra lỗi compile-time","concept":"• Hệ thống kiểu Dart phân biệt null/non-null để giảm crash.","whyCorrect":"• Hệ thống kiểu Dart phân biệt null/non-null để giảm crash.\n• Bắt buộc khởi tạo non-nullable trước khi dùng.","intent":"• Phân biệt const, final, var và null safety.\n• Compile-time vs runtime assignment.","whatIs":{"A":"Cụm «Im lặng thành null» mang một nghĩa riêng cần đối chiếu với đề.","B":"Phần mềm quản lý phần cứng, tiến trình, bộ nhớ, I/O.","C":"Hệ thống kiểu Dart phân biệt null/non-null để giảm crash.","D":"Cụm «Git commit thất bại» mang một nghĩa riêng cần đối chiếu với đề."},"whyWrong":{"A":"• Là gì? Cụm «Im lặng thành null» mang một nghĩa riêng cần đối chiếu với đề.\n• Dùng để làm gì? So bản chất với đáp án đúng; loại nếu sai đối tượng hoặc sai lớp khái niệm.\n• Vì sao sai? «It silently becomes null» — Cụm «Im lặng thành null» mang một nghĩa riêng cần đối chiếu với đề. Đề cần: Hệ thống kiểu Dart phân biệt null/non-null để giảm crash.","B":"• Là gì? Phần mềm quản lý phần cứng, tiến trình, bộ nhớ, I/O.\n• Dùng để làm gì? Cấp tài nguyên và lập lịch cho chương trình.\n• Vì sao sai? «The OS reboots» — Phần mềm quản lý phần cứng, tiến trình, bộ nhớ, I/O. Đề cần: Hệ thống kiểu Dart phân biệt null/non-null để giảm crash.","D":"• Là gì? Cụm «Git commit thất bại» mang một nghĩa riêng cần đối chiếu với đề.\n• Dùng để làm gì? So bản chất với đáp án đúng; loại nếu sai đối tượng hoặc sai lớp khái niệm.\n• Vì sao sai? Git quản lý phiên bản code — chỉ đúng khi hỏi version control."}}},{"id":116,"task":"slides","taskLabel":"Slides","num":115,"question":"Which statement about Dart classes is correct?","options":{"A":"Dart is not object-oriented","B":"Dart is object-oriented; classes are blueprints for objects","C":"Classes cannot have methods","D":"Objects cannot be created from classes"},"answer":"B","alternatives":[],"source":"slides","exam":"PRM393_SLIDES_M2","explanation":{"questionVi":"Phát biểu nào về class Dart là đúng?","optionsVi":{"A":"Dart không hướng đối tượng","B":"Dart hướng đối tượng; class là bản thiết kế cho object","C":"Class không thể có method","D":"Không tạo được object từ class"},"answerDisplay":"B. Dart hướng đối tượng; class là bản thiết kế cho object","concept":"• Ngôn ngữ lập trình chính của Flutter. Viết UI và logic app Flutter.","whyCorrect":"• Ngôn ngữ lập trình chính của Flutter.\n• Viết UI và logic app Flutter.","intent":"• Ngôn ngữ lập trình chính của Flutter.\n• Viết UI và logic app Flutter.","whatIs":{"A":"Ngôn ngữ lập trình chính của Flutter.","B":"Ngôn ngữ lập trình chính của Flutter.","C":"Class không thể có method","D":"Không tạo được object từ class"},"whyWrong":{"A":"• Là gì? Ngôn ngữ lập trình chính của Flutter.\n• Dùng để làm gì? Viết UI và logic app Flutter.\n• Vì sao sai? «Dart is not object-oriented» lệch đối tượng/cơ chế so với đáp án đúng của đề.","C":"• Là gì? Class không thể có method\n• Dùng để làm gì? Bản dịch/diễn đạt phương án — đối chiếu với định nghĩa chuẩn của đề.\n• Vì sao sai? «Classes cannot have methods» — Class không thể có method. Đề cần: Ngôn ngữ lập trình chính của Flutter.","D":"• Là gì? Không tạo được object từ class\n• Dùng để làm gì? Bản dịch/diễn đạt phương án — đối chiếu với định nghĩa chuẩn của đề.\n• Vì sao sai? «Objects cannot be created from classes» — Không tạo được object từ class. Đề cần: Ngôn ngữ lập trình chính của Flutter."}}},{"id":117,"task":"slides","taskLabel":"Slides","num":116,"question":"What does string interpolation like \"$name\" do?","options":{"A":"Embeds expression/variable values into a string","B":"Encrypts the string with AES","C":"Deletes the variable","D":"Starts a new isolate always"},"answer":"A","alternatives":[],"source":"slides","exam":"PRM393_SLIDES_M2","explanation":{"questionVi":"String interpolation kiểu $name dùng để làm gì?","optionsVi":{"A":"Chèn giá trị biến/biểu thức vào chuỗi","B":"Mã hóa chuỗi bằng AES","C":"Xóa biến","D":"Luôn tạo isolate mới"},"answerDisplay":"A. Chèn giá trị biến/biểu thức vào chuỗi","concept":"• Chèn biến/biểu thức vào literal chuỗi (`$x`, `${expr}`).","whyCorrect":"• Chèn biến/biểu thức vào literal chuỗi (`$x`, `${expr}`).\n• Tạo chuỗi động gọn hơn nối +.","intent":"• Chèn biến/biểu thức vào literal chuỗi (`$x`, `${expr}`).\n• Tạo chuỗi động gọn hơn nối +.","whatIs":{"A":"Chèn biến/biểu thức vào literal chuỗi (`$x`, `${expr}`).","B":"Cụm «Mã hóa chuỗi bằng AES» mang một nghĩa riêng cần đối chiếu với đề.","C":"Cụm «Xóa biến» mang một nghĩa riêng cần đối chiếu với đề.","D":"Cụm «Luôn tạo isolate mới» mang một nghĩa riêng cần đối chiếu với đề."},"whyWrong":{"B":"• Là gì? Cụm «Mã hóa chuỗi bằng AES» mang một nghĩa riêng cần đối chiếu với đề.\n• Dùng để làm gì? So bản chất với đáp án đúng; loại nếu sai đối tượng hoặc sai lớp khái niệm.\n• Vì sao sai? «Encrypts the string with AES» — Cụm «Mã hóa chuỗi bằng AES» mang một nghĩa riêng cần đối chiếu với đề. Đề cần: Chèn biến/biểu thức vào literal chuỗi (`$x`, `${expr}`).","C":"• Là gì? Cụm «Xóa biến» mang một nghĩa riêng cần đối chiếu với đề.\n• Dùng để làm gì? So bản chất với đáp án đúng; loại nếu sai đối tượng hoặc sai lớp khái niệm.\n• Vì sao sai? «Deletes the variable» — Cụm «Xóa biến» mang một nghĩa riêng cần đối chiếu với đề. Đề cần: Chèn biến/biểu thức vào literal chuỗi (`$x`, `${expr}`).","D":"• Là gì? Cụm «Luôn tạo isolate mới» mang một nghĩa riêng cần đối chiếu với đề.\n• Dùng để làm gì? So bản chất với đáp án đúng; loại nếu sai đối tượng hoặc sai lớp khái niệm.\n• Vì sao sai? «Starts a new isolate always» — Cụm «Luôn tạo isolate mới» mang một nghĩa riêng cần đối chiếu với đề. Đề cần: Chèn biến/biểu thức vào literal chuỗi (`$x`, `${expr}`)."}}},{"id":118,"task":"slides","taskLabel":"Slides","num":117,"question":"Which type annotation is appropriate for a list of integers?","options":{"A":"List<String> only for ints","B":"List<int>","C":"Map<int> without value type","D":"Set<void>"},"answer":"B","alternatives":[],"source":"slides","exam":"PRM393_SLIDES_M2","explanation":{"questionVi":"Annotation kiểu nào phù hợp cho list số nguyên?","optionsVi":{"A":"List<String> chỉ cho số nguyên","B":"List<int>","C":"Map<int> thiếu kiểu value","D":"Set<void>"},"answerDisplay":"B. List<int>","concept":"• Collection có thứ tự, phần tử truy cập bằng chỉ số, cho phép trùng.","whyCorrect":"• Collection có thứ tự, phần tử truy cập bằng chỉ số, cho phép trùng.\n• Lưu dãy phần tử 0..n-1.","intent":"• Phân biệt List / Set / Map trong Dart.\n• Thứ tự, trùng lặp, hay key–value.","whatIs":{"A":"Collection có thứ tự, phần tử truy cập bằng chỉ số, cho phép trùng.","B":"Collection có thứ tự, phần tử truy cập bằng chỉ số, cho phép trùng.","C":"Cấu trúc ánh xạ khóa → giá trị.","D":"Tập hợp giá trị không trùng."},"whyWrong":{"A":"• Là gì? Collection có thứ tự, phần tử truy cập bằng chỉ số, cho phép trùng.\n• Dùng để làm gì? Lưu dãy phần tử 0..n-1.\n• Vì sao sai? «List<String> only for ints» lệch đối tượng/cơ chế so với đáp án đúng của đề.","C":"• Là gì? Cấu trúc ánh xạ khóa → giá trị.\n• Dùng để làm gì? Tra cứu nhanh theo key.\n• Vì sao sai? «Map<int> without value type» — Cấu trúc ánh xạ khóa → giá trị. Đề cần: Collection có thứ tự, phần tử truy cập bằng chỉ số, cho phép trùng.","D":"• Là gì? Tập hợp giá trị không trùng.\n• Dùng để làm gì? Loại trùng, kiểm tra membership.\n• Vì sao sai? Set không cho trùng và không dùng index như List."}}},{"id":119,"task":"slides","taskLabel":"Slides","num":118,"question":"Functions in Dart are described as:","options":{"A":"Never first-class","B":"Only allowed inside C++","C":"First-class objects (can be assigned/passed)","D":"Forbidden in Flutter"},"answer":"C","alternatives":[],"source":"slides","exam":"PRM393_SLIDES_M2","explanation":{"questionVi":"Hàm trong Dart được mô tả là:","optionsVi":{"A":"Không bao giờ first-class","B":"Chỉ được phép trong C++","C":"Đối tượng first-class (gán/truyền được)","D":"Bị cấm trong Flutter"},"answerDisplay":"C. Đối tượng first-class (gán/truyền được)","concept":"• Ngôn ngữ lập trình chính của Flutter. Viết UI và logic app Flutter.","whyCorrect":"• Ngôn ngữ lập trình chính của Flutter.\n• Viết UI và logic app Flutter.","intent":"• Ngôn ngữ lập trình chính của Flutter.\n• Viết UI và logic app Flutter.","whatIs":{"A":"Không bao giờ first-class","B":"Cơ chế Flutter/Dart liên quan «Chỉ được phép trong C++».","C":"Ngôn ngữ lập trình chính của Flutter.","D":"Cơ chế Flutter/Dart liên quan «Bị cấm trong Flutter»."},"whyWrong":{"A":"• Là gì? Không bao giờ first-class\n• Dùng để làm gì? Bản dịch/diễn đạt phương án — đối chiếu với định nghĩa chuẩn của đề.\n• Vì sao sai? «Never first-class» — Không bao giờ first-class. Đề cần: Ngôn ngữ lập trình chính của Flutter.","B":"• Là gì? Cơ chế Flutter/Dart liên quan «Chỉ được phép trong C++».\n• Dùng để làm gì? Đối chiếu đúng cơ chế/phạm trù với trọng tâm đề.\n• Vì sao sai? «Only allowed inside C++» — Cơ chế Flutter/Dart liên quan «Chỉ được phép trong C++». Đề cần: Ngôn ngữ lập trình chính của Flutter.","D":"• Là gì? Cơ chế Flutter/Dart liên quan «Bị cấm trong Flutter».\n• Dùng để làm gì? Đối chiếu đúng cơ chế/phạm trù với trọng tâm đề.\n• Vì sao sai? «Forbidden in Flutter» — Cơ chế Flutter/Dart liên quan «Bị cấm trong Flutter». Đề cần: Ngôn ngữ lập trình chính của Flutter."}}},{"id":120,"task":"slides","taskLabel":"Slides","num":119,"question":"What is a common use of a factory constructor mentioned in slides?","options":{"A":"Only painting pixels","B":"Return existing instance / singleton / .fromJson conversion","C":"Delete the class permanently","D":"Disable null safety"},"answer":"B","alternatives":[],"source":"slides","exam":"PRM393_SLIDES_M3","explanation":{"questionVi":"Factory constructor thường dùng để làm gì (theo slide)?","optionsVi":{"A":"Chỉ vẽ pixel","B":"Trả instance có sẵn / singleton / chuyển.fromJson","C":"Xóa class vĩnh viễn","D":"Tắt null safety"},"answerDisplay":"B. Trả instance có sẵn / singleton / chuyển.fromJson","concept":"• Trả instance có sẵn / singleton / chuyển .fromJson. Bản dịch/diễn đạt phương án — đối chiếu với định nghĩa chuẩn của đề.","whyCorrect":"• Trả instance có sẵn / singleton / chuyển .fromJson\n• Bản dịch/diễn đạt phương án — đối chiếu với định nghĩa chuẩn của đề.","intent":"• Phân biệt const, final, var và null safety.\n• Compile-time vs runtime assignment.","memoryTip":"• const = compile-time; final = gán 1 lần runtime.","whatIs":{"A":"Vẽ pixel/lớp đồ họa lên màn hình.","B":"Trả instance có sẵn / singleton / chuyển .fromJson","C":"Cụm «Xóa class vĩnh viễn» mang một nghĩa riêng cần đối chiếu với đề.","D":"Hệ thống kiểu Dart phân biệt null/non-null để giảm crash."},"whyWrong":{"A":"• Là gì? Vẽ pixel/lớp đồ họa lên màn hình.\n• Dùng để làm gì? Thuộc RenderObject/engine (Skia); không phải Handle BuildContext.\n• Vì sao sai? «Only painting pixels» — Vẽ pixel/lớp đồ họa lên màn hình. Đề cần: Trả instance có sẵn / singleton / chuyển .fromJson.","C":"• Là gì? Cụm «Xóa class vĩnh viễn» mang một nghĩa riêng cần đối chiếu với đề.\n• Dùng để làm gì? So bản chất với đáp án đúng; loại nếu sai đối tượng hoặc sai lớp khái niệm.\n• Vì sao sai? PUT/DELETE cập nhật/xóa; không phải thao tác retrieve mặc định.","D":"• Là gì? Hệ thống kiểu Dart phân biệt null/non-null để giảm crash.\n• Dùng để làm gì? Bắt buộc khởi tạo non-nullable trước khi dùng.\n• Vì sao sai? «Disable null safety» — Hệ thống kiểu Dart phân biệt null/non-null để giảm crash. Đề cần: Trả instance có sẵn / singleton / chuyển .fromJson."}}},{"id":121,"task":"slides","taskLabel":"Slides","num":120,"question":"Why is async/await important in Flutter apps?","options":{"A":"Handle asynchronous work without blocking the UI thread","B":"Force UI to freeze during network calls","C":"Replace all widgets with XML","D":"Compile Dart to COBOL"},"answer":"A","alternatives":[],"source":"slides","exam":"PRM393_SLIDES_M3","explanation":{"questionVi":"Vì sao async/await quan trọng trong app Flutter?","optionsVi":{"A":"Xử lý async mà không chặn luồng UI","B":"Ép UI đơ khi gọi mạng","C":"Thay mọi widget bằng XML","D":"Biên dịch Dart sang COBOL"},"answerDisplay":"A. Xử lý async mà không chặn luồng UI","concept":"• Xử lý việc bất đồng bộ mà không chặn luồng UI.","whyCorrect":"• Xử lý việc bất đồng bộ mà không chặn luồng UI.\n• Giữ app mượt khi gọi mạng/I/O (async/await, Future).","intent":"• Xử lý việc bất đồng bộ mà không chặn luồng UI.\n• Chọn phương án khớp cơ chế Flutter, không chọn stack web/Android nhầm.","whatIs":{"A":"Xử lý việc bất đồng bộ mà không chặn luồng UI.","B":"Ép giao diện đơ trong lúc gọi mạng.","C":"Thay mọi widget bằng XML","D":"Ngôn ngữ lập trình chính của Flutter."},"whyWrong":{"B":"• Là gì? Ép giao diện đơ trong lúc gọi mạng.\n• Dùng để làm gì? Phản pattern async — trái mục tiêu async/await.\n• Vì sao sai? «Force UI to freeze during network calls» — Ép giao diện đơ trong lúc gọi mạng. Đề cần: Xử lý việc bất đồng bộ mà không chặn luồng UI.","C":"• Là gì? Thay mọi widget bằng XML\n• Dùng để làm gì? Bản dịch/diễn đạt phương án — đối chiếu với định nghĩa chuẩn của đề.\n• Vì sao sai? Flutter không dựng UI chính bằng XML/HTML/CSS như Android View/web cổ điển.","D":"• Là gì? Ngôn ngữ lập trình chính của Flutter.\n• Dùng để làm gì? Viết UI và logic app Flutter.\n• Vì sao sai? «Compile Dart to COBOL» — Ngôn ngữ lập trình chính của Flutter. Đề cần: Xử lý việc bất đồng bộ mà không chặn luồng UI."}}},{"id":122,"task":"slides","taskLabel":"Slides","num":121,"question":"What does a Future represent?","options":{"A":"A completed widget tree only","B":"A synchronous int always","C":"A value or error that will be available later","D":"A GPU shader"},"answer":"C","alternatives":[],"source":"slides","exam":"PRM393_SLIDES_M3","explanation":{"questionVi":"Future đại diện cho điều gì?","optionsVi":{"A":"Chỉ một cây widget đã hoàn tất","B":"Luôn là số nguyên đồng bộ","C":"Một giá trị hoặc lỗi sẽ có sau (async)","D":"Một GPU shader"},"answerDisplay":"C. Một giá trị hoặc lỗi sẽ có sau (async)","concept":"• Đối tượng đại diện một kết quả (hoặc lỗi) sẽ có sau thao tác bất đồng bộ.","whyCorrect":"• Đối tượng đại diện một kết quả (hoặc lỗi) sẽ có sau thao tác bất đồng bộ.\n• async/await, gọi API, đọc file một lần.","intent":"• Future: một kết quả async.\n• Stream: nhiều sự kiện theo thời gian.","memoryTip":"• Future: 1 lần; Stream: nhiều lần.","whatIs":{"A":"Cây cấu hình UI lồng nhau mô tả giao diện tại một thời điểm.","B":"Một số nguyên có ngay lập tức (đồng bộ), không chờ I/O.","C":"Đối tượng đại diện một kết quả (hoặc lỗi) sẽ có sau thao tác bất đồng bộ.","D":"Chương trình nhỏ chạy trên GPU để xử lý đồ họa."},"whyWrong":{"A":"• Là gì? Cây cấu hình UI lồng nhau mô tả giao diện tại một thời điểm.\n• Dùng để làm gì? Đầu vào cho Element/Render pipeline của Flutter.\n• Vì sao sai? Cây widget mô tả UI; Future mô tả kết quả bất đồng bộ — khác tầng khái niệm.","B":"• Là gì? Một số nguyên có ngay lập tức (đồng bộ), không chờ I/O.\n• Dùng để làm gì? Giá trị sync; khác Future (async later).\n• Vì sao sai? Số nguyên đồng bộ có ngay; Future là giá trị/error sẽ có sau (async).","D":"• Là gì? Chương trình nhỏ chạy trên GPU để xử lý đồ họa.\n• Dùng để làm gì? Vẽ/hiệu ứng; không phải mô hình async Future.\n• Vì sao sai? GPU shader phục vụ đồ họa; không phải mô hình async một kết quả của Future."}}},{"id":123,"task":"slides","taskLabel":"Slides","num":122,"question":"What does a Stream provide compared to a single Future?","options":{"A":"Exactly one value then ends always only","B":"A sequence of asynchronous events/values over time","C":"Only file system permissions","D":"Only compile-time constants"},"answer":"B","alternatives":[],"source":"slides","exam":"PRM393_SLIDES_M3","explanation":{"questionVi":"So với một Future đơn lẻ, Stream cung cấp gì thêm?","optionsVi":{"A":"Chỉ đúng một giá trị rồi kết thúc","B":"Chuỗi sự kiện/giá trị bất đồng bộ theo thời gian","C":"Chỉ quyền hệ thống tệp","D":"Chỉ hằng số compile-time"},"answerDisplay":"B. Chuỗi sự kiện/giá trị bất đồng bộ theo thời gian","concept":"• Stream: chuỗi sự kiện/giá trị bất đồng bộ theo thời gian (khác Future one-shot).","whyCorrect":"• Stream: chuỗi sự kiện/giá trị bất đồng bộ theo thời gian (khác Future one-shot).\n• Lắng nghe nhiều lần: click stream, data chunk, BLoC states…","intent":"• Future: một kết quả async.\n• Stream: nhiều sự kiện theo thời gian.","memoryTip":"• Future: 1 lần; Stream: nhiều lần.","whatIs":{"A":"Mô tả Future: chỉ một kết quả async rồi hoàn tất (one-shot).","B":"Stream: chuỗi sự kiện/giá trị bất đồng bộ theo thời gian (khác Future one-shot).","C":"Quyền truy cập file/thư mục do hệ điều hành cấp (read/write/execute).","D":"Hằng số xác định từ lúc biên dịch (const trong Dart)."},"whyWrong":{"A":"• Là gì? Mô tả Future: chỉ một kết quả async rồi hoàn tất (one-shot).\n• Dùng để làm gì? Đại diện một giá trị/error sẽ có sau — không phải chuỗi sự kiện.\n• Vì sao sai? Đây là mô tả Future (một giá trị rồi xong). Đề hỏi Stream — chuỗi nhiều sự kiện theo thời gian.","C":"• Là gì? Quyền truy cập file/thư mục do hệ điều hành cấp (read/write/execute).\n• Dùng để làm gì? Kiểm soát bảo mật hệ thống tệp — không phải mô hình async Stream/Future.\n• Vì sao sai? Quyền hệ thống tệp thuộc bảo mật OS; Stream là mô hình async phát nhiều event, không cấp quyền file.","D":"• Là gì? Hằng số xác định từ lúc biên dịch (const trong Dart).\n• Dùng để làm gì? Giá trị cố định compile-time; không phát sự kiện async theo thời gian.\n• Vì sao sai? Hằng compile-time (const) là giá trị cố định lúc biên dịch; Stream là chuỗi async runtime."}}},{"id":124,"task":"slides","taskLabel":"Slides","num":123,"question":"How do packages and imports help structure Dart code?","options":{"A":"Organize reusable libraries and dependencies","B":"Increase APK size without any reuse","C":"Remove null safety","D":"Replace the Flutter engine"},"answer":"A","alternatives":[],"source":"slides","exam":"PRM393_SLIDES_M3","explanation":{"questionVi":"Package và import giúp tổ chức mã Dart như thế nào?","optionsVi":{"A":"Tổ chức thư viện tái sử dụng và dependency","B":"Làm phình APK mà không tái sử dụng gì","C":"Gỡ bỏ null safety","D":"Thay thế Flutter engine"},"answerDisplay":"A. Tổ chức thư viện tái sử dụng và dependency","concept":"• Cách package/import tổ chức thư viện và dependency để tái sử dụng.","whyCorrect":"• Cách package/import tổ chức thư viện và dependency để tái sử dụng.\n• Tách module, import có kiểm soát, chia sẻ code giữa project.","intent":"• Cách package/import tổ chức thư viện và dependency để tái sử dụng.\n• Tách module, import có kiểm soát, chia sẻ code giữa project.","whatIs":{"A":"Cách package/import tổ chức thư viện và dependency để tái sử dụng.","B":"Phát biểu làm phình APK mà không mang lại tái sử dụng code.","C":"Hệ thống kiểu Dart phân biệt null/non-null để giảm crash.","D":"Cơ chế Flutter/Dart liên quan «Thay thế Flutter engine»."},"whyWrong":{"B":"• Là gì? Phát biểu làm phình APK mà không mang lại tái sử dụng code.\n• Dùng để làm gì? Trái mục tiêu package/import (tái sử dụng, module hóa).\n• Vì sao sai? Package/import nhằm tái sử dụng module; làm phình APK không reuse là trái mục tiêu.","C":"• Là gì? Hệ thống kiểu Dart phân biệt null/non-null để giảm crash.\n• Dùng để làm gì? Bắt buộc khởi tạo non-nullable trước khi dùng.\n• Vì sao sai? Null safety là hệ thống kiểu; package/import không gỡ null safety.","D":"• Là gì? Cơ chế Flutter/Dart liên quan «Thay thế Flutter engine».\n• Dùng để làm gì? Đối chiếu đúng cơ chế/phạm trù với trọng tâm đề.\n• Vì sao sai? Engine là tầng render native; package/import tổ chức mã Dart, không thay engine."}}},{"id":125,"task":"slides","taskLabel":"Slides","num":124,"question":"What is .fromJson() typically used for?","options":{"A":"Drawing custom paint","B":"Converting JSON map data into a Dart model object","C":"Starting the emulator","D":"Signing release APKs"},"answer":"B","alternatives":[],"source":"slides","exam":"PRM393_SLIDES_M3","explanation":{"questionVi":".fromJson() thường dùng để làm gì?","optionsVi":{"A":"Vẽ custom paint","B":"Chuyển map JSON thành object model Dart","C":"Khởi động emulator","D":"Ký APK bản release"},"answerDisplay":"B. Chuyển map JSON thành object model Dart","concept":"• Cấu trúc ánh xạ khóa → giá trị. Tra cứu nhanh theo key.","whyCorrect":"• Cấu trúc ánh xạ khóa → giá trị.\n• Tra cứu nhanh theo key.","intent":"• Cấu trúc ánh xạ khóa → giá trị.\n• Tra cứu nhanh theo key.","whatIs":{"A":"Vẽ pixel/lớp đồ họa lên màn hình.","B":"Cấu trúc ánh xạ khóa → giá trị.","C":"Cụm «Khởi động emulator» mang một nghĩa riêng cần đối chiếu với đề.","D":"Cụm «Ký APK bản release» mang một nghĩa riêng cần đối chiếu với đề."},"whyWrong":{"A":"• Là gì? Vẽ pixel/lớp đồ họa lên màn hình.\n• Dùng để làm gì? Thuộc RenderObject/engine (Skia); không phải Handle BuildContext.\n• Vì sao sai? «Drawing custom paint» — Vẽ pixel/lớp đồ họa lên màn hình. Đề cần: Cấu trúc ánh xạ khóa → giá trị.","C":"• Là gì? Cụm «Khởi động emulator» mang một nghĩa riêng cần đối chiếu với đề.\n• Dùng để làm gì? So bản chất với đáp án đúng; loại nếu sai đối tượng hoặc sai lớp khái niệm.\n• Vì sao sai? Emulator chạy app giả lập; không phải công cụ phân tích performance.","D":"• Là gì? Cụm «Ký APK bản release» mang một nghĩa riêng cần đối chiếu với đề.\n• Dùng để làm gì? So bản chất với đáp án đúng; loại nếu sai đối tượng hoặc sai lớp khái niệm.\n• Vì sao sai? «Signing release APKs» — Cụm «Ký APK bản release» mang một nghĩa riêng cần đối chiếu với đề. Đề cần: Cấu trúc ánh xạ khóa → giá trị."}}},{"id":126,"task":"slides","taskLabel":"Slides","num":125,"question":"Which practice is recommended for long-running CPU work?","options":{"A":"Run heavy loops directly in every build()","B":"Block the main isolate forever","C":"Use async patterns / avoid blocking UI (and isolates when needed)","D":"Disable the UI thread intentionally"},"answer":"C","alternatives":[],"source":"slides","exam":"PRM393_SLIDES_M3","explanation":{"questionVi":"Thực hành nào được khuyến nghị cho việc CPU chạy lâu?","optionsVi":{"A":"Chạy vòng lặp nặng ngay trong mọi build()","B":"Chặn main isolate mãi mãi","C":"Dùng async patterns / Tránh chặn UI (và isolates Khi needed)","D":"Tắt luồng UI intentionally"},"answerDisplay":"C. Dùng async patterns / Tránh chặn UI (và isolates Khi needed)","concept":"• Tiến trình đang chiếm CPU và thực thi lệnh.","whyCorrect":"• Tiến trình đang chiếm CPU và thực thi lệnh.\n• Đang làm việc trên bộ xử lý.","intent":"• OS quản lý tiến trình qua các trạng thái.\n• Chờ I/O (Waiting) khác chờ CPU (Ready) và khác Suspended.","whatIs":{"A":"Chạy vòng lặp nặng ngay trong mọi build()","B":"Cách chia sẻ và phản ứng với trạng thái dùng chung giữa nhiều widget/màn.","C":"Tiến trình đang chiếm CPU và thực thi lệnh.","D":"Tắt luồng UI intentionally"},"whyWrong":{"A":"• Là gì? Chạy vòng lặp nặng ngay trong mọi build()\n• Dùng để làm gì? Bản dịch/diễn đạt phương án — đối chiếu với định nghĩa chuẩn của đề.\n• Vì sao sai? build() mô tả UI; không phải chỗ gọi để “cập nhật state”.","B":"• Là gì? Cách chia sẻ và phản ứng với trạng thái dùng chung giữa nhiều widget/màn.\n• Dùng để làm gì? Tránh truyền prop sâu; cập nhật UI khi state đổi.\n• Vì sao sai? «Block the main isolate forever» — Cách chia sẻ và phản ứng với trạng thái dùng chung giữa nhiều widget/màn. Đề cần: Tiến trình đang chiếm CPU và thực thi lệnh.","D":"• Là gì? Tắt luồng UI intentionally\n• Dùng để làm gì? Bản dịch/diễn đạt phương án — đối chiếu với định nghĩa chuẩn của đề.\n• Vì sao sai? «Disable the UI thread intentionally» — Tắt luồng UI intentionally. Đề cần: Tiến trình đang chiếm CPU và thực thi lệnh."}}},{"id":127,"task":"slides","taskLabel":"Slides","num":126,"question":"What does await do when used with a Future?","options":{"A":"Suspends the async function until the Future completes","B":"Cancels null safety","C":"Converts widgets to HTML","D":"Forces a hot restart"},"answer":"A","alternatives":[],"source":"slides","exam":"PRM393_SLIDES_M3","explanation":{"questionVi":"await làm gì khi dùng với Future?","optionsVi":{"A":"Tạm dừng hàm async đến khi Future hoàn tất","B":"Cancels null safety","C":"Converts widgets để HTML","D":"Forces một hot restart"},"answerDisplay":"A. Tạm dừng hàm async đến khi Future hoàn tất","concept":"• Tạm dừng hàm async cho đến khi Future hoàn tất, rồi trả kết quả.","whyCorrect":"• Tạm dừng hàm async cho đến khi Future hoàn tất, rồi trả kết quả.\n• Cú pháp await: viết async tuần tự, không block isolate bằng busy-wait.","intent":"• Future: một kết quả async.\n• Stream: nhiều sự kiện theo thời gian.","memoryTip":"• Future: 1 lần; Stream: nhiều lần.","whatIs":{"A":"Tạm dừng hàm async cho đến khi Future hoàn tất, rồi trả kết quả.","B":"Hệ thống kiểu Dart phân biệt null/non-null để giảm crash.","C":"Converts widgets để HTML","D":"Chạy lại app từ đầu, reset state."},"whyWrong":{"B":"• Là gì? Hệ thống kiểu Dart phân biệt null/non-null để giảm crash.\n• Dùng để làm gì? Bắt buộc khởi tạo non-nullable trước khi dùng.\n• Vì sao sai? «Cancels null safety» — Hệ thống kiểu Dart phân biệt null/non-null để giảm crash. Đề cần: Tạm dừng hàm async cho đến khi Future hoàn tất, rồi trả kết quả.","C":"• Là gì? Converts widgets để HTML\n• Dùng để làm gì? Bản dịch/diễn đạt phương án — đối chiếu với định nghĩa chuẩn của đề.\n• Vì sao sai? Flutter không dựng UI chính bằng XML/HTML/CSS như Android View/web cổ điển.","D":"• Là gì? Chạy lại app từ đầu, reset state.\n• Dùng để làm gì? Khi cần khởi tạo lại toàn bộ sau đổi lớn.\n• Vì sao sai? «Forces a hot restart» — Chạy lại app từ đầu, reset state. Đề cần: Tạm dừng hàm async cho đến khi Future hoàn tất, rồi trả kết quả."}}},{"id":128,"task":"slides","taskLabel":"Slides","num":127,"question":"Which is a valid reason to use a singleton via factory?","options":{"A":"To create millions of identical DB connections every frame","B":"To reuse one shared service instance","C":"To avoid all state management","D":"To replace Navigator"},"answer":"B","alternatives":[],"source":"slides","exam":"PRM393_SLIDES_M3","explanation":{"questionVi":"Lý do hợp lệ nào để dùng singleton qua factory?","optionsVi":{"A":"Để Tạo millions củ identical DB connections mọi frame","B":"để tái sử dụng một shared service instance","C":"để Tránh tất cả quản lý state","D":"để Thay thế Navigator"},"answerDisplay":"B. để tái sử dụng một shared service instance","concept":"• để tái sử dụng một shared service instance. Bản dịch/diễn đạt phương án — đối chiếu với định nghĩa chuẩn của đề.","whyCorrect":"• để tái sử dụng một shared service instance\n• Bản dịch/diễn đạt phương án — đối chiếu với định nghĩa chuẩn của đề.","intent":"• để tái sử dụng một shared service instance\n• Bản dịch/diễn đạt phương án — đối chiếu với định nghĩa chuẩn của đề.","whatIs":{"A":"để Tạo millions của identical DB connections mọi frame","B":"để tái sử dụng một shared service instance","C":"Cách chia sẻ và phản ứng với trạng thái dùng chung giữa nhiều widget/màn.","D":"Cơ chế xếp chồng màn hình (stack) và chuyển page."},"whyWrong":{"A":"• Là gì? để Tạo millions của identical DB connections mọi frame\n• Dùng để làm gì? Bản dịch/diễn đạt phương án — đối chiếu với định nghĩa chuẩn của đề.\n• Vì sao sai? «To create millions of identical DB connections every frame» — để Tạo millions của identical DB connections mọi frame. Đề cần: để tái sử dụng một shared service instance.","C":"• Là gì? Cách chia sẻ và phản ứng với trạng thái dùng chung giữa nhiều widget/màn.\n• Dùng để làm gì? Tránh truyền prop sâu; cập nhật UI khi state đổi.\n• Vì sao sai? «To avoid all state management» — Cách chia sẻ và phản ứng với trạng thái dùng chung giữa nhiều widget/màn. Đề cần: để tái sử dụng một shared service instance.","D":"• Là gì? Cơ chế xếp chồng màn hình (stack) và chuyển page.\n• Dùng để làm gì? push/pop route, điều hướng luồng màn hình.\n• Vì sao sai? «To replace Navigator» — Cơ chế xếp chồng màn hình (stack) và chuyển page. Đề cần: để tái sử dụng một shared service instance."}}},{"id":129,"task":"slides","taskLabel":"Slides","num":128,"question":"Generics in Dart mainly help you:","options":{"A":"Remove type safety","B":"Only style colors","C":"Write reusable type-safe APIs (e.g., List<T>)","D":"Compile CSS"},"answer":"C","alternatives":[],"source":"slides","exam":"PRM393_SLIDES_M3","explanation":{"questionVi":"Generics trong Dart chủ yếu giúp bạn:","optionsVi":{"A":"Gỡ bỏ an toàn kiểu (type safety)","B":"Chỉ style màu sắc","C":"Viết API tái sử dụng, an toàn kiểu (vd. List<T>)","D":"Biên dịch CSS"},"answerDisplay":"C. Viết API tái sử dụng, an toàn kiểu (vd. List<T>)","concept":"• Generics: viết code tái sử dụng với nhiều kiểu dữ liệu mà vẫn type-safe (vd. List<T>, Map<K,V>).","whyCorrect":"• Generics: viết code tái sử dụng với nhiều kiểu dữ liệu mà vẫn type-safe (vd. List<T>, Map<K,V>).\n• Một API/generic class dùng được cho int, String… mà compiler vẫn kiểm tra kiểu.\n• Ví dụ: List<T>, Map<K,V>, Future<T> — một API dùng nhiều kiểu, compiler vẫn kiểm tra.","intent":"• Generics = type parameter tái sử dụng + type-safe (List<T>, Map<K,V>).\n• Không nhầm với «ngôn ngữ Dart» hay style UI.","memoryTip":"• Generics = List<T> / Map<K,V> — tái sử dụng + type-safe.\n• Không gỡ type safety; không liên quan CSS/màu.","whatIs":{"A":"Gỡ bỏ kiểm tra kiểu tĩnh (type safety).","B":"Chỉ liên quan style/màu giao diện.","C":"Generics: viết code tái sử dụng với nhiều kiểu dữ liệu mà vẫn type-safe (vd. List<T>, Map<K,V>).","D":"Biên dịch CSS (stylesheet web)."},"whyWrong":{"A":"• Là gì? Gỡ bỏ kiểm tra kiểu tĩnh (type safety).\n• Dùng để làm gì? Trái mục tiêu Generics (Generics tăng type safety).\n• Vì sao sai? Generics tăng type safety (kiểm tra kiểu lúc biên dịch), không loại bỏ type safety.","B":"• Là gì? Chỉ liên quan style/màu giao diện.\n• Dùng để làm gì? Thuộc tầng UI decoration — không phải hệ thống kiểu Generics.\n• Vì sao sai? Màu/style UI không liên quan cơ chế generic type parameters.","D":"• Là gì? Biên dịch CSS (stylesheet web).\n• Dùng để làm gì? Flutter/Dart không dùng pipeline CSS làm UI chính.\n• Vì sao sai? Flutter/Dart không biên dịch CSS; Generics là tính năng hệ thống kiểu (List<T>…)."}}},{"id":130,"task":"slides","taskLabel":"Slides","num":129,"question":"What is the role of BuildContext?","options":{"A":"Store only binary APK data","B":"Locate a widget in the widget tree / access inherited widgets","C":"Replace the Dart VM","D":"Manage only SQL transactions"},"answer":"B","alternatives":[],"source":"slides","exam":"PRM393_SLIDES_M4","explanation":{"questionVi":"Vai trò của BuildContext là gì?","optionsVi":{"A":"Chỉ lưu dữ liệu nhị phân APK","B":"Định vị widget trên cây / truy cập InheritedWidget","C":"Thay thế Dart VM","D":"Chỉ quản lý giao dịch SQL"},"answerDisplay":"B. Định vị widget trên cây / truy cập InheritedWidget","concept":"• Handle trỏ tới vị trí Element của một widget trên widget tree.","whyCorrect":"• BuildContext: vị trí widget trong tree (FE + M4).\n• Handle trỏ tới vị trí Element của một widget trên widget tree.\n• Tìm ancestor/InheritedWidget (Theme, MediaQuery, Navigator.of…).","intent":"• BuildContext gắn với vị trí widget trên cây.\n• Dùng context để lấy InheritedWidget/Navigator — không phải kho data hay engine vẽ.","memoryTip":"• UI = cây widget; BuildContext định vị trên cây; build() chỉ mô tả UI.","whatIs":{"A":"Gói cài đặt Android chứa mã và tài nguyên đã build.","B":"Handle trỏ tới vị trí Element của một widget trên widget tree.","C":"Máy ảo chạy mã Dart (JIT/AOT tùy chế độ).","D":"Thao tác/giao dịch trên cơ sở dữ liệu quan hệ."},"whyWrong":{"A":"• Là gì? Gói cài đặt Android chứa mã và tài nguyên đã build.\n• Dùng để làm gì? Phát hành/cài app lên thiết bị.\n• Vì sao sai? APK là gói cài đặt đã build; BuildContext chỉ là tọa độ widget lúc app đang chạy, không lưu binary.","C":"• Là gì? Máy ảo chạy mã Dart (JIT/AOT tùy chế độ).\n• Dùng để làm gì? Thực thi logic app; không định vị widget trên tree.\n• Vì sao sai? Dart VM thực thi mã; BuildContext không thay thế VM mà chỉ trỏ vị trí trên widget tree.","D":"• Là gì? Thao tác/giao dịch trên cơ sở dữ liệu quan hệ.\n• Dùng để làm gì? Lưu trữ và truy vấn dữ liệu bền vững; không thuộc widget tree UI.\n• Vì sao sai? Giao dịch SQL thuộc lớp dữ liệu; BuildContext thuộc lớp UI tree."}}},{"id":131,"task":"slides","taskLabel":"Slides","num":130,"question":"What does setState() do in a StatefulWidget?","options":{"A":"Marks state changed so Flutter rebuilds the widget","B":"Deletes the widget forever","C":"Only changes AndroidManifest","D":"Uploads the app to stores"},"answer":"A","alternatives":[],"source":"slides","exam":"PRM393_SLIDES_M4","explanation":{"questionVi":"setState() làm gì trong StatefulWidget?","optionsVi":{"A":"Đánh dấu state đổi để Flutter rebuild widget","B":"Deletes widget mãi mãi","C":"Chỉ thay đổi AndroidManifest","D":"Uploads app để stores"},"answerDisplay":"A. Đánh dấu state đổi để Flutter rebuild widget","concept":"• API đánh dấu State đã đổi và xếp lịch rebuild nhánh widget liên quan.","whyCorrect":"• setState đánh dấu State đã đổi → Flutter gọi lại build() cho subtree liên quan. A: Marks state changed so Flutter rebuilds the widget.\n• API đánh dấu State đã đổi và xếp lịch rebuild nhánh widget liên quan.\n• Cập nhật UI sau khi dữ liệu nội bộ thay đổi.","intent":"• Phân biệt List / Set / Map trong Dart.\n• Thứ tự, trùng lặp, hay key–value.","memoryTip":"• Đổi state → rebuild; BLoC/Cubit/Provider tách logic khỏi UI; state nên immutable.","whatIs":{"A":"API đánh dấu State đã đổi và xếp lịch rebuild nhánh widget liên quan.","B":"Cơ chế Flutter/Dart liên quan «Deletes widget mãi mãi».","C":"Chỉ thay đổi AndroidManifest","D":"Cơ chế Flutter/Dart liên quan «Uploads app để stores»."},"whyWrong":{"B":"• Là gì? Cơ chế Flutter/Dart liên quan «Deletes widget mãi mãi».\n• Dùng để làm gì? Đối chiếu đúng cơ chế/phạm trù với trọng tâm đề.\n• Vì sao sai? «Deletes the widget forever» — Cơ chế Flutter/Dart liên quan «Deletes widget mãi mãi». Đề cần: API đánh dấu State đã đổi và xếp lịch rebuild nhánh widget liên quan.","C":"• Là gì? Chỉ thay đổi AndroidManifest\n• Dùng để làm gì? Bản dịch/diễn đạt phương án — đối chiếu với định nghĩa chuẩn của đề.\n• Vì sao sai? «Only changes AndroidManifest» — Chỉ thay đổi AndroidManifest. Đề cần: API đánh dấu State đã đổi và xếp lịch rebuild nhánh widget liên quan.","D":"• Là gì? Cơ chế Flutter/Dart liên quan «Uploads app để stores».\n• Dùng để làm gì? Đối chiếu đúng cơ chế/phạm trù với trọng tâm đề.\n• Vì sao sai? «Uploads the app to stores» — Cơ chế Flutter/Dart liên quan «Uploads app để stores». Đề cần: API đánh dấu State đã đổi và xếp lịch rebuild nhánh widget liên quan."}}},{"id":132,"task":"slides","taskLabel":"Slides","num":131,"question":"Which widget arranges children vertically?","options":{"A":"Row","B":"Stack only always","C":"Column","D":"GridView only"},"answer":"C","alternatives":[],"source":"slides","exam":"PRM393_SLIDES_M4","explanation":{"questionVi":"Widget nào xếp con theo chiều dọc?","optionsVi":{"A":"Row","B":"Stack chỉ Luôn","C":"Column","D":"GridView"},"answerDisplay":"C. Column","concept":"• Xếp widget con theo cột dọc (main axis = vertical).","whyCorrect":"• Xếp widget con theo cột dọc (main axis = vertical).\n• Bố cục dọc; cross axis là ngang. Không scroll mặc định, không overlap.","intent":"• Xếp widget con theo cột dọc (main axis = vertical).\n• Chọn phương án khớp cơ chế Flutter, không chọn stack web/Android nhầm.","whatIs":{"A":"Xếp widget con theo hàng ngang (main axis = horizontal).","B":"Xếp chồng widget con theo trục Z, cho phép overlap.","C":"Xếp widget con theo cột dọc (main axis = vertical).","D":"Cơ chế Flutter/Dart liên quan «GridView»."},"whyWrong":{"A":"• Là gì? Xếp widget con theo hàng ngang (main axis = horizontal).\n• Dùng để làm gì? Bố cục ngang; cross axis là dọc.\n• Vì sao sai? Row xếp ngang.","B":"• Là gì? Xếp chồng widget con theo trục Z, cho phép overlap.\n• Dùng để làm gì? Badge, overlay, layer UI chồng lên nhau.\n• Vì sao sai? Stack chồng widget (overlap); chỉ đúng khi cần chồng lớp.","D":"• Là gì? Cơ chế Flutter/Dart liên quan «GridView».\n• Dùng để làm gì? Đối chiếu đúng cơ chế/phạm trù với trọng tâm đề.\n• Vì sao sai? «GridView only» — Cơ chế Flutter/Dart liên quan «GridView». Đề cần: Xếp widget con theo cột dọc (main axis = vertical)."}}},{"id":133,"task":"slides","taskLabel":"Slides","num":132,"question":"Which widget allows children to overlap?","options":{"A":"Column","B":"Stack","C":"ListView.builder only","D":"LinearProgressIndicator"},"answer":"B","alternatives":[],"source":"slides","exam":"PRM393_SLIDES_M4","explanation":{"questionVi":"Widget nào cho phép các con chồng lên nhau?","optionsVi":{"A":"Column","B":"Stack","C":"ListView.builder","D":"LinearProgressIndicator"},"answerDisplay":"B. Stack","concept":"• Xếp chồng widget con theo trục Z, cho phép overlap.","whyCorrect":"• Xếp chồng widget con theo trục Z, cho phép overlap.\n• Badge, overlay, layer UI chồng lên nhau.","intent":"• Stack cho overlap theo trục Z.\n• Row/Column/Expanded là layout flex, không chồng lớp.","memoryTip":"• Stack xếp chồng (Z); Row/Column không overlap mặc định.","whatIs":{"A":"Xếp widget con theo cột dọc (main axis = vertical).","B":"Xếp chồng widget con theo trục Z, cho phép overlap.","C":"Cơ chế Flutter/Dart liên quan «ListView.builder».","D":"Cơ chế/thuật ngữ CNTT «LinearProgressIndicator»."},"whyWrong":{"A":"• Là gì? Xếp widget con theo cột dọc (main axis = vertical).\n• Dùng để làm gì? Bố cục dọc; cross axis là ngang. Không scroll mặc định, không overlap.\n• Vì sao sai? Column xếp dọc, không scroll mặc định, không overlap.","C":"• Là gì? Cơ chế Flutter/Dart liên quan «ListView.builder».\n• Dùng để làm gì? Đối chiếu đúng cơ chế/phạm trù với trọng tâm đề.\n• Vì sao sai? ListView cuộn danh sách; không phải Future/Stream builder hay layout flex chính.","D":"• Là gì? Cơ chế/thuật ngữ CNTT «LinearProgressIndicator».\n• Dùng để làm gì? Đối chiếu đúng định nghĩa/đặc trưng kỹ thuật mà đề hỏi.\n• Vì sao sai? «LinearProgressIndicator» — Cơ chế/thuật ngữ CNTT «LinearProgressIndicator». Đề cần: Xếp chồng widget con theo trục Z, cho phép overlap."}}},{"id":134,"task":"slides","taskLabel":"Slides","num":133,"question":"What is Scaffold typically used for?","options":{"A":"Basic page structure (AppBar, body, etc.)","B":"HTTP client only","C":"Database migration only","D":"Code generation of isolates"},"answer":"A","alternatives":[],"source":"slides","exam":"PRM393_SLIDES_M4","explanation":{"questionVi":"Scaffold thường dùng để làm gì?","optionsVi":{"A":"Khung trang cơ bản (AppBar, body…)","B":"HTTP client","C":"Cơ sở dữ liệu migration","D":"Mã generation của isolates"},"answerDisplay":"A. Khung trang cơ bản (AppBar, body…)","concept":"• Khung trang cơ bản (AppBar, body…). Bản dịch/diễn đạt phương án — đối chiếu với định nghĩa chuẩn của đề.","whyCorrect":"• Khung trang cơ bản (AppBar, body…)\n• Bản dịch/diễn đạt phương án — đối chiếu với định nghĩa chuẩn của đề.","intent":"• Khung trang cơ bản (AppBar, body…)\n• Bản dịch/diễn đạt phương án — đối chiếu với định nghĩa chuẩn của đề.","whatIs":{"A":"Khung trang cơ bản (AppBar, body…)","B":"Client HTTP để gửi request mạng (GET/POST…).","C":"Cụm «Cơ sở dữ liệu migration» mang một nghĩa riêng cần đối chiếu với đề.","D":"Mã generation của isolates"},"whyWrong":{"B":"• Là gì? Client HTTP để gửi request mạng (GET/POST…).\n• Dùng để làm gì? Gọi API/tải dữ liệu; không phải widget layout hay spacer UI.\n• Vì sao sai? Gói http gọi API; không quản lý state UI hay storage local.","C":"• Là gì? Cụm «Cơ sở dữ liệu migration» mang một nghĩa riêng cần đối chiếu với đề.\n• Dùng để làm gì? So bản chất với đáp án đúng; loại nếu sai đối tượng hoặc sai lớp khái niệm.\n• Vì sao sai? Scaffold khung màn (AppBar/body); không apply theme toàn app.","D":"• Là gì? Mã generation của isolates\n• Dùng để làm gì? Bản dịch/diễn đạt phương án — đối chiếu với định nghĩa chuẩn của đề.\n• Vì sao sai? Scaffold khung màn (AppBar/body); không apply theme toàn app."}}},{"id":135,"task":"slides","taskLabel":"Slides","num":134,"question":"What does a Switch widget primarily toggle?","options":{"A":"Git branches","B":"A boolean ON/OFF value","C":"CPU frequency","D":"Null safety mode"},"answer":"B","alternatives":[],"source":"slides","exam":"PRM393_SLIDES_M4","explanation":{"questionVi":"Widget Switch chủ yếu bật/tắt gì?","optionsVi":{"A":"Git branches","B":"Giá trị boolean bật/tắt","C":"CPU frequency","D":"Null safety mode"},"answerDisplay":"B. Giá trị boolean bật/tắt","concept":"• Thiết bị tầng 2: chuyển frame theo bảng MAC, mỗi cổng một collision domain.","whyCorrect":"• Thiết bị tầng 2: chuyển frame theo bảng MAC, mỗi cổng một collision domain.\n• LAN switching; routing liên mạng vẫn cần router (L3).","intent":"• Thiết bị tầng 2: chuyển frame theo bảng MAC, mỗi cổng một collision domain.\n• Chọn phương án khớp cơ chế Flutter, không chọn stack web/Android nhầm.","whatIs":{"A":"Thiết bị/khái niệm mạng «Git branches».","B":"Thiết bị tầng 2: chuyển frame theo bảng MAC, mỗi cổng một collision domain.","C":"Trạng thái/khái niệm OS liên quan «CPU frequency».","D":"Hệ thống kiểu Dart phân biệt null/non-null để giảm crash."},"whyWrong":{"A":"• Là gì? Thiết bị/khái niệm mạng «Git branches».\n• Dùng để làm gì? Đối chiếu đúng tầng OSI và chức năng (routing / switching / physical).\n• Vì sao sai? Git quản lý phiên bản code — chỉ đúng khi hỏi version control.","C":"• Là gì? Trạng thái/khái niệm OS liên quan «CPU frequency».\n• Dùng để làm gì? Gắn vòng đời tiến trình, lập lịch CPU hoặc chờ I/O.\n• Vì sao sai? «CPU frequency» — Trạng thái/khái niệm OS liên quan «CPU frequency». Đề cần: Thiết bị tầng 2: chuyển frame theo bảng MAC, mỗi cổng một collision domain.","D":"• Là gì? Hệ thống kiểu Dart phân biệt null/non-null để giảm crash.\n• Dùng để làm gì? Bắt buộc khởi tạo non-nullable trước khi dùng.\n• Vì sao sai? «Null safety mode» — Hệ thống kiểu Dart phân biệt null/non-null để giảm crash. Đề cần: Thiết bị tầng 2: chuyển frame theo bảng MAC, mỗi cổng một collision domain."}}},{"id":136,"task":"slides","taskLabel":"Slides","num":135,"question":"Why use const widgets when possible?","options":{"A":"They force full tree rebuild every frame","B":"They disable hot reload","C":"They reduce rebuild cost for stable UI","D":"They remove type safety"},"answer":"C","alternatives":[],"source":"slides","exam":"PRM393_SLIDES_M4","explanation":{"questionVi":"Vì sao nên dùng const widget khi có thể?","optionsVi":{"A":"They Ép full tree rebuild mọi frame","B":"They Tắt hot reload","C":"Giảm chi phí rebuild cho UI ổn định","D":"They Gỡ bỏ kiểu safety"},"answerDisplay":"C. Giảm chi phí rebuild cho UI ổn định","concept":"• Hằng được xác định từ lúc biên dịch (compile-time).","whyCorrect":"• Hằng được xác định từ lúc biên dịch (compile-time).\n• Giá trị bất biến, tối ưu và an toàn.","intent":"• Phân biệt const, final, var và null safety.\n• Compile-time vs runtime assignment.","memoryTip":"• UI = cây widget; BuildContext định vị trên cây; build() chỉ mô tả UI.","whatIs":{"A":"They Ép full tree rebuild mọi frame","B":"Nạp lại code UI gần như giữ state đang chạy.","C":"Hằng được xác định từ lúc biên dịch (compile-time).","D":"Gỡ bỏ kiểm tra kiểu tĩnh (type safety)."},"whyWrong":{"A":"• Là gì? They Ép full tree rebuild mọi frame\n• Dùng để làm gì? Bản dịch/diễn đạt phương án — đối chiếu với định nghĩa chuẩn của đề.\n• Vì sao sai? const giúp tái sử dụng widget, giảm rebuild — đúng khi hỏi tối ưu const.","B":"• Là gì? Nạp lại code UI gần như giữ state đang chạy.\n• Dùng để làm gì? Xem thay đổi nhanh khi dev.\n• Vì sao sai? Hot reload nạp code UI nhanh khi dev; không phải công cụ phân tích sâu.","D":"• Là gì? Gỡ bỏ kiểm tra kiểu tĩnh (type safety).\n• Dùng để làm gì? Trái mục tiêu Generics (Generics tăng type safety).\n• Vì sao sai? const giúp tái sử dụng widget, giảm rebuild — đúng khi hỏi tối ưu const."}}},{"id":137,"task":"slides","taskLabel":"Slides","num":136,"question":"What does ThemeData primarily define?","options":{"A":"Application-wide visual styles","B":"Only SQLite schema","C":"Only deep link schemes","D":"Only test coverage reports"},"answer":"A","alternatives":[],"source":"slides","exam":"PRM393_SLIDES_M4","explanation":{"questionVi":"ThemeData chủ yếu định nghĩa gì?","optionsVi":{"A":"Style giao diện toàn app","B":"Chỉ SQLite schema","C":"Chỉ deep link schemes","D":"Chỉ test coverage reports"},"answerDisplay":"A. Style giao diện toàn app","concept":"• Style giao diện toàn app. Bản dịch/diễn đạt phương án — đối chiếu với định nghĩa chuẩn của đề.","whyCorrect":"• Style giao diện toàn app\n• Bản dịch/diễn đạt phương án — đối chiếu với định nghĩa chuẩn của đề.","intent":"• Style giao diện toàn app\n• Bản dịch/diễn đạt phương án — đối chiếu với định nghĩa chuẩn của đề.","whatIs":{"A":"Style giao diện toàn app","B":"Cụm «Chỉ SQLite schema» mang một nghĩa riêng cần đối chiếu với đề.","C":"Mở ứng dụng (hoặc màn cụ thể) từ URL/URI bên ngoài.","D":"Chỉ test coverage reports"},"whyWrong":{"B":"• Là gì? Cụm «Chỉ SQLite schema» mang một nghĩa riêng cần đối chiếu với đề.\n• Dùng để làm gì? So bản chất với đáp án đúng; loại nếu sai đối tượng hoặc sai lớp khái niệm.\n• Vì sao sai? Theme/ThemeData lo style giao diện, không phải state/auth/logic chính ở đây.","C":"• Là gì? Mở ứng dụng (hoặc màn cụ thể) từ URL/URI bên ngoài.\n• Dùng để làm gì? Routing/deep linking; không liên quan chia không gian layout Flex.\n• Vì sao sai? Theme/ThemeData lo style giao diện, không phải state/auth/logic chính ở đây.","D":"• Là gì? Chỉ test coverage reports\n• Dùng để làm gì? Bản dịch/diễn đạt phương án — đối chiếu với định nghĩa chuẩn của đề.\n• Vì sao sai? Theme/ThemeData lo style giao diện, không phải state/auth/logic chính ở đây."}}},{"id":138,"task":"slides","taskLabel":"Slides","num":137,"question":"What does the build() method return?","options":{"A":"Raw GPU pixels only","B":"A widget tree describing the UI","C":"A signed APK","D":"A database connection pool"},"answer":"B","alternatives":[],"source":"slides","exam":"PRM393_SLIDES_M4","explanation":{"questionVi":"Method build() trả về gì?","optionsVi":{"A":"Raw GPU pixels","B":"Cây widget mô tả UI","C":"Một signed APK","D":"Một cơ sở dữ liệu connection pool"},"answerDisplay":"B. Cây widget mô tả UI","concept":"• Cây cấu hình UI lồng nhau mô tả giao diện tại một thời điểm.","whyCorrect":"• Cây cấu hình UI lồng nhau mô tả giao diện tại một thời điểm.\n• Đầu vào cho Element/Render pipeline của Flutter.","intent":"• Cây cấu hình UI lồng nhau mô tả giao diện tại một thời điểm.\n• Đầu vào cho Element/Render pipeline của Flutter.","memoryTip":"• UI = cây widget; BuildContext định vị trên cây; build() chỉ mô tả UI.","whatIs":{"A":"Vẽ pixel/lớp đồ họa lên màn hình.","B":"Cây cấu hình UI lồng nhau mô tả giao diện tại một thời điểm.","C":"Gói cài đặt Android chứa mã và tài nguyên đã build.","D":"Một cơ sở dữ liệu connection pool"},"whyWrong":{"A":"• Là gì? Vẽ pixel/lớp đồ họa lên màn hình.\n• Dùng để làm gì? Thuộc RenderObject/engine (Skia); không phải Handle BuildContext.\n• Vì sao sai? build() mô tả UI; không phải chỗ gọi để “cập nhật state”.","C":"• Là gì? Gói cài đặt Android chứa mã và tài nguyên đã build.\n• Dùng để làm gì? Phát hành/cài app lên thiết bị.\n• Vì sao sai? build() mô tả UI; không phải chỗ gọi để “cập nhật state”.","D":"• Là gì? Một cơ sở dữ liệu connection pool\n• Dùng để làm gì? Bản dịch/diễn đạt phương án — đối chiếu với định nghĩa chuẩn của đề.\n• Vì sao sai? build() mô tả UI; không phải chỗ gọi để “cập nhật state”."}}},{"id":139,"task":"slides","taskLabel":"Slides","num":138,"question":"StatelessWidget is best when:","options":{"A":"UI must hold mutable local state with setState","B":"You need AnimationController disposal always","C":"UI depends only on constructor inputs / configuration","D":"You must ignore BuildContext"},"answer":"C","alternatives":[],"source":"slides","exam":"PRM393_SLIDES_M4","explanation":{"questionVi":"StatelessWidget phù hợp nhất khi:","optionsVi":{"A":"UI phải giữ state local mutable bằng setState","B":"You cần AnimationController disposal Luôn","C":"UI chỉ phụ thuộc tham số constructor/cấu hình","D":"You phải ignore BuildContext"},"answerDisplay":"C. UI chỉ phụ thuộc tham số constructor/cấu hình","concept":"• Widget không giữ state nội bộ; UI chỉ phụ thuộc tham số truyền vào.","whyCorrect":"• Widget không giữ state nội bộ; UI chỉ phụ thuộc tham số truyền vào.\n• Hiển thị phần tĩnh hoặc dữ liệu từ cha/provider.","intent":"• Widget không giữ state nội bộ; UI chỉ phụ thuộc tham số truyền vào.\n• Chọn phương án khớp cơ chế Flutter, không chọn stack web/Android nhầm.","whatIs":{"A":"API đánh dấu State đã đổi và xếp lịch rebuild nhánh widget liên quan.","B":"Đường cong/thời gian điều khiển nhịp chuyển động UI (ease-in/out…).","C":"Widget không giữ state nội bộ; UI chỉ phụ thuộc tham số truyền vào.","D":"Handle trỏ tới vị trí Element của một widget trên widget tree."},"whyWrong":{"A":"• Là gì? API đánh dấu State đã đổi và xếp lịch rebuild nhánh widget liên quan.\n• Dùng để làm gì? Cập nhật UI sau khi dữ liệu nội bộ thay đổi.\n• Vì sao sai? «UI must hold mutable local state with setState» — API đánh dấu State đã đổi và xếp lịch rebuild nhánh widget liên quan. Đề cần: Widget không giữ state nội bộ; UI chỉ phụ thuộc tham số truyền vào.","B":"• Là gì? Đường cong/thời gian điều khiển nhịp chuyển động UI (ease-in/out…).\n• Dùng để làm gì? Làm animation mượt, không tuyến tính cứng.\n• Vì sao sai? «You need AnimationController disposal always» — Đường cong/thời gian điều khiển nhịp chuyển động UI (ease-in/out…). Đề cần: Widget không giữ state nội bộ; UI chỉ phụ thuộc tham số truyền vào.","D":"• Là gì? Handle trỏ tới vị trí Element của một widget trên widget tree.\n• Dùng để làm gì? Tìm ancestor/InheritedWidget (Theme, MediaQuery, Navigator.of…).\n• Vì sao sai? «You must ignore BuildContext» — Handle trỏ tới vị trí Element của một widget trên widget tree. Đề cần: Widget không giữ state nội bộ; UI chỉ phụ thuộc tham số truyền vào."}}},{"id":140,"task":"slides","taskLabel":"Slides","num":139,"question":"crossAxisAlignment in a Column controls alignment along which axis?","options":{"A":"Horizontal (cross axis) for a vertical Column","B":"Only Z-depth","C":"Only time axis","D":"Network latency"},"answer":"A","alternatives":[],"source":"slides","exam":"PRM393_SLIDES_M4","explanation":{"questionVi":"crossAxisAlignment trong Column căn theo trục nào?","optionsVi":{"A":"Trục ngang (cross axis) với Column dọc","B":"Chỉ Z-depth","C":"Chỉ time axis","D":"Mạng latency"},"answerDisplay":"A. Trục ngang (cross axis) với Column dọc","concept":"• Xếp widget con theo cột dọc (main axis = vertical).","whyCorrect":"• Xếp widget con theo cột dọc (main axis = vertical).\n• Bố cục dọc; cross axis là ngang. Không scroll mặc định, không overlap.","intent":"• Xếp widget con theo cột dọc (main axis = vertical).\n• Bố cục dọc; cross axis là ngang. Không scroll mặc định, không overlap.","whatIs":{"A":"Xếp widget con theo cột dọc (main axis = vertical).","B":"Cụm «Chỉ Z-depth» mang một nghĩa riêng cần đối chiếu với đề.","C":"Cụm «Chỉ time axis» mang một nghĩa riêng cần đối chiếu với đề.","D":"Cụm «Mạng latency» mang một nghĩa riêng cần đối chiếu với đề."},"whyWrong":{"B":"• Là gì? Cụm «Chỉ Z-depth» mang một nghĩa riêng cần đối chiếu với đề.\n• Dùng để làm gì? So bản chất với đáp án đúng; loại nếu sai đối tượng hoặc sai lớp khái niệm.\n• Vì sao sai? Cụm «Chỉ Z-depth» mang một nghĩa riêng cần đối chiếu với đề. Expanded chỉ chia không gian còn lại trên main axis của Flex.","C":"• Là gì? Cụm «Chỉ time axis» mang một nghĩa riêng cần đối chiếu với đề.\n• Dùng để làm gì? So bản chất với đáp án đúng; loại nếu sai đối tượng hoặc sai lớp khái niệm.\n• Vì sao sai? Cụm «Chỉ time axis» mang một nghĩa riêng cần đối chiếu với đề. Expanded chỉ chia không gian còn lại trên main axis của Flex.","D":"• Là gì? Cụm «Mạng latency» mang một nghĩa riêng cần đối chiếu với đề.\n• Dùng để làm gì? So bản chất với đáp án đúng; loại nếu sai đối tượng hoặc sai lớp khái niệm.\n• Vì sao sai? Cụm «Mạng latency» mang một nghĩa riêng cần đối chiếu với đề. Expanded chỉ chia không gian còn lại trên main axis của Flex."}}},{"id":141,"task":"slides","taskLabel":"Slides","num":140,"question":"Which widget is best for fixed empty space of a given size?","options":{"A":"Expanded always filling remaining space","B":"SizedBox","C":"Navigator","D":"HttpClient"},"answer":"B","alternatives":[],"source":"slides","exam":"PRM393_SLIDES_M4","explanation":{"questionVi":"Widget nào tốt nhất cho khoảng trống cố định theo size?","optionsVi":{"A":"Expanded luôn lấp đầy phần không gian còn lại","B":"SizedBox","C":"Navigator","D":"HttpClient"},"answerDisplay":"B. SizedBox","concept":"• Tạo hộp kích thước cố định hoặc khoảng trống size cho trước.","whyCorrect":"• Tạo hộp kích thước cố định hoặc khoảng trống size cho trước.\n• Spacer cố định (width/height); khác Expanded (chiếm phần còn lại).","intent":"• Phân biệt khoảng trống cố định (SizedBox) và flex fill (Expanded).\n• Padding/Container không thay thế SizedBox cho spacer size rõ ràng.","memoryTip":"• SizedBox = size cố định; Expanded = chiếm phần còn lại (flex).","whatIs":{"A":"Expanded luôn lấp đầy phần không gian còn lại trên main axis của Flex.","B":"Tạo hộp kích thước cố định hoặc khoảng trống size cho trước.","C":"Cơ chế xếp chồng màn hình (stack) và chuyển page.","D":"Client HTTP để gửi request mạng (GET/POST…)."},"whyWrong":{"A":"• Là gì? Expanded luôn lấp đầy phần không gian còn lại trên main axis của Flex.\n• Dùng để làm gì? Khác SizedBox (size cố định); dùng khi cần giãn theo khoảng trống.\n• Vì sao sai? Expanded chiếm phần còn lại trên trục chính Flex; không tạo khoảng trống cố định.","C":"• Là gì? Cơ chế xếp chồng màn hình (stack) và chuyển page.\n• Dùng để làm gì? push/pop route, điều hướng luồng màn hình.\n• Vì sao sai? Navigator điều hướng route/màn hình; không tạo khoảng trống layout.","D":"• Là gì? Client HTTP để gửi request mạng (GET/POST…).\n• Dùng để làm gì? Gọi API/tải dữ liệu; không phải widget layout hay spacer UI.\n• Vì sao sai? HttpClient thuộc tầng mạng/HTTP; không liên quan spacer UI."}}},{"id":142,"task":"slides","taskLabel":"Slides","num":141,"question":"What is a key idea of Navigator 2.0 in the slides?","options":{"A":"Only imperative push/pop forever with no description of stack","B":"Declarative model: describe the desired navigation stack","C":"Remove all routes from Flutter","D":"Use only Android Activities XML"},"answer":"B","alternatives":[],"source":"slides","exam":"PRM393_SLIDES_M5","explanation":{"questionVi":"Ý chính của Navigator 2.0 trong slide là gì?","optionsVi":{"A":"Chỉ push/pop mệnh lệnh, không mô tả stack","B":"Mô hình khai báo: mô tả stack điều hướng mong muốn","C":"Gỡ bỏ tất cả route từ Flutter","D":"Dùng chỉ Android Activities XML"},"answerDisplay":"B. Mô hình khai báo: mô tả stack điều hướng mong muốn","concept":"• Cơ chế xếp chồng màn hình (stack) và chuyển page.","whyCorrect":"• Cơ chế xếp chồng màn hình (stack) và chuyển page.\n• push/pop route, điều hướng luồng màn hình.","intent":"• Cơ chế xếp chồng màn hình (stack) và chuyển page.\n• push/pop route, điều hướng luồng màn hình.","whatIs":{"A":"Xếp chồng widget con theo trục Z, cho phép overlap.","B":"Cơ chế xếp chồng màn hình (stack) và chuyển page.","C":"Gỡ bỏ tất cả route từ Flutter","D":"Dùng chỉ Android Activities XML"},"whyWrong":{"A":"• Là gì? Xếp chồng widget con theo trục Z, cho phép overlap.\n• Dùng để làm gì? Badge, overlay, layer UI chồng lên nhau.\n• Vì sao sai? Stack chồng widget (overlap); chỉ đúng khi cần chồng lớp.","C":"• Là gì? Gỡ bỏ tất cả route từ Flutter\n• Dùng để làm gì? Bản dịch/diễn đạt phương án — đối chiếu với định nghĩa chuẩn của đề.\n• Vì sao sai? «Remove all routes from Flutter» — Gỡ bỏ tất cả route từ Flutter. Đề cần: Cơ chế xếp chồng màn hình (stack) và chuyển page.","D":"• Là gì? Dùng chỉ Android Activities XML\n• Dùng để làm gì? Bản dịch/diễn đạt phương án — đối chiếu với định nghĩa chuẩn của đề.\n• Vì sao sai? Flutter không dựng UI chính bằng XML/HTML/CSS như Android View/web cổ điển."}}},{"id":143,"task":"slides","taskLabel":"Slides","num":142,"question":"What is deep linking used for?","options":{"A":"Open a specific screen via URL/external source","B":"Compress images only","C":"Generate unit tests only","D":"Increase battery temperature"},"answer":"A","alternatives":[],"source":"slides","exam":"PRM393_SLIDES_M5","explanation":{"questionVi":"Deep linking dùng để làm gì?","optionsVi":{"A":"Mở màn hình cụ thể qua URL/nguồn ngoài","B":"Compress images","C":"Generate unit tests","D":"Tăng battery temperature"},"answerDisplay":"A. Mở màn hình cụ thể qua URL/nguồn ngoài","concept":"• Mở màn hình cụ thể qua URL/nguồn ngoài. Bản dịch/diễn đạt phương án — đối chiếu với định nghĩa chuẩn của đề.","whyCorrect":"• Mở màn hình cụ thể qua URL/nguồn ngoài\n• Bản dịch/diễn đạt phương án — đối chiếu với định nghĩa chuẩn của đề.","intent":"• Mở màn hình cụ thể qua URL/nguồn ngoài\n• Bản dịch/diễn đạt phương án — đối chiếu với định nghĩa chuẩn của đề.","whatIs":{"A":"Mở màn hình cụ thể qua URL/nguồn ngoài","B":"Cụm «Compress images» mang một nghĩa riêng cần đối chiếu với đề.","C":"Cụm «Generate unit tests» mang một nghĩa riêng cần đối chiếu với đề.","D":"Tăng battery temperature"},"whyWrong":{"B":"• Là gì? Cụm «Compress images» mang một nghĩa riêng cần đối chiếu với đề.\n• Dùng để làm gì? So bản chất với đáp án đúng; loại nếu sai đối tượng hoặc sai lớp khái niệm.\n• Vì sao sai? «Compress images only» — Cụm «Compress images» mang một nghĩa riêng cần đối chiếu với đề. Đề cần: Mở màn hình cụ thể qua URL/nguồn ngoài.","C":"• Là gì? Cụm «Generate unit tests» mang một nghĩa riêng cần đối chiếu với đề.\n• Dùng để làm gì? So bản chất với đáp án đúng; loại nếu sai đối tượng hoặc sai lớp khái niệm.\n• Vì sao sai? Unit test: hàm/class nhỏ; không phải UI widget hay E2E.","D":"• Là gì? Tăng battery temperature\n• Dùng để làm gì? Bản dịch/diễn đạt phương án — đối chiếu với định nghĩa chuẩn của đề.\n• Vì sao sai? «Increase battery temperature» — Tăng battery temperature. Đề cần: Mở màn hình cụ thể qua URL/nguồn ngoài."}}},{"id":144,"task":"slides","taskLabel":"Slides","num":143,"question":"Where do you typically configure Android deep link intent filters?","options":{"A":"pubspec.yaml only","B":"iOS Info.plist only","C":"AndroidManifest.xml","D":"README.md"},"answer":"C","alternatives":[],"source":"slides","exam":"PRM393_SLIDES_M5","explanation":{"questionVi":"Thường cấu hình intent filter deep link Android ở đâu?","optionsVi":{"A":"Pubspec.yaml","B":"IOS Info.plist","C":"AndroidManifest.xml","D":"README.md"},"answerDisplay":"C. AndroidManifest.xml","concept":"• Cụm «AndroidManifest.xml» mang một nghĩa riêng cần đối chiếu với đề.","whyCorrect":"• Cụm «AndroidManifest.xml» mang một nghĩa riêng cần đối chiếu với đề.\n• So bản chất với đáp án đúng; loại nếu sai đối tượng hoặc sai lớp khái niệm.","intent":"• Cụm «AndroidManifest.xml» mang một nghĩa riêng cần đối chiếu với đề.\n• So bản chất với đáp án đúng; loại nếu sai đối tượng hoặc sai lớp khái niệm.","whatIs":{"A":"Cụm «Pubspec.yaml» mang một nghĩa riêng cần đối chiếu với đề.","B":"Phần mềm quản lý phần cứng, tiến trình, bộ nhớ, I/O.","C":"Cụm «AndroidManifest.xml» mang một nghĩa riêng cần đối chiếu với đề.","D":"Cụm «README.md» mang một nghĩa riêng cần đối chiếu với đề."},"whyWrong":{"A":"• Là gì? Cụm «Pubspec.yaml» mang một nghĩa riêng cần đối chiếu với đề.\n• Dùng để làm gì? So bản chất với đáp án đúng; loại nếu sai đối tượng hoặc sai lớp khái niệm.\n• Vì sao sai? «pubspec.yaml only» — Cụm «Pubspec.yaml» mang một nghĩa riêng cần đối chiếu với đề. Đề cần: Cụm «AndroidManifest.xml» mang một nghĩa riêng cần đối chiếu với đề.","B":"• Là gì? Phần mềm quản lý phần cứng, tiến trình, bộ nhớ, I/O.\n• Dùng để làm gì? Cấp tài nguyên và lập lịch cho chương trình.\n• Vì sao sai? «iOS Info.plist only» — Phần mềm quản lý phần cứng, tiến trình, bộ nhớ, I/O. Đề cần: Cụm «AndroidManifest.xml» mang một nghĩa riêng cần đối chiếu với đề.","D":"• Là gì? Cụm «README.md» mang một nghĩa riêng cần đối chiếu với đề.\n• Dùng để làm gì? So bản chất với đáp án đúng; loại nếu sai đối tượng hoặc sai lớp khái niệm.\n• Vì sao sai? «README.md» — Cụm «README.md» mang một nghĩa riêng cần đối chiếu với đề. Đề cần: Cụm «AndroidManifest.xml» mang một nghĩa riêng cần đối chiếu với đề."}}},{"id":145,"task":"slides","taskLabel":"Slides","num":144,"question":"BLoC architecture primarily separates:","options":{"A":"HTML and CSS","B":"UI from business logic via events and states (often Streams)","C":"CPU and GPU permanently","D":"Git and SVN"},"answer":"B","alternatives":[],"source":"slides","exam":"PRM393_SLIDES_M5","explanation":{"questionVi":"Kiến trúc BLoC chủ yếu tách:","optionsVi":{"A":"HTML và CSS","B":"Tách UI khỏi business logic qua sự kiện/state (thường Stream)","C":"CPU và GPU vĩnh viễn","D":"Git và SVN"},"answerDisplay":"B. Tách UI khỏi business logic qua sự kiện/state (thường Stream)","concept":"• Cách chia sẻ và phản ứng với trạng thái dùng chung giữa nhiều widget/màn.","whyCorrect":"• BLoC xử lý theo luồng: nhận Event, xử lý bất đồng bộ, phát State qua Stream. Vì vậy B đúng.\n• Cách chia sẻ và phản ứng với trạng thái dùng chung giữa nhiều widget/màn.\n• Tránh truyền prop sâu; cập nhật UI khi state đổi.","intent":"• Cách chia sẻ và phản ứng với trạng thái dùng chung giữa nhiều widget/màn.\n• Tránh truyền prop sâu; cập nhật UI khi state đổi.","memoryTip":"• Đổi state → rebuild; BLoC/Cubit/Provider tách logic khỏi UI; state nên immutable.","whatIs":{"A":"Cơ chế Flutter/Dart liên quan «HTML và CSS».","B":"Cách chia sẻ và phản ứng với trạng thái dùng chung giữa nhiều widget/màn.","C":"Trạng thái/khái niệm OS liên quan «CPU và GPU vĩnh viễn».","D":"Cơ chế Flutter/Dart liên quan «Git và SVN»."},"whyWrong":{"A":"• Là gì? Cơ chế Flutter/Dart liên quan «HTML và CSS».\n• Dùng để làm gì? Đối chiếu đúng cơ chế/phạm trù với trọng tâm đề.\n• Vì sao sai? Flutter không dựng UI chính bằng XML/HTML/CSS như Android View/web cổ điển.","C":"• Là gì? Trạng thái/khái niệm OS liên quan «CPU và GPU vĩnh viễn».\n• Dùng để làm gì? Gắn vòng đời tiến trình, lập lịch CPU hoặc chờ I/O.\n• Vì sao sai? «CPU and GPU permanently» — Trạng thái/khái niệm OS liên quan «CPU và GPU vĩnh viễn». Đề cần: Cách chia sẻ và phản ứng với trạng thái dùng chung giữa nhiều widget/màn.","D":"• Là gì? Cơ chế Flutter/Dart liên quan «Git và SVN».\n• Dùng để làm gì? Đối chiếu đúng cơ chế/phạm trù với trọng tâm đề.\n• Vì sao sai? Git quản lý phiên bản code — chỉ đúng khi hỏi version control."}}},{"id":146,"task":"slides","taskLabel":"Slides","num":145,"question":"What is the output of a BLoC typically?","options":{"A":"States","B":"Only raw SQL dumps","C":"APK files","D":"Certificate pins only"},"answer":"A","alternatives":[],"source":"slides","exam":"PRM393_SLIDES_M5","explanation":{"questionVi":"Output của BLoC thường là gì?","optionsVi":{"A":"States","B":"Chỉ raw SQL dumps","C":"APK files","D":"Certificate pins"},"answerDisplay":"A. States","concept":"• Cách chia sẻ và phản ứng với trạng thái dùng chung giữa nhiều widget/màn.","whyCorrect":"• Cách chia sẻ và phản ứng với trạng thái dùng chung giữa nhiều widget/màn.\n• Tránh truyền prop sâu; cập nhật UI khi state đổi.","intent":"• Cách chia sẻ và phản ứng với trạng thái dùng chung giữa nhiều widget/màn.\n• Tránh truyền prop sâu; cập nhật UI khi state đổi.","memoryTip":"• Đổi state → rebuild; BLoC/Cubit/Provider tách logic khỏi UI; state nên immutable.","whatIs":{"A":"Cách chia sẻ và phản ứng với trạng thái dùng chung giữa nhiều widget/màn.","B":"Thao tác/giao dịch trên cơ sở dữ liệu quan hệ.","C":"Gói cài đặt Android chứa mã và tài nguyên đã build.","D":"Cơ chế Flutter/Dart liên quan «Certificate pins»."},"whyWrong":{"B":"• Là gì? Thao tác/giao dịch trên cơ sở dữ liệu quan hệ.\n• Dùng để làm gì? Lưu trữ và truy vấn dữ liệu bền vững; không thuộc widget tree UI.\n• Vì sao sai? «Only raw SQL dumps» — Thao tác/giao dịch trên cơ sở dữ liệu quan hệ. Đề cần: Cách chia sẻ và phản ứng với trạng thái dùng chung giữa nhiều widget/màn.","C":"• Là gì? Gói cài đặt Android chứa mã và tài nguyên đã build.\n• Dùng để làm gì? Phát hành/cài app lên thiết bị.\n• Vì sao sai? «APK files» — Gói cài đặt Android chứa mã và tài nguyên đã build. Đề cần: Cách chia sẻ và phản ứng với trạng thái dùng chung giữa nhiều widget/màn.","D":"• Là gì? Cơ chế Flutter/Dart liên quan «Certificate pins».\n• Dùng để làm gì? Đối chiếu đúng cơ chế/phạm trù với trọng tâm đề.\n• Vì sao sai? «Certificate pins only» — Cơ chế Flutter/Dart liên quan «Certificate pins». Đề cần: Cách chia sẻ và phản ứng với trạng thái dùng chung giữa nhiều widget/màn."}}},{"id":147,"task":"slides","taskLabel":"Slides","num":146,"question":"What do events do in BLoC?","options":{"A":"Render pixels directly","B":"Trigger state changes / business handling","C":"Sign the APK","D":"Replace Material icons"},"answer":"B","alternatives":[],"source":"slides","exam":"PRM393_SLIDES_M5","explanation":{"questionVi":"Event trong BLoC làm gì?","optionsVi":{"A":"Render pixels trực tiếp","B":"Kích hoạt đổi state / xử lý nghiệp vụ","C":"Sign the APK","D":"Thay thế Material icons"},"answerDisplay":"B. Kích hoạt đổi state / xử lý nghiệp vụ","concept":"• Cách chia sẻ và phản ứng với trạng thái dùng chung giữa nhiều widget/màn.","whyCorrect":"• Cách chia sẻ và phản ứng với trạng thái dùng chung giữa nhiều widget/màn.\n• Tránh truyền prop sâu; cập nhật UI khi state đổi.","intent":"• Cách chia sẻ và phản ứng với trạng thái dùng chung giữa nhiều widget/màn.\n• Tránh truyền prop sâu; cập nhật UI khi state đổi.","memoryTip":"• Đổi state → rebuild; BLoC/Cubit/Provider tách logic khỏi UI; state nên immutable.","whatIs":{"A":"Vẽ pixel/lớp đồ họa lên màn hình.","B":"Cách chia sẻ và phản ứng với trạng thái dùng chung giữa nhiều widget/màn.","C":"Gói cài đặt Android chứa mã và tài nguyên đã build.","D":"Cơ chế Flutter/Dart liên quan «Thay thế Material icons»."},"whyWrong":{"A":"• Là gì? Vẽ pixel/lớp đồ họa lên màn hình.\n• Dùng để làm gì? Thuộc RenderObject/engine (Skia); không phải Handle BuildContext.\n• Vì sao sai? «Render pixels directly» — Vẽ pixel/lớp đồ họa lên màn hình. Đề cần: Cách chia sẻ và phản ứng với trạng thái dùng chung giữa nhiều widget/màn.","C":"• Là gì? Gói cài đặt Android chứa mã và tài nguyên đã build.\n• Dùng để làm gì? Phát hành/cài app lên thiết bị.\n• Vì sao sai? «Sign the APK» — Gói cài đặt Android chứa mã và tài nguyên đã build. Đề cần: Cách chia sẻ và phản ứng với trạng thái dùng chung giữa nhiều widget/màn.","D":"• Là gì? Cơ chế Flutter/Dart liên quan «Thay thế Material icons».\n• Dùng để làm gì? Đối chiếu đúng cơ chế/phạm trù với trọng tâm đề.\n• Vì sao sai? «Replace Material icons» — Cơ chế Flutter/Dart liên quan «Thay thế Material icons». Đề cần: Cách chia sẻ và phản ứng với trạng thái dùng chung giữa nhiều widget/màn."}}},{"id":148,"task":"slides","taskLabel":"Slides","num":147,"question":"Why is immutability important for BLoC states?","options":{"A":"To make states random","B":"To prevent any UI update","C":"Predictable state changes / easier comparison","D":"To disable Streams"},"answer":"C","alternatives":[],"source":"slides","exam":"PRM393_SLIDES_M5","explanation":{"questionVi":"Vì sao immutability quan trọng với state BLoC?","optionsVi":{"A":"để make state random","B":"để Ngăn bất kỳ UI update","C":"Đổi state dễ đoán / dễ so sánh","D":"để Tắt Streams"},"answerDisplay":"C. Đổi state dễ đoán / dễ so sánh","concept":"• Cách chia sẻ và phản ứng với trạng thái dùng chung giữa nhiều widget/màn.","whyCorrect":"• Cách chia sẻ và phản ứng với trạng thái dùng chung giữa nhiều widget/màn.\n• Tránh truyền prop sâu; cập nhật UI khi state đổi.","intent":"• Cách chia sẻ và phản ứng với trạng thái dùng chung giữa nhiều widget/màn.\n• Tránh truyền prop sâu; cập nhật UI khi state đổi.","memoryTip":"• Đổi state → rebuild; BLoC/Cubit/Provider tách logic khỏi UI; state nên immutable.","whatIs":{"A":"Cơ chế Flutter/Dart liên quan «để make state random».","B":"để Ngăn bất kỳ UI update","C":"Cách chia sẻ và phản ứng với trạng thái dùng chung giữa nhiều widget/màn.","D":"Cơ chế Flutter/Dart liên quan «để Tắt Streams»."},"whyWrong":{"A":"• Là gì? Cơ chế Flutter/Dart liên quan «để make state random».\n• Dùng để làm gì? Đối chiếu đúng cơ chế/phạm trù với trọng tâm đề.\n• Vì sao sai? «To make states random» — Cơ chế Flutter/Dart liên quan «để make state random». Đề cần: Cách chia sẻ và phản ứng với trạng thái dùng chung giữa nhiều widget/màn.","B":"• Là gì? để Ngăn bất kỳ UI update\n• Dùng để làm gì? Bản dịch/diễn đạt phương án — đối chiếu với định nghĩa chuẩn của đề.\n• Vì sao sai? «To prevent any UI update» — để Ngăn bất kỳ UI update. Đề cần: Cách chia sẻ và phản ứng với trạng thái dùng chung giữa nhiều widget/màn.","D":"• Là gì? Cơ chế Flutter/Dart liên quan «để Tắt Streams».\n• Dùng để làm gì? Đối chiếu đúng cơ chế/phạm trù với trọng tâm đề.\n• Vì sao sai? BLoC: event → state qua stream; đúng khi hỏi kiến trúc BLoC."}}},{"id":149,"task":"slides","taskLabel":"Slides","num":148,"question":"How can data be passed to a new screen in common Flutter practice?","options":{"A":"Via constructor arguments / route arguments","B":"Only by rebooting the phone","C":"Only by editing the Flutter engine","D":"Only through SMS"},"answer":"A","alternatives":[],"source":"slides","exam":"PRM393_SLIDES_M5","explanation":{"questionVi":"Thường truyền dữ liệu sang màn mới trong Flutter như thế nào?","optionsVi":{"A":"Via constructor arguments / route arguments","B":"Chỉ bằng rebooting phone","C":"Chỉ bằng editing Flutter engine","D":"Chỉ through SMS"},"answerDisplay":"A. Via constructor arguments / route arguments","concept":"• Cơ chế xếp chồng màn hình (stack) và chuyển page.","whyCorrect":"• Cơ chế xếp chồng màn hình (stack) và chuyển page.\n• push/pop route, điều hướng luồng màn hình.","intent":"• Cơ chế xếp chồng màn hình (stack) và chuyển page.\n• Chọn phương án khớp cơ chế Flutter, không chọn stack web/Android nhầm.","whatIs":{"A":"Cơ chế xếp chồng màn hình (stack) và chuyển page.","B":"Chỉ bằng rebooting phone","C":"Chỉ bằng editing Flutter engine","D":"Cơ chế Flutter/Dart liên quan «Chỉ through SMS»."},"whyWrong":{"B":"• Là gì? Chỉ bằng rebooting phone\n• Dùng để làm gì? Bản dịch/diễn đạt phương án — đối chiếu với định nghĩa chuẩn của đề.\n• Vì sao sai? «Only by rebooting the phone» — Chỉ bằng rebooting phone. Đề cần: Cơ chế xếp chồng màn hình (stack) và chuyển page.","C":"• Là gì? Chỉ bằng editing Flutter engine\n• Dùng để làm gì? Bản dịch/diễn đạt phương án — đối chiếu với định nghĩa chuẩn của đề.\n• Vì sao sai? «Only by editing the Flutter engine» — Chỉ bằng editing Flutter engine. Đề cần: Cơ chế xếp chồng màn hình (stack) và chuyển page.","D":"• Là gì? Cơ chế Flutter/Dart liên quan «Chỉ through SMS».\n• Dùng để làm gì? Đối chiếu đúng cơ chế/phạm trù với trọng tâm đề.\n• Vì sao sai? «Only through SMS» — Cơ chế Flutter/Dart liên quan «Chỉ through SMS». Đề cần: Cơ chế xếp chồng màn hình (stack) và chuyển page."}}},{"id":150,"task":"slides","taskLabel":"Slides","num":149,"question":"Which widget rebuilds when a Stream emits new data?","options":{"A":"SizedBox only","B":"StreamBuilder","C":"Icon only","D":"Divider only"},"answer":"B","alternatives":[],"source":"slides","exam":"PRM393_SLIDES_M5","explanation":{"questionVi":"Widget nào rebuild khi Stream phát dữ liệu mới?","optionsVi":{"A":"SizedBox","B":"StreamBuilder","C":"Icon","D":"Divider"},"answerDisplay":"B. StreamBuilder","concept":"• Chuỗi sự kiện/giá trị bất đồng bộ theo thời gian.","whyCorrect":"• StreamBuilder lắng nghe Stream và rebuild mỗi khi có event mới (auth state, BLoC stream…). B đúng.\n• Chuỗi sự kiện/giá trị bất đồng bộ theo thời gian.\n• Lắng nghe nhiều lần (click stream, data chunk).","intent":"• Future: một kết quả async.\n• Stream: nhiều sự kiện theo thời gian.","memoryTip":"• Đổi state → rebuild; BLoC/Cubit/Provider tách logic khỏi UI; state nên immutable.","whatIs":{"A":"Tạo hộp kích thước cố định hoặc khoảng trống size cho trước.","B":"Chuỗi sự kiện/giá trị bất đồng bộ theo thời gian.","C":"Cơ chế Flutter/Dart liên quan «Icon».","D":"Cơ chế Flutter/Dart liên quan «Divider»."},"whyWrong":{"A":"• Là gì? Tạo hộp kích thước cố định hoặc khoảng trống size cho trước.\n• Dùng để làm gì? Spacer cố định (width/height); khác Expanded (chiếm phần còn lại).\n• Vì sao sai? SizedBox tạo kích thước/khoảng trống cố định.","C":"• Là gì? Cơ chế Flutter/Dart liên quan «Icon».\n• Dùng để làm gì? Đối chiếu đúng cơ chế/phạm trù với trọng tâm đề.\n• Vì sao sai? «Icon only» — Cơ chế Flutter/Dart liên quan «Icon». Đề cần: Chuỗi sự kiện/giá trị bất đồng bộ theo thời gian.","D":"• Là gì? Cơ chế Flutter/Dart liên quan «Divider».\n• Dùng để làm gì? Đối chiếu đúng cơ chế/phạm trù với trọng tâm đề.\n• Vì sao sai? «Divider only» — Cơ chế Flutter/Dart liên quan «Divider». Đề cần: Chuỗi sự kiện/giá trị bất đồng bộ theo thời gian."}}},{"id":151,"task":"slides","taskLabel":"Slides","num":150,"question":"Why separate UI and state logic?","options":{"A":"Improve maintainability and testability","B":"Make animations slower only","C":"Force more global mutable state","D":"Avoid widgets entirely"},"answer":"A","alternatives":[],"source":"slides","exam":"PRM393_SLIDES_M5","explanation":{"questionVi":"Vì sao tách UI và logic state?","optionsVi":{"A":"Cải thiện khả năng bảo trì và khả năng kiểm thử","B":"Make animations chậm hơn","C":"Ép more global mutable state","D":"Tránh widgets entirely"},"answerDisplay":"A. Cải thiện khả năng bảo trì và khả năng kiểm thử","concept":"• Cải thiện khả năng bảo trì và khả năng kiểm thử. Bản dịch/diễn đạt phương án — đối chiếu với định nghĩa chuẩn của đề.","whyCorrect":"• Cải thiện khả năng bảo trì và khả năng kiểm thử\n• Bản dịch/diễn đạt phương án — đối chiếu với định nghĩa chuẩn của đề.","intent":"• Cải thiện khả năng bảo trì và khả năng kiểm thử\n• Bản dịch/diễn đạt phương án — đối chiếu với định nghĩa chuẩn của đề.","whatIs":{"A":"Cải thiện khả năng bảo trì và khả năng kiểm thử","B":"Make animations chậm hơn","C":"Ép more global mutable state","D":"Cơ chế Flutter/Dart liên quan «Tránh widgets entirely»."},"whyWrong":{"B":"• Là gì? Make animations chậm hơn\n• Dùng để làm gì? Bản dịch/diễn đạt phương án — đối chiếu với định nghĩa chuẩn của đề.\n• Vì sao sai? «Make animations slower only» — Make animations chậm hơn. Đề cần: Cải thiện khả năng bảo trì và khả năng kiểm thử.","C":"• Là gì? Ép more global mutable state\n• Dùng để làm gì? Bản dịch/diễn đạt phương án — đối chiếu với định nghĩa chuẩn của đề.\n• Vì sao sai? «Force more global mutable state» — Ép more global mutable state. Đề cần: Cải thiện khả năng bảo trì và khả năng kiểm thử.","D":"• Là gì? Cơ chế Flutter/Dart liên quan «Tránh widgets entirely».\n• Dùng để làm gì? Đối chiếu đúng cơ chế/phạm trù với trọng tâm đề.\n• Vì sao sai? «Avoid widgets entirely» — Cơ chế Flutter/Dart liên quan «Tránh widgets entirely». Đề cần: Cải thiện khả năng bảo trì và khả năng kiểm thử."}}},{"id":152,"task":"slides","taskLabel":"Slides","num":151,"question":"What does a route guard pattern aim to protect?","options":{"A":"GPU shaders","B":"Only font files","C":"Authenticated routes / unauthorized access","D":"Hot reload itself"},"answer":"C","alternatives":[],"source":"slides","exam":"PRM393_SLIDES_M5","explanation":{"questionVi":"Pattern route guard nhằm bảo vệ gì?","optionsVi":{"A":"GPU shaders","B":"Chỉ font files","C":"Route cần auth / chặn truy cập trái phép","D":"Hot reload itself"},"answerDisplay":"C. Route cần auth / chặn truy cập trái phép","concept":"• Cơ chế xếp chồng màn hình (stack) và chuyển page.","whyCorrect":"• Cơ chế xếp chồng màn hình (stack) và chuyển page.\n• push/pop route, điều hướng luồng màn hình.","intent":"• Cơ chế xếp chồng màn hình (stack) và chuyển page.\n• push/pop route, điều hướng luồng màn hình.","memoryTip":"• Auth: token/session tập trung; Guard chặn route; StreamBuilder hay dùng với auth stream.","whatIs":{"A":"Chương trình nhỏ chạy trên GPU để xử lý đồ họa.","B":"Bảo vệ route cần đăng nhập (cho phép/chặn vào màn).","C":"Cơ chế xếp chồng màn hình (stack) và chuyển page.","D":"Nạp lại code UI gần như giữ state đang chạy."},"whyWrong":{"A":"• Là gì? Chương trình nhỏ chạy trên GPU để xử lý đồ họa.\n• Dùng để làm gì? Vẽ/hiệu ứng; không phải mô hình async Future.\n• Vì sao sai? «GPU shaders» — Chương trình nhỏ chạy trên GPU để xử lý đồ họa. Đề cần: Cơ chế xếp chồng màn hình (stack) và chuyển page.","B":"• Là gì? Bảo vệ route cần đăng nhập (cho phép/chặn vào màn).\n• Dùng để làm gì? Route guard / auth gate trước khi vào màn bảo vệ.\n• Vì sao sai? «Only font files» — Bảo vệ route cần đăng nhập (cho phép/chặn vào màn). Đề cần: Cơ chế xếp chồng màn hình (stack) và chuyển page.","D":"• Là gì? Nạp lại code UI gần như giữ state đang chạy.\n• Dùng để làm gì? Xem thay đổi nhanh khi dev.\n• Vì sao sai? Hot reload nạp code UI nhanh khi dev; không phải công cụ phân tích sâu."}}},{"id":153,"task":"slides","taskLabel":"Slides","num":152,"question":"Provider is commonly used for:","options":{"A":"Image compression only","B":"Dependency injection / state exposure to the widget tree","C":"Replacing Dart with Java","D":"Building Windows kernels"},"answer":"B","alternatives":[],"source":"slides","exam":"PRM393_SLIDES_M5","explanation":{"questionVi":"Provider thường dùng cho:","optionsVi":{"A":"Image compression","B":"DI / đưa state ra cây widget","C":"Replacing Dart với Java","D":"Building Windows kernels"},"answerDisplay":"B. DI / đưa state ra cây widget","concept":"• Cách chia sẻ và phản ứng với trạng thái dùng chung giữa nhiều widget/màn.","whyCorrect":"• Cách chia sẻ và phản ứng với trạng thái dùng chung giữa nhiều widget/màn.\n• Tránh truyền prop sâu; cập nhật UI khi state đổi.","intent":"• Cách chia sẻ và phản ứng với trạng thái dùng chung giữa nhiều widget/màn.\n• Tránh truyền prop sâu; cập nhật UI khi state đổi.","whatIs":{"A":"Cơ chế Flutter/Dart liên quan «Image compression».","B":"Cách chia sẻ và phản ứng với trạng thái dùng chung giữa nhiều widget/màn.","C":"Ngôn ngữ lập trình chính của Flutter.","D":"Các lớp hệ điều hành/môi trường desktop (kernel, shell…)."},"whyWrong":{"A":"• Là gì? Cơ chế Flutter/Dart liên quan «Image compression».\n• Dùng để làm gì? Đối chiếu đúng cơ chế/phạm trù với trọng tâm đề.\n• Vì sao sai? Provider là DI/state; không phải thư viện lưu trữ hay HTTP.","C":"• Là gì? Ngôn ngữ lập trình chính của Flutter.\n• Dùng để làm gì? Viết UI và logic app Flutter.\n• Vì sao sai? Provider là DI/state; không phải thư viện lưu trữ hay HTTP.","D":"• Là gì? Các lớp hệ điều hành/môi trường desktop (kernel, shell…).\n• Dùng để làm gì? Quản lý máy/OS; không phải 3 tầng Framework–Engine–Embedder của Flutter.\n• Vì sao sai? Provider là DI/state; không phải thư viện lưu trữ hay HTTP."}}},{"id":154,"task":"slides","taskLabel":"Slides","num":153,"question":"What is the main goal of responsive UI?","options":{"A":"UI only works on one fixed phone model","B":"Layouts adapt to different screen sizes","C":"Disable orientation changes forever","D":"Remove MediaQuery"},"answer":"B","alternatives":[],"source":"slides","exam":"PRM393_SLIDES_M6","explanation":{"questionVi":"Mục tiêu chính của UI responsive là gì?","optionsVi":{"A":"UI chỉ works trên một fixed phone model","B":"Bố cục thích ứng nhiều kích thước màn","C":"Tắt orientation thay đổi mãi mãi","D":"Gỡ bỏ MediaQuery"},"answerDisplay":"B. Bố cục thích ứng nhiều kích thước màn","concept":"• Bố cục thích ứng nhiều kích thước màn. Bản dịch/diễn đạt phương án — đối chiếu với định nghĩa chuẩn của đề.","whyCorrect":"• Bố cục thích ứng nhiều kích thước màn\n• Bản dịch/diễn đạt phương án — đối chiếu với định nghĩa chuẩn của đề.","intent":"• Bố cục thích ứng nhiều kích thước màn\n• Bản dịch/diễn đạt phương án — đối chiếu với định nghĩa chuẩn của đề.","whatIs":{"A":"UI chỉ works trên một fixed phone model","B":"Bố cục thích ứng nhiều kích thước màn","C":"Tắt orientation thay đổi mãi mãi","D":"Cụm «Gỡ bỏ MediaQuery» mang một nghĩa riêng cần đối chiếu với đề."},"whyWrong":{"A":"• Là gì? UI chỉ works trên một fixed phone model\n• Dùng để làm gì? Bản dịch/diễn đạt phương án — đối chiếu với định nghĩa chuẩn của đề.\n• Vì sao sai? «UI only works on one fixed phone model» — UI chỉ works trên một fixed phone model. Đề cần: Bố cục thích ứng nhiều kích thước màn.","C":"• Là gì? Tắt orientation thay đổi mãi mãi\n• Dùng để làm gì? Bản dịch/diễn đạt phương án — đối chiếu với định nghĩa chuẩn của đề.\n• Vì sao sai? «Disable orientation changes forever» — Tắt orientation thay đổi mãi mãi. Đề cần: Bố cục thích ứng nhiều kích thước màn.","D":"• Là gì? Cụm «Gỡ bỏ MediaQuery» mang một nghĩa riêng cần đối chiếu với đề.\n• Dùng để làm gì? So bản chất với đáp án đúng; loại nếu sai đối tượng hoặc sai lớp khái niệm.\n• Vì sao sai? «Remove MediaQuery» — Cụm «Gỡ bỏ MediaQuery» mang một nghĩa riêng cần đối chiếu với đề. Đề cần: Bố cục thích ứng nhiều kích thước màn."}}},{"id":155,"task":"slides","taskLabel":"Slides","num":154,"question":"What does GridView help build according to the slides?","options":{"A":"Scrollable grids that adapt columns to width","B":"Only 3D games engines","C":"SQL indexes","D":"Certificate authorities"},"answer":"A","alternatives":[],"source":"slides","exam":"PRM393_SLIDES_M6","explanation":{"questionVi":"Theo slide, GridView giúp dựng gì?","optionsVi":{"A":"Lưới cuộn, số cột theo chiều rộng","B":"Chỉ 3D games engines","C":"SQL indexes","D":"Certificate authorities"},"answerDisplay":"A. Lưới cuộn, số cột theo chiều rộng","concept":"• Lưới cuộn, số cột theo chiều rộng. Bản dịch/diễn đạt phương án — đối chiếu với định nghĩa chuẩn của đề.","whyCorrect":"• Lưới cuộn, số cột theo chiều rộng\n• Bản dịch/diễn đạt phương án — đối chiếu với định nghĩa chuẩn của đề.","intent":"• Lưới cuộn, số cột theo chiều rộng\n• Bản dịch/diễn đạt phương án — đối chiếu với định nghĩa chuẩn của đề.","whatIs":{"A":"Lưới cuộn, số cột theo chiều rộng","B":"Cụm «Chỉ 3D games engines» mang một nghĩa riêng cần đối chiếu với đề.","C":"Thao tác/giao dịch trên cơ sở dữ liệu quan hệ.","D":"Cụm «Certificate authorities» mang một nghĩa riêng cần đối chiếu với đề."},"whyWrong":{"B":"• Là gì? Cụm «Chỉ 3D games engines» mang một nghĩa riêng cần đối chiếu với đề.\n• Dùng để làm gì? So bản chất với đáp án đúng; loại nếu sai đối tượng hoặc sai lớp khái niệm.\n• Vì sao sai? «Only 3D games engines» — Cụm «Chỉ 3D games engines» mang một nghĩa riêng cần đối chiếu với đề. Đề cần: Lưới cuộn, số cột theo chiều rộng.","C":"• Là gì? Thao tác/giao dịch trên cơ sở dữ liệu quan hệ.\n• Dùng để làm gì? Lưu trữ và truy vấn dữ liệu bền vững; không thuộc widget tree UI.\n• Vì sao sai? «SQL indexes» — Thao tác/giao dịch trên cơ sở dữ liệu quan hệ. Đề cần: Lưới cuộn, số cột theo chiều rộng.","D":"• Là gì? Cụm «Certificate authorities» mang một nghĩa riêng cần đối chiếu với đề.\n• Dùng để làm gì? So bản chất với đáp án đúng; loại nếu sai đối tượng hoặc sai lớp khái niệm.\n• Vì sao sai? «Certificate authorities» — Cụm «Certificate authorities» mang một nghĩa riêng cần đối chiếu với đề. Đề cần: Lưới cuộn, số cột theo chiều rộng."}}},{"id":156,"task":"slides","taskLabel":"Slides","num":155,"question":"Which API is commonly used to read screen size/orientation?","options":{"A":"SharedPreferences only","B":"HttpClient only","C":"MediaQuery","D":"FlutterDriver only"},"answer":"C","alternatives":[],"source":"slides","exam":"PRM393_SLIDES_M6","explanation":{"questionVi":"API nào thường dùng để đọc size/orientation màn hình?","optionsVi":{"A":"SharedPreferences","B":"HttpClient","C":"MediaQuery","D":"FlutterDriver"},"answerDisplay":"C. MediaQuery","concept":"• Cụm «MediaQuery» mang một nghĩa riêng cần đối chiếu với đề.","whyCorrect":"• Cụm «MediaQuery» mang một nghĩa riêng cần đối chiếu với đề.\n• So bản chất với đáp án đúng; loại nếu sai đối tượng hoặc sai lớp khái niệm.","intent":"• Cụm «MediaQuery» mang một nghĩa riêng cần đối chiếu với đề.\n• So bản chất với đáp án đúng; loại nếu sai đối tượng hoặc sai lớp khái niệm.","memoryTip":"• GET lấy · POST tạo · Authorization mang token · parse JSON → object Dart.","whatIs":{"A":"Cụm «SharedPreferences» mang một nghĩa riêng cần đối chiếu với đề.","B":"Client HTTP để gửi request mạng (GET/POST…).","C":"Cụm «MediaQuery» mang một nghĩa riêng cần đối chiếu với đề.","D":"Cơ chế Flutter/Dart liên quan «FlutterDriver»."},"whyWrong":{"A":"• Là gì? Cụm «SharedPreferences» mang một nghĩa riêng cần đối chiếu với đề.\n• Dùng để làm gì? So bản chất với đáp án đúng; loại nếu sai đối tượng hoặc sai lớp khái niệm.\n• Vì sao sai? shared_preferences chỉ key-value đơn giản (bool/int/string), không phù hợp mọi nhu cầu.","B":"• Là gì? Client HTTP để gửi request mạng (GET/POST…).\n• Dùng để làm gì? Gọi API/tải dữ liệu; không phải widget layout hay spacer UI.\n• Vì sao sai? «HttpClient only» — Client HTTP để gửi request mạng (GET/POST…). Đề cần: Cụm «MediaQuery» mang một nghĩa riêng cần đối chiếu với đề.","D":"• Là gì? Cơ chế Flutter/Dart liên quan «FlutterDriver».\n• Dùng để làm gì? Đối chiếu đúng cơ chế/phạm trù với trọng tâm đề.\n• Vì sao sai? «FlutterDriver only» — Cơ chế Flutter/Dart liên quan «FlutterDriver». Đề cần: Cụm «MediaQuery» mang một nghĩa riêng cần đối chiếu với đề."}}},{"id":157,"task":"slides","taskLabel":"Slides","num":156,"question":"Adaptive layout typically means:","options":{"A":"Same exact pixels on all devices always","B":"UI chooses suitable layout patterns for platform/screen class","C":"No widgets allowed","D":"Only landscape tablets forever"},"answer":"B","alternatives":[],"source":"slides","exam":"PRM393_SLIDES_M6","explanation":{"questionVi":"Adaptive layout thường nghĩa là:","optionsVi":{"A":"Same exact pixels trên tất cả devices Luôn","B":"UI chọn pattern layout phù hợp nền tảng/loại màn","C":"Không widgets allowed","D":"Chỉ landscape tablets mãi mãi"},"answerDisplay":"B. UI chọn pattern layout phù hợp nền tảng/loại màn","concept":"• Phần mềm quản lý phần cứng, tiến trình, bộ nhớ, I/O.","whyCorrect":"• Phần mềm quản lý phần cứng, tiến trình, bộ nhớ, I/O.\n• Cấp tài nguyên và lập lịch cho chương trình.","intent":"• Phần mềm quản lý phần cứng, tiến trình, bộ nhớ, I/O.\n• Cấp tài nguyên và lập lịch cho chương trình.","whatIs":{"A":"Same exact pixels trên tất cả devices Luôn","B":"Phần mềm quản lý phần cứng, tiến trình, bộ nhớ, I/O.","C":"Cơ chế Flutter/Dart liên quan «Không widgets allowed».","D":"Chỉ landscape tablets mãi mãi"},"whyWrong":{"A":"• Là gì? Same exact pixels trên tất cả devices Luôn\n• Dùng để làm gì? Bản dịch/diễn đạt phương án — đối chiếu với định nghĩa chuẩn của đề.\n• Vì sao sai? «Same exact pixels on all devices always» — Same exact pixels trên tất cả devices Luôn. Đề cần: Phần mềm quản lý phần cứng, tiến trình, bộ nhớ, I/O.","C":"• Là gì? Cơ chế Flutter/Dart liên quan «Không widgets allowed».\n• Dùng để làm gì? Đối chiếu đúng cơ chế/phạm trù với trọng tâm đề.\n• Vì sao sai? «No widgets allowed» — Cơ chế Flutter/Dart liên quan «Không widgets allowed». Đề cần: Phần mềm quản lý phần cứng, tiến trình, bộ nhớ, I/O.","D":"• Là gì? Chỉ landscape tablets mãi mãi\n• Dùng để làm gì? Bản dịch/diễn đạt phương án — đối chiếu với định nghĩa chuẩn của đề.\n• Vì sao sai? «Only landscape tablets forever» — Chỉ landscape tablets mãi mãi. Đề cần: Phần mềm quản lý phần cứng, tiến trình, bộ nhớ, I/O."}}},{"id":158,"task":"slides","taskLabel":"Slides","num":157,"question":"Expanded inside a Flex (Row/Column) is used to:","options":{"A":"Take remaining free space along the main axis","B":"Hide the keyboard only","C":"Start deep links","D":"Compile AOT"},"answer":"A","alternatives":[],"source":"slides","exam":"PRM393_SLIDES_M6","explanation":{"questionVi":"Expanded trong Flex (Row/Column) dùng để:","optionsVi":{"A":"Chiếm phần trống còn lại theo trục chính","B":"Chỉ ẩn bàn phím","C":"Khởi chạy deep links","D":"Biên dịch AOT"},"answerDisplay":"A. Chiếm phần trống còn lại theo trục chính","concept":"• Buộc widget con chiếm toàn bộ không gian còn lại theo main axis của Flex (Row/Column/Flex).","whyCorrect":"• Buộc widget con chiếm toàn bộ không gian còn lại theo main axis của Flex (Row/Column/Flex).\n• Trong Row giãn ngang, trong Column giãn dọc; nhiều Expanded chia phần trống theo flex. Tương đương Flexible(fit: FlexFit.tight).","intent":"• Expanded chỉ dùng trong Flex/Row/Column.\n• Giãn theo main axis: Row → ngang, Column → dọc; nhiều Expanded chia theo flex.","memoryTip":"• Expanded = Flexible(fit: FlexFit.tight) — bắt buộc full phần còn lại trên main axis.\n• Row: main = ngang · Column: main = dọc.","whatIs":{"A":"Buộc widget con chiếm toàn bộ không gian còn lại theo main axis của Flex (Row/Column/Flex).","B":"Ẩn bàn phím ảo trên màn hình.","C":"Mở ứng dụng (hoặc màn cụ thể) từ URL/URI bên ngoài.","D":"Biên dịch Ahead-of-Time: dịch Dart ra native trước khi chạy (bản release)."},"whyWrong":{"B":"• Là gì? Ẩn bàn phím ảo trên màn hình.\n• Dùng để làm gì? Thường dùng FocusScope.of(context).unfocus() / FocusNode — không phải Expanded.\n• Vì sao sai? Expanded không điều khiển bàn phím. Ẩn bàn phím thường dùng FocusScope.of(context).unfocus() hoặc FocusNode.","C":"• Là gì? Mở ứng dụng (hoặc màn cụ thể) từ URL/URI bên ngoài.\n• Dùng để làm gì? Routing/deep linking; không liên quan chia không gian layout Flex.\n• Vì sao sai? Deep links mở app/màn hình qua URL; không liên quan chia không gian layout Flex.","D":"• Là gì? Biên dịch Ahead-of-Time: dịch Dart ra native trước khi chạy (bản release).\n• Dùng để làm gì? Tối ưu hiệu năng bản ship; không phải widget layout.\n• Vì sao sai? AOT (Ahead-of-Time) là cơ chế biên dịch Dart khi build release; không phải widget Expanded."}}},{"id":159,"task":"slides","taskLabel":"Slides","num":158,"question":"Why avoid hard-coded sizes for all devices?","options":{"A":"Hard-coded sizes always look perfect everywhere","B":"Screens differ; rigid sizes break layouts on small/large devices","C":"Flutter forbids numbers","D":"MediaQuery is illegal"},"answer":"B","alternatives":[],"source":"slides","exam":"PRM393_SLIDES_M6","explanation":{"questionVi":"Vì sao tránh hard-code size cho mọi thiết bị?","optionsVi":{"A":"Kích thước hard-code luôn đẹp mọi nơi","B":"Màn khác nhau; size cứng vỡ layout trên máy nhỏ/lớn","C":"Flutter forbids numbers","D":"MediaQuery là illegal"},"answerDisplay":"B. Màn khác nhau; size cứng vỡ layout trên máy nhỏ/lớn","concept":"• Màn khác nhau; size cứng vỡ layout trên máy nhỏ/lớn. Bản dịch/diễn đạt phương án — đối chiếu với định nghĩa chuẩn của đề.","whyCorrect":"• Màn khác nhau; size cứng vỡ layout trên máy nhỏ/lớn\n• Bản dịch/diễn đạt phương án — đối chiếu với định nghĩa chuẩn của đề.","intent":"• Màn khác nhau; size cứng vỡ layout trên máy nhỏ/lớn\n• Bản dịch/diễn đạt phương án — đối chiếu với định nghĩa chuẩn của đề.","whatIs":{"A":"Kích thước hard-code luôn đẹp mọi nơi","B":"Màn khác nhau; size cứng vỡ layout trên máy nhỏ/lớn","C":"Cơ chế Flutter/Dart liên quan «Flutter forbids numbers».","D":"Cụm «MediaQuery là illegal» mang một nghĩa riêng cần đối chiếu với đề."},"whyWrong":{"A":"• Là gì? Kích thước hard-code luôn đẹp mọi nơi\n• Dùng để làm gì? Bản dịch/diễn đạt phương án — đối chiếu với định nghĩa chuẩn của đề.\n• Vì sao sai? «Hard-coded sizes always look perfect everywhere» — Kích thước hard-code luôn đẹp mọi nơi. Đề cần: Màn khác nhau; size cứng vỡ layout trên máy nhỏ/lớn.","C":"• Là gì? Cơ chế Flutter/Dart liên quan «Flutter forbids numbers».\n• Dùng để làm gì? Đối chiếu đúng cơ chế/phạm trù với trọng tâm đề.\n• Vì sao sai? «Flutter forbids numbers» — Cơ chế Flutter/Dart liên quan «Flutter forbids numbers». Đề cần: Màn khác nhau; size cứng vỡ layout trên máy nhỏ/lớn.","D":"• Là gì? Cụm «MediaQuery là illegal» mang một nghĩa riêng cần đối chiếu với đề.\n• Dùng để làm gì? So bản chất với đáp án đúng; loại nếu sai đối tượng hoặc sai lớp khái niệm.\n• Vì sao sai? «MediaQuery is illegal» — Cụm «MediaQuery là illegal» mang một nghĩa riêng cần đối chiếu với đề. Đề cần: Màn khác nhau; size cứng vỡ layout trên máy nhỏ/lớn."}}},{"id":160,"task":"slides","taskLabel":"Slides","num":159,"question":"LayoutBuilder is useful because it:","options":{"A":"Only builds APKs","B":"Only manages auth tokens","C":"Provides parent constraints to choose layout","D":"Replaces Navigator permanently"},"answer":"C","alternatives":[],"source":"slides","exam":"PRM393_SLIDES_M6","explanation":{"questionVi":"LayoutBuilder hữu ích vì nó:","optionsVi":{"A":"Chỉ builds APKs","B":"Chỉ manages auth token","C":"Cho constraint từ cha để chọn layout","D":"Replaces Navigator vĩnh viễn"},"answerDisplay":"C. Cho constraint từ cha để chọn layout","concept":"• Phần mềm quản lý phần cứng, tiến trình, bộ nhớ, I/O.","whyCorrect":"• Phần mềm quản lý phần cứng, tiến trình, bộ nhớ, I/O.\n• Cấp tài nguyên và lập lịch cho chương trình.","intent":"• Phần mềm quản lý phần cứng, tiến trình, bộ nhớ, I/O.\n• Cấp tài nguyên và lập lịch cho chương trình.","whatIs":{"A":"Cụm «Chỉ builds APKs» mang một nghĩa riêng cần đối chiếu với đề.","B":"Cụm «Chỉ manages auth token» mang một nghĩa riêng cần đối chiếu với đề.","C":"Phần mềm quản lý phần cứng, tiến trình, bộ nhớ, I/O.","D":"Cơ chế xếp chồng màn hình (stack) và chuyển page."},"whyWrong":{"A":"• Là gì? Cụm «Chỉ builds APKs» mang một nghĩa riêng cần đối chiếu với đề.\n• Dùng để làm gì? So bản chất với đáp án đúng; loại nếu sai đối tượng hoặc sai lớp khái niệm.\n• Vì sao sai? «Only builds APKs» — Cụm «Chỉ builds APKs» mang một nghĩa riêng cần đối chiếu với đề. Đề cần: Phần mềm quản lý phần cứng, tiến trình, bộ nhớ, I/O.","B":"• Là gì? Cụm «Chỉ manages auth token» mang một nghĩa riêng cần đối chiếu với đề.\n• Dùng để làm gì? So bản chất với đáp án đúng; loại nếu sai đối tượng hoặc sai lớp khái niệm.\n• Vì sao sai? «Only manages auth tokens» — Cụm «Chỉ manages auth token» mang một nghĩa riêng cần đối chiếu với đề. Đề cần: Phần mềm quản lý phần cứng, tiến trình, bộ nhớ, I/O.","D":"• Là gì? Cơ chế xếp chồng màn hình (stack) và chuyển page.\n• Dùng để làm gì? push/pop route, điều hướng luồng màn hình.\n• Vì sao sai? «Replaces Navigator permanently» — Cơ chế xếp chồng màn hình (stack) và chuyển page. Đề cần: Phần mềm quản lý phần cứng, tiến trình, bộ nhớ, I/O."}}},{"id":161,"task":"slides","taskLabel":"Slides","num":160,"question":"Which widget is commonly used for scrollable single-child content?","options":{"A":"SingleChildScrollView","B":"AppBar only","C":"SnackBar only","D":"Tooltip only"},"answer":"A","alternatives":[],"source":"slides","exam":"PRM393_SLIDES_M6","explanation":{"questionVi":"Widget nào thường dùng cho nội dung 1 con có thể cuộn?","optionsVi":{"A":"SingleChildScrollView","B":"AppBar","C":"SnackBar","D":"Tooltip"},"answerDisplay":"A. SingleChildScrollView","concept":"• Cơ chế Flutter/Dart liên quan «SingleChildScrollView».","whyCorrect":"• Cơ chế Flutter/Dart liên quan «SingleChildScrollView».","intent":"• Cơ chế Flutter/Dart liên quan «SingleChildScrollView».\n• Chọn phương án khớp cơ chế Flutter, không chọn stack web/Android nhầm.","whatIs":{"A":"Cơ chế Flutter/Dart liên quan «SingleChildScrollView».","B":"Cơ chế Flutter/Dart liên quan «AppBar».","C":"Cơ chế Flutter/Dart liên quan «SnackBar».","D":"Cơ chế Flutter/Dart liên quan «Tooltip»."},"whyWrong":{"B":"• Là gì? Cơ chế Flutter/Dart liên quan «AppBar».\n• Dùng để làm gì? Đối chiếu đúng cơ chế/phạm trù với trọng tâm đề.\n• Vì sao sai? «AppBar only» — Cơ chế Flutter/Dart liên quan «AppBar». Đề cần: Cơ chế Flutter/Dart liên quan «SingleChildScrollView».","C":"• Là gì? Cơ chế Flutter/Dart liên quan «SnackBar».\n• Dùng để làm gì? Đối chiếu đúng cơ chế/phạm trù với trọng tâm đề.\n• Vì sao sai? «SnackBar only» — Cơ chế Flutter/Dart liên quan «SnackBar». Đề cần: Cơ chế Flutter/Dart liên quan «SingleChildScrollView».","D":"• Là gì? Cơ chế Flutter/Dart liên quan «Tooltip».\n• Dùng để làm gì? Đối chiếu đúng cơ chế/phạm trù với trọng tâm đề.\n• Vì sao sai? «Tooltip only» — Cơ chế Flutter/Dart liên quan «Tooltip». Đề cần: Cơ chế Flutter/Dart liên quan «SingleChildScrollView»."}}},{"id":162,"task":"slides","taskLabel":"Slides","num":161,"question":"What is the primary purpose of forms in mobile apps?","options":{"A":"GPU profiling only","B":"User data collection with validation","C":"Deep link DNS setup only","D":"Engine compilation"},"answer":"B","alternatives":[],"source":"slides","exam":"PRM393_SLIDES_M7","explanation":{"questionVi":"Mục đích chính của form trong app mobile?","optionsVi":{"A":"GPU profiling","B":"Thu thập dữ liệu người dùng kèm validate","C":"Deep link DNS setup","D":"Engine compilation"},"answerDisplay":"B. Thu thập dữ liệu người dùng kèm validate","concept":"• Phần mềm quản lý phần cứng, tiến trình, bộ nhớ, I/O.","whyCorrect":"• Phần mềm quản lý phần cứng, tiến trình, bộ nhớ, I/O.\n• Cấp tài nguyên và lập lịch cho chương trình.","intent":"• Phần mềm quản lý phần cứng, tiến trình, bộ nhớ, I/O.\n• Cấp tài nguyên và lập lịch cho chương trình.","whatIs":{"A":"Cụm «GPU profiling» mang một nghĩa riêng cần đối chiếu với đề.","B":"Phần mềm quản lý phần cứng, tiến trình, bộ nhớ, I/O.","C":"Mở ứng dụng (hoặc màn cụ thể) từ URL/URI bên ngoài.","D":"Cụm «Engine compilation» mang một nghĩa riêng cần đối chiếu với đề."},"whyWrong":{"A":"• Là gì? Cụm «GPU profiling» mang một nghĩa riêng cần đối chiếu với đề.\n• Dùng để làm gì? So bản chất với đáp án đúng; loại nếu sai đối tượng hoặc sai lớp khái niệm.\n• Vì sao sai? «GPU profiling only» — Cụm «GPU profiling» mang một nghĩa riêng cần đối chiếu với đề. Đề cần: Phần mềm quản lý phần cứng, tiến trình, bộ nhớ, I/O.","C":"• Là gì? Mở ứng dụng (hoặc màn cụ thể) từ URL/URI bên ngoài.\n• Dùng để làm gì? Routing/deep linking; không liên quan chia không gian layout Flex.\n• Vì sao sai? «Deep link DNS setup only» — Mở ứng dụng (hoặc màn cụ thể) từ URL/URI bên ngoài. Đề cần: Phần mềm quản lý phần cứng, tiến trình, bộ nhớ, I/O.","D":"• Là gì? Cụm «Engine compilation» mang một nghĩa riêng cần đối chiếu với đề.\n• Dùng để làm gì? So bản chất với đáp án đúng; loại nếu sai đối tượng hoặc sai lớp khái niệm.\n• Vì sao sai? «Engine compilation» — Cụm «Engine compilation» mang một nghĩa riêng cần đối chiếu với đề. Đề cần: Phần mềm quản lý phần cứng, tiến trình, bộ nhớ, I/O."}}},{"id":163,"task":"slides","taskLabel":"Slides","num":162,"question":"TextEditingController is used to:","options":{"A":"Read/control text field values","B":"Sign APKs","C":"Manage isolates only","D":"Configure AndroidManifest deep links"},"answer":"A","alternatives":[],"source":"slides","exam":"PRM393_SLIDES_M7","explanation":{"questionVi":"TextEditingController dùng để:","optionsVi":{"A":"Đọc/điều khiển giá trị TextField","B":"Sign APKs","C":"Quản lý isolates","D":"Configure AndroidManifest deep links"},"answerDisplay":"A. Đọc/điều khiển giá trị TextField","concept":"• Đọc/điều khiển giá trị TextField. Bản dịch/diễn đạt phương án — đối chiếu với định nghĩa chuẩn của đề.","whyCorrect":"• Đọc/điều khiển giá trị TextField\n• Bản dịch/diễn đạt phương án — đối chiếu với định nghĩa chuẩn của đề.","intent":"• Đọc/điều khiển giá trị TextField\n• Bản dịch/diễn đạt phương án — đối chiếu với định nghĩa chuẩn của đề.","whatIs":{"A":"Đọc/điều khiển giá trị TextField","B":"Cụm «Sign APKs» mang một nghĩa riêng cần đối chiếu với đề.","C":"Cụm «Quản lý isolates» mang một nghĩa riêng cần đối chiếu với đề.","D":"Mở ứng dụng (hoặc màn cụ thể) từ URL/URI bên ngoài."},"whyWrong":{"B":"• Là gì? Cụm «Sign APKs» mang một nghĩa riêng cần đối chiếu với đề.\n• Dùng để làm gì? So bản chất với đáp án đúng; loại nếu sai đối tượng hoặc sai lớp khái niệm.\n• Vì sao sai? «Sign APKs» — Cụm «Sign APKs» mang một nghĩa riêng cần đối chiếu với đề. Đề cần: Đọc/điều khiển giá trị TextField.","C":"• Là gì? Cụm «Quản lý isolates» mang một nghĩa riêng cần đối chiếu với đề.\n• Dùng để làm gì? So bản chất với đáp án đúng; loại nếu sai đối tượng hoặc sai lớp khái niệm.\n• Vì sao sai? «Manage isolates only» — Cụm «Quản lý isolates» mang một nghĩa riêng cần đối chiếu với đề. Đề cần: Đọc/điều khiển giá trị TextField.","D":"• Là gì? Mở ứng dụng (hoặc màn cụ thể) từ URL/URI bên ngoài.\n• Dùng để làm gì? Routing/deep linking; không liên quan chia không gian layout Flex.\n• Vì sao sai? «Configure AndroidManifest deep links» — Mở ứng dụng (hoặc màn cụ thể) từ URL/URI bên ngoài. Đề cần: Đọc/điều khiển giá trị TextField."}}},{"id":164,"task":"slides","taskLabel":"Slides","num":163,"question":"How do you typically hide password characters in a TextField?","options":{"A":"Set keyboardType to email only","B":"Use ListView","C":"obscureText: true","D":"Use GridView.count"},"answer":"C","alternatives":[],"source":"slides","exam":"PRM393_SLIDES_M7","explanation":{"questionVi":"Thường ẩn ký tự mật khẩu trong TextField như thế nào?","optionsVi":{"A":"Set keyboardType để email","B":"Dùng ListView","C":"obscureText: true","D":"Dùng GridView.count"},"answerDisplay":"C. obscureText: true","concept":"• Cụm «obscureText: true» mang một nghĩa riêng cần đối chiếu với đề.","whyCorrect":"• Cụm «obscureText: true» mang một nghĩa riêng cần đối chiếu với đề.\n• So bản chất với đáp án đúng; loại nếu sai đối tượng hoặc sai lớp khái niệm.","intent":"• Cụm «obscureText: true» mang một nghĩa riêng cần đối chiếu với đề.\n• So bản chất với đáp án đúng; loại nếu sai đối tượng hoặc sai lớp khái niệm.","whatIs":{"A":"Tập hợp giá trị không trùng.","B":"Cụm «Dùng ListView» mang một nghĩa riêng cần đối chiếu với đề.","C":"Cụm «obscureText: true» mang một nghĩa riêng cần đối chiếu với đề.","D":"Cụm «Dùng GridView.count» mang một nghĩa riêng cần đối chiếu với đề."},"whyWrong":{"A":"• Là gì? Tập hợp giá trị không trùng.\n• Dùng để làm gì? Loại trùng, kiểm tra membership.\n• Vì sao sai? «Set keyboardType to email only» — Tập hợp giá trị không trùng. Đề cần: Cụm «obscureText: true» mang một nghĩa riêng cần đối chiếu với đề.","B":"• Là gì? Cụm «Dùng ListView» mang một nghĩa riêng cần đối chiếu với đề.\n• Dùng để làm gì? So bản chất với đáp án đúng; loại nếu sai đối tượng hoặc sai lớp khái niệm.\n• Vì sao sai? ListView cuộn danh sách; không phải Future/Stream builder hay layout flex chính.","D":"• Là gì? Cụm «Dùng GridView.count» mang một nghĩa riêng cần đối chiếu với đề.\n• Dùng để làm gì? So bản chất với đáp án đúng; loại nếu sai đối tượng hoặc sai lớp khái niệm.\n• Vì sao sai? «Use GridView.count» — Cụm «Dùng GridView.count» mang một nghĩa riêng cần đối chiếu với đề. Đề cần: Cụm «obscureText: true» mang một nghĩa riêng cần đối chiếu với đề."}}},{"id":165,"task":"slides","taskLabel":"Slides","num":164,"question":"What does FormState.reset() do?","options":{"A":"Uninstall the app","B":"Reset form fields to initial values","C":"Clear device storage entirely","D":"Invalidate SSL certificates"},"answer":"B","alternatives":[],"source":"slides","exam":"PRM393_SLIDES_M7","explanation":{"questionVi":"FormState.reset() làm gì?","optionsVi":{"A":"Uninstall the app","B":"Đặt lại form về giá trị ban đầu","C":"Xómột device lưu trữ entirely","D":"Invalidate SSL certificates"},"answerDisplay":"B. Đặt lại form về giá trị ban đầu","concept":"• Đặt lại form về giá trị ban đầu. Bản dịch/diễn đạt phương án — đối chiếu với định nghĩa chuẩn của đề.","whyCorrect":"• Đặt lại form về giá trị ban đầu\n• Bản dịch/diễn đạt phương án — đối chiếu với định nghĩa chuẩn của đề.","intent":"• Phân biệt List / Set / Map trong Dart.\n• Thứ tự, trùng lặp, hay key–value.","whatIs":{"A":"Cụm «Uninstall the app» mang một nghĩa riêng cần đối chiếu với đề.","B":"Đặt lại form về giá trị ban đầu","C":"Xómột device lưu trữ entirely","D":"Cụm «Invalidate SSL certificates» mang một nghĩa riêng cần đối chiếu với đề."},"whyWrong":{"A":"• Là gì? Cụm «Uninstall the app» mang một nghĩa riêng cần đối chiếu với đề.\n• Dùng để làm gì? So bản chất với đáp án đúng; loại nếu sai đối tượng hoặc sai lớp khái niệm.\n• Vì sao sai? «Uninstall the app» — Cụm «Uninstall the app» mang một nghĩa riêng cần đối chiếu với đề. Đề cần: Đặt lại form về giá trị ban đầu.","C":"• Là gì? Xómột device lưu trữ entirely\n• Dùng để làm gì? Bản dịch/diễn đạt phương án — đối chiếu với định nghĩa chuẩn của đề.\n• Vì sao sai? «Clear device storage entirely» — Xómột device lưu trữ entirely. Đề cần: Đặt lại form về giá trị ban đầu.","D":"• Là gì? Cụm «Invalidate SSL certificates» mang một nghĩa riêng cần đối chiếu với đề.\n• Dùng để làm gì? So bản chất với đáp án đúng; loại nếu sai đối tượng hoặc sai lớp khái niệm.\n• Vì sao sai? «Invalidate SSL certificates» — Cụm «Invalidate SSL certificates» mang một nghĩa riêng cần đối chiếu với đề. Đề cần: Đặt lại form về giá trị ban đầu."}}},{"id":166,"task":"slides","taskLabel":"Slides","num":165,"question":"A strong password validation demo in slides requires at least:","options":{"A":"Length rules (e.g. ≥ 8) and matching confirm password","B":"Only one character always","C":"No validation ever","D":"Password stored in plain Text widget title only"},"answer":"A","alternatives":[],"source":"slides","exam":"PRM393_SLIDES_M7","explanation":{"questionVi":"Demo validate mật khẩu mạnh trong slide yêu cầu tối thiểu:","optionsVi":{"A":"Quy tắc độ dài (vd. ≥ 8) và khớp confirm password","B":"Chỉ một character Luôn","C":"Không validation ever","D":"Mật khẩu stored trong plain Text widget title"},"answerDisplay":"A. Quy tắc độ dài (vd. ≥ 8) và khớp confirm password","concept":"• Quy tắc độ dài (vd. ≥ 8) và khớp confirm password. Bản dịch/diễn đạt phương án — đối chiếu với định nghĩa chuẩn của đề.","whyCorrect":"• Quy tắc độ dài (vd. ≥ 8) và khớp confirm password\n• Bản dịch/diễn đạt phương án — đối chiếu với định nghĩa chuẩn của đề.","intent":"• Quy tắc độ dài (vd. ≥ 8) và khớp confirm password\n• Bản dịch/diễn đạt phương án — đối chiếu với định nghĩa chuẩn của đề.","whatIs":{"A":"Quy tắc độ dài (vd. ≥ 8) và khớp confirm password","B":"Cụm «Chỉ một character Luôn» mang một nghĩa riêng cần đối chiếu với đề.","C":"Cụm «Không validation ever» mang một nghĩa riêng cần đối chiếu với đề.","D":"Mật khẩu stored trong plain Text widget title"},"whyWrong":{"B":"• Là gì? Cụm «Chỉ một character Luôn» mang một nghĩa riêng cần đối chiếu với đề.\n• Dùng để làm gì? So bản chất với đáp án đúng; loại nếu sai đối tượng hoặc sai lớp khái niệm.\n• Vì sao sai? «Only one character always» — Cụm «Chỉ một character Luôn» mang một nghĩa riêng cần đối chiếu với đề. Đề cần: Quy tắc độ dài (vd. ≥ 8) và khớp confirm password.","C":"• Là gì? Cụm «Không validation ever» mang một nghĩa riêng cần đối chiếu với đề.\n• Dùng để làm gì? So bản chất với đáp án đúng; loại nếu sai đối tượng hoặc sai lớp khái niệm.\n• Vì sao sai? «No validation ever» — Cụm «Không validation ever» mang một nghĩa riêng cần đối chiếu với đề. Đề cần: Quy tắc độ dài (vd. ≥ 8) và khớp confirm password.","D":"• Là gì? Mật khẩu stored trong plain Text widget title\n• Dùng để làm gì? Bản dịch/diễn đạt phương án — đối chiếu với định nghĩa chuẩn của đề.\n• Vì sao sai? «Password stored in plain Text widget title only» — Mật khẩu stored trong plain Text widget title. Đề cần: Quy tắc độ dài (vd. ≥ 8) và khớp confirm password."}}},{"id":167,"task":"slides","taskLabel":"Slides","num":166,"question":"GlobalKey<FormState> is commonly used to:","options":{"A":"Paint custom shaders","B":"Replace MaterialApp","C":"Validate the form from outside (currentState.validate())","D":"Start the emulator"},"answer":"C","alternatives":[],"source":"slides","exam":"PRM393_SLIDES_M7","explanation":{"questionVi":"GlobalKey<FormState> thường dùng để:","optionsVi":{"A":"Paint custom shaders","B":"Thay thế MaterialApp","C":"Validate form từ ngoài (currentState.Validate())","D":"Start the emulator"},"answerDisplay":"C. Validate form từ ngoài (currentState.Validate())","concept":"• Validate form từ ngoài (currentState.validate()). Bản dịch/diễn đạt phương án — đối chiếu với định nghĩa chuẩn của đề.","whyCorrect":"• Validate form từ ngoài (currentState.validate())\n• Bản dịch/diễn đạt phương án — đối chiếu với định nghĩa chuẩn của đề.","intent":"• Validate form từ ngoài (currentState.validate())\n• Bản dịch/diễn đạt phương án — đối chiếu với định nghĩa chuẩn của đề.","whatIs":{"A":"Vẽ pixel/lớp đồ họa lên màn hình.","B":"Cụm «Thay thế MaterialApp» mang một nghĩa riêng cần đối chiếu với đề.","C":"Validate form từ ngoài (currentState.validate())","D":"Cụm «Start the emulator» mang một nghĩa riêng cần đối chiếu với đề."},"whyWrong":{"A":"• Là gì? Vẽ pixel/lớp đồ họa lên màn hình.\n• Dùng để làm gì? Thuộc RenderObject/engine (Skia); không phải Handle BuildContext.\n• Vì sao sai? «Paint custom shaders» — Vẽ pixel/lớp đồ họa lên màn hình. Đề cần: Validate form từ ngoài (currentState.validate()).","B":"• Là gì? Cụm «Thay thế MaterialApp» mang một nghĩa riêng cần đối chiếu với đề.\n• Dùng để làm gì? So bản chất với đáp án đúng; loại nếu sai đối tượng hoặc sai lớp khái niệm.\n• Vì sao sai? MaterialApp bọc app + theme/route; đúng khi hỏi theme toàn cục / app root.","D":"• Là gì? Cụm «Start the emulator» mang một nghĩa riêng cần đối chiếu với đề.\n• Dùng để làm gì? So bản chất với đáp án đúng; loại nếu sai đối tượng hoặc sai lớp khái niệm.\n• Vì sao sai? Emulator chạy app giả lập; không phải công cụ phân tích performance."}}},{"id":168,"task":"slides","taskLabel":"Slides","num":167,"question":"Why validate user input before submit?","options":{"A":"To slow the UI intentionally","B":"To ensure correct data and better UX / fewer server errors","C":"To disable null safety","D":"To remove FocusNode"},"answer":"B","alternatives":[],"source":"slides","exam":"PRM393_SLIDES_M7","explanation":{"questionVi":"Vì sao validate input trước khi submit?","optionsVi":{"A":"để slow UI intentionally","B":"Đảm bảo dữ liệu đúng, UX tốt hơn / ít lỗi server","C":"để Tắt null safety","D":"để Gỡ bỏ FocusNode"},"answerDisplay":"B. Đảm bảo dữ liệu đúng, UX tốt hơn / ít lỗi server","concept":"• Đảm bảo dữ liệu đúng, UX tốt hơn / ít lỗi server. Bản dịch/diễn đạt phương án — đối chiếu với định nghĩa chuẩn của đề.","whyCorrect":"• Đảm bảo dữ liệu đúng, UX tốt hơn / ít lỗi server\n• Bản dịch/diễn đạt phương án — đối chiếu với định nghĩa chuẩn của đề.","intent":"• Đảm bảo dữ liệu đúng, UX tốt hơn / ít lỗi server\n• Bản dịch/diễn đạt phương án — đối chiếu với định nghĩa chuẩn của đề.","whatIs":{"A":"để slow UI intentionally","B":"Đảm bảo dữ liệu đúng, UX tốt hơn / ít lỗi server","C":"Hệ thống kiểu Dart phân biệt null/non-null để giảm crash.","D":"Cụm «để Gỡ bỏ FocusNode» mang một nghĩa riêng cần đối chiếu với đề."},"whyWrong":{"A":"• Là gì? để slow UI intentionally\n• Dùng để làm gì? Bản dịch/diễn đạt phương án — đối chiếu với định nghĩa chuẩn của đề.\n• Vì sao sai? «To slow the UI intentionally» — để slow UI intentionally. Đề cần: Đảm bảo dữ liệu đúng, UX tốt hơn / ít lỗi server.","C":"• Là gì? Hệ thống kiểu Dart phân biệt null/non-null để giảm crash.\n• Dùng để làm gì? Bắt buộc khởi tạo non-nullable trước khi dùng.\n• Vì sao sai? «To disable null safety» — Hệ thống kiểu Dart phân biệt null/non-null để giảm crash. Đề cần: Đảm bảo dữ liệu đúng, UX tốt hơn / ít lỗi server.","D":"• Là gì? Cụm «để Gỡ bỏ FocusNode» mang một nghĩa riêng cần đối chiếu với đề.\n• Dùng để làm gì? So bản chất với đáp án đúng; loại nếu sai đối tượng hoặc sai lớp khái niệm.\n• Vì sao sai? «To remove FocusNode» — Cụm «để Gỡ bỏ FocusNode» mang một nghĩa riêng cần đối chiếu với đề. Đề cần: Đảm bảo dữ liệu đúng, UX tốt hơn / ít lỗi server."}}},{"id":169,"task":"slides","taskLabel":"Slides","num":168,"question":"Async validation checks are useful when:","options":{"A":"You must verify uniqueness against a server (e.g. username taken)","B":"You never use network","C":"You only draw icons","D":"You compile the engine"},"answer":"A","alternatives":[],"source":"slides","exam":"PRM393_SLIDES_M7","explanation":{"questionVi":"Validate async hữu ích khi:","optionsVi":{"A":"Phải kiểm tra uniqueness trên server (vd. username đã tồn tại)","B":"You Không bao giờ dùng mạng","C":"You chỉ draw icons","D":"You Biên dịch engine"},"answerDisplay":"A. Phải kiểm tra uniqueness trên server (vd. username đã tồn tại)","concept":"• Phải kiểm tra uniqueness trên server (vd. username đã tồn tại). Bản dịch/diễn đạt phương án — đối chiếu với định nghĩa chuẩn của đề.","whyCorrect":"• Phải kiểm tra uniqueness trên server (vd. username đã tồn tại)\n• Bản dịch/diễn đạt phương án — đối chiếu với định nghĩa chuẩn của đề.","intent":"• Phải kiểm tra uniqueness trên server (vd. username đã tồn tại)\n• Bản dịch/diễn đạt phương án — đối chiếu với định nghĩa chuẩn của đề.","whatIs":{"A":"Phải kiểm tra uniqueness trên server (vd. username đã tồn tại)","B":"You Không bao giờ dùng mạng","C":"Cơ chế Flutter/Dart liên quan «You chỉ draw icons».","D":"Cơ chế Flutter/Dart liên quan «You Biên dịch engine»."},"whyWrong":{"B":"• Là gì? You Không bao giờ dùng mạng\n• Dùng để làm gì? Bản dịch/diễn đạt phương án — đối chiếu với định nghĩa chuẩn của đề.\n• Vì sao sai? «You never use network» — You Không bao giờ dùng mạng. Đề cần: Phải kiểm tra uniqueness trên server (vd. username đã tồn tại).","C":"• Là gì? Cơ chế Flutter/Dart liên quan «You chỉ draw icons».\n• Dùng để làm gì? Đối chiếu đúng cơ chế/phạm trù với trọng tâm đề.\n• Vì sao sai? «You only draw icons» — Cơ chế Flutter/Dart liên quan «You chỉ draw icons». Đề cần: Phải kiểm tra uniqueness trên server (vd. username đã tồn tại).","D":"• Là gì? Cơ chế Flutter/Dart liên quan «You Biên dịch engine».\n• Dùng để làm gì? Đối chiếu đúng cơ chế/phạm trù với trọng tâm đề.\n• Vì sao sai? «You compile the engine» — Cơ chế Flutter/Dart liên quan «You Biên dịch engine». Đề cần: Phải kiểm tra uniqueness trên server (vd. username đã tồn tại)."}}},{"id":170,"task":"slides","taskLabel":"Slides","num":169,"question":"Which widget groups multiple fields for joint validation?","options":{"A":"Spacer","B":"Divider","C":"Form","D":"Placeholder"},"answer":"C","alternatives":[],"source":"slides","exam":"PRM393_SLIDES_M7","explanation":{"questionVi":"Widget nào gom nhiều field để validate chung?","optionsVi":{"A":"Spacer","B":"Divider","C":"Form","D":"Placeholder"},"answerDisplay":"C. Form","concept":"• Cơ chế Flutter/Dart liên quan «Form».","whyCorrect":"• Cơ chế Flutter/Dart liên quan «Form».","intent":"• Cơ chế Flutter/Dart liên quan «Form».\n• Chọn phương án khớp cơ chế Flutter, không chọn stack web/Android nhầm.","whatIs":{"A":"Cơ chế Flutter/Dart liên quan «Spacer».","B":"Cơ chế Flutter/Dart liên quan «Divider».","C":"Cơ chế Flutter/Dart liên quan «Form».","D":"Cơ chế Flutter/Dart liên quan «Placeholder»."},"whyWrong":{"A":"• Là gì? Cơ chế Flutter/Dart liên quan «Spacer».\n• Dùng để làm gì? Đối chiếu đúng cơ chế/phạm trù với trọng tâm đề.\n• Vì sao sai? «Spacer» — Cơ chế Flutter/Dart liên quan «Spacer». Đề cần: Cơ chế Flutter/Dart liên quan «Form».","B":"• Là gì? Cơ chế Flutter/Dart liên quan «Divider».\n• Dùng để làm gì? Đối chiếu đúng cơ chế/phạm trù với trọng tâm đề.\n• Vì sao sai? «Divider» — Cơ chế Flutter/Dart liên quan «Divider». Đề cần: Cơ chế Flutter/Dart liên quan «Form».","D":"• Là gì? Cơ chế Flutter/Dart liên quan «Placeholder».\n• Dùng để làm gì? Đối chiếu đúng cơ chế/phạm trù với trọng tâm đề.\n• Vì sao sai? «Placeholder» — Cơ chế Flutter/Dart liên quan «Placeholder». Đề cần: Cơ chế Flutter/Dart liên quan «Form»."}}},{"id":171,"task":"slides","taskLabel":"Slides","num":170,"question":"AutovalidateMode.onUserInteraction typically means:","options":{"A":"Never validate","B":"Validate as the user interacts with fields","C":"Validate only after APK install","D":"Validate only on desktop"},"answer":"B","alternatives":[],"source":"slides","exam":"PRM393_SLIDES_M7","explanation":{"questionVi":"AutovalidateMode.onUserInteraction thường nghĩa là:","optionsVi":{"A":"Không bao giờ Validate","B":"Validate khi người dùng tương tác field","C":"Validate chỉ Sau khi APK install","D":"Validate chỉ trên desktop"},"answerDisplay":"B. Validate khi người dùng tương tác field","concept":"• Validate khi người dùng tương tác field. Bản dịch/diễn đạt phương án — đối chiếu với định nghĩa chuẩn của đề.","whyCorrect":"• Validate khi người dùng tương tác field\n• Bản dịch/diễn đạt phương án — đối chiếu với định nghĩa chuẩn của đề.","intent":"• Validate khi người dùng tương tác field\n• Bản dịch/diễn đạt phương án — đối chiếu với định nghĩa chuẩn của đề.","whatIs":{"A":"Cụm «Không bao giờ Validate» mang một nghĩa riêng cần đối chiếu với đề.","B":"Validate khi người dùng tương tác field","C":"Gói cài đặt Android chứa mã và tài nguyên đã build.","D":"Validate chỉ trên desktop"},"whyWrong":{"A":"• Là gì? Cụm «Không bao giờ Validate» mang một nghĩa riêng cần đối chiếu với đề.\n• Dùng để làm gì? So bản chất với đáp án đúng; loại nếu sai đối tượng hoặc sai lớp khái niệm.\n• Vì sao sai? «Never validate» — Cụm «Không bao giờ Validate» mang một nghĩa riêng cần đối chiếu với đề. Đề cần: Validate khi người dùng tương tác field.","C":"• Là gì? Gói cài đặt Android chứa mã và tài nguyên đã build.\n• Dùng để làm gì? Phát hành/cài app lên thiết bị.\n• Vì sao sai? «Validate only after APK install» — Gói cài đặt Android chứa mã và tài nguyên đã build. Đề cần: Validate khi người dùng tương tác field.","D":"• Là gì? Validate chỉ trên desktop\n• Dùng để làm gì? Bản dịch/diễn đạt phương án — đối chiếu với định nghĩa chuẩn của đề.\n• Vì sao sai? «Validate only on desktop» — Validate chỉ trên desktop. Đề cần: Validate khi người dùng tương tác field."}}},{"id":172,"task":"slides","taskLabel":"Slides","num":171,"question":"Which HTTP method is typically used to retrieve data?","options":{"A":"DELETE only","B":"PUT only","C":"GET","D":"PATCH only always"},"answer":"C","alternatives":[],"source":"slides","exam":"PRM393_SLIDES_M8","explanation":{"questionVi":"HTTP method nào thường dùng để lấy dữ liệu?","optionsVi":{"A":"Xómột","B":"PUT","C":"GET","D":"PATCH chỉ Luôn"},"answerDisplay":"C. GET","concept":"• Cơ chế/thuật ngữ CNTT «GET». Đối chiếu đúng định nghĩa/đặc trưng kỹ thuật mà đề hỏi.","whyCorrect":"• Cơ chế/thuật ngữ CNTT «GET».\n• Đối chiếu đúng định nghĩa/đặc trưng kỹ thuật mà đề hỏi.","intent":"• Cơ chế/thuật ngữ CNTT «GET».\n• Đối chiếu đúng định nghĩa/đặc trưng kỹ thuật mà đề hỏi.","memoryTip":"• GET lấy · POST tạo · Authorization mang token · parse JSON → object Dart.","whatIs":{"A":"Cơ chế/thuật ngữ CNTT «Xómột».","B":"Cơ chế/thuật ngữ CNTT «PUT».","C":"Cơ chế/thuật ngữ CNTT «GET».","D":"Cơ chế/thuật ngữ CNTT «PATCH chỉ Luôn»."},"whyWrong":{"A":"• Là gì? Cơ chế/thuật ngữ CNTT «Xómột».\n• Dùng để làm gì? Đối chiếu đúng định nghĩa/đặc trưng kỹ thuật mà đề hỏi.\n• Vì sao sai? PUT/DELETE cập nhật/xóa; không phải thao tác retrieve mặc định.","B":"• Là gì? Cơ chế/thuật ngữ CNTT «PUT».\n• Dùng để làm gì? Đối chiếu đúng định nghĩa/đặc trưng kỹ thuật mà đề hỏi.\n• Vì sao sai? PUT/DELETE cập nhật/xóa; không phải thao tác retrieve mặc định.","D":"• Là gì? Cơ chế/thuật ngữ CNTT «PATCH chỉ Luôn».\n• Dùng để làm gì? Đối chiếu đúng định nghĩa/đặc trưng kỹ thuật mà đề hỏi.\n• Vì sao sai? Gói http gọi API; không quản lý state UI hay storage local."}}},{"id":173,"task":"slides","taskLabel":"Slides","num":172,"question":"What is the purpose of parsing JSON?","options":{"A":"Encrypt the APK","B":"Convert JSON into Dart objects/maps","C":"Start Android Studio","D":"Create deep links"},"answer":"B","alternatives":[],"source":"slides","exam":"PRM393_SLIDES_M8","explanation":{"questionVi":"Mục đích parse JSON là gì?","optionsVi":{"A":"Encrypt the APK","B":"Chuyển JSON thành object/map Dart","C":"Start Android Studio","D":"Tạo deep links"},"answerDisplay":"B. Chuyển JSON thành object/map Dart","concept":"• Phần mềm quản lý phần cứng, tiến trình, bộ nhớ, I/O.","whyCorrect":"• Phần mềm quản lý phần cứng, tiến trình, bộ nhớ, I/O.\n• Cấp tài nguyên và lập lịch cho chương trình.","intent":"• Phần mềm quản lý phần cứng, tiến trình, bộ nhớ, I/O.\n• Cấp tài nguyên và lập lịch cho chương trình.","memoryTip":"• GET lấy · POST tạo · Authorization mang token · parse JSON → object Dart.","whatIs":{"A":"Gói cài đặt Android chứa mã và tài nguyên đã build.","B":"Phần mềm quản lý phần cứng, tiến trình, bộ nhớ, I/O.","C":"Cụm «Start Android Studio» mang một nghĩa riêng cần đối chiếu với đề.","D":"Mở ứng dụng (hoặc màn cụ thể) từ URL/URI bên ngoài."},"whyWrong":{"A":"• Là gì? Gói cài đặt Android chứa mã và tài nguyên đã build.\n• Dùng để làm gì? Phát hành/cài app lên thiết bị.\n• Vì sao sai? «Encrypt the APK» — Gói cài đặt Android chứa mã và tài nguyên đã build. Đề cần: Phần mềm quản lý phần cứng, tiến trình, bộ nhớ, I/O.","C":"• Là gì? Cụm «Start Android Studio» mang một nghĩa riêng cần đối chiếu với đề.\n• Dùng để làm gì? So bản chất với đáp án đúng; loại nếu sai đối tượng hoặc sai lớp khái niệm.\n• Vì sao sai? «Start Android Studio» — Cụm «Start Android Studio» mang một nghĩa riêng cần đối chiếu với đề. Đề cần: Phần mềm quản lý phần cứng, tiến trình, bộ nhớ, I/O.","D":"• Là gì? Mở ứng dụng (hoặc màn cụ thể) từ URL/URI bên ngoài.\n• Dùng để làm gì? Routing/deep linking; không liên quan chia không gian layout Flex.\n• Vì sao sai? «Create deep links» — Mở ứng dụng (hoặc màn cụ thể) từ URL/URI bên ngoài. Đề cần: Phần mềm quản lý phần cứng, tiến trình, bộ nhớ, I/O."}}},{"id":174,"task":"slides","taskLabel":"Slides","num":173,"question":"Why is FutureBuilder useful for API data?","options":{"A":"Binds async Future to UI (loading/success/error)","B":"Replaces HTTP with Bluetooth only","C":"Compiles C++ Skia","D":"Manages only FormState"},"answer":"A","alternatives":[],"source":"slides","exam":"PRM393_SLIDES_M8","explanation":{"questionVi":"Vì sao FutureBuilder hữu ích với dữ liệu API?","optionsVi":{"A":"Gắn Future async với UI (Tải/success/lỗi)","B":"Replaces HTTP với Bluetooth","C":"Compiles C++ Skia","D":"Manages chỉ FormState"},"answerDisplay":"A. Gắn Future async với UI (Tải/success/lỗi)","concept":"• Đối tượng đại diện một kết quả (hoặc lỗi) sẽ có sau thao tác bất đồng bộ.","whyCorrect":"• FutureBuilder lắng Future one-shot và rebuild theo waiting/done/error. Phù hợp: Binds async Future to UI (loading/success/error).\n• Đối tượng đại diện một kết quả (hoặc lỗi) sẽ có sau thao tác bất đồng bộ.\n• async/await, gọi API, đọc file một lần.","intent":"• Future: một kết quả async.\n• Stream: nhiều sự kiện theo thời gian.","memoryTip":"• GET lấy · POST tạo · Authorization mang token · parse JSON → object Dart.","whatIs":{"A":"Đối tượng đại diện một kết quả (hoặc lỗi) sẽ có sau thao tác bất đồng bộ.","B":"Replaces HTTP với Bluetooth","C":"Thư viện đồ họa 2D (C++) mà Flutter Engine dùng để vẽ.","D":"Cơ chế Flutter/Dart liên quan «Manages chỉ FormState»."},"whyWrong":{"B":"• Là gì? Replaces HTTP với Bluetooth\n• Dùng để làm gì? Bản dịch/diễn đạt phương án — đối chiếu với định nghĩa chuẩn của đề.\n• Vì sao sai? Gói http gọi API; không quản lý state UI hay storage local.","C":"• Là gì? Thư viện đồ họa 2D (C++) mà Flutter Engine dùng để vẽ.\n• Dùng để làm gì? Render UI nhất quán, tận dụng GPU.\n• Vì sao sai? FutureBuilder cho Future one-shot; không phải Stream liên tục.","D":"• Là gì? Cơ chế Flutter/Dart liên quan «Manages chỉ FormState».\n• Dùng để làm gì? Đối chiếu đúng cơ chế/phạm trù với trọng tâm đề.\n• Vì sao sai? FutureBuilder cho Future one-shot; không phải Stream liên tục."}}},{"id":175,"task":"slides","taskLabel":"Slides","num":174,"question":"Which HTTP header commonly carries access credentials?","options":{"A":"Content-Language only","B":"Authorization","C":"Accept-Charset only","D":"Warning only"},"answer":"B","alternatives":[],"source":"slides","exam":"PRM393_SLIDES_M8","explanation":{"questionVi":"HTTP header nào thường mang thông tin xác thực?","optionsVi":{"A":"Content-Language","B":"Authorization (thường mang access token)","C":"Accept-Charset","D":"Warning"},"answerDisplay":"B. Authorization (thường mang access token)","concept":"• Authorization (thường mang access token). Bản dịch/diễn đạt phương án — đối chiếu với định nghĩa chuẩn của đề.","whyCorrect":"• Authorization (thường mang access token)\n• Bản dịch/diễn đạt phương án — đối chiếu với định nghĩa chuẩn của đề.","intent":"• Authorization (thường mang access token)\n• Bản dịch/diễn đạt phương án — đối chiếu với định nghĩa chuẩn của đề.","memoryTip":"• GET lấy · POST tạo · Authorization mang token · parse JSON → object Dart.","whatIs":{"A":"Cơ chế/thuật ngữ CNTT «Content-Language».","B":"Authorization (thường mang access token)","C":"Cơ chế/thuật ngữ CNTT «Accept-Charset».","D":"Cơ chế/thuật ngữ CNTT «Warning»."},"whyWrong":{"A":"• Là gì? Cơ chế/thuật ngữ CNTT «Content-Language».\n• Dùng để làm gì? Đối chiếu đúng định nghĩa/đặc trưng kỹ thuật mà đề hỏi.\n• Vì sao sai? Gói http gọi API; không quản lý state UI hay storage local.","C":"• Là gì? Cơ chế/thuật ngữ CNTT «Accept-Charset».\n• Dùng để làm gì? Đối chiếu đúng định nghĩa/đặc trưng kỹ thuật mà đề hỏi.\n• Vì sao sai? Gói http gọi API; không quản lý state UI hay storage local.","D":"• Là gì? Cơ chế/thuật ngữ CNTT «Warning».\n• Dùng để làm gì? Đối chiếu đúng định nghĩa/đặc trưng kỹ thuật mà đề hỏi.\n• Vì sao sai? Gói http gọi API; không quản lý state UI hay storage local."}}},{"id":176,"task":"slides","taskLabel":"Slides","num":175,"question":"Which status code indicates a server error?","options":{"A":"200","B":"301","C":"404","D":"500"},"answer":"D","alternatives":[],"source":"slides","exam":"PRM393_SLIDES_M8","explanation":{"questionVi":"Status code nào chỉ lỗi server?","optionsVi":{"A":"200","B":"301","C":"404","D":"500"},"answerDisplay":"D. 500","concept":"• Một giá trị số cụ thể (500) cần kiểm tra trong điều kiện/công thức đề.","whyCorrect":"• Một giá trị số cụ thể (500) cần kiểm tra trong điều kiện/công thức đề.\n• Thay vào phép tính hoặc tiêu chí để xem có thỏa không.","intent":"• Một giá trị số cụ thể (500) cần kiểm tra trong điều kiện/công thức đề.\n• Thay vào phép tính hoặc tiêu chí để xem có thỏa không.","memoryTip":"• GET lấy · POST tạo · Authorization mang token · parse JSON → object Dart.","whatIs":{"A":"Một giá trị số cụ thể (200) cần kiểm tra trong điều kiện/công thức đề.","B":"Một giá trị số cụ thể (301) cần kiểm tra trong điều kiện/công thức đề.","C":"Một giá trị số cụ thể (404) cần kiểm tra trong điều kiện/công thức đề.","D":"Một giá trị số cụ thể (500) cần kiểm tra trong điều kiện/công thức đề."},"whyWrong":{"A":"• Là gì? Một giá trị số cụ thể (200) cần kiểm tra trong điều kiện/công thức đề.\n• Dùng để làm gì? Thay vào phép tính hoặc tiêu chí để xem có thỏa không.\n• Vì sao sai? 200 = OK, không phải lỗi server.","B":"• Là gì? Một giá trị số cụ thể (301) cần kiểm tra trong điều kiện/công thức đề.\n• Dùng để làm gì? Thay vào phép tính hoặc tiêu chí để xem có thỏa không.\n• Vì sao sai? 301 = redirect, không phải server error.","C":"• Là gì? Một giá trị số cụ thể (404) cần kiểm tra trong điều kiện/công thức đề.\n• Dùng để làm gì? Thay vào phép tính hoặc tiêu chí để xem có thỏa không.\n• Vì sao sai? 404 = không tìm thấy, không phải 5xx server error."}}},{"id":177,"task":"slides","taskLabel":"Slides","num":176,"question":"What does status code 404 typically mean?","options":{"A":"Resource not found","B":"OK success","C":"Server internal error","D":"Redirect permanent only"},"answer":"A","alternatives":[],"source":"slides","exam":"PRM393_SLIDES_M8","explanation":{"questionVi":"Status code 404 thường nghĩa là gì?","optionsVi":{"A":"Không tìm thấy tài nguyên","B":"OK success","C":"Lỗi nội bộ server","D":"Redirect permanent"},"answerDisplay":"A. Không tìm thấy tài nguyên","concept":"• Không tìm thấy tài nguyên. Bản dịch/diễn đạt phương án — đối chiếu với định nghĩa chuẩn của đề.","whyCorrect":"• Không tìm thấy tài nguyên\n• Bản dịch/diễn đạt phương án — đối chiếu với định nghĩa chuẩn của đề.","intent":"• Không tìm thấy tài nguyên\n• Bản dịch/diễn đạt phương án — đối chiếu với định nghĩa chuẩn của đề.","memoryTip":"• GET lấy · POST tạo · Authorization mang token · parse JSON → object Dart.","whatIs":{"A":"Không tìm thấy tài nguyên","B":"Cụm «OK success» mang một nghĩa riêng cần đối chiếu với đề.","C":"Cụm «Lỗi nội bộ server» mang một nghĩa riêng cần đối chiếu với đề.","D":"Cụm «Redirect permanent» mang một nghĩa riêng cần đối chiếu với đề."},"whyWrong":{"B":"• Là gì? Cụm «OK success» mang một nghĩa riêng cần đối chiếu với đề.\n• Dùng để làm gì? So bản chất với đáp án đúng; loại nếu sai đối tượng hoặc sai lớp khái niệm.\n• Vì sao sai? 404 = không tìm thấy, không phải 5xx server error.","C":"• Là gì? Cụm «Lỗi nội bộ server» mang một nghĩa riêng cần đối chiếu với đề.\n• Dùng để làm gì? So bản chất với đáp án đúng; loại nếu sai đối tượng hoặc sai lớp khái niệm.\n• Vì sao sai? 404 = không tìm thấy, không phải 5xx server error.","D":"• Là gì? Cụm «Redirect permanent» mang một nghĩa riêng cần đối chiếu với đề.\n• Dùng để làm gì? So bản chất với đáp án đúng; loại nếu sai đối tượng hoặc sai lớp khái niệm.\n• Vì sao sai? 404 = không tìm thấy, không phải 5xx server error."}}},{"id":178,"task":"slides","taskLabel":"Slides","num":177,"question":"What is pagination used for?","options":{"A":"Only styling buttons","B":"Loading large datasets in pages efficiently","C":"Signing APKs","D":"Disabling JSON"},"answer":"B","alternatives":[],"source":"slides","exam":"PRM393_SLIDES_M8","explanation":{"questionVi":"Pagination dùng để làm gì?","optionsVi":{"A":"Chỉ styling buttons","B":"Tải dataset lớn theo trang hiệu quả","C":"Ký APKs","D":"Disabling JSON"},"answerDisplay":"B. Tải dataset lớn theo trang hiệu quả","concept":"• Tải dataset lớn theo trang hiệu quả. Bản dịch/diễn đạt phương án — đối chiếu với định nghĩa chuẩn của đề.","whyCorrect":"• Tải dataset lớn theo trang hiệu quả\n• Bản dịch/diễn đạt phương án — đối chiếu với định nghĩa chuẩn của đề.","intent":"• Tải dataset lớn theo trang hiệu quả\n• Bản dịch/diễn đạt phương án — đối chiếu với định nghĩa chuẩn của đề.","whatIs":{"A":"Cụm «Chỉ styling buttons» mang một nghĩa riêng cần đối chiếu với đề.","B":"Tải dataset lớn theo trang hiệu quả","C":"Cụm «Ký APKs» mang một nghĩa riêng cần đối chiếu với đề.","D":"Cụm «Disabling JSON» mang một nghĩa riêng cần đối chiếu với đề."},"whyWrong":{"A":"• Là gì? Cụm «Chỉ styling buttons» mang một nghĩa riêng cần đối chiếu với đề.\n• Dùng để làm gì? So bản chất với đáp án đúng; loại nếu sai đối tượng hoặc sai lớp khái niệm.\n• Vì sao sai? «Only styling buttons» — Cụm «Chỉ styling buttons» mang một nghĩa riêng cần đối chiếu với đề. Đề cần: Tải dataset lớn theo trang hiệu quả.","C":"• Là gì? Cụm «Ký APKs» mang một nghĩa riêng cần đối chiếu với đề.\n• Dùng để làm gì? So bản chất với đáp án đúng; loại nếu sai đối tượng hoặc sai lớp khái niệm.\n• Vì sao sai? «Signing APKs» — Cụm «Ký APKs» mang một nghĩa riêng cần đối chiếu với đề. Đề cần: Tải dataset lớn theo trang hiệu quả.","D":"• Là gì? Cụm «Disabling JSON» mang một nghĩa riêng cần đối chiếu với đề.\n• Dùng để làm gì? So bản chất với đáp án đúng; loại nếu sai đối tượng hoặc sai lớp khái niệm.\n• Vì sao sai? «Disabling JSON» — Cụm «Disabling JSON» mang một nghĩa riêng cần đối chiếu với đề. Đề cần: Tải dataset lớn theo trang hiệu quả."}}},{"id":179,"task":"slides","taskLabel":"Slides","num":178,"question":"What is a refresh token used for?","options":{"A":"UI theme switching","B":"Image caching only","C":"Obtain new access tokens without re-login","D":"Hot reload"},"answer":"C","alternatives":[],"source":"slides","exam":"PRM393_SLIDES_M8","explanation":{"questionVi":"Refresh token dùng để làm gì?","optionsVi":{"A":"UI theme switching","B":"Image caching","C":"Lấy access token mới mà không đăng nhập lại","D":"Hot reload"},"answerDisplay":"C. Lấy access token mới mà không đăng nhập lại","concept":"• Lấy access token mới mà không đăng nhập lại. Bản dịch/diễn đạt phương án — đối chiếu với định nghĩa chuẩn của đề.","whyCorrect":"• Lấy access token mới mà không đăng nhập lại\n• Bản dịch/diễn đạt phương án — đối chiếu với định nghĩa chuẩn của đề.","intent":"• Lấy access token mới mà không đăng nhập lại\n• Bản dịch/diễn đạt phương án — đối chiếu với định nghĩa chuẩn của đề.","memoryTip":"• GET lấy · POST tạo · Authorization mang token · parse JSON → object Dart.","whatIs":{"A":"Thiết bị/khái niệm mạng «UI theme switching».","B":"Cụm «Image caching» mang một nghĩa riêng cần đối chiếu với đề.","C":"Lấy access token mới mà không đăng nhập lại","D":"Nạp lại code UI gần như giữ state đang chạy."},"whyWrong":{"A":"• Là gì? Thiết bị/khái niệm mạng «UI theme switching».\n• Dùng để làm gì? Đối chiếu đúng tầng OSI và chức năng (routing / switching / physical).\n• Vì sao sai? Theme/ThemeData lo style giao diện, không phải state/auth/logic chính ở đây.","B":"• Là gì? Cụm «Image caching» mang một nghĩa riêng cần đối chiếu với đề.\n• Dùng để làm gì? So bản chất với đáp án đúng; loại nếu sai đối tượng hoặc sai lớp khái niệm.\n• Vì sao sai? «Image caching only» — Cụm «Image caching» mang một nghĩa riêng cần đối chiếu với đề. Đề cần: Lấy access token mới mà không đăng nhập lại.","D":"• Là gì? Nạp lại code UI gần như giữ state đang chạy.\n• Dùng để làm gì? Xem thay đổi nhanh khi dev.\n• Vì sao sai? Hot reload nạp code UI nhanh khi dev; không phải công cụ phân tích sâu."}}},{"id":180,"task":"slides","taskLabel":"Slides","num":179,"question":"When calling APIs, why handle loading and error states in UI?","options":{"A":"Network is async; users need feedback and recovery paths","B":"HTTP is always instant and never fails","C":"Flutter forbids try/catch","D":"JSON cannot fail"},"answer":"A","alternatives":[],"source":"slides","exam":"PRM393_SLIDES_M8","explanation":{"questionVi":"Khi gọi API, vì sao xử lý loading/error trên UI?","optionsVi":{"A":"Mạng async; cần feedback và đường phục hồi cho user","B":"HTTP là Luôn instant và Không bao giờ fails","C":"Flutter forbids try/catch","D":"JSON không thể fail"},"answerDisplay":"A. Mạng async; cần feedback và đường phục hồi cho user","concept":"• Mạng async; cần feedback và đường phục hồi cho user. Bản dịch/diễn đạt phương án — đối chiếu với định nghĩa chuẩn của đề.","whyCorrect":"• Mạng async; cần feedback và đường phục hồi cho user\n• Bản dịch/diễn đạt phương án — đối chiếu với định nghĩa chuẩn của đề.","intent":"• Mạng async; cần feedback và đường phục hồi cho user\n• Bản dịch/diễn đạt phương án — đối chiếu với định nghĩa chuẩn của đề.","whatIs":{"A":"Mạng async; cần feedback và đường phục hồi cho user","B":"HTTP là Luôn instant và Không bao giờ fails","C":"Cơ chế Flutter/Dart liên quan «Flutter forbids try/catch».","D":"Cụm «JSON không thể fail» mang một nghĩa riêng cần đối chiếu với đề."},"whyWrong":{"B":"• Là gì? HTTP là Luôn instant và Không bao giờ fails\n• Dùng để làm gì? Bản dịch/diễn đạt phương án — đối chiếu với định nghĩa chuẩn của đề.\n• Vì sao sai? Gói http gọi API; không quản lý state UI hay storage local.","C":"• Là gì? Cơ chế Flutter/Dart liên quan «Flutter forbids try/catch».\n• Dùng để làm gì? Đối chiếu đúng cơ chế/phạm trù với trọng tâm đề.\n• Vì sao sai? «Flutter forbids try/catch» — Cơ chế Flutter/Dart liên quan «Flutter forbids try/catch». Đề cần: Mạng async; cần feedback và đường phục hồi cho user.","D":"• Là gì? Cụm «JSON không thể fail» mang một nghĩa riêng cần đối chiếu với đề.\n• Dùng để làm gì? So bản chất với đáp án đúng; loại nếu sai đối tượng hoặc sai lớp khái niệm.\n• Vì sao sai? «JSON cannot fail» — Cụm «JSON không thể fail» mang một nghĩa riêng cần đối chiếu với đề. Đề cần: Mạng async; cần feedback và đường phục hồi cho user."}}},{"id":181,"task":"slides","taskLabel":"Slides","num":180,"question":"POST is most appropriate when:","options":{"A":"Idempotent pure retrieval of a static file only","B":"Creating/submitting data to the server","C":"Only deleting DNS records","D":"Only reading SharedPreferences"},"answer":"B","alternatives":[],"source":"slides","exam":"PRM393_SLIDES_M8","explanation":{"questionVi":"POST phù hợp nhất khi:","optionsVi":{"A":"Idempotent pure retrieval củ một static file","B":"Tạo/gửi dữ liệu lên server","C":"Chỉ deleting DNS records","D":"Chỉ Đọc SharedPreferences"},"answerDisplay":"B. Tạo/gửi dữ liệu lên server","concept":"• Phần mềm quản lý phần cứng, tiến trình, bộ nhớ, I/O.","whyCorrect":"• Phần mềm quản lý phần cứng, tiến trình, bộ nhớ, I/O.\n• Cấp tài nguyên và lập lịch cho chương trình.","intent":"• Phần mềm quản lý phần cứng, tiến trình, bộ nhớ, I/O.\n• Cấp tài nguyên và lập lịch cho chương trình.","whatIs":{"A":"Idempotent pure retrieval của một static file","B":"Phần mềm quản lý phần cứng, tiến trình, bộ nhớ, I/O.","C":"Hệ thống phân giải tên miền thành địa chỉ IP.","D":"Chỉ Đọc SharedPreferences"},"whyWrong":{"A":"• Là gì? Idempotent pure retrieval của một static file\n• Dùng để làm gì? Bản dịch/diễn đạt phương án — đối chiếu với định nghĩa chuẩn của đề.\n• Vì sao sai? POST thường tạo/gửi dữ liệu; GET mới lấy dữ liệu.","C":"• Là gì? Hệ thống phân giải tên miền thành địa chỉ IP.\n• Dùng để làm gì? Người dùng dùng tên dễ nhớ thay vì số IP.\n• Vì sao sai? POST thường tạo/gửi dữ liệu; GET mới lấy dữ liệu.","D":"• Là gì? Chỉ Đọc SharedPreferences\n• Dùng để làm gì? Bản dịch/diễn đạt phương án — đối chiếu với định nghĩa chuẩn của đề.\n• Vì sao sai? shared_preferences chỉ key-value đơn giản (bool/int/string), không phù hợp mọi nhu cầu."}}},{"id":182,"task":"slides","taskLabel":"Slides","num":181,"question":"What does Content-Type: application/json indicate?","options":{"A":"Body is an image PNG","B":"Body is multipart file only","C":"Request/response body is JSON","D":"Request is a WebSocket upgrade only"},"answer":"C","alternatives":[],"source":"slides","exam":"PRM393_SLIDES_M8","explanation":{"questionVi":"Content-Type: application/json cho biết gì?","optionsVi":{"A":"Body là một image PNG","B":"Body là multipart file","C":"Body request/response là JSON","D":"Request là một WebSocket upgrade"},"answerDisplay":"C. Body request/response là JSON","concept":"• Body request/response là JSON. Bản dịch/diễn đạt phương án — đối chiếu với định nghĩa chuẩn của đề.","whyCorrect":"• Body request/response là JSON\n• Bản dịch/diễn đạt phương án — đối chiếu với định nghĩa chuẩn của đề.","intent":"• Body request/response là JSON\n• Bản dịch/diễn đạt phương án — đối chiếu với định nghĩa chuẩn của đề.","memoryTip":"• GET lấy · POST tạo · Authorization mang token · parse JSON → object Dart.","whatIs":{"A":"Cụm «Body là một image PNG» mang một nghĩa riêng cần đối chiếu với đề.","B":"Cụm «Body là multipart file» mang một nghĩa riêng cần đối chiếu với đề.","C":"Body request/response là JSON","D":"Request là một WebSocket upgrade"},"whyWrong":{"A":"• Là gì? Cụm «Body là một image PNG» mang một nghĩa riêng cần đối chiếu với đề.\n• Dùng để làm gì? So bản chất với đáp án đúng; loại nếu sai đối tượng hoặc sai lớp khái niệm.\n• Vì sao sai? «Body is an image PNG» — Cụm «Body là một image PNG» mang một nghĩa riêng cần đối chiếu với đề. Đề cần: Body request/response là JSON.","B":"• Là gì? Cụm «Body là multipart file» mang một nghĩa riêng cần đối chiếu với đề.\n• Dùng để làm gì? So bản chất với đáp án đúng; loại nếu sai đối tượng hoặc sai lớp khái niệm.\n• Vì sao sai? «Body is multipart file only» — Cụm «Body là multipart file» mang một nghĩa riêng cần đối chiếu với đề. Đề cần: Body request/response là JSON.","D":"• Là gì? Request là một WebSocket upgrade\n• Dùng để làm gì? Bản dịch/diễn đạt phương án — đối chiếu với định nghĩa chuẩn của đề.\n• Vì sao sai? «Request is a WebSocket upgrade only» — Request là một WebSocket upgrade. Đề cần: Body request/response là JSON."}}},{"id":183,"task":"slides","taskLabel":"Slides","num":182,"question":"Why map JSON fields into model classes?","options":{"A":"Type safety, readability, and easier UI binding","B":"To avoid using Dart","C":"To disable null safety","D":"To force stringly-typed maps forever without structure"},"answer":"A","alternatives":[],"source":"slides","exam":"PRM393_SLIDES_M8","explanation":{"questionVi":"Vì sao map field JSON sang model class?","optionsVi":{"A":"An toàn kiểu, dễ đọc, bind UI dễ hơn","B":"để Tránh dùng Dart","C":"để Tắt null safety","D":"Để Ép stringly-typed maps mãi mãi Không có structure"},"answerDisplay":"A. An toàn kiểu, dễ đọc, bind UI dễ hơn","concept":"• Cấu trúc ánh xạ khóa → giá trị. Tra cứu nhanh theo key.","whyCorrect":"• Cấu trúc ánh xạ khóa → giá trị.\n• Tra cứu nhanh theo key.","intent":"• Phân biệt List / Set / Map trong Dart.\n• Thứ tự, trùng lặp, hay key–value.","memoryTip":"• GET lấy · POST tạo · Authorization mang token · parse JSON → object Dart.","whatIs":{"A":"Cấu trúc ánh xạ khóa → giá trị.","B":"Ngôn ngữ lập trình chính của Flutter.","C":"Hệ thống kiểu Dart phân biệt null/non-null để giảm crash.","D":"để Ép stringly-typed maps mãi mãi Không có structure"},"whyWrong":{"B":"• Là gì? Ngôn ngữ lập trình chính của Flutter.\n• Dùng để làm gì? Viết UI và logic app Flutter.\n• Vì sao sai? «To avoid using Dart» — Ngôn ngữ lập trình chính của Flutter. Đề cần: Cấu trúc ánh xạ khóa → giá trị.","C":"• Là gì? Hệ thống kiểu Dart phân biệt null/non-null để giảm crash.\n• Dùng để làm gì? Bắt buộc khởi tạo non-nullable trước khi dùng.\n• Vì sao sai? «To disable null safety» — Hệ thống kiểu Dart phân biệt null/non-null để giảm crash. Đề cần: Cấu trúc ánh xạ khóa → giá trị.","D":"• Là gì? để Ép stringly-typed maps mãi mãi Không có structure\n• Dùng để làm gì? Bản dịch/diễn đạt phương án — đối chiếu với định nghĩa chuẩn của đề.\n• Vì sao sai? «To force stringly-typed maps forever without structure» — để Ép stringly-typed maps mãi mãi Không có structure. Đề cần: Cấu trúc ánh xạ khóa → giá trị."}}},{"id":184,"task":"slides","taskLabel":"Slides","num":183,"question":"When are local files preferred over simple key–value storage?","options":{"A":"Only for one boolean flag","B":"When data is bigger/structured but may not need full SQL","C":"When you never need persistence","D":"When only cloud is allowed"},"answer":"B","alternatives":[],"source":"slides","exam":"PRM393_SLIDES_M9","explanation":{"questionVi":"Khi nào ưu tiên file local hơn lưu key–value đơn giản?","optionsVi":{"A":"Chỉ cho một boolean flag","B":"Khi dữ liệu lớn/có cấu trúc nhưng chưa cần full SQL","C":"Khi you Không bao giờ cần persistence","D":"Khi chỉ cloud là allowed"},"answerDisplay":"B. Khi dữ liệu lớn/có cấu trúc nhưng chưa cần full SQL","concept":"• Cấu trúc ánh xạ khóa → giá trị. Tra cứu nhanh theo key.","whyCorrect":"• Cấu trúc ánh xạ khóa → giá trị.\n• Tra cứu nhanh theo key.","intent":"• Cấu trúc ánh xạ khóa → giá trị.\n• Tra cứu nhanh theo key.","whatIs":{"A":"Chỉ cho một boolean flag","B":"Cấu trúc ánh xạ khóa → giá trị.","C":"Khi you Không bao giờ cần persistence","D":"Thuê tài nguyên tính toán/lưu trữ qua mạng theo nhu cầu."},"whyWrong":{"A":"• Là gì? Chỉ cho một boolean flag\n• Dùng để làm gì? Bản dịch/diễn đạt phương án — đối chiếu với định nghĩa chuẩn của đề.\n• Vì sao sai? «Only for one boolean flag» — Chỉ cho một boolean flag. Đề cần: Cấu trúc ánh xạ khóa → giá trị.","C":"• Là gì? Khi you Không bao giờ cần persistence\n• Dùng để làm gì? Bản dịch/diễn đạt phương án — đối chiếu với định nghĩa chuẩn của đề.\n• Vì sao sai? «When you never need persistence» — Khi you Không bao giờ cần persistence. Đề cần: Cấu trúc ánh xạ khóa → giá trị.","D":"• Là gì? Thuê tài nguyên tính toán/lưu trữ qua mạng theo nhu cầu.\n• Dùng để làm gì? Scale linh hoạt, giảm tự vận hành server.\n• Vì sao sai? «When only cloud is allowed» — Thuê tài nguyên tính toán/lưu trữ qua mạng theo nhu cầu. Đề cần: Cấu trúc ánh xạ khóa → giá trị."}}},{"id":185,"task":"slides","taskLabel":"Slides","num":184,"question":"Which package is commonly used for simple key-value storage?","options":{"A":"shared_preferences","B":"flutter_bloc only","C":"flutter_test only","D":"path_provider only always as KV store"},"answer":"A","alternatives":[],"source":"slides","exam":"PRM393_SLIDES_M9","explanation":{"questionVi":"Package nào thường dùng lưu key–value đơn giản?","optionsVi":{"A":"shared_preferences","B":"Flutter_bloc","C":"Flutter_test","D":"Path_provider chỉ Luôn as KV Lưu"},"answerDisplay":"A. shared_preferences","concept":"• Cấu trúc ánh xạ khóa → giá trị. Tra cứu nhanh theo key.","whyCorrect":"• Cấu trúc ánh xạ khóa → giá trị.\n• Tra cứu nhanh theo key.","intent":"• Cấu trúc ánh xạ khóa → giá trị.\n• Tra cứu nhanh theo key.","whatIs":{"A":"Cấu trúc ánh xạ khóa → giá trị.","B":"Cách chia sẻ và phản ứng với trạng thái dùng chung giữa nhiều widget/màn.","C":"Cơ chế Flutter/Dart liên quan «Flutter_test».","D":"Cách chia sẻ và phản ứng với trạng thái dùng chung giữa nhiều widget/màn."},"whyWrong":{"B":"• Là gì? Cách chia sẻ và phản ứng với trạng thái dùng chung giữa nhiều widget/màn.\n• Dùng để làm gì? Tránh truyền prop sâu; cập nhật UI khi state đổi.\n• Vì sao sai? «flutter_bloc only» — Cách chia sẻ và phản ứng với trạng thái dùng chung giữa nhiều widget/màn. Đề cần: Cấu trúc ánh xạ khóa → giá trị.","C":"• Là gì? Cơ chế Flutter/Dart liên quan «Flutter_test».\n• Dùng để làm gì? Đối chiếu đúng cơ chế/phạm trù với trọng tâm đề.\n• Vì sao sai? «flutter_test only» — Cơ chế Flutter/Dart liên quan «Flutter_test». Đề cần: Cấu trúc ánh xạ khóa → giá trị.","D":"• Là gì? Cách chia sẻ và phản ứng với trạng thái dùng chung giữa nhiều widget/màn.\n• Dùng để làm gì? Tránh truyền prop sâu; cập nhật UI khi state đổi.\n• Vì sao sai? «path_provider only always as KV store» — Cách chia sẻ và phản ứng với trạng thái dùng chung giữa nhiều widget/màn. Đề cần: Cấu trúc ánh xạ khóa → giá trị."}}},{"id":186,"task":"slides","taskLabel":"Slides","num":185,"question":"What is Hive mainly used for?","options":{"A":"Remote PostgreSQL hosting","B":"Lightweight local NoSQL storage","C":"Only SSL pinning","D":"Only deep links"},"answer":"B","alternatives":[],"source":"slides","exam":"PRM393_SLIDES_M9","explanation":{"questionVi":"Hive chủ yếu dùng để làm gì?","optionsVi":{"A":"Remote PostgreSQL hosting","B":"Lưu trữ NoSQL local nhẹ","C":"Chỉ SSL pinning","D":"Chỉ deep links"},"answerDisplay":"B. Lưu trữ NoSQL local nhẹ","concept":"• Phần mềm quản lý phần cứng, tiến trình, bộ nhớ, I/O.","whyCorrect":"• Phần mềm quản lý phần cứng, tiến trình, bộ nhớ, I/O.\n• Cấp tài nguyên và lập lịch cho chương trình.","intent":"• Phần mềm quản lý phần cứng, tiến trình, bộ nhớ, I/O.\n• Cấp tài nguyên và lập lịch cho chương trình.","memoryTip":"• KV nhỏ → shared_preferences · NoSQL local → Hive · SQL → sqflite.","whatIs":{"A":"Phần mềm quản lý phần cứng, tiến trình, bộ nhớ, I/O.","B":"Phần mềm quản lý phần cứng, tiến trình, bộ nhớ, I/O.","C":"Cụm «Chỉ SSL pinning» mang một nghĩa riêng cần đối chiếu với đề.","D":"Mở ứng dụng (hoặc màn cụ thể) từ URL/URI bên ngoài."},"whyWrong":{"A":"• Là gì? Phần mềm quản lý phần cứng, tiến trình, bộ nhớ, I/O.\n• Dùng để làm gì? Cấp tài nguyên và lập lịch cho chương trình.\n• Vì sao sai? Hive = NoSQL local; không thay cho SQLite quan hệ / HTTP / state management.","C":"• Là gì? Cụm «Chỉ SSL pinning» mang một nghĩa riêng cần đối chiếu với đề.\n• Dùng để làm gì? So bản chất với đáp án đúng; loại nếu sai đối tượng hoặc sai lớp khái niệm.\n• Vì sao sai? Hive = NoSQL local; không thay cho SQLite quan hệ / HTTP / state management.","D":"• Là gì? Mở ứng dụng (hoặc màn cụ thể) từ URL/URI bên ngoài.\n• Dùng để làm gì? Routing/deep linking; không liên quan chia không gian layout Flex.\n• Vì sao sai? Hive = NoSQL local; không thay cho SQLite quan hệ / HTTP / state management."}}},{"id":187,"task":"slides","taskLabel":"Slides","num":186,"question":"Which plugin provides SQLite support in Flutter?","options":{"A":"provider","B":"http","C":"sqflite","D":"flutter_local_notifications only"},"answer":"C","alternatives":[],"source":"slides","exam":"PRM393_SLIDES_M9","explanation":{"questionVi":"Plugin nào cung cấp SQLite trong Flutter?","optionsVi":{"A":"provider","B":"http","C":"sqflite","D":"Flutter_local_notifications"},"answerDisplay":"C. sqflite","concept":"• Cơ chế Flutter/Dart liên quan «sqflite».","whyCorrect":"• Cơ chế Flutter/Dart liên quan «sqflite».","intent":"• Cơ chế Flutter/Dart liên quan «sqflite».\n• Chọn phương án khớp cơ chế Flutter, không chọn stack web/Android nhầm.","whatIs":{"A":"Cách chia sẻ và phản ứng với trạng thái dùng chung giữa nhiều widget/màn.","B":"Cơ chế/thuật ngữ CNTT «http».","C":"Cơ chế Flutter/Dart liên quan «sqflite».","D":"Cơ chế Flutter/Dart liên quan «Flutter_local_notifications»."},"whyWrong":{"A":"• Là gì? Cách chia sẻ và phản ứng với trạng thái dùng chung giữa nhiều widget/màn.\n• Dùng để làm gì? Tránh truyền prop sâu; cập nhật UI khi state đổi.\n• Vì sao sai? «provider» — Cách chia sẻ và phản ứng với trạng thái dùng chung giữa nhiều widget/màn. Đề cần: Cơ chế Flutter/Dart liên quan «sqflite».","B":"• Là gì? Cơ chế/thuật ngữ CNTT «http».\n• Dùng để làm gì? Đối chiếu đúng định nghĩa/đặc trưng kỹ thuật mà đề hỏi.\n• Vì sao sai? «http» — Cơ chế/thuật ngữ CNTT «http». Đề cần: Cơ chế Flutter/Dart liên quan «sqflite».","D":"• Là gì? Cơ chế Flutter/Dart liên quan «Flutter_local_notifications».\n• Dùng để làm gì? Đối chiếu đúng cơ chế/phạm trù với trọng tâm đề.\n• Vì sao sai? «flutter_local_notifications only» — Cơ chế Flutter/Dart liên quan «Flutter_local_notifications». Đề cần: Cơ chế Flutter/Dart liên quan «sqflite»."}}},{"id":188,"task":"slides","taskLabel":"Slides","num":187,"question":"Which widget is often used to show async local storage reads?","options":{"A":"FutureBuilder","B":"IconButton only","C":"AppBar only","D":"SnackBar only"},"answer":"A","alternatives":[],"source":"slides","exam":"PRM393_SLIDES_M9","explanation":{"questionVi":"Widget nào thường hiện kết quả đọc storage async?","optionsVi":{"A":"FutureBuilder","B":"IconButton","C":"AppBar","D":"SnackBar"},"answerDisplay":"A. FutureBuilder","concept":"• Cơ chế Flutter/Dart liên quan «FutureBuilder».","whyCorrect":"• FutureBuilder lắng Future one-shot và rebuild theo waiting/done/error. Phù hợp: FutureBuilder.\n• Cơ chế Flutter/Dart liên quan «FutureBuilder».","intent":"• Cơ chế Flutter/Dart liên quan «FutureBuilder».\n• Chọn phương án khớp cơ chế Flutter, không chọn stack web/Android nhầm.","memoryTip":"• KV nhỏ → shared_preferences · NoSQL local → Hive · SQL → sqflite.","whatIs":{"A":"Cơ chế Flutter/Dart liên quan «FutureBuilder».","B":"Cơ chế Flutter/Dart liên quan «IconButton».","C":"Cơ chế Flutter/Dart liên quan «AppBar».","D":"Cơ chế Flutter/Dart liên quan «SnackBar»."},"whyWrong":{"B":"• Là gì? Cơ chế Flutter/Dart liên quan «IconButton».\n• Dùng để làm gì? Đối chiếu đúng cơ chế/phạm trù với trọng tâm đề.\n• Vì sao sai? «IconButton only» — Cơ chế Flutter/Dart liên quan «IconButton». Đề cần: Cơ chế Flutter/Dart liên quan «FutureBuilder».","C":"• Là gì? Cơ chế Flutter/Dart liên quan «AppBar».\n• Dùng để làm gì? Đối chiếu đúng cơ chế/phạm trù với trọng tâm đề.\n• Vì sao sai? «AppBar only» — Cơ chế Flutter/Dart liên quan «AppBar». Đề cần: Cơ chế Flutter/Dart liên quan «FutureBuilder».","D":"• Là gì? Cơ chế Flutter/Dart liên quan «SnackBar».\n• Dùng để làm gì? Đối chiếu đúng cơ chế/phạm trù với trọng tâm đề.\n• Vì sao sai? «SnackBar only» — Cơ chế Flutter/Dart liên quan «SnackBar». Đề cần: Cơ chế Flutter/Dart liên quan «FutureBuilder»."}}},{"id":189,"task":"slides","taskLabel":"Slides","num":188,"question":"Why should database operations be asynchronous?","options":{"A":"To freeze the UI on purpose","B":"To avoid blocking the UI thread","C":"Because SQL cannot run async ever","D":"To disable persistence"},"answer":"B","alternatives":[],"source":"slides","exam":"PRM393_SLIDES_M9","explanation":{"questionVi":"Vì sao thao tác DB nên bất đồng bộ?","optionsVi":{"A":"để đơ UI trên purpose","B":"để Tránh chặn luồng UI","C":"Vì SQL không bao giờ chạy async được","D":"để Tắt persistence"},"answerDisplay":"B. để Tránh chặn luồng UI","concept":"• Cách chia sẻ và phản ứng với trạng thái dùng chung giữa nhiều widget/màn.","whyCorrect":"• Cách chia sẻ và phản ứng với trạng thái dùng chung giữa nhiều widget/màn.\n• Tránh truyền prop sâu; cập nhật UI khi state đổi.","intent":"• Cách chia sẻ và phản ứng với trạng thái dùng chung giữa nhiều widget/màn.\n• Tránh truyền prop sâu; cập nhật UI khi state đổi.","whatIs":{"A":"Phần mềm quản lý phần cứng, tiến trình, bộ nhớ, I/O.","B":"Cách chia sẻ và phản ứng với trạng thái dùng chung giữa nhiều widget/màn.","C":"Thao tác/giao dịch trên cơ sở dữ liệu quan hệ.","D":"Cơ chế Flutter/Dart liên quan «để Tắt persistence»."},"whyWrong":{"A":"• Là gì? Phần mềm quản lý phần cứng, tiến trình, bộ nhớ, I/O.\n• Dùng để làm gì? Cấp tài nguyên và lập lịch cho chương trình.\n• Vì sao sai? «To freeze the UI on purpose» — Phần mềm quản lý phần cứng, tiến trình, bộ nhớ, I/O. Đề cần: Cách chia sẻ và phản ứng với trạng thái dùng chung giữa nhiều widget/màn.","C":"• Là gì? Thao tác/giao dịch trên cơ sở dữ liệu quan hệ.\n• Dùng để làm gì? Lưu trữ và truy vấn dữ liệu bền vững; không thuộc widget tree UI.\n• Vì sao sai? «Because SQL cannot run async ever» — Thao tác/giao dịch trên cơ sở dữ liệu quan hệ. Đề cần: Cách chia sẻ và phản ứng với trạng thái dùng chung giữa nhiều widget/màn.","D":"• Là gì? Cơ chế Flutter/Dart liên quan «để Tắt persistence».\n• Dùng để làm gì? Đối chiếu đúng cơ chế/phạm trù với trọng tâm đề.\n• Vì sao sai? «To disable persistence» — Cơ chế Flutter/Dart liên quan «để Tắt persistence». Đề cần: Cách chia sẻ và phản ứng với trạng thái dùng chung giữa nhiều widget/màn."}}},{"id":190,"task":"slides","taskLabel":"Slides","num":189,"question":"path_provider is typically used to:","options":{"A":"Call REST APIs","B":"Manage BLoC events","C":"Locate app directories for file storage","D":"Theme the MaterialApp"},"answer":"C","alternatives":[],"source":"slides","exam":"PRM393_SLIDES_M9","explanation":{"questionVi":"path_provider thường dùng để:","optionsVi":{"A":"Gọi REST APIs","B":"Quản lý BLoC sự kiện","C":"Tìm thư mục app để lưu file","D":"Theme the MaterialApp"},"answerDisplay":"C. Tìm thư mục app để lưu file","concept":"• Cách chia sẻ và phản ứng với trạng thái dùng chung giữa nhiều widget/màn.","whyCorrect":"• Cách chia sẻ và phản ứng với trạng thái dùng chung giữa nhiều widget/màn.\n• Tránh truyền prop sâu; cập nhật UI khi state đổi.","intent":"• Cách chia sẻ và phản ứng với trạng thái dùng chung giữa nhiều widget/màn.\n• Tránh truyền prop sâu; cập nhật UI khi state đổi.","whatIs":{"A":"Cơ chế Flutter/Dart liên quan «Gọi REST APIs».","B":"Cách chia sẻ và phản ứng với trạng thái dùng chung giữa nhiều widget/màn.","C":"Cách chia sẻ và phản ứng với trạng thái dùng chung giữa nhiều widget/màn.","D":"Cơ chế Flutter/Dart liên quan «Theme the MaterialApp»."},"whyWrong":{"A":"• Là gì? Cơ chế Flutter/Dart liên quan «Gọi REST APIs».\n• Dùng để làm gì? Đối chiếu đúng cơ chế/phạm trù với trọng tâm đề.\n• Vì sao sai? «Call REST APIs» — Cơ chế Flutter/Dart liên quan «Gọi REST APIs». Đề cần: Cách chia sẻ và phản ứng với trạng thái dùng chung giữa nhiều widget/màn.","B":"• Là gì? Cách chia sẻ và phản ứng với trạng thái dùng chung giữa nhiều widget/màn.\n• Dùng để làm gì? Tránh truyền prop sâu; cập nhật UI khi state đổi.\n• Vì sao sai? BLoC: event → state qua stream; đúng khi hỏi kiến trúc BLoC.","D":"• Là gì? Cơ chế Flutter/Dart liên quan «Theme the MaterialApp».\n• Dùng để làm gì? Đối chiếu đúng cơ chế/phạm trù với trọng tâm đề.\n• Vì sao sai? Theme/ThemeData lo style giao diện, không phải state/auth/logic chính ở đây."}}},{"id":191,"task":"slides","taskLabel":"Slides","num":190,"question":"Which storage suits a small flag like 'onboardingCompleted'?","options":{"A":"shared_preferences","B":"Full remote warehouse DB only","C":"Video codec storage","D":"Git LFS only"},"answer":"A","alternatives":[],"source":"slides","exam":"PRM393_SLIDES_M9","explanation":{"questionVi":"Lưu trữ nào hợp cờ nhỏ như 'onboardingCompleted'?","optionsVi":{"A":"shared_preferences","B":"Full remote warehouse DB","C":"Video codec lưu trữ","D":"Git LFS"},"answerDisplay":"A. shared_preferences","concept":"• Cụm «shared_preferences» mang một nghĩa riêng cần đối chiếu với đề.","whyCorrect":"• Cụm «shared_preferences» mang một nghĩa riêng cần đối chiếu với đề.\n• So bản chất với đáp án đúng; loại nếu sai đối tượng hoặc sai lớp khái niệm.","intent":"• Cụm «shared_preferences» mang một nghĩa riêng cần đối chiếu với đề.\n• So bản chất với đáp án đúng; loại nếu sai đối tượng hoặc sai lớp khái niệm.","whatIs":{"A":"Cụm «shared_preferences» mang một nghĩa riêng cần đối chiếu với đề.","B":"Cụm «Full remote warehouse DB» mang một nghĩa riêng cần đối chiếu với đề.","C":"Cụm «Video codec lưu trữ» mang một nghĩa riêng cần đối chiếu với đề.","D":"Cụm «Git LFS» mang một nghĩa riêng cần đối chiếu với đề."},"whyWrong":{"B":"• Là gì? Cụm «Full remote warehouse DB» mang một nghĩa riêng cần đối chiếu với đề.\n• Dùng để làm gì? So bản chất với đáp án đúng; loại nếu sai đối tượng hoặc sai lớp khái niệm.\n• Vì sao sai? «Full remote warehouse DB only» — Cụm «Full remote warehouse DB» mang một nghĩa riêng cần đối chiếu với đề. Đề cần: Cụm «shared_preferences» mang một nghĩa riêng cần đối chiếu với đề.","C":"• Là gì? Cụm «Video codec lưu trữ» mang một nghĩa riêng cần đối chiếu với đề.\n• Dùng để làm gì? So bản chất với đáp án đúng; loại nếu sai đối tượng hoặc sai lớp khái niệm.\n• Vì sao sai? «Video codec storage» — Cụm «Video codec lưu trữ» mang một nghĩa riêng cần đối chiếu với đề. Đề cần: Cụm «shared_preferences» mang một nghĩa riêng cần đối chiếu với đề.","D":"• Là gì? Cụm «Git LFS» mang một nghĩa riêng cần đối chiếu với đề.\n• Dùng để làm gì? So bản chất với đáp án đúng; loại nếu sai đối tượng hoặc sai lớp khái niệm.\n• Vì sao sai? Git quản lý phiên bản code — chỉ đúng khi hỏi version control."}}},{"id":192,"task":"slides","taskLabel":"Slides","num":191,"question":"What is persistence in mobile apps?","options":{"A":"Keeping data only in RAM until process death always","B":"Saving data so it survives app restarts","C":"Only drawing frames","D":"Only hot reload state"},"answer":"B","alternatives":[],"source":"slides","exam":"PRM393_SLIDES_M9","explanation":{"questionVi":"Persistence trong app mobile là gì?","optionsVi":{"A":"Keeping dữ liệu chỉ trong RAM cho đến khi process death Luôn","B":"Lưu dữ liệu sống sót qua lần mở app lại","C":"Chỉ drawing frames","D":"Chỉ hot reload state"},"answerDisplay":"B. Lưu dữ liệu sống sót qua lần mở app lại","concept":"• Lưu dữ liệu sống sót qua lần mở app lại. Bản dịch/diễn đạt phương án — đối chiếu với định nghĩa chuẩn của đề.","whyCorrect":"• Lưu dữ liệu sống sót qua lần mở app lại\n• Bản dịch/diễn đạt phương án — đối chiếu với định nghĩa chuẩn của đề.","intent":"• Lưu dữ liệu sống sót qua lần mở app lại\n• Bản dịch/diễn đạt phương án — đối chiếu với định nghĩa chuẩn của đề.","memoryTip":"• KV nhỏ → shared_preferences · NoSQL local → Hive · SQL → sqflite.","whatIs":{"A":"Keeping dữ liệu chỉ trong RAM cho đến khi process death Luôn","B":"Lưu dữ liệu sống sót qua lần mở app lại","C":"Cụm «Chỉ drawing frames» mang một nghĩa riêng cần đối chiếu với đề.","D":"Nạp lại code UI gần như giữ state đang chạy."},"whyWrong":{"A":"• Là gì? Keeping dữ liệu chỉ trong RAM cho đến khi process death Luôn\n• Dùng để làm gì? Bản dịch/diễn đạt phương án — đối chiếu với định nghĩa chuẩn của đề.\n• Vì sao sai? «Keeping data only in RAM until process death always» — Keeping dữ liệu chỉ trong RAM cho đến khi process death Luôn. Đề cần: Lưu dữ liệu sống sót qua lần mở app lại.","C":"• Là gì? Cụm «Chỉ drawing frames» mang một nghĩa riêng cần đối chiếu với đề.\n• Dùng để làm gì? So bản chất với đáp án đúng; loại nếu sai đối tượng hoặc sai lớp khái niệm.\n• Vì sao sai? «Only drawing frames» — Cụm «Chỉ drawing frames» mang một nghĩa riêng cần đối chiếu với đề. Đề cần: Lưu dữ liệu sống sót qua lần mở app lại.","D":"• Là gì? Nạp lại code UI gần như giữ state đang chạy.\n• Dùng để làm gì? Xem thay đổi nhanh khi dev.\n• Vì sao sai? Hot reload nạp code UI nhanh khi dev; không phải công cụ phân tích sâu."}}},{"id":193,"task":"slides","taskLabel":"Slides","num":192,"question":"Choosing SQLite is more appropriate when:","options":{"A":"You store one boolean","B":"You need only ephemeral memory","C":"You need relational queries on structured local data","D":"You never read data back"},"answer":"C","alternatives":[],"source":"slides","exam":"PRM393_SLIDES_M9","explanation":{"questionVi":"Chọn SQLite phù hợp hơn khi:","optionsVi":{"A":"You Lưu một boolean","B":"You cần chỉ ephemeral memory","C":"Cần truy vấn quan hệ trên dữ liệu local có cấu trúc","D":"You Không bao giờ read dữ liệu back"},"answerDisplay":"C. Cần truy vấn quan hệ trên dữ liệu local có cấu trúc","concept":"• Phần mềm quản lý phần cứng, tiến trình, bộ nhớ, I/O.","whyCorrect":"• Phần mềm quản lý phần cứng, tiến trình, bộ nhớ, I/O.\n• Cấp tài nguyên và lập lịch cho chương trình.","intent":"• Phần mềm quản lý phần cứng, tiến trình, bộ nhớ, I/O.\n• Cấp tài nguyên và lập lịch cho chương trình.","whatIs":{"A":"Thiết bị/khái niệm mạng «You Lưu một boolean».","B":"You cần chỉ ephemeral memory","C":"Phần mềm quản lý phần cứng, tiến trình, bộ nhớ, I/O.","D":"You Không bao giờ read dữ liệu back"},"whyWrong":{"A":"• Là gì? Thiết bị/khái niệm mạng «You Lưu một boolean».\n• Dùng để làm gì? Đối chiếu đúng tầng OSI và chức năng (routing / switching / physical).\n• Vì sao sai? «You store one boolean» — Thiết bị/khái niệm mạng «You Lưu một boolean». Đề cần: Phần mềm quản lý phần cứng, tiến trình, bộ nhớ, I/O.","B":"• Là gì? You cần chỉ ephemeral memory\n• Dùng để làm gì? Bản dịch/diễn đạt phương án — đối chiếu với định nghĩa chuẩn của đề.\n• Vì sao sai? «You need only ephemeral memory» — You cần chỉ ephemeral memory. Đề cần: Phần mềm quản lý phần cứng, tiến trình, bộ nhớ, I/O.","D":"• Là gì? You Không bao giờ read dữ liệu back\n• Dùng để làm gì? Bản dịch/diễn đạt phương án — đối chiếu với định nghĩa chuẩn của đề.\n• Vì sao sai? «You never read data back» — You Không bao giờ read dữ liệu back. Đề cần: Phần mềm quản lý phần cứng, tiến trình, bộ nhớ, I/O."}}},{"id":194,"task":"slides","taskLabel":"Slides","num":193,"question":"Why is secure authentication critical in mobile apps?","options":{"A":"Only to change icon colors","B":"To protect user data and control access","C":"To improve GPU fill rate","D":"To compile Dart faster"},"answer":"B","alternatives":[],"source":"slides","exam":"PRM393_SLIDES_M10","explanation":{"questionVi":"Vì sao xác thực an toàn quan trọng trên mobile?","optionsVi":{"A":"Chỉ để thay đổi icon colors","B":"Bảo vệ dữ liệu user và kiểm soát truy cập","C":"để Cải thiện GPU fill rate","D":"để Biên dịch Dart nhanh hơn"},"answerDisplay":"B. Bảo vệ dữ liệu user và kiểm soát truy cập","concept":"• Bảo vệ dữ liệu user và kiểm soát truy cập. Bản dịch/diễn đạt phương án — đối chiếu với định nghĩa chuẩn của đề.","whyCorrect":"• Bảo vệ dữ liệu user và kiểm soát truy cập\n• Bản dịch/diễn đạt phương án — đối chiếu với định nghĩa chuẩn của đề.","intent":"• Bảo vệ dữ liệu user và kiểm soát truy cập\n• Bản dịch/diễn đạt phương án — đối chiếu với định nghĩa chuẩn của đề.","memoryTip":"• Auth: token/session tập trung; Guard chặn route; StreamBuilder hay dùng với auth stream.","whatIs":{"A":"Chỉ để thay đổi icon colors","B":"Bảo vệ dữ liệu user và kiểm soát truy cập","C":"để Cải thiện GPU fill rate","D":"Ngôn ngữ lập trình chính của Flutter."},"whyWrong":{"A":"• Là gì? Chỉ để thay đổi icon colors\n• Dùng để làm gì? Bản dịch/diễn đạt phương án — đối chiếu với định nghĩa chuẩn của đề.\n• Vì sao sai? «Only to change icon colors» — Chỉ để thay đổi icon colors. Đề cần: Bảo vệ dữ liệu user và kiểm soát truy cập.","C":"• Là gì? để Cải thiện GPU fill rate\n• Dùng để làm gì? Bản dịch/diễn đạt phương án — đối chiếu với định nghĩa chuẩn của đề.\n• Vì sao sai? «To improve GPU fill rate» — để Cải thiện GPU fill rate. Đề cần: Bảo vệ dữ liệu user và kiểm soát truy cập.","D":"• Là gì? Ngôn ngữ lập trình chính của Flutter.\n• Dùng để làm gì? Viết UI và logic app Flutter.\n• Vì sao sai? «To compile Dart faster» — Ngôn ngữ lập trình chính của Flutter. Đề cần: Bảo vệ dữ liệu user và kiểm soát truy cập."}}},{"id":195,"task":"slides","taskLabel":"Slides","num":194,"question":"After successful login with a mock token flow, what should you typically do?","options":{"A":"Save token (e.g. in AuthService) and prepare next navigation","B":"Delete the Flutter SDK","C":"Disable all network","D":"Force a compile error"},"answer":"A","alternatives":[],"source":"slides","exam":"PRM393_SLIDES_M10","explanation":{"questionVi":"Sau login thành công (mock token), thường nên làm gì?","optionsVi":{"A":"Lưu token (vd. AuthService) và chuẩn bị điều hướng tiếp","B":"Xómột Flutter SDK","C":"Tắt tất cả mạng","D":"Ép một Biên dịch lỗi"},"answerDisplay":"A. Lưu token (vd. AuthService) và chuẩn bị điều hướng tiếp","concept":"• Lưu token (vd. AuthService) và chuẩn bị điều hướng tiếp. Bản dịch/diễn đạt phương án — đối chiếu với định nghĩa chuẩn của đề.","whyCorrect":"• Lưu token (vd. AuthService) và chuẩn bị điều hướng tiếp\n• Bản dịch/diễn đạt phương án — đối chiếu với định nghĩa chuẩn của đề.","intent":"• Lưu token (vd. AuthService) và chuẩn bị điều hướng tiếp\n• Bản dịch/diễn đạt phương án — đối chiếu với định nghĩa chuẩn của đề.","memoryTip":"• Auth: token/session tập trung; Guard chặn route; StreamBuilder hay dùng với auth stream.","whatIs":{"A":"Lưu token (vd. AuthService) và chuẩn bị điều hướng tiếp","B":"Cơ chế Flutter/Dart liên quan «Xómột Flutter SDK».","C":"Cụm «Tắt tất cả mạng» mang một nghĩa riêng cần đối chiếu với đề.","D":"Cụm «Ép một Biên dịch lỗi» mang một nghĩa riêng cần đối chiếu với đề."},"whyWrong":{"B":"• Là gì? Cơ chế Flutter/Dart liên quan «Xómột Flutter SDK».\n• Dùng để làm gì? Đối chiếu đúng cơ chế/phạm trù với trọng tâm đề.\n• Vì sao sai? PUT/DELETE cập nhật/xóa; không phải thao tác retrieve mặc định.","C":"• Là gì? Cụm «Tắt tất cả mạng» mang một nghĩa riêng cần đối chiếu với đề.\n• Dùng để làm gì? So bản chất với đáp án đúng; loại nếu sai đối tượng hoặc sai lớp khái niệm.\n• Vì sao sai? «Disable all network» — Cụm «Tắt tất cả mạng» mang một nghĩa riêng cần đối chiếu với đề. Đề cần: Lưu token (vd. AuthService) và chuẩn bị điều hướng tiếp.","D":"• Là gì? Cụm «Ép một Biên dịch lỗi» mang một nghĩa riêng cần đối chiếu với đề.\n• Dùng để làm gì? So bản chất với đáp án đúng; loại nếu sai đối tượng hoặc sai lớp khái niệm.\n• Vì sao sai? «Force a compile error» — Cụm «Ép một Biên dịch lỗi» mang một nghĩa riêng cần đối chiếu với đề. Đề cần: Lưu token (vd. AuthService) và chuẩn bị điều hướng tiếp."}}},{"id":196,"task":"slides","taskLabel":"Slides","num":195,"question":"What is a token in authentication systems?","options":{"A":"A UI color","B":"A layout constraint","C":"A temporary access credential","D":"A Git commit hash only"},"answer":"C","alternatives":[],"source":"slides","exam":"PRM393_SLIDES_M10","explanation":{"questionVi":"Token trong hệ xác thực là gì?","optionsVi":{"A":"Một UI color","B":"Một bố cục constraint","C":"Chứng chỉ/thông tin truy cập tạm thời","D":"Một Git commit hash"},"answerDisplay":"C. Chứng chỉ/thông tin truy cập tạm thời","concept":"• Chứng chỉ/thông tin truy cập tạm thời. Bản dịch/diễn đạt phương án — đối chiếu với định nghĩa chuẩn của đề.","whyCorrect":"• Chứng chỉ/thông tin truy cập tạm thời\n• Bản dịch/diễn đạt phương án — đối chiếu với định nghĩa chuẩn của đề.","intent":"• Chứng chỉ/thông tin truy cập tạm thời\n• Bản dịch/diễn đạt phương án — đối chiếu với định nghĩa chuẩn của đề.","memoryTip":"• Auth: token/session tập trung; Guard chặn route; StreamBuilder hay dùng với auth stream.","whatIs":{"A":"Cụm «Một UI color» mang một nghĩa riêng cần đối chiếu với đề.","B":"Cụm «Một bố cục constraint» mang một nghĩa riêng cần đối chiếu với đề.","C":"Chứng chỉ/thông tin truy cập tạm thời","D":"Cụm «Một Git commit hash» mang một nghĩa riêng cần đối chiếu với đề."},"whyWrong":{"A":"• Là gì? Cụm «Một UI color» mang một nghĩa riêng cần đối chiếu với đề.\n• Dùng để làm gì? So bản chất với đáp án đúng; loại nếu sai đối tượng hoặc sai lớp khái niệm.\n• Vì sao sai? Auth/session không giải quyết bằng chỉnh UI/theme/animation.","B":"• Là gì? Cụm «Một bố cục constraint» mang một nghĩa riêng cần đối chiếu với đề.\n• Dùng để làm gì? So bản chất với đáp án đúng; loại nếu sai đối tượng hoặc sai lớp khái niệm.\n• Vì sao sai? Auth/session không giải quyết bằng chỉnh UI/theme/animation.","D":"• Là gì? Cụm «Một Git commit hash» mang một nghĩa riêng cần đối chiếu với đề.\n• Dùng để làm gì? So bản chất với đáp án đúng; loại nếu sai đối tượng hoặc sai lớp khái niệm.\n• Vì sao sai? Git quản lý phiên bản code — chỉ đúng khi hỏi version control."}}},{"id":197,"task":"slides","taskLabel":"Slides","num":196,"question":"Why centralize authentication state?","options":{"A":"To scatter tokens in random widgets","B":"Ensure consistent access control across screens","C":"To avoid secure storage forever","D":"To remove logout"},"answer":"B","alternatives":[],"source":"slides","exam":"PRM393_SLIDES_M10","explanation":{"questionVi":"Vì sao tập trung state xác thực?","optionsVi":{"A":"Để scatter token trong random widgets","B":"Kiểm soát truy cập thống nhất giữa các màn","C":"để Tránh secure lưu trữ mãi mãi","D":"để Gỡ bỏ logout"},"answerDisplay":"B. Kiểm soát truy cập thống nhất giữa các màn","concept":"• Phần mềm quản lý phần cứng, tiến trình, bộ nhớ, I/O.","whyCorrect":"• Phần mềm quản lý phần cứng, tiến trình, bộ nhớ, I/O.\n• Cấp tài nguyên và lập lịch cho chương trình.","intent":"• Phần mềm quản lý phần cứng, tiến trình, bộ nhớ, I/O.\n• Cấp tài nguyên và lập lịch cho chương trình.","memoryTip":"• Auth: token/session tập trung; Guard chặn route; StreamBuilder hay dùng với auth stream.","whatIs":{"A":"để scatter token trong random widgets","B":"Phần mềm quản lý phần cứng, tiến trình, bộ nhớ, I/O.","C":"để Tránh secure lưu trữ mãi mãi","D":"Cụm «để Gỡ bỏ logout» mang một nghĩa riêng cần đối chiếu với đề."},"whyWrong":{"A":"• Là gì? để scatter token trong random widgets\n• Dùng để làm gì? Bản dịch/diễn đạt phương án — đối chiếu với định nghĩa chuẩn của đề.\n• Vì sao sai? «To scatter tokens in random widgets» — để scatter token trong random widgets. Đề cần: Phần mềm quản lý phần cứng, tiến trình, bộ nhớ, I/O.","C":"• Là gì? để Tránh secure lưu trữ mãi mãi\n• Dùng để làm gì? Bản dịch/diễn đạt phương án — đối chiếu với định nghĩa chuẩn của đề.\n• Vì sao sai? «To avoid secure storage forever» — để Tránh secure lưu trữ mãi mãi. Đề cần: Phần mềm quản lý phần cứng, tiến trình, bộ nhớ, I/O.","D":"• Là gì? Cụm «để Gỡ bỏ logout» mang một nghĩa riêng cần đối chiếu với đề.\n• Dùng để làm gì? So bản chất với đáp án đúng; loại nếu sai đối tượng hoặc sai lớp khái niệm.\n• Vì sao sai? «To remove logout» — Cụm «để Gỡ bỏ logout» mang một nghĩa riêng cần đối chiếu với đề. Đề cần: Phần mềm quản lý phần cứng, tiến trình, bộ nhớ, I/O."}}},{"id":198,"task":"slides","taskLabel":"Slides","num":197,"question":"Which widget can react to auth state exposed as a Stream?","options":{"A":"StreamBuilder","B":"SizedBox only","C":"Divider only","D":"Placeholder only"},"answer":"A","alternatives":[],"source":"slides","exam":"PRM393_SLIDES_M10","explanation":{"questionVi":"Widget nào phản ứng state auth dạng Stream?","optionsVi":{"A":"StreamBuilder","B":"SizedBox","C":"Divider","D":"Placeholder"},"answerDisplay":"A. StreamBuilder","concept":"• Chuỗi sự kiện/giá trị bất đồng bộ theo thời gian.","whyCorrect":"• StreamBuilder lắng nghe Stream và rebuild mỗi khi có event mới (auth state, BLoC stream…). A đúng.\n• Chuỗi sự kiện/giá trị bất đồng bộ theo thời gian.\n• Lắng nghe nhiều lần (click stream, data chunk).","intent":"• Future: một kết quả async.\n• Stream: nhiều sự kiện theo thời gian.","memoryTip":"• Auth: token/session tập trung; Guard chặn route; StreamBuilder hay dùng với auth stream.","whatIs":{"A":"Chuỗi sự kiện/giá trị bất đồng bộ theo thời gian.","B":"Tạo hộp kích thước cố định hoặc khoảng trống size cho trước.","C":"Cơ chế Flutter/Dart liên quan «Divider».","D":"Cơ chế Flutter/Dart liên quan «Placeholder»."},"whyWrong":{"B":"• Là gì? Tạo hộp kích thước cố định hoặc khoảng trống size cho trước.\n• Dùng để làm gì? Spacer cố định (width/height); khác Expanded (chiếm phần còn lại).\n• Vì sao sai? SizedBox tạo kích thước/khoảng trống cố định.","C":"• Là gì? Cơ chế Flutter/Dart liên quan «Divider».\n• Dùng để làm gì? Đối chiếu đúng cơ chế/phạm trù với trọng tâm đề.\n• Vì sao sai? «Divider only» — Cơ chế Flutter/Dart liên quan «Divider». Đề cần: Chuỗi sự kiện/giá trị bất đồng bộ theo thời gian.","D":"• Là gì? Cơ chế Flutter/Dart liên quan «Placeholder».\n• Dùng để làm gì? Đối chiếu đúng cơ chế/phạm trù với trọng tâm đề.\n• Vì sao sai? «Placeholder only» — Cơ chế Flutter/Dart liên quan «Placeholder». Đề cần: Chuỗi sự kiện/giá trị bất đồng bộ theo thời gian."}}},{"id":199,"task":"slides","taskLabel":"Slides","num":198,"question":"What happens after successful login from a session perspective?","options":{"A":"App always crashes","B":"User session starts (authenticated context)","C":"Device factory resets","D":"All tokens are printed to UI permanently"},"answer":"B","alternatives":[],"source":"slides","exam":"PRM393_SLIDES_M10","explanation":{"questionVi":"Sau login thành công, về mặt session thì sao?","optionsVi":{"A":"App Luôn crashes","B":"Phiên user bắt đầu (đã auth)","C":"Device factory resets","D":"Tất cả token là printed để UI vĩnh viễn"},"answerDisplay":"B. Phiên user bắt đầu (đã auth)","concept":"• Phiên user bắt đầu (đã auth). Bản dịch/diễn đạt phương án — đối chiếu với định nghĩa chuẩn của đề.","whyCorrect":"• Phiên user bắt đầu (đã auth)\n• Bản dịch/diễn đạt phương án — đối chiếu với định nghĩa chuẩn của đề.","intent":"• Phiên user bắt đầu (đã auth)\n• Bản dịch/diễn đạt phương án — đối chiếu với định nghĩa chuẩn của đề.","memoryTip":"• Auth: token/session tập trung; Guard chặn route; StreamBuilder hay dùng với auth stream.","whatIs":{"A":"Cụm «App Luôn crashes» mang một nghĩa riêng cần đối chiếu với đề.","B":"Phiên user bắt đầu (đã auth)","C":"Cụm «Device factory resets» mang một nghĩa riêng cần đối chiếu với đề.","D":"Tất cả token là printed để UI vĩnh viễn"},"whyWrong":{"A":"• Là gì? Cụm «App Luôn crashes» mang một nghĩa riêng cần đối chiếu với đề.\n• Dùng để làm gì? So bản chất với đáp án đúng; loại nếu sai đối tượng hoặc sai lớp khái niệm.\n• Vì sao sai? «App always crashes» — Cụm «App Luôn crashes» mang một nghĩa riêng cần đối chiếu với đề. Đề cần: Phiên user bắt đầu (đã auth).","C":"• Là gì? Cụm «Device factory resets» mang một nghĩa riêng cần đối chiếu với đề.\n• Dùng để làm gì? So bản chất với đáp án đúng; loại nếu sai đối tượng hoặc sai lớp khái niệm.\n• Vì sao sai? «Device factory resets» — Cụm «Device factory resets» mang một nghĩa riêng cần đối chiếu với đề. Đề cần: Phiên user bắt đầu (đã auth).","D":"• Là gì? Tất cả token là printed để UI vĩnh viễn\n• Dùng để làm gì? Bản dịch/diễn đạt phương án — đối chiếu với định nghĩa chuẩn của đề.\n• Vì sao sai? Auth/session không giải quyết bằng chỉnh UI/theme/animation."}}},{"id":200,"task":"slides","taskLabel":"Slides","num":199,"question":"Storing tokens insecurely (plain SharedPreferences without care) risks:","options":{"A":"Faster animations","B":"Better SEO","C":"Token theft / account compromise","D":"Better null safety"},"answer":"C","alternatives":[],"source":"slides","exam":"PRM393_SLIDES_M10","explanation":{"questionVi":"Lưu token không an toàn (SharedPreferences thô) rủi ro gì?","optionsVi":{"A":"Nhanh hơn animations","B":"Tốt hơn SEO","C":"Mất token / chiếm tài khoản","D":"Tốt hơn null safety"},"answerDisplay":"C. Mất token / chiếm tài khoản","concept":"• Mất token / chiếm tài khoản. Bản dịch/diễn đạt phương án — đối chiếu với định nghĩa chuẩn của đề.","whyCorrect":"• Mất token / chiếm tài khoản\n• Bản dịch/diễn đạt phương án — đối chiếu với định nghĩa chuẩn của đề.","intent":"• Mất token / chiếm tài khoản\n• Bản dịch/diễn đạt phương án — đối chiếu với định nghĩa chuẩn của đề.","memoryTip":"• KV nhỏ → shared_preferences · NoSQL local → Hive · SQL → sqflite.","whatIs":{"A":"Cụm «Nhanh hơn animations» mang một nghĩa riêng cần đối chiếu với đề.","B":"Cụm «Tốt hơn SEO» mang một nghĩa riêng cần đối chiếu với đề.","C":"Mất token / chiếm tài khoản","D":"Hệ thống kiểu Dart phân biệt null/non-null để giảm crash."},"whyWrong":{"A":"• Là gì? Cụm «Nhanh hơn animations» mang một nghĩa riêng cần đối chiếu với đề.\n• Dùng để làm gì? So bản chất với đáp án đúng; loại nếu sai đối tượng hoặc sai lớp khái niệm.\n• Vì sao sai? shared_preferences chỉ key-value đơn giản (bool/int/string), không phù hợp mọi nhu cầu.","B":"• Là gì? Cụm «Tốt hơn SEO» mang một nghĩa riêng cần đối chiếu với đề.\n• Dùng để làm gì? So bản chất với đáp án đúng; loại nếu sai đối tượng hoặc sai lớp khái niệm.\n• Vì sao sai? shared_preferences chỉ key-value đơn giản (bool/int/string), không phù hợp mọi nhu cầu.","D":"• Là gì? Hệ thống kiểu Dart phân biệt null/non-null để giảm crash.\n• Dùng để làm gì? Bắt buộc khởi tạo non-nullable trước khi dùng.\n• Vì sao sai? shared_preferences chỉ key-value đơn giản (bool/int/string), không phù hợp mọi nhu cầu."}}},{"id":201,"task":"slides","taskLabel":"Slides","num":200,"question":"Logout should typically:","options":{"A":"Clear session/token and return to unauthenticated UI","B":"Keep tokens forever without clearing","C":"Uninstall Flutter","D":"Disable hot reload"},"answer":"A","alternatives":[],"source":"slides","exam":"PRM393_SLIDES_M10","explanation":{"questionVi":"Logout thường nên:","optionsVi":{"A":"Xóa session/token và về UI chưa đăng nhập","B":"Keep token mãi mãi Không có clearing","C":"Uninstall Flutter","D":"Tắt hot reload"},"answerDisplay":"A. Xóa session/token và về UI chưa đăng nhập","concept":"• Xóa session/token và về UI chưa đăng nhập. Bản dịch/diễn đạt phương án — đối chiếu với định nghĩa chuẩn của đề.","whyCorrect":"• Xóa session/token và về UI chưa đăng nhập\n• Bản dịch/diễn đạt phương án — đối chiếu với định nghĩa chuẩn của đề.","intent":"• Xóa session/token và về UI chưa đăng nhập\n• Bản dịch/diễn đạt phương án — đối chiếu với định nghĩa chuẩn của đề.","whatIs":{"A":"Xóa session/token và về UI chưa đăng nhập","B":"Keep token mãi mãi Không có clearing","C":"Cơ chế Flutter/Dart liên quan «Uninstall Flutter».","D":"Nạp lại code UI gần như giữ state đang chạy."},"whyWrong":{"B":"• Là gì? Keep token mãi mãi Không có clearing\n• Dùng để làm gì? Bản dịch/diễn đạt phương án — đối chiếu với định nghĩa chuẩn của đề.\n• Vì sao sai? «Keep tokens forever without clearing» — Keep token mãi mãi Không có clearing. Đề cần: Xóa session/token và về UI chưa đăng nhập.","C":"• Là gì? Cơ chế Flutter/Dart liên quan «Uninstall Flutter».\n• Dùng để làm gì? Đối chiếu đúng cơ chế/phạm trù với trọng tâm đề.\n• Vì sao sai? «Uninstall Flutter» — Cơ chế Flutter/Dart liên quan «Uninstall Flutter». Đề cần: Xóa session/token và về UI chưa đăng nhập.","D":"• Là gì? Nạp lại code UI gần như giữ state đang chạy.\n• Dùng để làm gì? Xem thay đổi nhanh khi dev.\n• Vì sao sai? Hot reload nạp code UI nhanh khi dev; không phải công cụ phân tích sâu."}}},{"id":202,"task":"slides","taskLabel":"Slides","num":201,"question":"Push notifications in this module are related to:","options":{"A":"Only offline SQLite vacuum","B":"Alerting users (often after auth/session context exists)","C":"Replacing REST entirely","D":"Compiling Skia"},"answer":"B","alternatives":[],"source":"slides","exam":"PRM393_SLIDES_M10","explanation":{"questionVi":"Push notification trong module này liên quan tới:","optionsVi":{"A":"Chỉ offline SQLite vacuum","B":"Báo user (thường khi đã có auth/session)","C":"Replacing REST entirely","D":"Compiling Skia"},"answerDisplay":"B. Báo user (thường khi đã có auth/session)","concept":"• Báo user (thường khi đã có auth/session). Bản dịch/diễn đạt phương án — đối chiếu với định nghĩa chuẩn của đề.","whyCorrect":"• Báo user (thường khi đã có auth/session)\n• Bản dịch/diễn đạt phương án — đối chiếu với định nghĩa chuẩn của đề.","intent":"• Báo user (thường khi đã có auth/session)\n• Bản dịch/diễn đạt phương án — đối chiếu với định nghĩa chuẩn của đề.","whatIs":{"A":"Chỉ offline SQLite vacuum","B":"Báo user (thường khi đã có auth/session)","C":"Cụm «Replacing REST entirely» mang một nghĩa riêng cần đối chiếu với đề.","D":"Thư viện đồ họa 2D (C++) mà Flutter Engine dùng để vẽ."},"whyWrong":{"A":"• Là gì? Chỉ offline SQLite vacuum\n• Dùng để làm gì? Bản dịch/diễn đạt phương án — đối chiếu với định nghĩa chuẩn của đề.\n• Vì sao sai? «Only offline SQLite vacuum» — Chỉ offline SQLite vacuum. Đề cần: Báo user (thường khi đã có auth/session).","C":"• Là gì? Cụm «Replacing REST entirely» mang một nghĩa riêng cần đối chiếu với đề.\n• Dùng để làm gì? So bản chất với đáp án đúng; loại nếu sai đối tượng hoặc sai lớp khái niệm.\n• Vì sao sai? «Replacing REST entirely» — Cụm «Replacing REST entirely» mang một nghĩa riêng cần đối chiếu với đề. Đề cần: Báo user (thường khi đã có auth/session).","D":"• Là gì? Thư viện đồ họa 2D (C++) mà Flutter Engine dùng để vẽ.\n• Dùng để làm gì? Render UI nhất quán, tận dụng GPU.\n• Vì sao sai? «Compiling Skia» — Thư viện đồ họa 2D (C++) mà Flutter Engine dùng để vẽ. Đề cần: Báo user (thường khi đã có auth/session)."}}},{"id":203,"task":"slides","taskLabel":"Slides","num":202,"question":"Protected routes should:","options":{"A":"Always be public without checks","B":"Ignore tokens","C":"Allow access only when authenticated","D":"Bypass SSL always"},"answer":"C","alternatives":[],"source":"slides","exam":"PRM393_SLIDES_M10","explanation":{"questionVi":"Route được bảo vệ nên:","optionsVi":{"A":"Luôn be public Không có checks","B":"Ignore tokens","C":"Chỉ cho vào khi đã xác thực","D":"Bypass SSL Luôn"},"answerDisplay":"C. Chỉ cho vào khi đã xác thực","concept":"• Chỉ cho vào khi đã xác thực. Bản dịch/diễn đạt phương án — đối chiếu với định nghĩa chuẩn của đề.","whyCorrect":"• Chỉ cho vào khi đã xác thực\n• Bản dịch/diễn đạt phương án — đối chiếu với định nghĩa chuẩn của đề.","intent":"• Chỉ cho vào khi đã xác thực\n• Bản dịch/diễn đạt phương án — đối chiếu với định nghĩa chuẩn của đề.","whatIs":{"A":"Luôn be public Không có checks","B":"Cụm «Ignore tokens» mang một nghĩa riêng cần đối chiếu với đề.","C":"Chỉ cho vào khi đã xác thực","D":"Cụm «Bypass SSL Luôn» mang một nghĩa riêng cần đối chiếu với đề."},"whyWrong":{"A":"• Là gì? Luôn be public Không có checks\n• Dùng để làm gì? Bản dịch/diễn đạt phương án — đối chiếu với định nghĩa chuẩn của đề.\n• Vì sao sai? «Always be public without checks» — Luôn be public Không có checks. Đề cần: Chỉ cho vào khi đã xác thực.","B":"• Là gì? Cụm «Ignore tokens» mang một nghĩa riêng cần đối chiếu với đề.\n• Dùng để làm gì? So bản chất với đáp án đúng; loại nếu sai đối tượng hoặc sai lớp khái niệm.\n• Vì sao sai? «Ignore tokens» — Cụm «Ignore tokens» mang một nghĩa riêng cần đối chiếu với đề. Đề cần: Chỉ cho vào khi đã xác thực.","D":"• Là gì? Cụm «Bypass SSL Luôn» mang một nghĩa riêng cần đối chiếu với đề.\n• Dùng để làm gì? So bản chất với đáp án đúng; loại nếu sai đối tượng hoặc sai lớp khái niệm.\n• Vì sao sai? «Bypass SSL always» — Cụm «Bypass SSL Luôn» mang một nghĩa riêng cần đối chiếu với đề. Đề cần: Chỉ cho vào khi đã xác thực."}}},{"id":204,"task":"slides","taskLabel":"Slides","num":203,"question":"Which test type checks individual functions or classes?","options":{"A":"Widget test","B":"Integration test","C":"Unit test","D":"Manual only screenshot without code"},"answer":"C","alternatives":[],"source":"slides","exam":"PRM393_SLIDES_M11","explanation":{"questionVi":"Loại test nào kiểm tra từng hàm/class?","optionsVi":{"A":"Widget test","B":"Integration test","C":"Unit test","D":"Manual chỉ screenshot Không có mã"},"answerDisplay":"C. Unit test","concept":"• Cụm «Unit test» mang một nghĩa riêng cần đối chiếu với đề.","whyCorrect":"• Cụm «Unit test» mang một nghĩa riêng cần đối chiếu với đề.\n• So bản chất với đáp án đúng; loại nếu sai đối tượng hoặc sai lớp khái niệm.","intent":"• Cụm «Unit test» mang một nghĩa riêng cần đối chiếu với đề.\n• So bản chất với đáp án đúng; loại nếu sai đối tượng hoặc sai lớp khái niệm.","whatIs":{"A":"Cơ chế Flutter/Dart liên quan «Widget test».","B":"Cụm «Integration test» mang một nghĩa riêng cần đối chiếu với đề.","C":"Cụm «Unit test» mang một nghĩa riêng cần đối chiếu với đề.","D":"Manual chỉ screenshot Không có mã"},"whyWrong":{"A":"• Là gì? Cơ chế Flutter/Dart liên quan «Widget test».\n• Dùng để làm gì? Đối chiếu đúng cơ chế/phạm trù với trọng tâm đề.\n• Vì sao sai? Widget test: UI component; không phải pure logic hay full app E2E.","B":"• Là gì? Cụm «Integration test» mang một nghĩa riêng cần đối chiếu với đề.\n• Dùng để làm gì? So bản chất với đáp án đúng; loại nếu sai đối tượng hoặc sai lớp khái niệm.\n• Vì sao sai? Integration: nhiều thành phần/E2E; không phải unit đơn lẻ.","D":"• Là gì? Manual chỉ screenshot Không có mã\n• Dùng để làm gì? Bản dịch/diễn đạt phương án — đối chiếu với định nghĩa chuẩn của đề.\n• Vì sao sai? «Manual only screenshot without code» — Manual chỉ screenshot Không có mã. Đề cần: Cụm «Unit test» mang một nghĩa riêng cần đối chiếu với đề."}}},{"id":205,"task":"slides","taskLabel":"Slides","num":204,"question":"Which Flutter test focuses on UI components/widgets?","options":{"A":"Unit test only of pure Dart math","B":"Widget test","C":"Load test of servers only","D":"DNS test only"},"answer":"B","alternatives":[],"source":"slides","exam":"PRM393_SLIDES_M11","explanation":{"questionVi":"Test Flutter nào tập trung UI/widget?","optionsVi":{"A":"Unit test chỉ củ pure Dart math","B":"Widget test","C":"Load test của servers","D":"DNS test"},"answerDisplay":"B. Widget test","concept":"• Cơ chế Flutter/Dart liên quan «Widget test».","whyCorrect":"• Cơ chế Flutter/Dart liên quan «Widget test».","intent":"• Cơ chế Flutter/Dart liên quan «Widget test».\n• Chọn phương án khớp cơ chế Flutter, không chọn stack web/Android nhầm.","whatIs":{"A":"Ngôn ngữ lập trình chính của Flutter.","B":"Cơ chế Flutter/Dart liên quan «Widget test».","C":"Cơ chế Flutter/Dart liên quan «Load test của servers».","D":"Hệ thống phân giải tên miền thành địa chỉ IP."},"whyWrong":{"A":"• Là gì? Ngôn ngữ lập trình chính của Flutter.\n• Dùng để làm gì? Viết UI và logic app Flutter.\n• Vì sao sai? «Unit test only of pure Dart math» — Ngôn ngữ lập trình chính của Flutter. Đề cần: Cơ chế Flutter/Dart liên quan «Widget test».","C":"• Là gì? Cơ chế Flutter/Dart liên quan «Load test của servers».\n• Dùng để làm gì? Đối chiếu đúng cơ chế/phạm trù với trọng tâm đề.\n• Vì sao sai? «Load test of servers only» — Cơ chế Flutter/Dart liên quan «Load test của servers». Đề cần: Cơ chế Flutter/Dart liên quan «Widget test».","D":"• Là gì? Hệ thống phân giải tên miền thành địa chỉ IP.\n• Dùng để làm gì? Người dùng dùng tên dễ nhớ thay vì số IP.\n• Vì sao sai? «DNS test only» — Hệ thống phân giải tên miền thành địa chỉ IP. Đề cần: Cơ chế Flutter/Dart liên quan «Widget test»."}}},{"id":206,"task":"slides","taskLabel":"Slides","num":205,"question":"What does an integration test verify?","options":{"A":"End-to-end app behavior across parts","B":"Only one private method always","C":"Only font file integrity","D":"Only Gradle version"},"answer":"A","alternatives":[],"source":"slides","exam":"PRM393_SLIDES_M11","explanation":{"questionVi":"Integration test xác minh gì?","optionsVi":{"A":"Hành vi app end-to-end qua nhiều phần","B":"Chỉ một private method Luôn","C":"Chỉ font file integrity","D":"Chỉ Gradle version"},"answerDisplay":"A. Hành vi app end-to-end qua nhiều phần","concept":"• Phần mềm quản lý phần cứng, tiến trình, bộ nhớ, I/O.","whyCorrect":"• Phần mềm quản lý phần cứng, tiến trình, bộ nhớ, I/O.\n• Cấp tài nguyên và lập lịch cho chương trình.","intent":"• Phần mềm quản lý phần cứng, tiến trình, bộ nhớ, I/O.\n• Cấp tài nguyên và lập lịch cho chương trình.","memoryTip":"• Unit = logic nhỏ · Widget = UI · Integration = nhiều phần/E2E · Test bảo vệ khi refactor.","whatIs":{"A":"Phần mềm quản lý phần cứng, tiến trình, bộ nhớ, I/O.","B":"Chỉ một private method Luôn","C":"Cụm «Chỉ font file integrity» mang một nghĩa riêng cần đối chiếu với đề.","D":"Cụm «Chỉ Gradle version» mang một nghĩa riêng cần đối chiếu với đề."},"whyWrong":{"B":"• Là gì? Chỉ một private method Luôn\n• Dùng để làm gì? Bản dịch/diễn đạt phương án — đối chiếu với định nghĩa chuẩn của đề.\n• Vì sao sai? Integration: nhiều thành phần/E2E; không phải unit đơn lẻ.","C":"• Là gì? Cụm «Chỉ font file integrity» mang một nghĩa riêng cần đối chiếu với đề.\n• Dùng để làm gì? So bản chất với đáp án đúng; loại nếu sai đối tượng hoặc sai lớp khái niệm.\n• Vì sao sai? Integration: nhiều thành phần/E2E; không phải unit đơn lẻ.","D":"• Là gì? Cụm «Chỉ Gradle version» mang một nghĩa riêng cần đối chiếu với đề.\n• Dùng để làm gì? So bản chất với đáp án đúng; loại nếu sai đối tượng hoặc sai lớp khái niệm.\n• Vì sao sai? Integration: nhiều thành phần/E2E; không phải unit đơn lẻ."}}},{"id":207,"task":"slides","taskLabel":"Slides","num":206,"question":"Why are tests important for refactoring?","options":{"A":"They slow CI only with no benefit","B":"Ensure changes don't break functionality","C":"They replace product requirements","D":"They remove the need for UI"},"answer":"B","alternatives":[],"source":"slides","exam":"PRM393_SLIDES_M11","explanation":{"questionVi":"Vì sao test quan trọng khi refactor?","optionsVi":{"A":"They slow CI chỉ với không benefit","B":"Đảm bảo thay đổi không phá chức năng","C":"They Thay thế product requirements","D":"They Gỡ bỏ cần cho UI"},"answerDisplay":"B. Đảm bảo thay đổi không phá chức năng","concept":"• Đảm bảo thay đổi không phá chức năng. Bản dịch/diễn đạt phương án — đối chiếu với định nghĩa chuẩn của đề.","whyCorrect":"• Đảm bảo thay đổi không phá chức năng\n• Bản dịch/diễn đạt phương án — đối chiếu với định nghĩa chuẩn của đề.","intent":"• Đảm bảo thay đổi không phá chức năng\n• Bản dịch/diễn đạt phương án — đối chiếu với định nghĩa chuẩn của đề.","memoryTip":"• Unit = logic nhỏ · Widget = UI · Integration = nhiều phần/E2E · Test bảo vệ khi refactor.","whatIs":{"A":"They slow CI chỉ với không benefit","B":"Đảm bảo thay đổi không phá chức năng","C":"They Thay thế product requirements","D":"Cụm «They Gỡ bỏ cần cho UI» mang một nghĩa riêng cần đối chiếu với đề."},"whyWrong":{"A":"• Là gì? They slow CI chỉ với không benefit\n• Dùng để làm gì? Bản dịch/diễn đạt phương án — đối chiếu với định nghĩa chuẩn của đề.\n• Vì sao sai? Không phải mục tiêu chính của test khi refactor; test bảo vệ hành vi khỏi bị hỏng.","C":"• Là gì? They Thay thế product requirements\n• Dùng để làm gì? Bản dịch/diễn đạt phương án — đối chiếu với định nghĩa chuẩn của đề.\n• Vì sao sai? Không phải mục tiêu chính của test khi refactor; test bảo vệ hành vi khỏi bị hỏng.","D":"• Là gì? Cụm «They Gỡ bỏ cần cho UI» mang một nghĩa riêng cần đối chiếu với đề.\n• Dùng để làm gì? So bản chất với đáp án đúng; loại nếu sai đối tượng hoặc sai lớp khái niệm.\n• Vì sao sai? Không phải mục tiêu chính của test khi refactor; test bảo vệ hành vi khỏi bị hỏng."}}},{"id":208,"task":"slides","taskLabel":"Slides","num":207,"question":"What is test isolation?","options":{"A":"Independence of test cases","B":"Running all tests in one shared mutable global only","C":"Disabling assertions","D":"Skipping failures"},"answer":"A","alternatives":[],"source":"slides","exam":"PRM393_SLIDES_M11","explanation":{"questionVi":"Test isolation là gì?","optionsVi":{"A":"Tính độc lập giữa các test case","B":"Chạy tất cả tests trong một shared mutable global","C":"Disabling assertions","D":"Skipping failures"},"answerDisplay":"A. Tính độc lập giữa các test case","concept":"• Tính độc lập giữa các test case. Bản dịch/diễn đạt phương án — đối chiếu với định nghĩa chuẩn của đề.","whyCorrect":"• Tính độc lập giữa các test case\n• Bản dịch/diễn đạt phương án — đối chiếu với định nghĩa chuẩn của đề.","intent":"• Tính độc lập giữa các test case\n• Bản dịch/diễn đạt phương án — đối chiếu với định nghĩa chuẩn của đề.","whatIs":{"A":"Tính độc lập giữa các test case","B":"Tiến trình đang chiếm CPU và thực thi lệnh.","C":"Cụm «Disabling assertions» mang một nghĩa riêng cần đối chiếu với đề.","D":"Cụm «Skipping failures» mang một nghĩa riêng cần đối chiếu với đề."},"whyWrong":{"B":"• Là gì? Tiến trình đang chiếm CPU và thực thi lệnh.\n• Dùng để làm gì? Đang làm việc trên bộ xử lý.\n• Vì sao sai? «Running all tests in one shared mutable global only» — Tiến trình đang chiếm CPU và thực thi lệnh. Đề cần: Tính độc lập giữa các test case.","C":"• Là gì? Cụm «Disabling assertions» mang một nghĩa riêng cần đối chiếu với đề.\n• Dùng để làm gì? So bản chất với đáp án đúng; loại nếu sai đối tượng hoặc sai lớp khái niệm.\n• Vì sao sai? «Disabling assertions» — Cụm «Disabling assertions» mang một nghĩa riêng cần đối chiếu với đề. Đề cần: Tính độc lập giữa các test case.","D":"• Là gì? Cụm «Skipping failures» mang một nghĩa riêng cần đối chiếu với đề.\n• Dùng để làm gì? So bản chất với đáp án đúng; loại nếu sai đối tượng hoặc sai lớp khái niệm.\n• Vì sao sai? «Skipping failures» — Cụm «Skipping failures» mang một nghĩa riêng cần đối chiếu với đề. Đề cần: Tính độc lập giữa các test case."}}},{"id":209,"task":"slides","taskLabel":"Slides","num":208,"question":"Which tool helps debug Flutter apps (network, performance, etc.)?","options":{"A":"Notepad only","B":"Paint.exe","C":"DevTools","D":"Calculator only"},"answer":"C","alternatives":[],"source":"slides","exam":"PRM393_SLIDES_M11","explanation":{"questionVi":"Công cụ nào giúp debug app Flutter (mạng, hiệu năng…)?","optionsVi":{"A":"Notepad","B":"Paint.exe","C":"DevTools","D":"Calculator"},"answerDisplay":"C. DevTools","concept":"• Mức mượt và tiết kiệm tài nguyên khi render/chạy app.","whyCorrect":"• Mức mượt và tiết kiệm tài nguyên khi render/chạy app.\n• Skia/AOT/rebuild hẹp giúp UI mượt.","intent":"• Mức mượt và tiết kiệm tài nguyên khi render/chạy app.\n• Chọn phương án khớp cơ chế Flutter, không chọn stack web/Android nhầm.","whatIs":{"A":"Cơ chế Flutter/Dart liên quan «Notepad».","B":"Vẽ pixel/lớp đồ họa lên màn hình.","C":"Mức mượt và tiết kiệm tài nguyên khi render/chạy app.","D":"Cơ chế Flutter/Dart liên quan «Calculator»."},"whyWrong":{"A":"• Là gì? Cơ chế Flutter/Dart liên quan «Notepad».\n• Dùng để làm gì? Đối chiếu đúng cơ chế/phạm trù với trọng tâm đề.\n• Vì sao sai? «Notepad only» — Cơ chế Flutter/Dart liên quan «Notepad». Đề cần: Mức mượt và tiết kiệm tài nguyên khi render/chạy app.","B":"• Là gì? Vẽ pixel/lớp đồ họa lên màn hình.\n• Dùng để làm gì? Thuộc RenderObject/engine (Skia); không phải Handle BuildContext.\n• Vì sao sai? «Paint.exe» — Vẽ pixel/lớp đồ họa lên màn hình. Đề cần: Mức mượt và tiết kiệm tài nguyên khi render/chạy app.","D":"• Là gì? Cơ chế Flutter/Dart liên quan «Calculator».\n• Dùng để làm gì? Đối chiếu đúng cơ chế/phạm trù với trọng tâm đề.\n• Vì sao sai? «Calculator only» — Cơ chế Flutter/Dart liên quan «Calculator». Đề cần: Mức mượt và tiết kiệm tài nguyên khi render/chạy app."}}},{"id":210,"task":"slides","taskLabel":"Slides","num":209,"question":"The Taskly demo app in slides is used to:","options":{"A":"Replace the Flutter engine","B":"Demonstrate each test type on a simple Todo app","C":"Host production payments only","D":"Compile C++ only"},"answer":"B","alternatives":[],"source":"slides","exam":"PRM393_SLIDES_M11","explanation":{"questionVi":"App demo Taskly trong slide dùng để:","optionsVi":{"A":"Thay thế Flutter engine","B":"Minh họa từng loại test trên app Todo đơn giản","C":"Host production payments","D":"Biên dịch C++"},"answerDisplay":"B. Minh họa từng loại test trên app Todo đơn giản","concept":"• Minh họa từng loại test trên app Todo đơn giản. Bản dịch/diễn đạt phương án — đối chiếu với định nghĩa chuẩn của đề.","whyCorrect":"• Minh họa từng loại test trên app Todo đơn giản\n• Bản dịch/diễn đạt phương án — đối chiếu với định nghĩa chuẩn của đề.","intent":"• Minh họa từng loại test trên app Todo đơn giản\n• Bản dịch/diễn đạt phương án — đối chiếu với định nghĩa chuẩn của đề.","whatIs":{"A":"Cơ chế Flutter/Dart liên quan «Thay thế Flutter engine».","B":"Minh họa từng loại test trên app Todo đơn giản","C":"Phần mềm quản lý phần cứng, tiến trình, bộ nhớ, I/O.","D":"Cụm «Biên dịch C++» mang một nghĩa riêng cần đối chiếu với đề."},"whyWrong":{"A":"• Là gì? Cơ chế Flutter/Dart liên quan «Thay thế Flutter engine».\n• Dùng để làm gì? Đối chiếu đúng cơ chế/phạm trù với trọng tâm đề.\n• Vì sao sai? «Replace the Flutter engine» — Cơ chế Flutter/Dart liên quan «Thay thế Flutter engine». Đề cần: Minh họa từng loại test trên app Todo đơn giản.","C":"• Là gì? Phần mềm quản lý phần cứng, tiến trình, bộ nhớ, I/O.\n• Dùng để làm gì? Cấp tài nguyên và lập lịch cho chương trình.\n• Vì sao sai? «Host production payments only» — Phần mềm quản lý phần cứng, tiến trình, bộ nhớ, I/O. Đề cần: Minh họa từng loại test trên app Todo đơn giản.","D":"• Là gì? Cụm «Biên dịch C++» mang một nghĩa riêng cần đối chiếu với đề.\n• Dùng để làm gì? So bản chất với đáp án đúng; loại nếu sai đối tượng hoặc sai lớp khái niệm.\n• Vì sao sai? «Compile C++ only» — Cụm «Biên dịch C++» mang một nghĩa riêng cần đối chiếu với đề. Đề cần: Minh họa từng loại test trên app Todo đơn giản."}}},{"id":211,"task":"slides","taskLabel":"Slides","num":210,"question":"find.byType / find.text in widget tests are used to:","options":{"A":"Locate widgets in the test environment","B":"Deploy to Play Store","C":"Generate icons","D":"Create keystores"},"answer":"A","alternatives":[],"source":"slides","exam":"PRM393_SLIDES_M11","explanation":{"questionVi":"find.byType / find.text trong widget test dùng để:","optionsVi":{"A":"Định vị widget trong môi trường test","B":"Triển khai để Play Lưu","C":"Generate icons","D":"Tạo keystores"},"answerDisplay":"A. Định vị widget trong môi trường test","concept":"• Định vị widget trong môi trường test. Bản dịch/diễn đạt phương án — đối chiếu với định nghĩa chuẩn của đề.","whyCorrect":"• Định vị widget trong môi trường test\n• Bản dịch/diễn đạt phương án — đối chiếu với định nghĩa chuẩn của đề.","intent":"• Định vị widget trong môi trường test\n• Chọn phương án khớp cơ chế Flutter, không chọn stack web/Android nhầm.","memoryTip":"• Unit = logic nhỏ · Widget = UI · Integration = nhiều phần/E2E · Test bảo vệ khi refactor.","whatIs":{"A":"Định vị widget trong môi trường test","B":"Cơ chế Flutter/Dart liên quan «Triển khai để Play Lưu».","C":"Cơ chế Flutter/Dart liên quan «Generate icons».","D":"Cơ chế Flutter/Dart liên quan «Tạo keystores»."},"whyWrong":{"B":"• Là gì? Cơ chế Flutter/Dart liên quan «Triển khai để Play Lưu».\n• Dùng để làm gì? Đối chiếu đúng cơ chế/phạm trù với trọng tâm đề.\n• Vì sao sai? Widget test: UI component; không phải pure logic hay full app E2E.","C":"• Là gì? Cơ chế Flutter/Dart liên quan «Generate icons».\n• Dùng để làm gì? Đối chiếu đúng cơ chế/phạm trù với trọng tâm đề.\n• Vì sao sai? Widget test: UI component; không phải pure logic hay full app E2E.","D":"• Là gì? Cơ chế Flutter/Dart liên quan «Tạo keystores».\n• Dùng để làm gì? Đối chiếu đúng cơ chế/phạm trù với trọng tâm đề.\n• Vì sao sai? Widget test: UI component; không phải pure logic hay full app E2E."}}},{"id":212,"task":"slides","taskLabel":"Slides","num":211,"question":"Mocking dependencies in unit tests helps:","options":{"A":"Increase flakiness only","B":"Force real network always","C":"Test logic in isolation without external systems","D":"Disable CI"},"answer":"C","alternatives":[],"source":"slides","exam":"PRM393_SLIDES_M11","explanation":{"questionVi":"Mock dependency trong unit test giúp:","optionsVi":{"A":"Tăng flakiness","B":"Ép real mạng Luôn","C":"Test logic cô lập, không phụ thuộc hệ ngoài","D":"Tắt CI"},"answerDisplay":"C. Test logic cô lập, không phụ thuộc hệ ngoài","concept":"• Test logic cô lập, không phụ thuộc hệ ngoài. Bản dịch/diễn đạt phương án — đối chiếu với định nghĩa chuẩn của đề.","whyCorrect":"• Test logic cô lập, không phụ thuộc hệ ngoài\n• Bản dịch/diễn đạt phương án — đối chiếu với định nghĩa chuẩn của đề.","intent":"• Test logic cô lập, không phụ thuộc hệ ngoài\n• Bản dịch/diễn đạt phương án — đối chiếu với định nghĩa chuẩn của đề.","memoryTip":"• Unit = logic nhỏ · Widget = UI · Integration = nhiều phần/E2E · Test bảo vệ khi refactor.","whatIs":{"A":"Cụm «Tăng flakiness» mang một nghĩa riêng cần đối chiếu với đề.","B":"Cụm «Ép real mạng Luôn» mang một nghĩa riêng cần đối chiếu với đề.","C":"Test logic cô lập, không phụ thuộc hệ ngoài","D":"Cụm «Tắt CI» mang một nghĩa riêng cần đối chiếu với đề."},"whyWrong":{"A":"• Là gì? Cụm «Tăng flakiness» mang một nghĩa riêng cần đối chiếu với đề.\n• Dùng để làm gì? So bản chất với đáp án đúng; loại nếu sai đối tượng hoặc sai lớp khái niệm.\n• Vì sao sai? Unit test: hàm/class nhỏ; không phải UI widget hay E2E.","B":"• Là gì? Cụm «Ép real mạng Luôn» mang một nghĩa riêng cần đối chiếu với đề.\n• Dùng để làm gì? So bản chất với đáp án đúng; loại nếu sai đối tượng hoặc sai lớp khái niệm.\n• Vì sao sai? Unit test: hàm/class nhỏ; không phải UI widget hay E2E.","D":"• Là gì? Cụm «Tắt CI» mang một nghĩa riêng cần đối chiếu với đề.\n• Dùng để làm gì? So bản chất với đáp án đúng; loại nếu sai đối tượng hoặc sai lớp khái niệm.\n• Vì sao sai? Unit test: hàm/class nhỏ; không phải UI widget hay E2E."}}},{"id":213,"task":"slides","taskLabel":"Slides","num":212,"question":"Golden tests primarily verify:","options":{"A":"API JSON schema only","B":"UI appearance consistency (screenshots/baselines)","C":"Battery temperature","D":"DNS TTL"},"answer":"B","alternatives":[],"source":"slides","exam":"PRM393_SLIDES_M11","explanation":{"questionVi":"Golden test chủ yếu xác minh:","optionsVi":{"A":"API JSON schema","B":"Nhất quán giao diện (screenshot/baseline)","C":"Battery temperature","D":"DNS TTL"},"answerDisplay":"B. Nhất quán giao diện (screenshot/baseline)","concept":"• UI/hành vi thống nhất trên nhiều thiết bị nhờ một codebase Flutter.","whyCorrect":"• UI/hành vi thống nhất trên nhiều thiết bị nhờ một codebase Flutter.\n• Giảm lệch giao diện giữa iOS/Android.","intent":"• UI/hành vi thống nhất trên nhiều thiết bị nhờ một codebase Flutter.\n• Giảm lệch giao diện giữa iOS/Android.","memoryTip":"• Unit = logic nhỏ · Widget = UI · Integration = nhiều phần/E2E · Test bảo vệ khi refactor.","whatIs":{"A":"Cụm «API JSON schema» mang một nghĩa riêng cần đối chiếu với đề.","B":"UI/hành vi thống nhất trên nhiều thiết bị nhờ một codebase Flutter.","C":"Cụm «Battery temperature» mang một nghĩa riêng cần đối chiếu với đề.","D":"Hệ thống phân giải tên miền thành địa chỉ IP."},"whyWrong":{"A":"• Là gì? Cụm «API JSON schema» mang một nghĩa riêng cần đối chiếu với đề.\n• Dùng để làm gì? So bản chất với đáp án đúng; loại nếu sai đối tượng hoặc sai lớp khái niệm.\n• Vì sao sai? Golden test so sánh ảnh UI; khác integration/unit thuần.","C":"• Là gì? Cụm «Battery temperature» mang một nghĩa riêng cần đối chiếu với đề.\n• Dùng để làm gì? So bản chất với đáp án đúng; loại nếu sai đối tượng hoặc sai lớp khái niệm.\n• Vì sao sai? Golden test so sánh ảnh UI; khác integration/unit thuần.","D":"• Là gì? Hệ thống phân giải tên miền thành địa chỉ IP.\n• Dùng để làm gì? Người dùng dùng tên dễ nhớ thay vì số IP.\n• Vì sao sai? Golden test so sánh ảnh UI; khác integration/unit thuần."}}},{"id":214,"task":"slides","taskLabel":"Slides","num":213,"question":"What should you avoid doing inside build()?","options":{"A":"Heavy work: sorting, JSON parse, complex calc, DB/API calls","B":"Returning a simple widget tree","C":"Using const widgets","D":"Reading Theme.of(context) lightly"},"answer":"A","alternatives":[],"source":"slides","exam":"PRM393_SLIDES_M12","explanation":{"questionVi":"Nên tránh làm gì trong build()?","optionsVi":{"A":"Việc nặng: sort, parse JSON, tính toán, gọi DB/API","B":"Returning một đơn giản cây widget","C":"Dùng const widgets","D":"Đọc Theme.của(context) lightly"},"answerDisplay":"A. Việc nặng: sort, parse JSON, tính toán, gọi DB/API","concept":"• Việc nặng: sort, parse JSON, tính toán, gọi DB/API. Bản dịch/diễn đạt phương án — đối chiếu với định nghĩa chuẩn của đề.","whyCorrect":"• Việc nặng: sort, parse JSON, tính toán, gọi DB/API\n• Bản dịch/diễn đạt phương án — đối chiếu với định nghĩa chuẩn của đề.","intent":"• Việc nặng: sort, parse JSON, tính toán, gọi DB/API\n• Bản dịch/diễn đạt phương án — đối chiếu với định nghĩa chuẩn của đề.","memoryTip":"• UI = cây widget; BuildContext định vị trên cây; build() chỉ mô tả UI.","whatIs":{"A":"Việc nặng: sort, parse JSON, tính toán, gọi DB/API","B":"Cây cấu hình UI lồng nhau mô tả giao diện tại một thời điểm.","C":"Hằng được xác định từ lúc biên dịch (compile-time).","D":"Đọc Theme.của(context) lightly"},"whyWrong":{"B":"• Là gì? Cây cấu hình UI lồng nhau mô tả giao diện tại một thời điểm.\n• Dùng để làm gì? Đầu vào cho Element/Render pipeline của Flutter.\n• Vì sao sai? build() mô tả UI; không phải chỗ gọi để “cập nhật state”.","C":"• Là gì? Hằng được xác định từ lúc biên dịch (compile-time).\n• Dùng để làm gì? Giá trị bất biến, tối ưu và an toàn.\n• Vì sao sai? const giúp tái sử dụng widget, giảm rebuild — đúng khi hỏi tối ưu const.","D":"• Là gì? Đọc Theme.của(context) lightly\n• Dùng để làm gì? Bản dịch/diễn đạt phương án — đối chiếu với định nghĩa chuẩn của đề.\n• Vì sao sai? Theme/ThemeData lo style giao diện, không phải state/auth/logic chính ở đây."}}},{"id":215,"task":"slides","taskLabel":"Slides","num":214,"question":"Why extract list item widgets (e.g. TaskTile) and use Selector?","options":{"A":"To rebuild the entire screen on every tiny change always","B":"To reduce unnecessary rebuilds / narrow rebuild scope","C":"To disable DevTools","D":"To remove keys"},"answer":"B","alternatives":[],"source":"slides","exam":"PRM393_SLIDES_M12","explanation":{"questionVi":"Vì sao tách widget item list (vd. TaskTile) và dùng Selector?","optionsVi":{"A":"Để rebuild entire màn hình trên mọi tiny thay đổi Luôn","B":"Giảm rebuild thừa / thu hẹp phạm vi rebuild","C":"để Tắt DevTools","D":"để Gỡ bỏ keys"},"answerDisplay":"B. Giảm rebuild thừa / thu hẹp phạm vi rebuild","concept":"• Collection có thứ tự, phần tử truy cập bằng chỉ số, cho phép trùng.","whyCorrect":"• Collection có thứ tự, phần tử truy cập bằng chỉ số, cho phép trùng.\n• Lưu dãy phần tử 0..n-1.","intent":"• Phân biệt List / Set / Map trong Dart.\n• Thứ tự, trùng lặp, hay key–value.","whatIs":{"A":"để rebuild entire màn hình trên mọi tiny thay đổi Luôn","B":"Collection có thứ tự, phần tử truy cập bằng chỉ số, cho phép trùng.","C":"Cơ chế Flutter/Dart liên quan «để Tắt DevTools».","D":"Cơ chế Flutter/Dart liên quan «để Gỡ bỏ keys»."},"whyWrong":{"A":"• Là gì? để rebuild entire màn hình trên mọi tiny thay đổi Luôn\n• Dùng để làm gì? Bản dịch/diễn đạt phương án — đối chiếu với định nghĩa chuẩn của đề.\n• Vì sao sai? «To rebuild the entire screen on every tiny change always» — để rebuild entire màn hình trên mọi tiny thay đổi Luôn. Đề cần: Collection có thứ tự, phần tử truy cập bằng chỉ số, cho phép trùng.","C":"• Là gì? Cơ chế Flutter/Dart liên quan «để Tắt DevTools».\n• Dùng để làm gì? Đối chiếu đúng cơ chế/phạm trù với trọng tâm đề.\n• Vì sao sai? DevTools: debug performance/network/memory.","D":"• Là gì? Cơ chế Flutter/Dart liên quan «để Gỡ bỏ keys».\n• Dùng để làm gì? Đối chiếu đúng cơ chế/phạm trù với trọng tâm đề.\n• Vì sao sai? «To remove keys» — Cơ chế Flutter/Dart liên quan «để Gỡ bỏ keys». Đề cần: Collection có thứ tự, phần tử truy cập bằng chỉ số, cho phép trùng."}}},{"id":216,"task":"slides","taskLabel":"Slides","num":215,"question":"What is the main purpose of hot reload?","options":{"A":"Publish to stores","B":"Increase APK size","C":"Instantly reflect code changes in UI while developing","D":"Replace unit tests"},"answer":"C","alternatives":[],"source":"slides","exam":"PRM393_SLIDES_M12","explanation":{"questionVi":"Mục đích chính của hot reload?","optionsVi":{"A":"Publish để stores","B":"Tăng APK kích thước","C":"Phản ánh ngay thay đổi code lên UI khi dev","D":"Thay thế unit tests"},"answerDisplay":"C. Phản ánh ngay thay đổi code lên UI khi dev","concept":"• Nạp lại code UI gần như giữ state đang chạy.","whyCorrect":"• Nạp lại code UI gần như giữ state đang chạy.\n• Xem thay đổi nhanh khi dev.","intent":"• Nạp lại code UI gần như giữ state đang chạy.\n• Xem thay đổi nhanh khi dev.","whatIs":{"A":"Cụm «Publish để stores» mang một nghĩa riêng cần đối chiếu với đề.","B":"Gói cài đặt Android chứa mã và tài nguyên đã build.","C":"Nạp lại code UI gần như giữ state đang chạy.","D":"Cụm «Thay thế unit tests» mang một nghĩa riêng cần đối chiếu với đề."},"whyWrong":{"A":"• Là gì? Cụm «Publish để stores» mang một nghĩa riêng cần đối chiếu với đề.\n• Dùng để làm gì? So bản chất với đáp án đúng; loại nếu sai đối tượng hoặc sai lớp khái niệm.\n• Vì sao sai? Hot reload nạp code UI nhanh khi dev; không phải công cụ phân tích sâu.","B":"• Là gì? Gói cài đặt Android chứa mã và tài nguyên đã build.\n• Dùng để làm gì? Phát hành/cài app lên thiết bị.\n• Vì sao sai? Hot reload nạp code UI nhanh khi dev; không phải công cụ phân tích sâu.","D":"• Là gì? Cụm «Thay thế unit tests» mang một nghĩa riêng cần đối chiếu với đề.\n• Dùng để làm gì? So bản chất với đáp án đúng; loại nếu sai đối tượng hoặc sai lớp khái niệm.\n• Vì sao sai? Unit test: hàm/class nhỏ; không phải UI widget hay E2E."}}},{"id":217,"task":"slides","taskLabel":"Slides","num":216,"question":"Which command builds a release APK?","options":{"A":"flutter run","B":"flutter build apk","C":"flutter doctor --uninstall","D":"dart fix --dry-run only"},"answer":"B","alternatives":[],"source":"slides","exam":"PRM393_SLIDES_M12","explanation":{"questionVi":"Lệnh nào build APK release?","optionsVi":{"A":"flutter run","B":"flutter build apk","C":"flutter doctor --uninstall","D":"dart fix --dry-run only"},"answerDisplay":"B. flutter build apk","concept":"• Gói cài đặt Android chứa mã và tài nguyên đã build.","whyCorrect":"• Gói cài đặt Android chứa mã và tài nguyên đã build.\n• Phát hành/cài app lên thiết bị.","intent":"• Gói cài đặt Android chứa mã và tài nguyên đã build.\n• Phát hành/cài app lên thiết bị.","whatIs":{"A":"Cơ chế Flutter/Dart liên quan «flutter run».","B":"Gói cài đặt Android chứa mã và tài nguyên đã build.","C":"Lệnh kiểm tra môi trường SDK, toolchain, thiết bị Flutter.","D":"Cơ chế Flutter/Dart liên quan «dart fix --dry-run only»."},"whyWrong":{"A":"• Là gì? Cơ chế Flutter/Dart liên quan «flutter run».\n• Dùng để làm gì? Đối chiếu đúng cơ chế/phạm trù với trọng tâm đề.\n• Vì sao sai? «flutter run» — Cơ chế Flutter/Dart liên quan «flutter run». Đề cần: Gói cài đặt Android chứa mã và tài nguyên đã build.","C":"• Là gì? Lệnh kiểm tra môi trường SDK, toolchain, thiết bị Flutter.\n• Dùng để làm gì? Xác nhận cài đặt/PATH sau setup.\n• Vì sao sai? «flutter doctor --uninstall» — Lệnh kiểm tra môi trường SDK, toolchain, thiết bị Flutter. Đề cần: Gói cài đặt Android chứa mã và tài nguyên đã build.","D":"• Là gì? Cơ chế Flutter/Dart liên quan «dart fix --dry-run only».\n• Dùng để làm gì? Đối chiếu đúng cơ chế/phạm trù với trọng tâm đề.\n• Vì sao sai? «dart fix --dry-run only» — Cơ chế Flutter/Dart liên quan «dart fix --dry-run only». Đề cần: Gói cài đặt Android chứa mã và tài nguyên đã build."}}},{"id":218,"task":"slides","taskLabel":"Slides","num":217,"question":"Why use ValueKey(task.id) instead of UniqueKey() for list items?","options":{"A":"Preserve identity/state; UniqueKey forces excess rebuilds","B":"UniqueKey is always faster","C":"Keys are forbidden in lists","D":"ValueKey disables scrolling"},"answer":"A","alternatives":[],"source":"slides","exam":"PRM393_SLIDES_M12","explanation":{"questionVi":"Vì sao dùng ValueKey(task.id) thay UniqueKey() cho item list?","optionsVi":{"A":"Giữ identity/state; UniqueKey gây rebuild thừ","B":"UniqueKey là Luôn nhanh hơn","C":"Keys là forbidden trong lists","D":"ValueKey disables scrolling"},"answerDisplay":"A. Giữ identity/state; UniqueKey gây rebuild thừ","concept":"• Collection có thứ tự, phần tử truy cập bằng chỉ số, cho phép trùng.","whyCorrect":"• Collection có thứ tự, phần tử truy cập bằng chỉ số, cho phép trùng.\n• Lưu dãy phần tử 0..n-1.","intent":"• Phân biệt List / Set / Map trong Dart.\n• Thứ tự, trùng lặp, hay key–value.","whatIs":{"A":"Collection có thứ tự, phần tử truy cập bằng chỉ số, cho phép trùng.","B":"UniqueKey là Luôn nhanh hơn","C":"Keys là forbidden trong lists","D":"Cụm «ValueKey disables scrolling» mang một nghĩa riêng cần đối chiếu với đề."},"whyWrong":{"B":"• Là gì? UniqueKey là Luôn nhanh hơn\n• Dùng để làm gì? Bản dịch/diễn đạt phương án — đối chiếu với định nghĩa chuẩn của đề.\n• Vì sao sai? «UniqueKey is always faster» — UniqueKey là Luôn nhanh hơn. Đề cần: Collection có thứ tự, phần tử truy cập bằng chỉ số, cho phép trùng.","C":"• Là gì? Keys là forbidden trong lists\n• Dùng để làm gì? Bản dịch/diễn đạt phương án — đối chiếu với định nghĩa chuẩn của đề.\n• Vì sao sai? «Keys are forbidden in lists» — Keys là forbidden trong lists. Đề cần: Collection có thứ tự, phần tử truy cập bằng chỉ số, cho phép trùng.","D":"• Là gì? Cụm «ValueKey disables scrolling» mang một nghĩa riêng cần đối chiếu với đề.\n• Dùng để làm gì? So bản chất với đáp án đúng; loại nếu sai đối tượng hoặc sai lớp khái niệm.\n• Vì sao sai? «ValueKey disables scrolling» — Cụm «ValueKey disables scrolling» mang một nghĩa riêng cần đối chiếu với đề. Đề cần: Collection có thứ tự, phần tử truy cập bằng chỉ số, cho phép trùng."}}},{"id":219,"task":"slides","taskLabel":"Slides","num":218,"question":"GlobalKey warning in slides: GlobalKey is:","options":{"A":"Always free and should be used everywhere","B":"Powerful but expensive; avoid unless necessary","C":"Required for every Text widget","D":"Only used in unit tests"},"answer":"B","alternatives":[],"source":"slides","exam":"PRM393_SLIDES_M12","explanation":{"questionVi":"Cảnh báo GlobalKey trong slide: GlobalKey là:","optionsVi":{"A":"Luôn free và nên be được dùng everywhere","B":"Mạnh nhưng tốn kém; tránh dùng trừ khi cần","C":"Bắt buộc cho mọi Text widget","D":"Chỉ được dùng trong unit tests"},"answerDisplay":"B. Mạnh nhưng tốn kém; tránh dùng trừ khi cần","concept":"• Mạnh nhưng tốn kém; tránh dùng trừ khi cần. Bản dịch/diễn đạt phương án — đối chiếu với định nghĩa chuẩn của đề.","whyCorrect":"• Mạnh nhưng tốn kém; tránh dùng trừ khi cần\n• Bản dịch/diễn đạt phương án — đối chiếu với định nghĩa chuẩn của đề.","intent":"• Mạnh nhưng tốn kém; tránh dùng trừ khi cần\n• Bản dịch/diễn đạt phương án — đối chiếu với định nghĩa chuẩn của đề.","whatIs":{"A":"Luôn free và nên be được dùng everywhere","B":"Mạnh nhưng tốn kém; tránh dùng trừ khi cần","C":"Bắt buộc cho mọi Text widget","D":"Chỉ được dùng trong unit tests"},"whyWrong":{"A":"• Là gì? Luôn free và nên be được dùng everywhere\n• Dùng để làm gì? Bản dịch/diễn đạt phương án — đối chiếu với định nghĩa chuẩn của đề.\n• Vì sao sai? «Always free and should be used everywhere» — Luôn free và nên be được dùng everywhere. Đề cần: Mạnh nhưng tốn kém; tránh dùng trừ khi cần.","C":"• Là gì? Bắt buộc cho mọi Text widget\n• Dùng để làm gì? Bản dịch/diễn đạt phương án — đối chiếu với định nghĩa chuẩn của đề.\n• Vì sao sai? «Required for every Text widget» — Bắt buộc cho mọi Text widget. Đề cần: Mạnh nhưng tốn kém; tránh dùng trừ khi cần.","D":"• Là gì? Chỉ được dùng trong unit tests\n• Dùng để làm gì? Bản dịch/diễn đạt phương án — đối chiếu với định nghĩa chuẩn của đề.\n• Vì sao sai? Unit test: hàm/class nhỏ; không phải UI widget hay E2E."}}},{"id":220,"task":"slides","taskLabel":"Slides","num":219,"question":"Which practice improves deployment security?","options":{"A":"Hardcoding secrets in source","B":"Committing keystores to public repos","C":"Protecting signing keys / secure release process","D":"Using only debug builds in production"},"answer":"C","alternatives":[],"source":"slides","exam":"PRM393_SLIDES_M12","explanation":{"questionVi":"Thực hành nào cải thiện bảo mật triển khai?","optionsVi":{"A":"Hardcoding secrets trong mã nguồn","B":"Committing keystores để public repos","C":"Bảo vệ signing key / quy trình release an toàn","D":"Dùng chỉ debug builds trong production"},"answerDisplay":"C. Bảo vệ signing key / quy trình release an toàn","concept":"• Bảo vệ signing key / quy trình release an toàn. Bản dịch/diễn đạt phương án — đối chiếu với định nghĩa chuẩn của đề.","whyCorrect":"• Bảo vệ signing key / quy trình release an toàn\n• Bản dịch/diễn đạt phương án — đối chiếu với định nghĩa chuẩn của đề.","intent":"• Bảo vệ signing key / quy trình release an toàn\n• Bản dịch/diễn đạt phương án — đối chiếu với định nghĩa chuẩn của đề.","whatIs":{"A":"Hardcoding secrets trong mã nguồn","B":"Phần mềm quản lý phần cứng, tiến trình, bộ nhớ, I/O.","C":"Bảo vệ signing key / quy trình release an toàn","D":"Dùng chỉ debug builds trong production"},"whyWrong":{"A":"• Là gì? Hardcoding secrets trong mã nguồn\n• Dùng để làm gì? Bản dịch/diễn đạt phương án — đối chiếu với định nghĩa chuẩn của đề.\n• Vì sao sai? Thực hành kém về bảo mật/chất lượng — không phải đáp án đúng.","B":"• Là gì? Phần mềm quản lý phần cứng, tiến trình, bộ nhớ, I/O.\n• Dùng để làm gì? Cấp tài nguyên và lập lịch cho chương trình.\n• Vì sao sai? «Committing keystores to public repos» — Phần mềm quản lý phần cứng, tiến trình, bộ nhớ, I/O. Đề cần: Bảo vệ signing key / quy trình release an toàn.","D":"• Là gì? Dùng chỉ debug builds trong production\n• Dùng để làm gì? Bản dịch/diễn đạt phương án — đối chiếu với định nghĩa chuẩn của đề.\n• Vì sao sai? Thực hành kém về bảo mật/chất lượng — không phải đáp án đúng."}}},{"id":221,"task":"slides","taskLabel":"Slides","num":220,"question":"const widgets help performance because they:","options":{"A":"Can be reused and reduce rebuild work","B":"Force full screen invalidation always","C":"Disable tree shaking","D":"Remove AOT"},"answer":"A","alternatives":[],"source":"slides","exam":"PRM393_SLIDES_M12","explanation":{"questionVi":"const widget giúp hiệu năng vì chúng:","optionsVi":{"A":"Tái sử dụng được, giảm việc rebuild","B":"Ép full màn hình invalidation Luôn","C":"Tắt tree shaking","D":"Gỡ bỏ AOT"},"answerDisplay":"A. Tái sử dụng được, giảm việc rebuild","concept":"• Hằng được xác định từ lúc biên dịch (compile-time).","whyCorrect":"• Hằng được xác định từ lúc biên dịch (compile-time).\n• Giá trị bất biến, tối ưu và an toàn.","intent":"• Phân biệt const, final, var và null safety.\n• Compile-time vs runtime assignment.","memoryTip":"• UI = cây widget; BuildContext định vị trên cây; build() chỉ mô tả UI.","whatIs":{"A":"Hằng được xác định từ lúc biên dịch (compile-time).","B":"Ép full màn hình invalidation Luôn","C":"Cơ chế Flutter/Dart liên quan «Tắt tree shaking».","D":"Biên dịch Ahead-of-Time: dịch Dart ra native trước khi chạy (bản release)."},"whyWrong":{"B":"• Là gì? Ép full màn hình invalidation Luôn\n• Dùng để làm gì? Bản dịch/diễn đạt phương án — đối chiếu với định nghĩa chuẩn của đề.\n• Vì sao sai? const giúp tái sử dụng widget, giảm rebuild — đúng khi hỏi tối ưu const.","C":"• Là gì? Cơ chế Flutter/Dart liên quan «Tắt tree shaking».\n• Dùng để làm gì? Đối chiếu đúng cơ chế/phạm trù với trọng tâm đề.\n• Vì sao sai? const giúp tái sử dụng widget, giảm rebuild — đúng khi hỏi tối ưu const.","D":"• Là gì? Biên dịch Ahead-of-Time: dịch Dart ra native trước khi chạy (bản release).\n• Dùng để làm gì? Tối ưu hiệu năng bản ship; không phải widget layout.\n• Vì sao sai? const giúp tái sử dụng widget, giảm rebuild — đúng khi hỏi tối ưu const."}}},{"id":222,"task":"slides","taskLabel":"Slides","num":221,"question":"What is technical debt?","options":{"A":"A bank loan for GPUs","B":"Future cost of poor design decisions","C":"A Flutter widget","D":"A type of Future"},"answer":"B","alternatives":[],"source":"slides","exam":"PRM393_SLIDES_M12","explanation":{"questionVi":"Nợ kỹ thuật (technical debt) là gì?","optionsVi":{"A":"Một bank loan cho GPUs","B":"Chi phí tương lai do quyết định thiết kế kém","C":"Một Flutter widget","D":"Một kiểu Future"},"answerDisplay":"B. Chi phí tương lai do quyết định thiết kế kém","concept":"• Đối tượng đại diện một kết quả (hoặc lỗi) sẽ có sau thao tác bất đồng bộ.","whyCorrect":"• Đối tượng đại diện một kết quả (hoặc lỗi) sẽ có sau thao tác bất đồng bộ.\n• async/await, gọi API, đọc file một lần.","intent":"• Đối tượng đại diện một kết quả (hoặc lỗi) sẽ có sau thao tác bất đồng bộ.\n• async/await, gọi API, đọc file một lần.","whatIs":{"A":"Cụm «Một bank loan cho GPUs» mang một nghĩa riêng cần đối chiếu với đề.","B":"Đối tượng đại diện một kết quả (hoặc lỗi) sẽ có sau thao tác bất đồng bộ.","C":"Cơ chế Flutter/Dart liên quan «Một Flutter widget».","D":"Đối tượng đại diện một kết quả (hoặc lỗi) sẽ có sau thao tác bất đồng bộ."},"whyWrong":{"A":"• Là gì? Cụm «Một bank loan cho GPUs» mang một nghĩa riêng cần đối chiếu với đề.\n• Dùng để làm gì? So bản chất với đáp án đúng; loại nếu sai đối tượng hoặc sai lớp khái niệm.\n• Vì sao sai? Nợ kỹ thuật = chi phí tương lai do thiết kế kém.","C":"• Là gì? Cơ chế Flutter/Dart liên quan «Một Flutter widget».\n• Dùng để làm gì? Đối chiếu đúng cơ chế/phạm trù với trọng tâm đề.\n• Vì sao sai? Nợ kỹ thuật = chi phí tương lai do thiết kế kém.","D":"• Là gì? Đối tượng đại diện một kết quả (hoặc lỗi) sẽ có sau thao tác bất đồng bộ.\n• Dùng để làm gì? async/await, gọi API, đọc file một lần.\n• Vì sao sai? «A type of Future» lệch đối tượng/cơ chế so với đáp án đúng của đề."}}},{"id":223,"task":"slides","taskLabel":"Slides","num":222,"question":"Why is clean architecture beneficial?","options":{"A":"Easier maintenance and testing via separation of concerns","B":"Fewer files always regardless of design","C":"Guaranteed faster GPU","D":"Removes need for tests"},"answer":"A","alternatives":[],"source":"slides","exam":"PRM393_SLIDES_M12","explanation":{"questionVi":"Vì sao clean architecture có lợi?","optionsVi":{"A":"Dễ bảo trì/test nhờ tách mối quan tâm","B":"Fewer files Luôn regardless của thiết kế","C":"Guaranteed nhanh hơn GPU","D":"Removes cần cho tests"},"answerDisplay":"A. Dễ bảo trì/test nhờ tách mối quan tâm","concept":"• Dễ bảo trì/test nhờ tách mối quan tâm. Bản dịch/diễn đạt phương án — đối chiếu với định nghĩa chuẩn của đề.","whyCorrect":"• Dễ bảo trì/test nhờ tách mối quan tâm\n• Bản dịch/diễn đạt phương án — đối chiếu với định nghĩa chuẩn của đề.","intent":"• Dễ bảo trì/test nhờ tách mối quan tâm\n• Bản dịch/diễn đạt phương án — đối chiếu với định nghĩa chuẩn của đề.","whatIs":{"A":"Dễ bảo trì/test nhờ tách mối quan tâm","B":"Fewer files Luôn regardless của thiết kế","C":"Guaranteed nhanh hơn GPU","D":"Cụm «Removes cần cho tests» mang một nghĩa riêng cần đối chiếu với đề."},"whyWrong":{"B":"• Là gì? Fewer files Luôn regardless của thiết kế\n• Dùng để làm gì? Bản dịch/diễn đạt phương án — đối chiếu với định nghĩa chuẩn của đề.\n• Vì sao sai? Đây là lợi ích phụ hoặc không liên quan trực tiếp đến câu hỏi.","C":"• Là gì? Guaranteed nhanh hơn GPU\n• Dùng để làm gì? Bản dịch/diễn đạt phương án — đối chiếu với định nghĩa chuẩn của đề.\n• Vì sao sai? Tách lớp giúp bảo trì/test — đúng khi hỏi lợi ích architecture.","D":"• Là gì? Cụm «Removes cần cho tests» mang một nghĩa riêng cần đối chiếu với đề.\n• Dùng để làm gì? So bản chất với đáp án đúng; loại nếu sai đối tượng hoặc sai lớp khái niệm.\n• Vì sao sai? Tách lớp giúp bảo trì/test — đúng khi hỏi lợi ích architecture."}}},{"id":224,"task":"slides","taskLabel":"Slides","num":223,"question":"App size analysis before deployment helps you:","options":{"A":"Ignore unused assets forever","B":"Increase size intentionally without reason","C":"Find large assets/code to optimize release package","D":"Disable Play Store"},"answer":"C","alternatives":[],"source":"slides","exam":"PRM393_SLIDES_M12","explanation":{"questionVi":"Phân tích kích thước app trước deploy giúp:","optionsVi":{"A":"Ignore unused asset mãi mãi","B":"Tăng kích thước intentionally Không có reason","C":"Tìm asset/code lớn để tối ưu gói release","D":"Tắt Play Lưu"},"answerDisplay":"C. Tìm asset/code lớn để tối ưu gói release","concept":"• Tìm asset/code lớn để tối ưu gói release. Bản dịch/diễn đạt phương án — đối chiếu với định nghĩa chuẩn của đề.","whyCorrect":"• Tìm asset/code lớn để tối ưu gói release\n• Bản dịch/diễn đạt phương án — đối chiếu với định nghĩa chuẩn của đề.","intent":"• Tìm asset/code lớn để tối ưu gói release\n• Bản dịch/diễn đạt phương án — đối chiếu với định nghĩa chuẩn của đề.","whatIs":{"A":"Ignore unused asset mãi mãi","B":"Tăng kích thước intentionally Không có reason","C":"Tìm asset/code lớn để tối ưu gói release","D":"Cụm «Tắt Play Lưu» mang một nghĩa riêng cần đối chiếu với đề."},"whyWrong":{"A":"• Là gì? Ignore unused asset mãi mãi\n• Dùng để làm gì? Bản dịch/diễn đạt phương án — đối chiếu với định nghĩa chuẩn của đề.\n• Vì sao sai? «Ignore unused assets forever» — Ignore unused asset mãi mãi. Đề cần: Tìm asset/code lớn để tối ưu gói release.","B":"• Là gì? Tăng kích thước intentionally Không có reason\n• Dùng để làm gì? Bản dịch/diễn đạt phương án — đối chiếu với định nghĩa chuẩn của đề.\n• Vì sao sai? «Increase size intentionally without reason» — Tăng kích thước intentionally Không có reason. Đề cần: Tìm asset/code lớn để tối ưu gói release.","D":"• Là gì? Cụm «Tắt Play Lưu» mang một nghĩa riêng cần đối chiếu với đề.\n• Dùng để làm gì? So bản chất với đáp án đúng; loại nếu sai đối tượng hoặc sai lớp khái niệm.\n• Vì sao sai? «Disable Play Store» — Cụm «Tắt Play Lưu» mang một nghĩa riêng cần đối chiếu với đề. Đề cần: Tìm asset/code lớn để tối ưu gói release."}}},{"id":225,"task":"slides","taskLabel":"Slides","num":224,"question":"Why decide architecture early?","options":{"A":"Architecture never matters","B":"Reduce later refactoring cost","C":"To avoid writing UI","D":"To skip testing"},"answer":"B","alternatives":[],"source":"slides","exam":"PRM393_SLIDES_M12","explanation":{"questionVi":"Vì sao quyết định kiến trúc sớm?","optionsVi":{"A":"Kiến trúc Không bao giờ matters","B":"Giảm chi phí refactor sau này","C":"để Tránh writing UI","D":"để skip testing"},"answerDisplay":"B. Giảm chi phí refactor sau này","concept":"• Phần mềm quản lý phần cứng, tiến trình, bộ nhớ, I/O.","whyCorrect":"• Phần mềm quản lý phần cứng, tiến trình, bộ nhớ, I/O.\n• Cấp tài nguyên và lập lịch cho chương trình.","intent":"• Phần mềm quản lý phần cứng, tiến trình, bộ nhớ, I/O.\n• Cấp tài nguyên và lập lịch cho chương trình.","whatIs":{"A":"Kiến trúc Không bao giờ matters","B":"Phần mềm quản lý phần cứng, tiến trình, bộ nhớ, I/O.","C":"Cụm «để Tránh writing UI» mang một nghĩa riêng cần đối chiếu với đề.","D":"Cụm «để skip testing» mang một nghĩa riêng cần đối chiếu với đề."},"whyWrong":{"A":"• Là gì? Kiến trúc Không bao giờ matters\n• Dùng để làm gì? Bản dịch/diễn đạt phương án — đối chiếu với định nghĩa chuẩn của đề.\n• Vì sao sai? «Architecture never matters» — Kiến trúc Không bao giờ matters. Đề cần: Phần mềm quản lý phần cứng, tiến trình, bộ nhớ, I/O.","C":"• Là gì? Cụm «để Tránh writing UI» mang một nghĩa riêng cần đối chiếu với đề.\n• Dùng để làm gì? So bản chất với đáp án đúng; loại nếu sai đối tượng hoặc sai lớp khái niệm.\n• Vì sao sai? «To avoid writing UI» — Cụm «để Tránh writing UI» mang một nghĩa riêng cần đối chiếu với đề. Đề cần: Phần mềm quản lý phần cứng, tiến trình, bộ nhớ, I/O.","D":"• Là gì? Cụm «để skip testing» mang một nghĩa riêng cần đối chiếu với đề.\n• Dùng để làm gì? So bản chất với đáp án đúng; loại nếu sai đối tượng hoặc sai lớp khái niệm.\n• Vì sao sai? «To skip testing» — Cụm «để skip testing» mang một nghĩa riêng cần đối chiếu với đề. Đề cần: Phần mềm quản lý phần cứng, tiến trình, bộ nhớ, I/O."}}}];
